// =============================================================================
// ESLint 9 (flat config) — AutoDrive
// Next.js 16 removeu `next lint`; o lint roda via ESLint CLI com flat config.
// eslint-config-next 16 já exporta arrays de flat config (core-web-vitals +
// typescript), então basta espalhá-los.
// =============================================================================

import coreWebVitals from 'eslint-config-next/core-web-vitals'
import typescript from 'eslint-config-next/typescript'

export default [
  {
    ignores: [
      '.next/**',
      'node_modules/**',
      'prisma/migrations/**',
      'sheets-service/**', // microserviço Python
      'scripts/**',        // utilitários de manutenção/dev
      'next-env.d.ts',
      '*.config.js',
      'robo_pendencias_easycar.gs',
    ],
  },
  ...coreWebVitals,
  ...typescript,
  {
    rules: {
      // Permite parâmetros/variáveis intencionalmente não usados com prefixo "_".
      '@typescript-eslint/no-unused-vars': [
        'warn',
        { argsIgnorePattern: '^_', varsIgnorePattern: '^_', caughtErrorsIgnorePattern: '^_' },
      ],
      // Padrão fetch-on-mount (useEffect → load → setState) é usado em todo o
      // app; regra advisory mantida como aviso, não erro.
      'react-hooks/set-state-in-effect': 'warn',
      // Dívida de estilo pervasiva no código legado (nunca foi lintado).
      // Mantida VISÍVEL como aviso; código novo deve evitar. Limpeza do legado
      // pode ser feita em um passe dedicado (ratchet para 'error' depois).
      '@typescript-eslint/no-explicit-any': 'warn',
      'react/no-unescaped-entities': 'warn',
    },
  },
]

// =============================================================================
// AutoDrive — Seed do banco de dados
//
// Comportamento:
//   • SEMPRE: cria/atualiza o usuário MASTER lendo MASTER_EMAIL e
//     MASTER_PASSWORD do ambiente. Hash via bcryptjs (salt 12) — mesmo
//     padrão usado em src/lib/auth.ts e nas rotas de auth.
//
//   • OPCIONAL (apenas se SEED_DEMO=true): popula tenant demo, ADM demo,
//     unidade matriz, módulos, configurações globais, provider WhatsApp,
//     templates e config Google Sheets de exemplo.
//     ⚠️ NÃO rodar em produção sem ter certeza — gera dados fictícios.
//
// Idempotência:
//   Todas as operações usam `upsert` (ou findFirst + create) — pode ser
//   executado várias vezes sem duplicar dados.
//
// Segurança:
//   • A senha do MASTER NUNCA é logada (mostra apenas o e-mail).
//   • Em produção, SEMPRE setar MASTER_EMAIL e MASTER_PASSWORD via env.
//   • O fallback de senha padrão só é usado em dev local, e o seed emite
//     warning bem visível.
// =============================================================================

import { PrismaClient, UserRole, UserStatus, TenantStatus, TenantPlan } from '@prisma/client'
// O `tsconfig` deste projeto tem `esModuleInterop: true` (necessário pro
// runtime do app), mas o seed roda via ts-node com módulo CommonJS — onde
// o default-import do bcryptjs falha. Usamos namespace import por garantia.
import * as bcrypt from 'bcryptjs'

const prisma = new PrismaClient()

// ── Lê configuração da env ──────────────────────────────────────────────────

const MASTER_EMAIL    = process.env.MASTER_EMAIL?.trim().toLowerCase()    || 'admin@autodrive.com.br'
const MASTER_PASSWORD = process.env.MASTER_PASSWORD                        || ''
const MASTER_NAME     = process.env.MASTER_NAME?.trim()                    || 'Administrador Master'
const MASTER_PHONE    = process.env.MASTER_PHONE?.trim()                   || null
const SEED_DEMO       = (process.env.SEED_DEMO ?? '').toLowerCase() === 'true'

// Senha padrão APENAS para desenvolvimento local. Em produção MASTER_PASSWORD
// deve sempre vir do ambiente.
const DEFAULT_DEV_PASSWORD = 'Admin@123'

function resolveMasterPassword(): { plain: string; usingDefault: boolean } {
  if (MASTER_PASSWORD && MASTER_PASSWORD.length >= 8) {
    return { plain: MASTER_PASSWORD, usingDefault: false }
  }
  if (process.env.NODE_ENV === 'production') {
    throw new Error(
      'MASTER_PASSWORD não foi definida no ambiente de produção. ' +
      'Defina MASTER_PASSWORD (mínimo 8 caracteres) antes de rodar `prisma db seed`.',
    )
  }
  return { plain: DEFAULT_DEV_PASSWORD, usingDefault: true }
}

function generatePublicId(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'
  let id = 'AD-'
  for (let i = 0; i < 10; i++) {
    id += chars[Math.floor(Math.random() * chars.length)]
  }
  return id
}

// ── Cargos padrão do sistema (sempre, não-DEMO) ─────────────────────────────

const SYSTEM_POSITIONS: Array<{
  name: string
  slug: string
  baseRole: UserRole
  sortOrder: number
}> = [
  { name: 'Vendedor',                slug: 'vendedor',             baseRole: UserRole.VENDEDOR,        sortOrder: 10 },
  { name: 'Vendedor Líder',          slug: 'vendedor_lider',       baseRole: UserRole.VENDEDOR_LIDER,  sortOrder: 11 },
  { name: 'Gerente',                 slug: 'gerente',              baseRole: UserRole.GERENTE,         sortOrder: 20 },
  { name: 'Gerente Geral',           slug: 'gerente_geral',        baseRole: UserRole.GERENTE_GERAL,   sortOrder: 30 },
  { name: 'Documentação',            slug: 'documentacao',         baseRole: UserRole.USUARIO,         sortOrder: 40 },
  { name: 'Gerente de Documentação', slug: 'gerente_documentacao', baseRole: UserRole.USUARIO_LIDER,   sortOrder: 41 },
  { name: 'Financeiro',              slug: 'financeiro',           baseRole: UserRole.USUARIO,         sortOrder: 50 },
  { name: 'Gerente do Financeiro',   slug: 'gerente_financeiro',   baseRole: UserRole.USUARIO_LIDER,   sortOrder: 51 },
  { name: 'F&I',                     slug: 'fi',                   baseRole: UserRole.USUARIO,         sortOrder: 60 },
  { name: 'Auxiliar Geral',          slug: 'auxiliar_geral',       baseRole: UserRole.USUARIO,         sortOrder: 70 },
  { name: 'Motorista',               slug: 'motorista',            baseRole: UserRole.USUARIO,         sortOrder: 80 },
  { name: 'Preparador',              slug: 'preparador',           baseRole: UserRole.USUARIO,         sortOrder: 90 },
]

async function upsertSystemPositions(): Promise<void> {
  for (const p of SYSTEM_POSITIONS) {
    // tenantId é nullable, então @@unique([tenantId, slug]) com null é tratado
    // como múltiplas linhas distintas pelo Postgres. Usamos findFirst + create
    // para garantir idempotência por (tenantId IS NULL, slug).
    const existing = await prisma.position.findFirst({
      where: { tenantId: null, slug: p.slug },
      select: { id: true },
    })
    if (existing) {
      await prisma.position.update({
        where: { id: existing.id },
        data: {
          name:      p.name,
          baseRole:  p.baseRole,
          isSystem:  true,
          active:    true,
          sortOrder: p.sortOrder,
        },
      })
    } else {
      await prisma.position.create({
        data: {
          tenantId:  null,
          name:      p.name,
          slug:      p.slug,
          baseRole:  p.baseRole,
          isSystem:  true,
          active:    true,
          sortOrder: p.sortOrder,
        },
      })
    }
  }
  console.log(`   ✓ ${SYSTEM_POSITIONS.length} cargos padrão garantidos`)
}

// ── Função obrigatória: upsert do usuário MASTER ────────────────────────────

async function upsertMaster(): Promise<{ id: string; email: string }> {
  const { plain, usingDefault } = resolveMasterPassword()
  const passwordHash = await bcrypt.hash(plain, 12)

  // MASTER da plataforma NÃO tem tenantId (acesso global).
  const master = await prisma.user.upsert({
    where:  { email: MASTER_EMAIL },
    update: {
      name:               MASTER_NAME,
      passwordHash,
      role:               UserRole.MASTER,
      status:             UserStatus.ATIVO,
      mustChangePassword: false,
      phone:              MASTER_PHONE,
    },
    create: {
      name:               MASTER_NAME,
      email:              MASTER_EMAIL,
      phone:              MASTER_PHONE,
      passwordHash,
      role:               UserRole.MASTER,
      status:             UserStatus.ATIVO,
      mustChangePassword: false,
      // tenantId nulo — MASTER opera fora de qualquer tenant
    },
    select: { id: true, email: true },
  })

  console.log(`   ✓ MASTER ${master.email} (id: ${master.id})`)
  if (usingDefault) {
    console.warn(
      '\n   ⚠️  USANDO SENHA PADRÃO DE DESENVOLVIMENTO. ' +
      'Configure MASTER_PASSWORD na env para produção.\n',
    )
  }
  return master
}

// ── Seed opcional de DEMO (tenant + ADM + módulos + templates) ──────────────
//
// Só roda quando SEED_DEMO=true. Em produção (Neon/Vercel) NÃO setar essa
// variável: o banco fica limpo, apenas com o MASTER.

async function seedDemoData(masterUserId: string) {
  console.log('\n🏢 [DEMO] Criando tenant demo...')
  const tenant = await prisma.tenant.upsert({
    where:  { slug: 'autodrive-demo' },
    update: {},
    create: {
      publicId:     generatePublicId(),
      slug:         'autodrive-demo',
      name:         'AutoDrive Demo',
      razaoSocial:  'AutoDrive Veículos LTDA',
      cnpj:         '00.000.000/0001-00',
      email:        'demo@autodrive.com.br',
      phone:        '(11) 99999-0000',
      plan:         TenantPlan.CUSTOM,
      status:       TenantStatus.ATIVO,
      primaryColor: '#166534',
      slogan:       'Sua loja no piloto automático',
      responsavel:  'Administrador AutoDrive',
    },
  })
  console.log(`   ✓ Tenant: ${tenant.name} (${tenant.publicId})`)

  // Módulos do tenant demo
  const modulesToActivate = [
    'dashboard', 'pendencies', 'negotiations', 'commissions', 'communication',
    'documents', 'registrations', 'settings', 'logs',
  ]
  for (const module of modulesToActivate) {
    await prisma.tenantModule.upsert({
      where:  { tenantId_module: { tenantId: tenant.id, module } },
      update: { active: true },
      create: { tenantId: tenant.id, module, active: true },
    })
  }
  console.log(`   ✓ ${modulesToActivate.length} módulos ativados`)

  // Unidade demo
  const unit = await prisma.unit.upsert({
    where:  { cnpj: '00.000.000/0001-00' },
    update: { tenantId: tenant.id },
    create: {
      tenantId:    tenant.id,
      name:        'AutoDrive Loja Matriz',
      razaoSocial: 'AutoDrive Veículos LTDA',
      cnpj:        '00.000.000/0001-00',
      address:     'Av. Principal, 1000',
      city:        'São Paulo',
      state:       'SP',
      phone:       '(11) 99999-0000',
      email:       'matriz@autodrive.com.br',
      responsavel: 'Administrador Geral',
      active:      true,
    },
  })
  console.log(`   ✓ Unidade demo: ${unit.name}`)

  // ADM do tenant demo — senha igual à do MASTER (apenas para conveniência em dev)
  const { plain } = resolveMasterPassword()
  const admHash = await bcrypt.hash(plain, 12)
  const admUser = await prisma.user.upsert({
    where:  { email: 'adm@autodrive-demo.com.br' },
    update: {
      passwordHash: admHash,
      role:         UserRole.ADM,
      status:       UserStatus.ATIVO,
      tenantId:     tenant.id,
      unitId:       unit.id,
    },
    create: {
      name:         'Administrador Demo',
      email:        'adm@autodrive-demo.com.br',
      passwordHash: admHash,
      role:         UserRole.ADM,
      status:       UserStatus.ATIVO,
      tenantId:     tenant.id,
      unitId:       unit.id,
    },
  })
  console.log(`   ✓ ADM demo: ${admUser.email}`)

  // ── Configurações do sistema ──────────────────────────────────────────────
  const systemSettings = [
    { key: 'app_name',        value: 'AutoDrive',                     description: 'Nome da plataforma',         group: 'identity' },
    { key: 'app_slogan',      value: 'Sua loja no piloto automático', description: 'Slogan da plataforma',       group: 'identity' },
    { key: 'app_version',     value: '2.0.0',                        description: 'Versão atual',               group: 'identity' },
    { key: 'app_url',         value: 'http://localhost:3000',         description: 'URL base da aplicação',      group: 'identity' },
    { key: 'app_color_primary', value: '#166534',                     description: 'Cor primária',              group: 'identity' },
    { key: 'whatsapp_send_enabled',     value: 'false',  description: 'Habilita envio WhatsApp', group: 'whatsapp' },
    { key: 'session_timeout_minutes',   value: '480',    description: 'Timeout de sessão (min)', group: 'system'   },
    { key: 'max_login_attempts',        value: '5',      description: 'Tentativas máx. login',  group: 'system'   },
    { key: 'maintenance_mode',          value: 'false',  description: 'Modo de manutenção',      group: 'system'   },
  ]
  for (const setting of systemSettings) {
    await prisma.systemSetting.upsert({
      where:  { key: setting.key },
      update: { value: setting.value, description: setting.description, updatedByUserId: masterUserId },
      create: { ...setting, updatedByUserId: masterUserId },
    })
  }
  console.log(`   ✓ ${systemSettings.length} configurações iniciais`)

  // Preferência de notificação do master
  await prisma.notificationPreference.upsert({
    where:  { userId: masterUserId },
    update: {},
    create: {
      userId:         masterUserId,
      appWeb:         true,
      appMobile:      false,
      whatsapp:       false,
      email:          false,
      push:           false,
      newPendency:    true,
      pendencyUrgent: true,
      commissionPaid: true,
      systemAlerts:   true,
    },
  })
  console.log(`   ✓ Preferências do MASTER ajustadas`)
}

// ── Entrypoint ──────────────────────────────────────────────────────────────

async function main() {
  console.log('\n🚀 AutoDrive — Iniciando seed...')
  console.log(`   Ambiente: ${process.env.NODE_ENV ?? 'development'}`)
  console.log(`   Dados demo: ${SEED_DEMO ? 'sim (SEED_DEMO=true)' : 'não'}\n`)

  console.log('👤 Garantindo usuário MASTER...')
  const master = await upsertMaster()

  console.log('\n🎯 Garantindo cargos padrão do sistema...')
  await upsertSystemPositions()

  if (SEED_DEMO) {
    await seedDemoData(master.id)
  }

  console.log('\n' + '═'.repeat(60))
  console.log('✅ AutoDrive seed concluído com sucesso!')
  console.log('═'.repeat(60))
  console.log(`\n📌 Login MASTER: ${master.email}`)
  console.log('   (a senha NÃO é exibida — use a definida em MASTER_PASSWORD)\n')
}

main()
  .catch((e) => {
    console.error('❌ Erro no seed:', e instanceof Error ? e.message : e)
    process.exit(1)
  })
  .finally(async () => {
    await prisma.$disconnect()
  })

'use client'

// =============================================================================
// Login Page — AutoDrive
// =============================================================================

import { useState, useEffect } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { signIn, useSession } from 'next-auth/react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import Link from 'next/link'
import { Eye, EyeOff, Loader2 } from 'lucide-react'

// ── Schema ─────────────────────────────────────────────────────────────────

const loginSchema = z.object({
  email: z.string().min(1, 'E-mail obrigatório').email('E-mail inválido'),
  password: z.string().min(1, 'Senha obrigatória'),
})

type LoginFormData = z.infer<typeof loginSchema>

// ── Mensagens de erro ───────────────────────────────────────────────────────

const AUTH_ERROR_MESSAGES: Record<string, string> = {
  CredentialsSignin: 'E-mail ou senha incorretos. Verifique e tente novamente.',
  INACTIVE: 'Usuário inativo. Entre em contato com o administrador.',
  PENDING:  'Cadastro aguardando aprovação. Entre em contato com o administrador.',
  BLOCKED:  'Usuário bloqueado. Entre em contato com o suporte.',
}

// ── Componente ──────────────────────────────────────────────────────────────

export default function LoginPage() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { data: session, status } = useSession()

  const [showPassword, setShowPassword] = useState(false)
  const [authError, setAuthError] = useState<string | null>(null)
  const [isSubmitting, setIsSubmitting] = useState(false)

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginFormData>({ resolver: zodResolver(loginSchema) })

  // Redireciona se já autenticado
  useEffect(() => {
    if (status === 'authenticated' && session) {
      router.replace('/dashboard')
    }
  }, [status, session, router])

  // Lê erro da URL (next-auth redirect com ?error=)
  useEffect(() => {
    const errorParam = searchParams.get('error')
    if (errorParam) {
      setAuthError(
        AUTH_ERROR_MESSAGES[errorParam] ??
          'Credenciais inválidas. Verifique e tente novamente.',
      )
    }
  }, [searchParams])

  const onSubmit = async (data: LoginFormData) => {
    setIsSubmitting(true)
    setAuthError(null)

    try {
      const result = await signIn('credentials', {
        email:    data.email,
        password: data.password,
        redirect: false,
      })

      if (result?.error) {
        setAuthError(
          AUTH_ERROR_MESSAGES[result.error] ??
            'Credenciais inválidas. Verifique e tente novamente.',
        )
      } else if (result?.ok) {
        router.replace('/dashboard')
      }
    } catch {
      setAuthError('Erro inesperado. Tente novamente.')
    } finally {
      setIsSubmitting(false)
    }
  }

  if (status === 'loading' || status === 'authenticated') return null

  return (
    <div className="px-8 py-8">
      {/* Título do card */}
      <div className="mb-6 text-center">
        <h2 className="text-xl font-bold text-gray-900">Entrar na plataforma</h2>
        <p className="mt-1 text-sm text-gray-500">
          Insira suas credenciais de acesso
        </p>
      </div>

      {/* Banner de erro */}
      {authError && (
        <div className="mb-5 flex items-start gap-2.5 rounded-lg border border-red-200 bg-red-50 px-4 py-3">
          <div className="mt-0.5 h-4 w-4 shrink-0 rounded-full bg-red-500 flex items-center justify-center">
            <span className="text-[10px] font-bold text-white">!</span>
          </div>
          <p className="text-sm text-red-700 leading-snug">{authError}</p>
        </div>
      )}

      {/* Formulário */}
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
        {/* E-mail */}
        <div>
          <label htmlFor="email" className="label">
            E-mail
          </label>
          <input
            id="email"
            type="email"
            autoComplete="email"
            placeholder="seu@email.com"
            {...register('email')}
            className={`input ${errors.email ? 'border-red-400 bg-red-50' : ''}`}
          />
          {errors.email && (
            <p className="mt-1 text-xs text-red-600">{errors.email.message}</p>
          )}
        </div>

        {/* Senha */}
        <div>
          <label htmlFor="password" className="label">
            Senha
          </label>
          <div className="relative">
            <input
              id="password"
              type={showPassword ? 'text' : 'password'}
              autoComplete="current-password"
              placeholder="••••••••"
              {...register('password')}
              className={`input pr-10 ${errors.password ? 'border-red-400 bg-red-50' : ''}`}
            />
            <button
              type="button"
              onClick={() => setShowPassword((v) => !v)}
              tabIndex={-1}
              aria-label={showPassword ? 'Ocultar senha' : 'Mostrar senha'}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition"
            >
              {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>
          {errors.password && (
            <p className="mt-1 text-xs text-red-600">{errors.password.message}</p>
          )}
        </div>

        {/* Esqueci a senha */}
        <div className="flex justify-end">
          <Link
            href="/recuperar-senha"
            className="text-xs font-medium text-brand-800 hover:text-brand-600 transition"
          >
            Esqueci minha senha
          </Link>
        </div>

        {/* Botão entrar */}
        <button
          type="submit"
          disabled={isSubmitting}
          className="btn-primary w-full"
        >
          {isSubmitting ? (
            <>
              <Loader2 className="w-4 h-4 animate-spin" />
              Entrando...
            </>
          ) : (
            'Entrar'
          )}
        </button>
      </form>

      {/* Ações secundárias */}
      <div className="mt-5 space-y-2 border-t border-gray-100 pt-5">
        <Link
          href="/ativar-cadastro"
          className="btn-secondary w-full text-center"
        >
          Ativar cadastro
        </Link>
        <Link
          href="/cadastro"
          className="btn-secondary w-full text-center"
        >
          Solicitar acesso
        </Link>
      </div>
    </div>
  )
}

'use client'

// =============================================================================
// Cadastro de Cargos — EasyCar
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import {
  Plus, Pencil, Trash2, Briefcase, X, Save, CheckCircle, AlertCircle, ShieldCheck,
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { canAccessModule, ROLE_LABELS, type UserRole } from '@/lib/permissions'

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

interface Position {
  id:          string
  tenantId:    string | null
  name:        string
  slug:        string
  description: string | null
  baseRole:    UserRole | null
  isSystem:    boolean
  active:      boolean
  sortOrder:   number
}

type PositionForm = {
  name:        string
  description: string
  baseRole:    UserRole | ''
  sortOrder:   number
  active:      boolean
}

const EMPTY_FORM: PositionForm = {
  name:        '',
  description: '',
  baseRole:    '',
  sortOrder:   0,
  active:      true,
}

const ROLE_OPTIONS: UserRole[] = [
  'MASTER',
  'ADM',
  'GERENTE_GERAL',
  'GERENTE',
  'VENDEDOR_LIDER',
  'VENDEDOR',
  'USUARIO_LIDER',
  'USUARIO',
]

// -----------------------------------------------------------------------------
// Helpers
// -----------------------------------------------------------------------------

function inputClass(extra?: string) {
  return cn(
    'w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500',
    extra,
  )
}

function ToggleRow({ checked, onChange, label }: { checked: boolean; onChange: (v: boolean) => void; label: string }) {
  return (
    <div className="flex items-center justify-between rounded-lg border border-gray-200 bg-gray-50 px-4 py-3">
      <span className="text-sm font-medium text-gray-700">{label}</span>
      <button
        type="button"
        role="switch"
        aria-checked={checked}
        onClick={() => onChange(!checked)}
        className={cn(
          'relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2',
          checked ? 'bg-brand-600' : 'bg-gray-200',
        )}
      >
        <span className={cn('inline-block h-4 w-4 rounded-full bg-white shadow transition-transform', checked ? 'translate-x-6' : 'translate-x-1')} />
      </button>
    </div>
  )
}

// -----------------------------------------------------------------------------
// Modal
// -----------------------------------------------------------------------------

function Modal({
  open, onClose, onSave, initial, saving, error,
}: {
  open:    boolean
  onClose: () => void
  onSave:  (data: PositionForm) => Promise<void>
  initial?: Position | null
  saving:  boolean
  error:   string | null
}) {
  const [form, setForm] = useState<PositionForm>(EMPTY_FORM)

  useEffect(() => {
    if (open) {
      setForm(
        initial
          ? {
              name:        initial.name,
              description: initial.description ?? '',
              baseRole:    initial.baseRole ?? '',
              sortOrder:   initial.sortOrder,
              active:      initial.active,
            }
          : { ...EMPTY_FORM },
      )
    }
  }, [open, initial])

  if (!open) return null

  const set = <K extends keyof PositionForm>(key: K, value: PositionForm[K]) => {
    setForm((prev) => ({ ...prev, [key]: value }))
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative w-full max-w-xl max-h-[90vh] overflow-y-auto rounded-2xl bg-white shadow-2xl">
        <div className="sticky top-0 flex items-center justify-between border-b border-gray-200 bg-white px-6 py-4 z-10">
          <div className="flex items-center gap-3">
            <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-brand-50">
              <Briefcase className="h-5 w-5 text-brand-700" />
            </div>
            <h2 className="text-base font-semibold text-gray-900">
              {initial ? 'Editar Cargo' : 'Novo Cargo'}
            </h2>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-600 transition-colors">
            <X className="h-5 w-5" />
          </button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSave(form) }} className="px-6 py-5 space-y-4">
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Nome do cargo *</label>
              <input required className={inputClass()} value={form.name} onChange={(e) => set('name', e.target.value)} placeholder="Ex: Vendedor Sênior" />
            </div>
            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Descrição</label>
              <textarea
                rows={2}
                className={inputClass('resize-none')}
                value={form.description}
                onChange={(e) => set('description', e.target.value)}
                placeholder="Descreva as responsabilidades..."
              />
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Role base (sistema)</label>
              <select
                className={inputClass()}
                value={form.baseRole}
                onChange={(e) => set('baseRole', e.target.value as UserRole | '')}
              >
                <option value="">— Nenhum —</option>
                {ROLE_OPTIONS.map((r) => (
                  <option key={r} value={r}>{ROLE_LABELS[r]}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Ordem</label>
              <input
                type="number"
                min={0}
                className={inputClass()}
                value={form.sortOrder}
                onChange={(e) => set('sortOrder', Number(e.target.value) || 0)}
              />
            </div>
          </div>

          <ToggleRow label="Cargo ativo" checked={form.active} onChange={(v) => set('active', v)} />

          {error && (
            <div className="flex items-center gap-2 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-700">
              <AlertCircle className="h-4 w-4 shrink-0" />
              {error}
            </div>
          )}

          <div className="flex justify-end gap-3 border-t border-gray-100 pt-4">
            <button type="button" onClick={onClose} className="rounded-lg border border-gray-300 px-5 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors">
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 rounded-lg bg-brand-700 px-5 py-2.5 text-sm font-medium text-white hover:bg-brand-800 disabled:opacity-60 transition-colors"
            >
              <Save className="h-4 w-4" />
              {saving ? 'Salvando...' : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

