// Clientes — AutoDrive
// Cadastro e busca de clientes
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { Users, Search, RefreshCw, Plus, Eye, Phone, Mail } from 'lucide-react'
import { cn, formatDate } from '@/lib/utils'

interface Customer {
  id:        string
  name:      string
  cpf:       string | null
  email:     string | null
  phone:     string | null
  whatsapp:  string | null
  city:      string | null
  state:     string | null
  createdAt: string
}

export default function ClientesPage() {
  const [customers, setCustomers] = useState<Customer[]>([])
  const [loading, setLoading]     = useState(true)
  const [search, setSearch]       = useState('')
  const [page, setPage]           = useState(1)
  const [total, setTotal]         = useState(0)
  const PER_PAGE = 50

  const fetchCustomers = useCallback(async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams({ page: String(page), perPage: String(PER_PAGE) })
      if (search) params.set('search', search)
      const res  = await fetch(`/api/customers?${params}`, { credentials: 'include' })
      const data = await res.json()
      if (data.success) {
        setCustomers(data.data ?? [])
        setTotal(data.meta?.total ?? 0)
      }
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [page, search])

  useEffect(() => { fetchCustomers() }, [fetchCustomers])

  const totalPages = Math.ceil(total / PER_PAGE)

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-gray-900">Clientes</h1>
          <p className="mt-0.5 text-sm text-gray-500">{loading ? 'Carregando...' : `${total} clientes cadastrados`}</p>
        </div>
        <div className="flex gap-2">
          <button onClick={fetchCustomers} disabled={loading} className="btn-secondary text-xs">
            <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
          </button>
          <button className="btn-primary text-xs">
            <Plus size={13} />
            Novo cliente
          </button>
        </div>
      </div>

      <div className="relative max-w-sm">
        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
        <input
          value={search}
          onChange={(e) => { setSearch(e.target.value); setPage(1) }}
          placeholder="Buscar por nome, CPF ou e-mail..."
          className="input pl-9"
        />
      </div>

      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-card">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200 text-sm">
            <thead className="bg-gray-50">
              <tr>
                {['Nome','CPF','Contato','Cidade/UF','Cadastrado em','Ações'].map((h) => (
                  <th key={h} className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wide text-gray-500 whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {loading ? (
                Array.from({ length: 8 }).map((_, i) => (
                  <tr key={i}>
                    {Array.from({ length: 6 }).map((_, j) => (
                      <td key={j} className="px-4 py-3"><div className="h-4 animate-pulse rounded bg-gray-200" /></td>
                    ))}
                  </tr>
                ))
              ) : customers.length === 0 ? (
                <tr>
                  <td colSpan={6} className="py-14 text-center">
                    <Users size={32} className="mx-auto mb-2 text-gray-300" strokeWidth={1} />
                    <p className="text-sm text-gray-400">Nenhum cliente encontrado</p>
                  </td>
                </tr>
              ) : (
                customers.map((c) => (
                  <tr key={c.id} className="hover:bg-gray-50">
                    <td className="whitespace-nowrap px-4 py-3 font-medium text-gray-800">{c.name}</td>
                    <td className="px-4 py-3 font-mono text-xs text-gray-500">{c.cpf ?? '—'}</td>
                    <td className="px-4 py-3">
                      <div className="flex flex-col gap-0.5">
                        {c.phone && (
                          <span className="flex items-center gap-1 text-xs text-gray-600">
                            <Phone size={11} />{c.phone}
                          </span>
                        )}
                        {c.email && (
                          <span className="flex items-center gap-1 text-xs text-gray-500">
                            <Mail size={11} />{c.email}
                          </span>
                        )}
                        {!c.phone && !c.email && <span className="text-gray-300 text-xs">—</span>}
                      </div>
                    </td>
                    <td className="whitespace-nowrap px-4 py-3 text-sm text-gray-600">
                      {c.city && c.state ? `${c.city}/${c.state}` : c.city ?? c.state ?? '—'}
                    </td>
                    <td className="whitespace-nowrap px-4 py-3 text-xs text-gray-400">
                      {formatDate(new Date(c.createdAt))}
                    </td>
                    <td className="px-4 py-3">
                      <button className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700">
                        <Eye size={13} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
        {totalPages > 1 && (
          <div className="flex items-center justify-between border-t px-4 py-3">
            <p className="text-xs text-gray-500">Página {page} de {totalPages} — {total} clientes</p>
            <div className="flex gap-2">
              <button disabled={page <= 1 || loading} onClick={() => setPage((p) => p - 1)} className="btn-secondary text-xs disabled:opacity-40">Anterior</button>
              <button disabled={page >= totalPages || loading} onClick={() => setPage((p) => p + 1)} className="btn-secondary text-xs disabled:opacity-40">Próxima</button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

// =============================================================================
// Cadastro de Garantias — AutoDrive
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { Plus, Pencil, Shield, X, Save, CheckCircle, AlertCircle } from 'lucide-react'
import { cn, formatMoney } from '@/lib/utils'
import { maskBRL, parseBRL } from '@/lib/masks'

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

interface Warranty {
  id: string
  name: string
  provider: string
  defaultValue: number
  defaultCommission: number
  active: boolean
  notes: string
}

type WarrantyForm = Omit<Warranty, 'id'>

const emptyForm: WarrantyForm = {
  name: '',
  provider: '',
  defaultValue: 0,
  defaultCommission: 0,
  active: true,
  notes: '',
}

// -----------------------------------------------------------------------------
// Helpers
// -----------------------------------------------------------------------------

function inputClass(extra?: string) {
  return cn(
    'w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500',
    extra
  )
}

function ToggleRow({ checked, onChange, label }: { checked: boolean; onChange: (v: boolean) => void; label: string }) {
  return (
    <div className="flex items-center justify-between rounded-lg border border-gray-200 bg-gray-50 px-4 py-3">
      <span className="text-sm font-medium text-gray-700">{label}</span>
      <button
        type="button"
        role="switch"
        aria-checked={checked}
        onClick={() => onChange(!checked)}
        className={cn(
          'relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2',
          checked ? 'bg-brand-600' : 'bg-gray-200'
        )}
      >
        <span className={cn('inline-block h-4 w-4 rounded-full bg-white shadow transition-transform', checked ? 'translate-x-6' : 'translate-x-1')} />
      </button>
    </div>
  )
}

// -----------------------------------------------------------------------------
// Modal
// -----------------------------------------------------------------------------

function Modal({
  open, onClose, onSave, initial, saving, error,
}: {
  open: boolean
  onClose: () => void
  onSave: (data: WarrantyForm) => Promise<void>
  initial?: Warranty | null
  saving: boolean
  error: string | null
}) {
  const [form, setForm] = useState<WarrantyForm>(emptyForm)

  useEffect(() => {
    if (open) {
      setForm(initial ? { ...initial } : { ...emptyForm })
    }
  }, [open, initial])

  if (!open) return null

  const set = <K extends keyof WarrantyForm>(key: K, value: WarrantyForm[K]) => {
    setForm((prev) => ({ ...prev, [key]: value }))
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative w-full max-w-xl max-h-[90vh] overflow-y-auto rounded-2xl bg-white shadow-2xl">
        <div className="sticky top-0 flex items-center justify-between border-b border-gray-200 bg-white px-6 py-4 z-10">
          <div className="flex items-center gap-3">
            <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-brand-50">
              <Shield className="h-5 w-5 text-brand-700" />
            </div>
            <h2 className="text-base font-semibold text-gray-900">
              {initial ? 'Editar Garantia' : 'Nova Garantia'}
            </h2>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-600 transition-colors">
            <X className="h-5 w-5" />
          </button>
        </div>

        <form
          onSubmit={(e) => { e.preventDefault(); onSave(form) }}
          className="px-6 py-5 space-y-4"
        >
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Nome da garantia *</label>
              <input required className={inputClass()} value={form.name} onChange={(e) => set('name', e.target.value)} placeholder="Garantia Estendida 12 meses" />
            </div>
            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Fornecedor / Seguradora</label>
              <input className={inputClass()} value={form.provider} onChange={(e) => set('provider', e.target.value)} placeholder="Nome do fornecedor" />
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Valor padrão (R$)</label>
              <input
                type="text"
                inputMode="numeric"
