  FIXO:       'Valor Fixo (R$)',
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="mb-1 block text-xs font-medium text-gray-700">{label}</label>
      {children}
    </div>
  )
}

function inputCls(extra?: string) {
  return cn(
    'w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400',
    'focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500',
    extra,
  )
}

// ── Modal — Criar / Editar ────────────────────────────────────────────────────

function RuleModal({
  initial,
  positions,
  onClose,
  onSaved,
}: {
  initial:   CommissionRule | null
  positions: PositionLite[]
  onClose:   () => void
  onSaved:   () => void
}) {
  const isEdit = !!initial
  const [form, setForm] = useState<Omit<CommissionRule, 'id' | 'unit' | 'position'>>(
    initial
      ? {
          name:           initial.name,
          description:    initial.description,
          ruleType:       initial.ruleType,
          commissionType: initial.commissionType,
          percentage:     initial.percentage,
          fixedValue:     initial.fixedValue,
          fromQuantity:   initial.fromQuantity,
          toQuantity:     initial.toQuantity,
          fromValue:      initial.fromValue,
          toValue:        initial.toValue,
          priority:       initial.priority,
          active:         initial.active,
          unitId:         initial.unitId,
          positionId:     initial.positionId,
          role:           initial.role,
          notes:          initial.notes,
        }
      : { ...EMPTY_FORM },
  )
  const [saving, setSaving] = useState(false)
  const [error, setError]   = useState('')

  const set = <K extends keyof typeof form>(k: K, v: (typeof form)[K]) =>
    setForm((p) => ({ ...p, [k]: v }))

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!form.name.trim()) { setError('Nome é obrigatório.'); return }

    setSaving(true)
    setError('')
    try {
      const url    = isEdit ? `/api/commissions/rules/${initial!.id}` : '/api/commissions/rules'
      const method = isEdit ? 'PUT' : 'POST'
      const res    = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(form),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao salvar')
      onSaved()
      onClose()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao salvar')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
      <div className="w-full max-w-xl rounded-2xl bg-white shadow-xl">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-gray-100 px-6 py-4">
          <div className="flex items-center gap-2">
            <Percent size={18} className="text-brand-600" />
            <h2 className="text-base font-semibold text-gray-900">
              {isEdit ? 'Editar Regra' : 'Nova Regra de Comissão'}
            </h2>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 text-gray-400 hover:bg-gray-100">
            <X size={16} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 px-6 py-5">
          {/* Nome */}
          <Field label="Nome da regra *">
            <input
              className={inputCls()}
              value={form.name}
              onChange={(e) => set('name', e.target.value)}
              placeholder="Ex: Comissão Venda Base"
              autoFocus
            />
          </Field>

          {/* Cargo vinculado */}
          <Field label="Cargo (opcional)">
            <select
              className={inputCls()}
              value={form.positionId ?? ''}
              onChange={(e) => {
                const newId = e.target.value || null
                const pos = positions.find((p) => p.id === newId)
                setForm((prev) => ({
                  ...prev,
                  positionId: newId,
                  // se role não foi setado ainda, auto-preenche pelo baseRole do cargo
                  role: prev.role || (pos?.baseRole ?? null),
                }))
              }}
            >
              <option value="">— Nenhum —</option>
              {positions.map((p) => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
          </Field>

          {/* Tipo e Comissão */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="Tipo da regra *">
              <select
                className={inputCls()}
                value={form.ruleType}
                onChange={(e) => set('ruleType', e.target.value)}
              >
                {Object.entries(RULE_TYPE_LABELS).map(([v, l]) => (
                  <option key={v} value={v}>{l}</option>
                ))}
              </select>
            </Field>
            <Field label="Tipo de comissão *">
              <select
                className={inputCls()}
                value={form.commissionType}
                onChange={(e) => set('commissionType', e.target.value)}
              >
                {Object.entries(COMMISSION_TYPE_LABELS).map(([v, l]) => (
                  <option key={v} value={v}>{l}</option>
                ))}
              </select>
            </Field>
          </div>

          {/* Valor */}
          <div className="grid grid-cols-2 gap-3">
            {form.commissionType === 'PERCENTUAL' ? (
              <Field label="Percentual (%)">
                <input
                  type="number" min={0} max={100} step={0.01}
                  className={inputCls()}
                  value={form.percentage ?? ''}
                  onChange={(e) => set('percentage', e.target.value ? Number(e.target.value) : null)}
                  placeholder="Ex: 2,5"
                />
              </Field>
            ) : (
              <Field label="Valor fixo (R$)">
                <input
                  inputMode="numeric"
                  className={inputCls()}
                  value={brlInputValue(form.fixedValue)}
                  onChange={(e) => set('fixedValue', parseBRL(e.target.value))}
                  placeholder="Ex: 500,00"
                />
              </Field>
            )}
            <Field label="Prioridade">
              <input
                type="number" min={0}
                className={inputCls()}
                value={form.priority}
                onChange={(e) => set('priority', Number(e.target.value))}
                placeholder="0"
              />
            </Field>
          </div>

          {/* Faixa de quantidade */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="Qtd. mínima de vendas">
              <input
                type="number" min={0}
                className={inputCls()}
                value={form.fromQuantity ?? ''}
                onChange={(e) => set('fromQuantity', e.target.value ? Number(e.target.value) : null)}
                placeholder="Ex: 1"
              />
            </Field>
            <Field label="Qtd. máxima de vendas">
              <input
                type="number" min={0}
                className={inputCls()}
                value={form.toQuantity ?? ''}
                onChange={(e) => set('toQuantity', e.target.value ? Number(e.target.value) : null)}
                placeholder="Sem limite"
              />
            </Field>
          </div>

          {/* Descrição */}
          <Field label="Descrição">
            <textarea
              rows={2}
              className={inputCls('resize-none')}
              value={form.description ?? ''}
              onChange={(e) => set('description', e.target.value || null)}
              placeholder="Descreva a regra..."
            />
          </Field>

          {/* Status */}
          <label className="flex cursor-pointer items-center gap-2.5">
            <input
              type="checkbox"
              checked={form.active}
              onChange={(e) => set('active', e.target.checked)}
              className="h-4 w-4 rounded border-gray-300 text-brand-600 focus:ring-brand-500"
            />
            <span className="text-sm text-gray-700">Regra ativa</span>
          </label>

          {error && (
            <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
              <AlertCircle size={14} />
              {error}
            </div>
          )}

          {/* Ações */}
          <div className="flex justify-end gap-2 pt-2">
            <button type="button" onClick={onClose} className="btn-secondary text-sm">
              Cancelar
            </button>
            <button type="submit" disabled={saving} className="btn-primary text-sm">
              {saving ? (
                <span className="flex items-center gap-2">
                  <RefreshCw size={13} className="animate-spin" /> Salvando...
                </span>
              ) : (
                <span className="flex items-center gap-2">
                  <Save size={13} /> {isEdit ? 'Salvar alterações' : 'Criar regra'}
                </span>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── Modal — Confirmar exclusão ────────────────────────────────────────────────

function DeleteModal({
  rule,
  onClose,
  onDeleted,
}: {
  rule: CommissionRule
  onClose: () => void
  onDeleted: () => void
}) {
  const [deleting, setDeleting] = useState(false)
  const [error, setError]       = useState('')

  const handleDelete = async () => {
    setDeleting(true)
    setError('')
    try {
      const res  = await fetch(`/api/commissions/rules/${rule.id}`, { method: 'DELETE' })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao excluir')
      onDeleted()
      onClose()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao excluir')
      setDeleting(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
      <div className="w-full max-w-sm rounded-2xl bg-white p-6 shadow-xl">
        <h3 className="text-base font-semibold text-gray-900">Excluir regra</h3>
        <p className="mt-2 text-sm text-gray-600">
          Tem certeza que deseja excluir a regra <strong>"{rule.name}"</strong>? Esta ação não pode ser desfeita.
        </p>
        {error && (
          <div className="mt-3 flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
            <AlertCircle size={14} /> {error}
          </div>
        )}
        <div className="mt-5 flex justify-end gap-2">
          <button onClick={onClose} className="btn-secondary text-sm">Cancelar</button>
          <button
            onClick={handleDelete}
            disabled={deleting}
            className="flex items-center gap-1.5 rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white hover:bg-red-700 disabled:opacity-60"
          >
            {deleting ? <RefreshCw size={13} className="animate-spin" /> : <Trash2 size={13} />}
            {deleting ? 'Excluindo...' : 'Excluir'}
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Page ──────────────────────────────────────────────────────────────────────

export default function RegrasComissoesPage() {
  const [rules, setRules]         = useState<CommissionRule[]>([])
  const [positions, setPositions] = useState<PositionLite[]>([])
  const [loading, setLoading]     = useState(true)
  const [editing, setEditing]     = useState<CommissionRule | null | 'new'>(null)
  const [deleting, setDeleting]   = useState<CommissionRule | null>(null)
  const [error, setError]         = useState('')

  const fetchRules = useCallback(async () => {
    setLoading(true)
    setError('')
    try {
      const res  = await fetch('/api/commissions/rules', { credentials: 'include' })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao carregar')
      setRules(data.data ?? [])
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao carregar regras')
    } finally {
      setLoading(false)
    }
  }, [])

  const fetchPositions = useCallback(async () => {
    try {
      const res  = await fetch('/api/positions?active=true', { credentials: 'include' })
      const data = await res.json()
      if (res.ok) setPositions(data.data ?? [])
    } catch {
      /* silencioso — campo é opcional */
    }
  }, [])

  useEffect(() => { fetchRules(); fetchPositions() }, [fetchRules, fetchPositions])

  return (
    <>
      <div className="space-y-5">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-xl font-bold text-gray-900">Regras de Comissão</h1>
            <p className="mt-0.5 text-sm text-gray-500">Gerencie as faixas e percentuais de comissionamento.</p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={fetchRules}
              disabled={loading}
              className="btn-secondary text-xs"
              title="Atualizar"
            >
              <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
            </button>
            <button onClick={() => setEditing('new')} className="btn-primary text-xs">
              <Plus size={13} />
              Nova regra
            </button>
          </div>
        </div>

        {/* Error */}
        {error && (
          <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
            <AlertCircle size={14} /> {error}
          </div>
        )}

        {/* Content */}
        {loading ? (
          <div className="space-y-3">
            {Array.from({ length: 3 }).map((_, i) => (
              <div key={i} className="h-14 animate-pulse rounded-xl bg-gray-100" />
            ))}
          </div>
        ) : rules.length === 0 ? (
          <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-gray-300 py-16">
            <Percent size={36} strokeWidth={1} className="text-gray-300" />
            <p className="mt-3 text-sm font-medium text-gray-500">Nenhuma regra configurada</p>
            <p className="text-xs text-gray-400">Crie regras de comissão para que o cálculo automático funcione.</p>
            <button onClick={() => setEditing('new')} className="btn-primary mt-4 text-xs">
              <Plus size={13} />
              Criar primeira regra
            </button>
          </div>
        ) : (
          <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-card">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 text-sm">
                <thead className="bg-gray-50">
                  <tr>
                    {['Nome', 'Tipo', 'Cargo', 'Comissão', 'Faixa de Qtd.', 'Prioridade', 'Unidade', 'Status', 'Ações'].map((h) => (
                      <th key={h} className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wide text-gray-500 whitespace-nowrap">
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {rules.map((r) => (
                    <tr key={r.id} className="hover:bg-gray-50">
                      <td className="px-4 py-3 font-medium text-gray-800">
                        {r.name}
                        {r.description && (
                          <p className="mt-0.5 text-xs text-gray-400">{r.description}</p>
                        )}
                      </td>
                      <td className="px-4 py-3 text-gray-600 whitespace-nowrap">
                        {RULE_TYPE_LABELS[r.ruleType] ?? r.ruleType}
                      </td>
                      <td className="px-4 py-3 text-gray-600 whitespace-nowrap">
                        {r.position?.name ?? '—'}
                      </td>
                      <td className="px-4 py-3 font-semibold text-brand-700 tabular-nums whitespace-nowrap">
                        {r.commissionType === 'PERCENTUAL'
                          ? `${r.percentage ?? 0}%`
                          : `R$ ${Number(r.fixedValue ?? 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`}
                      </td>
                      <td className="whitespace-nowrap px-4 py-3 text-gray-600">
                        {r.fromQuantity != null || r.toQuantity != null
                          ? `${r.fromQuantity ?? 0} – ${r.toQuantity ?? '∞'}`
                          : '—'}
                      </td>
                      <td className="px-4 py-3 text-center text-gray-600 tabular-nums">
                        {r.priority}
                      </td>
                      <td className="px-4 py-3 text-gray-600">{r.unit?.name ?? 'Todas'}</td>
                      <td className="px-4 py-3">
                        <span className={cn(
                          'rounded-full px-2 py-0.5 text-xs font-medium',
                          r.active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500',
                        )}>
                          {r.active ? 'Ativa' : 'Inativa'}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <div className="flex gap-1">
                          <button
                            onClick={() => setEditing(r)}
                            className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700"
                            title="Editar"
                          >
                            <Edit2 size={13} />
                          </button>
                          <button
                            onClick={() => setDeleting(r)}
                            className="rounded p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600"
                            title="Excluir"
                          >
                            <Trash2 size={13} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      {/* Modais */}
      {editing !== null && (
        <RuleModal
          initial={editing === 'new' ? null : editing}
          positions={positions}
          onClose={() => setEditing(null)}
          onSaved={fetchRules}
        />
      )}
      {deleting && (
        <DeleteModal
          rule={deleting}
          onClose={() => setDeleting(null)}
          onDeleted={fetchRules}
        />
      )}
    </>
  )
}

'use client'

// =============================================================================
// Regras de Retorno — AutoDrive
// Percentuais de conversão de retorno sobre comissão
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { RefreshCw, Plus, Edit2, Trash2, ArrowLeftRight, X, Loader2, CheckCircle2, AlertCircle } from 'lucide-react'
import { cn } from '@/lib/utils'

interface ReturnRule {
  id:                  string
  name:                string
  percentualInformado: number
  percentualAplicado:  number
  bank?:               string | null
  active:              boolean
}

interface FormState {
  name:                string
  percentualInformado: string
  percentualAplicado:  string
  bank:                string
}

const EMPTY_FORM: FormState = {
  name:                '',
  percentualInformado: '',
  percentualAplicado:  '',
  bank:                '',
}

export default function RetornosPage() {
  const [rules, setRules]     = useState<ReturnRule[]>([])
  const [loading, setLoading] = useState(true)
  const [open, setOpen]       = useState(false)
  const [form, setForm]       = useState<FormState>(EMPTY_FORM)
  const [saving, setSaving]   = useState(false)
  const [toast, setToast]     = useState<{ ok: boolean; msg: string } | null>(null)

  const fetchRules = useCallback(async () => {
    setLoading(true)
    try {
      const res  = await fetch('/api/commissions/return-rules', { credentials: 'include' })
      const data = await res.json()
      if (data.success) setRules(data.data ?? [])
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [])

  useEffect(() => { fetchRules() }, [fetchRules])

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 3500)
    return () => clearTimeout(t)
  }, [toast])

  const openModal = () => { setForm(EMPTY_FORM); setOpen(true) }
  const closeModal = () => { if (!saving) setOpen(false) }

  const handleSave = async () => {
    if (!form.name.trim()) {
      setToast({ ok: false, msg: 'Informe o nome da regra.' }); return
    }
    const pi = Number(form.percentualInformado.replace(',', '.'))
    const pa = Number(form.percentualAplicado.replace(',', '.'))
    if (!Number.isFinite(pi) || !Number.isFinite(pa)) {
      setToast({ ok: false, msg: 'Percentuais devem ser numéricos.' }); return
    }
    setSaving(true)
    try {
      const res = await fetch('/api/commissions/return-rules', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: form.name.trim(),
          percentualInformado: pi,
          percentualAplicado:  pa,
          bank: form.bank.trim() || null,
        }),
      })
      const data = await res.json()
      if (data.success) {
        setToast({ ok: true, msg: 'Regra criada com sucesso.' })
        setOpen(false)
        fetchRules()
      } else {
        setToast({ ok: false, msg: data.error ?? 'Erro ao salvar.' })
      }
    } catch {
      setToast({ ok: false, msg: 'Erro de conexão.' })
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-gray-900">Regras de Retorno</h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Configure as faixas de percentual de retorno e seus descontos na comissão.
          </p>
        </div>
        <div className="flex gap-2">
          <button onClick={fetchRules} disabled={loading} className="btn-secondary text-xs">
            <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
          </button>
          <button onClick={openModal} className="btn-primary text-xs"><Plus size={13} />Nova regra</button>
        </div>
      </div>

      {toast && (
        <div className={cn(
          'flex items-center gap-2 rounded-xl px-4 py-3 text-sm',
          toast.ok
            ? 'bg-green-50 border border-green-200 text-green-700'
            : 'bg-red-50 border border-red-200 text-red-700',
        )}>
          {toast.ok ? <CheckCircle2 size={15} /> : <AlertCircle size={15} />}
          {toast.msg}
        </div>
      )}

      {/* Info panel */}
      <div className="rounded-xl border border-blue-100 bg-blue-50 p-4 text-sm text-blue-700">
        <p className="font-semibold">Como funciona?</p>
        <p className="mt-1 text-xs text-blue-600">
          Se o percentual de retorno do vendedor no período estiver dentro de uma faixa configurada,
          o desconto correspondente é aplicado sobre a comissão bruta calculada.
        </p>
      </div>

      {loading ? (
        <div className="space-y-3">{Array.from({ length: 3 }).map((_, i) => <div key={i} className="h-16 animate-pulse rounded-xl bg-gray-100" />)}</div>
      ) : rules.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-gray-300 py-16">
          <ArrowLeftRight size={36} strokeWidth={1} className="text-gray-300" />
          <p className="mt-3 text-sm font-medium text-gray-500">Nenhuma regra de retorno configurada</p>
          <button onClick={openModal} className="btn-primary mt-4 text-xs"><Plus size={13} />Criar regra</button>
        </div>
      ) : (
        <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-card">
          <table className="min-w-full divide-y divide-gray-200 text-sm">
            <thead className="bg-gray-50">
              <tr>
                {['Nome','% Informado','% Aplicado','Banco','Status','Ações'].map((h) => (
                  <th key={h} className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wide text-gray-500 whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {rules.map((r) => (
                <tr key={r.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3 font-medium text-gray-800">{r.name}</td>
                  <td className="px-4 py-3 tabular-nums text-gray-600">{Number(r.percentualInformado)}%</td>
                  <td className="px-4 py-3 tabular-nums font-semibold text-red-600">{Number(r.percentualAplicado)}%</td>
                  <td className="px-4 py-3 text-gray-600">{r.bank ?? '—'}</td>
                  <td className="px-4 py-3">
                    <span className={cn('rounded-full px-2 py-0.5 text-xs font-medium', r.active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500')}>
                      {r.active ? 'Ativa' : 'Inativa'}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex gap-1">
                      <button className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700"><Edit2 size={13} /></button>
                      <button className="rounded p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600"><Trash2 size={13} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ── Modal ───────────────────────────────────────────────────────── */}
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4" onClick={closeModal}>
          <div
            className="w-full max-w-md rounded-2xl bg-white p-6 shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold text-gray-900">Nova regra de retorno</h2>
              <button onClick={closeModal} className="rounded p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-700">
                <X size={16} />
              </button>
            </div>
            <div className="mt-4 space-y-3">
              <div>
                <label className="label">Nome *</label>
                <input
                  className="input"
                  value={form.name}
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                  placeholder="Ex.: Faixa 1 — Banco X"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="label">% Informado</label>
                  <input
                    className="input"
                    value={form.percentualInformado}
                    onChange={(e) => setForm({ ...form, percentualInformado: e.target.value })}
                    placeholder="Ex.: 1,5"
                    inputMode="decimal"
                  />
                </div>
                <div>
                  <label className="label">% Aplicado</label>
                  <input
                    className="input"
                    value={form.percentualAplicado}
                    onChange={(e) => setForm({ ...form, percentualAplicado: e.target.value })}
                    placeholder="Ex.: 1,2"
                    inputMode="decimal"
                  />
                </div>
              </div>
              <div>
                <label className="label">Banco</label>
                <input
                  className="input"
                  value={form.bank}
                  onChange={(e) => setForm({ ...form, bank: e.target.value })}
                  placeholder="Ex.: Banco Bradesco"
                />
              </div>
            </div>
            <div className="mt-6 flex justify-end gap-2">
              <button onClick={closeModal} disabled={saving} className="btn-secondary text-sm">Cancelar</button>
              <button onClick={handleSave} disabled={saving} className="btn-primary text-sm">
                {saving ? <><Loader2 size={14} className="animate-spin" />Salvando...</> : 'Salvar'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Disparo Manual — AutoDrive
// Busca clientes/pendências e envia mensagem avulsa via WhatsApp
// =============================================================================

import { useState, useCallback } from 'react'
import {
  Search, Send, Phone, User, Car, MessageSquare,
  CheckCircle2, AlertCircle, X, Loader2,
} from 'lucide-react'
import { cn, formatDate } from '@/lib/utils'
import type { PendencyWithRelations } from '@/types'

interface SendResult {
  success: boolean
  message: string
}

export default function DisparoManualPage() {
  const [query, setQuery]         = useState('')
  const [results, setResults]     = useState<PendencyWithRelations[]>([])
  const [searching, setSearching] = useState(false)
  const [selected, setSelected]   = useState<PendencyWithRelations | null>(null)
  const [customMsg, setCustomMsg] = useState('')
  const [sending, setSending]     = useState(false)
  const [result, setResult]       = useState<SendResult | null>(null)

  // ── Busca ─────────────────────────────────────────────────────────────────

  const handleSearch = useCallback(async () => {
    if (!query.trim() || query.length < 2) return
    setSearching(true)
    setResults([])
    try {
      const params = new URLSearchParams({ search: query, perPage: '20' })
      const res  = await fetch(`/api/pendencies?${params}`, { credentials: 'include' })
      const data = await res.json()
      if (data.success) setResults(data.data ?? [])
    } catch {
      // silent
    } finally {
      setSearching(false)
    }
  }, [query])

  // ── Envio ─────────────────────────────────────────────────────────────────

  const handleSend = async () => {
    if (!selected) return
    const phone = selected.responsible?.whatsapp ?? selected.manager?.whatsapp
    if (!phone) {
      setResult({ success: false, message: 'Nenhum número de WhatsApp vinculado a esta pendência.' })
      return
    }

    setSending(true)
    setResult(null)
    try {
      const res = await fetch('/api/communication/dispatch', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          pendencyId: selected.id,
          phone,
          message:    customMsg.trim() || undefined,
        }),
      })
      const data = await res.json()
      setResult({
        success: data.success,
        message: data.success
          ? 'Mensagem enviada com sucesso!'
          : (data.error ?? 'Falha ao enviar mensagem.'),
      })
      if (data.success) {
        setSelected(null)
        setCustomMsg('')
      }
    } catch {
      setResult({ success: false, message: 'Erro de conexão ao tentar enviar.' })
    } finally {
      setSending(false)
    }
  }

  return (
    <div className="max-w-3xl space-y-6">
      {/* ── Header ────────────────────────────────────────────────────────── */}
      <div>
        <h1 className="text-xl font-bold text-gray-900">Disparo Manual</h1>
        <p className="mt-0.5 text-sm text-gray-500">
          Busque uma pendência pelo nome do cliente, placa ou veículo e envie uma mensagem avulsa.
        </p>
      </div>

      {/* ── Busca ─────────────────────────────────────────────────────────── */}
      <div className="card">
        <div className="section-header">
          <Search size={15} className="text-brand-700" />
          <h2 className="text-sm font-semibold text-gray-800">Buscar Pendência</h2>
        </div>
        <div className="p-4 space-y-3">
          <div className="flex gap-2">
            <div className="relative flex-1">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                placeholder="Cliente, placa ou veículo..."
                className="input pl-9"
              />
            </div>
            <button onClick={handleSearch} disabled={searching || query.length < 2} className="btn-primary">
              {searching ? <Loader2 size={14} className="animate-spin" /> : <Search size={14} />}
              Buscar
            </button>
          </div>

          {/* Resultados */}
          {results.length > 0 && (
            <div className="rounded-lg border border-gray-200 divide-y divide-gray-100 overflow-hidden">
              {results.map((p) => (
                <button
                  key={p.id}
                  onClick={() => { setSelected(p); setResult(null) }}
                  className={cn(
                    'w-full text-left px-4 py-3 transition-colors hover:bg-gray-50',
                    selected?.id === p.id && 'bg-brand-50 border-l-2 border-l-brand-600',
                  )}
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <User size={13} className="shrink-0 text-gray-400" />
                        <span className="font-medium text-gray-800 truncate">{p.customerName}</span>
                      </div>
                      <div className="mt-1 flex items-center gap-3 text-xs text-gray-500">
                        {p.plate && (
                          <span className="flex items-center gap-1">
                            <Car size={11} />
                            <span className="font-mono">{p.plate}</span>
                          </span>
                        )}
                        {(p.vehicleLabel || p.vehicle) && <span>{p.vehicleLabel ?? p.vehicle?.plate ?? p.vehicle?.model ?? ''}</span>}
                        {p.responsible && (
                          <span className="flex items-center gap-1">
                            <Phone size={11} />
                            {p.responsible.shortName ?? p.responsible.fullName}
                          </span>
                        )}
                      </div>
                    </div>
                    <span className={cn(
                      'shrink-0 rounded-full px-2 py-0.5 text-xs font-medium',
                      p.priority === 'URGENTE' ? 'bg-red-100 text-red-700' :
                      p.priority === 'ALTA'    ? 'bg-orange-100 text-orange-700' :
                      p.priority === 'MEDIA'   ? 'bg-blue-100 text-blue-700' :
                                                 'bg-gray-100 text-gray-600',
                    )}>
                      {p.priority}
                    </span>
                  </div>
                </button>
              ))}
            </div>
          )}

          {!searching && query.length >= 2 && results.length === 0 && (
            <p className="text-center py-6 text-sm text-gray-400">Nenhuma pendência encontrada para "{query}"</p>
          )}
        </div>
      </div>

      {/* ── Painel de envio ───────────────────────────────────────────────── */}
      {selected && (
        <div className="card animate-fade-in">
          <div className="section-header">
            <MessageSquare size={15} className="text-brand-700" />
            <h2 className="text-sm font-semibold text-gray-800">Enviar Mensagem</h2>
            <button onClick={() => setSelected(null)} className="ml-auto rounded p-1 hover:bg-gray-100">
              <X size={14} className="text-gray-400" />
            </button>
          </div>
          <div className="p-4 space-y-4">
            {/* Dados da pendência selecionada */}
            <div className="rounded-lg bg-gray-50 p-3 text-sm space-y-1.5">
              <div className="flex gap-2">
                <span className="w-24 text-xs text-gray-500 shrink-0">Cliente</span>
                <span className="font-medium text-gray-800">{selected.customerName}</span>
              </div>
              {selected.plate && (
                <div className="flex gap-2">
                  <span className="w-24 text-xs text-gray-500 shrink-0">Placa</span>
                  <span className="font-mono text-xs">{selected.plate}</span>
                </div>
              )}
              {selected.responsible && (
                <div className="flex gap-2">
                  <span className="w-24 text-xs text-gray-500 shrink-0">Responsável</span>
                  <span className="text-gray-700">{selected.responsible.fullName}</span>
                </div>
              )}
              {(selected.responsible?.whatsapp || selected.manager?.whatsapp) && (
                <div className="flex gap-2">
                  <span className="w-24 text-xs text-gray-500 shrink-0">WhatsApp</span>
                  <span className="font-mono text-xs text-brand-700">
                    {selected.responsible?.whatsapp ?? selected.manager?.whatsapp}
                  </span>
                </div>
              )}
            </div>

            {/* Mensagem customizada */}
            <div>
              <label className="label">
                Mensagem personalizada <span className="text-gray-400 font-normal">(opcional — usa template padrão se vazio)</span>
              </label>
              <textarea
                value={customMsg}
                onChange={(e) => setCustomMsg(e.target.value)}
                rows={4}
                placeholder="Digite uma mensagem personalizada para este cliente..."
                className="input resize-none"
              />
            </div>

            {/* Resultado */}
            {result && (
              <div className={cn(
                'flex items-center gap-2 rounded-lg px-4 py-3 text-sm',
                result.success
                  ? 'bg-green-50 text-green-700 border border-green-200'
                  : 'bg-red-50 text-red-700 border border-red-200',
              )}>
                {result.success
                  ? <CheckCircle2 size={15} className="shrink-0" />
                  : <AlertCircle  size={15} className="shrink-0" />}
                {result.message}
              </div>
            )}

            {/* Botão de envio */}
            <div className="flex justify-end gap-2">
              <button onClick={() => setSelected(null)} className="btn-secondary text-sm">
                Cancelar
              </button>
              <button
                onClick={handleSend}
                disabled={sending}
                className="btn-primary text-sm"
              >
                {sending
                  ? <><Loader2 size={14} className="animate-spin" />Enviando...</>
                  : <><Send size={14} />Enviar mensagem</>}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Templates de Mensagem — AutoDrive
// Gerenciamento dos templates usados nos disparos automáticos e manuais
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import {
  Plus, Edit2, Trash2, MessageSquare, RefreshCw,
  CheckCircle2, X, Loader2, Info,
} from 'lucide-react'
import { cn } from '@/lib/utils'

interface Template {
  id:         string
  name:       string
  content:    string
  category:   string
  active:     boolean
  createdAt:  string
  updatedAt:  string
}

interface TemplateFormData {
  name:     string
  content:  string
  category: string
  active:   boolean
}

const EMPTY_FORM: TemplateFormData = { name: '', content: '', category: 'GERAL', active: true }

const VARIABLE_HINTS = [
  { var: '{{nome_cliente}}',   desc: 'Nome completo do cliente' },
  { var: '{{placa}}',          desc: 'Placa do veículo' },
  { var: '{{veiculo}}',        desc: 'Modelo do veículo' },
  { var: '{{vendedor}}',       desc: 'Nome do vendedor responsável' },
  { var: '{{vencimento}}',     desc: 'Data de vencimento da pendência' },
  { var: '{{tipo_pendencia}}', desc: 'Tipo da pendência' },
]

export default function TemplatesPage() {
  const [templates, setTemplates] = useState<Template[]>([])
  const [loading, setLoading]     = useState(true)
  const [saving, setSaving]       = useState(false)
  const [showForm, setShowForm]   = useState(false)
  const [editing, setEditing]     = useState<Template | null>(null)
  const [form, setForm]           = useState<TemplateFormData>(EMPTY_FORM)
  const [deleteId, setDeleteId]   = useState<string | null>(null)
  const [feedback, setFeedback]   = useState<{ ok: boolean; msg: string } | null>(null)

  const fetchTemplates = useCallback(async () => {
    setLoading(true)
    try {
      const res  = await fetch('/api/communication/templates', { credentials: 'include' })
      const data = await res.json()
      if (data.success) setTemplates(data.data ?? [])
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [])

  useEffect(() => { fetchTemplates() }, [fetchTemplates])

  const openNew  = () => { setEditing(null); setForm(EMPTY_FORM); setShowForm(true); setFeedback(null) }
  const openEdit = (t: Template) => {
    setEditing(t)
    setForm({ name: t.name, content: t.content, category: t.category, active: t.active })
    setShowForm(true)
    setFeedback(null)
  }
  const closeForm = () => { setShowForm(false); setEditing(null); setForm(EMPTY_FORM) }

  const handleSave = async () => {
    if (!form.name.trim() || !form.content.trim()) {
      setFeedback({ ok: false, msg: 'Nome e conteúdo são obrigatórios.' })
      return
    }
    setSaving(true)
    setFeedback(null)
    try {
      const url    = editing ? `/api/communication/templates/${editing.id}` : '/api/communication/templates'
      const method = editing ? 'PATCH' : 'POST'
      const res    = await fetch(url, {
        method, credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      })
      const data = await res.json()
      if (data.success) {
        setFeedback({ ok: true, msg: editing ? 'Template atualizado.' : 'Template criado.' })
        closeForm()
        fetchTemplates()
      } else {
        setFeedback({ ok: false, msg: data.error ?? 'Erro ao salvar.' })
      }
    } catch {
      setFeedback({ ok: false, msg: 'Erro de conexão.' })
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async (id: string) => {
    try {
      const res  = await fetch(`/api/communication/templates/${id}`, { method: 'DELETE', credentials: 'include' })
      const data = await res.json()
      if (data.success) fetchTemplates()
    } catch { /* silent */ }
    finally { setDeleteId(null) }
  }

  const insertVar = (v: string) =>
    setForm((prev) => ({ ...prev, content: prev.content + v }))

  return (
    <div className="space-y-5">
      {/* ── Header ────────────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-gray-900">Templates de Mensagem</h1>
          <p className="mt-0.5 text-sm text-gray-500">
            {loading ? 'Carregando...' : `${templates.length} template${templates.length !== 1 ? 's' : ''} cadastrado${templates.length !== 1 ? 's' : ''}`}
          </p>
        </div>
        <div className="flex gap-2">
          <button onClick={fetchTemplates} disabled={loading} className="btn-secondary text-xs">
            <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
          </button>
          <button onClick={openNew} className="btn-primary text-xs">
            <Plus size={13} />
            Novo template
          </button>
        </div>
      </div>

      {/* ── Feedback global ───────────────────────────────────────────────── */}
      {feedback && !showForm && (
        <div className={cn(
          'flex items-center gap-2 rounded-lg px-4 py-3 text-sm',
          feedback.ok ? 'bg-green-50 border border-green-200 text-green-700' : 'bg-red-50 border border-red-200 text-red-700',
        )}>
          {feedback.ok ? <CheckCircle2 size={14} /> : <X size={14} />}
          {feedback.msg}
        </div>
      )}

      {/* ── Form ──────────────────────────────────────────────────────────── */}
      {showForm && (
        <div className="card animate-fade-in">
          <div className="section-header">
            <MessageSquare size={15} className="text-brand-700" />
            <h2 className="text-sm font-semibold text-gray-800">
              {editing ? 'Editar Template' : 'Novo Template'}
            </h2>
            <button onClick={closeForm} className="ml-auto rounded p-1 hover:bg-gray-100">
              <X size={14} className="text-gray-400" />
            </button>
          </div>
          <div className="p-4 space-y-4">
            <div className="grid gap-4 sm:grid-cols-2">
              <div>
                <label className="label">Nome do template *</label>
                <input
                  value={form.name}
                  onChange={(e) => setForm((p) => ({ ...p, name: e.target.value }))}
                  placeholder="Ex.: Lembrete de pendência vencida"
                  className="input"
                />
              </div>
              <div>
                <label className="label">Categoria</label>
                <select
                  value={form.category}
                  onChange={(e) => setForm((p) => ({ ...p, category: e.target.value }))}
                  className="input"
                >
                  <option value="GERAL">Geral</option>
                  <option value="LEMBRETE">Lembrete</option>
                  <option value="VENCIMENTO">Vencimento</option>
                  <option value="RESOLUCAO">Resolução</option>
                  <option value="URGENTE">Urgente</option>
                </select>
              </div>
            </div>

            <div>
              <div className="flex items-center justify-between mb-1">
                <label className="label mb-0">Conteúdo da mensagem *</label>
                <span className="text-xs text-gray-400">{form.content.length} caracteres</span>
              </div>
              <textarea
                value={form.content}
                onChange={(e) => setForm((p) => ({ ...p, content: e.target.value }))}
                rows={6}
                placeholder="Olá {{nome_cliente}}, sua pendência referente ao veículo {{veiculo}} venceu em {{vencimento}}..."
                className="input resize-none font-mono text-xs"
              />
            </div>

            {/* Variáveis */}
            <div className="rounded-lg border border-blue-100 bg-blue-50 p-3">
              <div className="flex items-center gap-2 mb-2">
                <Info size={13} className="text-blue-600 shrink-0" />
                <span className="text-xs font-semibold text-blue-700">Variáveis disponíveis — clique para inserir</span>
              </div>
              <div className="flex flex-wrap gap-2">
                {VARIABLE_HINTS.map((v) => (
                  <button
                    key={v.var}
                    onClick={() => insertVar(v.var)}
                    title={v.desc}
                    className="rounded bg-white border border-blue-200 px-2 py-0.5 text-xs text-blue-700 font-mono hover:bg-blue-100 transition-colors"
                  >
                    {v.var}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="active"
                checked={form.active}
                onChange={(e) => setForm((p) => ({ ...p, active: e.target.checked }))}
                className="h-4 w-4 rounded border-gray-300 text-brand-600 focus:ring-brand-500"
              />
              <label htmlFor="active" className="text-sm text-gray-700">Template ativo</label>
            </div>

            {feedback && (
              <div className={cn(
                'flex items-center gap-2 rounded-lg px-3 py-2 text-sm',
                feedback.ok ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700',
              )}>
                {feedback.ok ? <CheckCircle2 size={13} /> : <X size={13} />}
                {feedback.msg}
              </div>
            )}

            <div className="flex justify-end gap-2">
              <button onClick={closeForm} className="btn-secondary text-sm">Cancelar</button>
              <button onClick={handleSave} disabled={saving} className="btn-primary text-sm">
                {saving ? <><Loader2 size={13} className="animate-spin" />Salvando...</> : 'Salvar template'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── Lista de templates ────────────────────────────────────────────── */}
      {loading ? (
        <div className="space-y-3">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="h-24 animate-pulse rounded-xl bg-gray-100" />
          ))}
        </div>
      ) : templates.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-gray-400">
          <MessageSquare size={36} strokeWidth={1} />
          <p className="mt-3 text-sm font-medium">Nenhum template cadastrado</p>
          <p className="text-xs">Crie seu primeiro template para usar nos disparos.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {templates.map((t) => (
            <div key={t.id} className={cn(
              'card',
              !t.active && 'opacity-60',
            )}>
              <div className="p-4">
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="font-semibold text-gray-800">{t.name}</span>
                      <span className="rounded-full bg-gray-100 px-2 py-0.5 text-xs text-gray-500">
                        {t.category}
                      </span>
                      {!t.active && (
                        <span className="rounded-full bg-red-100 px-2 py-0.5 text-xs text-red-600">
                          Inativo
                        </span>
                      )}
                    </div>
                    <p className="mt-1.5 text-sm text-gray-600 font-mono whitespace-pre-line line-clamp-3">
                      {t.content}
                    </p>
                  </div>
                  <div className="flex shrink-0 gap-1">
                    <button
                      onClick={() => openEdit(t)}
                      className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700 transition-colors"
                      title="Editar"
                    >
                      <Edit2 size={14} />
                    </button>
                    <button
                      onClick={() => setDeleteId(t.id)}
                      className="rounded p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600 transition-colors"
                      title="Excluir"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── Modal de confirmação de exclusão ─────────────────────────────── */}
      {deleteId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4 animate-fade-in">
          <div className="w-full max-w-sm rounded-2xl bg-white p-6 shadow-xl">
            <h3 className="font-semibold text-gray-900">Excluir template?</h3>
            <p className="mt-1 text-sm text-gray-500">Esta ação não pode ser desfeita.</p>
            <div className="mt-4 flex justify-end gap-2">
              <button onClick={() => setDeleteId(null)} className="btn-secondary text-sm">Cancelar</button>
              <button onClick={() => handleDelete(deleteId)} className="btn-danger text-sm">Excluir</button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

