// ── Componente de status ──────────────────────────────────────────────────────

function StatusBadge({ status }: { status: string | null | undefined }) {
  if (!status) return <span className="badge bg-gray-100 text-gray-500">—</span>
  const map: Record<string, string> = {
    OK:    'badge bg-green-100 text-green-700',
    ERRO:  'badge bg-red-100 text-red-700',
    SYNC:  'badge bg-blue-100 text-blue-700',
  }
  return (
    <span className={map[status] ?? 'badge bg-gray-100 text-gray-500'}>
      {status}
    </span>
  )
}

// ── Modal de Planilha ─────────────────────────────────────────────────────────

interface SheetConfigModalProps {
  initial?: Partial<GoogleSheetConfig>
  onSave: (data: { name: string; spreadsheetId: string; description: string }) => void
  onClose: () => void
}

function SheetConfigModal({ initial, onSave, onClose }: SheetConfigModalProps) {
  const [name,          setName]          = useState(initial?.name          ?? '')
  const [spreadsheetId, setSpreadsheetId] = useState(initial?.spreadsheetId ?? '')
  const [description,   setDescription]   = useState(initial?.description   ?? '')

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm px-4">
      <div className="w-full max-w-lg rounded-2xl bg-white shadow-modal">
        <div className="border-b border-gray-100 px-6 py-4">
          <h3 className="text-base font-semibold text-gray-900">
            {initial?.id ? 'Editar planilha' : 'Adicionar planilha'}
          </h3>
        </div>
        <div className="p-6 space-y-4">
          <div>
            <label className="label">Nome interno</label>
            <input className="input" value={name} onChange={(e) => setName(e.target.value)} placeholder="Ex: Planilha Principal" />
          </div>
          <div>
            <label className="label">ID da planilha Google Sheets</label>
            <input className="input font-mono text-xs" value={spreadsheetId} onChange={(e) => setSpreadsheetId(e.target.value)} placeholder="1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgVE2upms" />
            <p className="mt-1 text-xs text-gray-400">Extraia da URL: docs.google.com/spreadsheets/d/<strong>ID</strong>/edit</p>
          </div>
          <div>
            <label className="label">Descrição</label>
            <textarea className="input resize-none" rows={2} value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Finalidade desta planilha..." />
          </div>
        </div>
        <div className="flex justify-end gap-2 border-t border-gray-100 px-6 py-4">
          <button type="button" onClick={onClose} className="btn-secondary">Cancelar</button>
          <button type="button" onClick={() => onSave({ name, spreadsheetId, description })} className="btn-primary">Salvar</button>
        </div>
      </div>
    </div>
  )
}

// ── Modal de Aba ──────────────────────────────────────────────────────────────

interface SheetTabModalProps {
  configId: string
  initial?: Partial<GoogleSheetTab>
  onSave: (data: Partial<GoogleSheetTab>) => void
  onClose: () => void
}

const TAB_TYPES = [
  'VENDAS','TROCAS','CLIENTES','VEICULOS','CONTRATOS','COMISSOES',
  'GARANTIAS','RETORNOS','PENDENCIAS','VENDEDORES','GERENTES','UNIDADES',
  'CONFIGURACOES','PERSONALIZADO',
]

function SheetTabModal({ configId, initial, onSave, onClose }: SheetTabModalProps) {
  const [internalName, setInternalName] = useState(initial?.internalName ?? '')
  const [sheetName,    setSheetName]    = useState(initial?.sheetName    ?? '')
  const [tabType,      setTabType]      = useState(initial?.tabType      ?? 'PERSONALIZADO')
  const [description,  setDescription]  = useState(initial?.description  ?? '')
  const [headerRow,    setHeaderRow]    = useState(initial?.headerRow     ?? 1)

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm px-4">
      <div className="w-full max-w-md rounded-2xl bg-white shadow-modal">
        <div className="border-b border-gray-100 px-6 py-4">
          <h3 className="text-base font-semibold text-gray-900">
            {initial?.id ? 'Editar aba' : 'Adicionar aba'}
          </h3>
        </div>
        <div className="p-6 space-y-4">
          <div>
            <label className="label">Nome interno (no sistema)</label>
            <input className="input" value={internalName} onChange={(e) => setInternalName(e.target.value)} placeholder="Ex: Vendas do Mês" />
          </div>
          <div>
            <label className="label">Nome real na planilha</label>
            <input className="input font-mono" value={sheetName} onChange={(e) => setSheetName(e.target.value)} placeholder="Ex: VENDAS" />
          </div>
          <div>
            <label className="label">Tipo da aba</label>
            <select className="input" value={tabType} onChange={(e) => setTabType(e.target.value as any)}>
              {TAB_TYPES.map((t) => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>
          <div>
            <label className="label">Linha do cabeçalho</label>
            <input type="number" min={1} className="input" value={headerRow} onChange={(e) => setHeaderRow(Number(e.target.value))} />
          </div>
          <div>
            <label className="label">Descrição</label>
            <textarea className="input resize-none" rows={2} value={description} onChange={(e) => setDescription(e.target.value)} />
          </div>
        </div>
        <div className="flex justify-end gap-2 border-t border-gray-100 px-6 py-4">
          <button type="button" onClick={onClose} className="btn-secondary">Cancelar</button>
          <button type="button" onClick={() => onSave({ configId, internalName, sheetName, tabType: tabType as any, description, headerRow })} className="btn-primary">Salvar</button>
        </div>
      </div>
    </div>
  )
}

// ── Página principal ──────────────────────────────────────────────────────────

export default function SheetsConfigPage() {
  const { data: session } = useSession()
  const role = session?.user?.role as UserRole | undefined

  const [configs,     setConfigs]     = useState<(GoogleSheetConfig & { tabs?: GoogleSheetTab[] })[]>([])
  const [loading,     setLoading]     = useState(true)
  const [expanded,    setExpanded]    = useState<Record<string, boolean>>({})
  const [showConfig,  setShowConfig]  = useState(false)
  const [editConfig,  setEditConfig]  = useState<GoogleSheetConfig | null>(null)
  const [showTab,     setShowTab]     = useState<string | null>(null) // configId
  const [editTab,     setEditTab]     = useState<GoogleSheetTab | null>(null)
  const [syncing,     setSyncing]     = useState<string | null>(null)
  const [message,     setMessage]     = useState<{ type: 'success' | 'error'; text: string } | null>(null)

  const canConfigure = canAccessModule(role, 'settings.sheets')

  const showMsg = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text })
    setTimeout(() => setMessage(null), 4000)
  }

  const loadConfigs = async () => {
    setLoading(true)
    try {
      const res = await fetch('/api/settings/sheets', { credentials: 'include' })
      if (res.ok) {
        const json = await res.json()
        setConfigs(json.data ?? [])
      }
    } catch { /* silent */ }
    finally { setLoading(false) }
  }

  useEffect(() => { loadConfigs() }, [])

  const handleSaveConfig = async (data: { name: string; spreadsheetId: string; description: string }) => {
    try {
      const url    = editConfig ? `/api/settings/sheets/${editConfig.id}` : '/api/settings/sheets'
      const method = editConfig ? 'PUT' : 'POST'
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
        credentials: 'include',
      })
      if (res.ok) {
        showMsg('success', editConfig ? 'Planilha atualizada!' : 'Planilha adicionada!')
        setShowConfig(false)
        setEditConfig(null)
        loadConfigs()
      } else {
        const j = await res.json()
        showMsg('error', j.error ?? 'Erro ao salvar planilha')
      }
    } catch { showMsg('error', 'Erro de conexão') }
  }

  const handleSaveTab = async (data: Partial<GoogleSheetTab>) => {
    try {
      const url    = editTab ? `/api/settings/sheets/tabs/${editTab.id}` : '/api/settings/sheets/tabs'
      const method = editTab ? 'PUT' : 'POST'
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
        credentials: 'include',
      })
      if (res.ok) {
        showMsg('success', editTab ? 'Aba atualizada!' : 'Aba adicionada!')
        setShowTab(null)
        setEditTab(null)
        loadConfigs()
      } else {
        const j = await res.json()
        showMsg('error', j.error ?? 'Erro ao salvar aba')
      }
    } catch { showMsg('error', 'Erro de conexão') }
  }

  const handleSync = async (configId: string, tabId?: string) => {
    setSyncing(tabId ?? configId)
    try {
      const res = await fetch('/api/settings/sheets/sync', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ configId, tabId }),
        credentials: 'include',
      })
      const j = await res.json()
      showMsg(res.ok ? 'success' : 'error', j.message ?? (res.ok ? 'Sincronizado!' : 'Erro ao sincronizar'))
      if (res.ok) loadConfigs()
    } catch { showMsg('error', 'Erro de conexão') }
    finally { setSyncing(null) }
  }

  const toggleExpand = (id: string) =>
    setExpanded((prev) => ({ ...prev, [id]: !prev[id] }))

  return (
    <div className="max-w-4xl space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-gray-900">Google Sheets</h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Configure planilhas e abas para importação de dados.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button type="button" onClick={loadConfigs} className="btn-secondary text-xs">
            <RefreshCw size={13} />
            Recarregar
          </button>
          {canConfigure && (
            <button type="button" onClick={() => { setEditConfig(null); setShowConfig(true) }} className="btn-primary text-xs">
              <Plus size={14} />
              Adicionar planilha
            </button>
          )}
        </div>
      </div>

      {/* Mensagem feedback */}
      {message && (
        <div className={cn(
          'flex items-center gap-2.5 rounded-lg px-4 py-3 text-sm',
          message.type === 'success'
            ? 'bg-green-50 border border-green-200 text-green-800'
            : 'bg-red-50 border border-red-200 text-red-800',
        )}>
          {message.type === 'success' ? <CheckCircle2 size={16} /> : <XCircle size={16} />}
          {message.text}
        </div>
      )}

      {/* Lista de planilhas */}
      {loading ? (
        <div className="flex items-center justify-center py-16">
          <RefreshCw size={20} className="animate-spin text-gray-400" />
        </div>
      ) : configs.length === 0 ? (
        <div className="card flex flex-col items-center justify-center py-16 text-center">
          <TableProperties size={40} className="text-gray-200 mb-3" />
          <p className="text-sm font-medium text-gray-500">Nenhuma planilha configurada</p>
          <p className="text-xs text-gray-400 mt-1">Clique em "Adicionar planilha" para começar.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {configs.map((config) => {
            const isExpanded = expanded[config.id] ?? false
            return (
              <div key={config.id} className="card overflow-hidden">
                {/* Header do card */}
                <div className="flex items-center gap-3 px-5 py-4">
                  <button type="button" onClick={() => toggleExpand(config.id)} className="text-gray-400 hover:text-gray-600 transition-colors">
                    {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                  </button>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-semibold text-gray-900 truncate">{config.name}</p>
                      <span className={cn('badge', config.active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500')}>
                        {config.active ? 'Ativo' : 'Inativo'}
                      </span>
                    </div>
                    <div className="flex items-center gap-1.5 mt-0.5">
                      <LinkIcon size={11} className="text-gray-400" />
                      <p className="text-xs text-gray-400 font-mono truncate max-w-xs">{config.spreadsheetId || '—'}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5 shrink-0">
                    {canConfigure && (
                      <>
                        <button type="button" onClick={() => handleSync(config.id)} disabled={!!syncing} className="btn-secondary text-xs py-1 px-2.5">
                          <RefreshCw size={12} className={syncing === config.id ? 'animate-spin' : ''} />
                          Sync
                        </button>
                        <button type="button" onClick={() => { setEditConfig(config); setShowConfig(true) }} className="btn-secondary text-xs py-1 px-2.5">
                          <Edit3 size={12} />
                        </button>
                      </>
                    )}
                  </div>
                </div>

                {/* Abas */}
                {isExpanded && (
                  <div className="border-t border-gray-50 bg-gray-50/50">
                    <div className="flex items-center justify-between px-5 py-2.5">
                      <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide">Abas ({config.tabs?.length ?? 0})</p>
                      {canConfigure && (
                        <button type="button" onClick={() => { setShowTab(config.id); setEditTab(null) }} className="flex items-center gap-1 text-xs font-medium text-brand-700 hover:text-brand-600 transition-colors">
                          <Plus size={12} /> Adicionar aba
                        </button>
                      )}
                    </div>

                    {(!config.tabs || config.tabs.length === 0) ? (
                      <div className="px-5 pb-4 text-center">
                        <p className="text-xs text-gray-400">Nenhuma aba cadastrada.</p>
                      </div>
                    ) : (
                      <div className="overflow-x-auto">
                        <table className="w-full text-xs">
                          <thead>
                            <tr className="border-y border-gray-100 bg-white">
                              <th className="px-5 py-2 text-left font-medium text-gray-500">Nome interno</th>
                              <th className="px-3 py-2 text-left font-medium text-gray-500">Aba na planilha</th>
                              <th className="px-3 py-2 text-left font-medium text-gray-500">Tipo</th>
                              <th className="px-3 py-2 text-left font-medium text-gray-500">Status</th>
                              <th className="px-3 py-2 text-left font-medium text-gray-500">Última sync</th>
                              <th className="px-3 py-2" />
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-50">
                            {config.tabs!.map((tab) => (
                              <tr key={tab.id} className="hover:bg-white transition-colors">
                                <td className="px-5 py-2.5 font-medium text-gray-700">{tab.internalName}</td>
                                <td className="px-3 py-2.5 font-mono text-gray-500">{tab.sheetName}</td>
                                <td className="px-3 py-2.5">
                                  <span className="badge bg-blue-50 text-blue-700">{tab.tabType}</span>
                                </td>
                                <td className="px-3 py-2.5">
                                  <StatusBadge status={tab.lastSyncStatus} />
                                </td>
                                <td className="px-3 py-2.5 text-gray-400">
                                  {tab.lastSyncAt ? new Date(tab.lastSyncAt).toLocaleString('pt-BR') : '—'}
                                </td>
                                <td className="px-3 py-2.5">
                                  {canConfigure && (
                                    <div className="flex items-center gap-1">
                                      <button type="button" onClick={() => handleSync(config.id, tab.id)} disabled={!!syncing} className="rounded p-1 text-gray-400 hover:text-brand-700 hover:bg-brand-50 transition-colors" title="Sincronizar">
                                        <RefreshCw size={12} className={syncing === tab.id ? 'animate-spin' : ''} />
                                      </button>
                                      <button type="button" onClick={() => { setEditTab(tab); setShowTab(config.id) }} className="rounded p-1 text-gray-400 hover:text-blue-600 hover:bg-blue-50 transition-colors" title="Editar">
                                        <Edit3 size={12} />
                                      </button>
                                    </div>
                                  )}
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}
                  </div>
                )}
              </div>
            )
          })}
        </div>
      )}

      {/* Modais */}
      {showConfig && (
        <SheetConfigModal
          initial={editConfig ?? undefined}
          onSave={handleSaveConfig}
          onClose={() => { setShowConfig(false); setEditConfig(null) }}
        />
      )}
      {showTab && (
        <SheetTabModal
          configId={showTab}
          initial={editTab ?? undefined}
          onSave={handleSaveTab}
          onClose={() => { setShowTab(null); setEditTab(null) }}
        />
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Configurações de WhatsApp — AutoDrive
// Provider Meta/Cloud API + webhook + templates oficiais
// Apenas MASTER pode configurar o gateway. Tenants veem aviso de configuração centralizada.
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import {
  MessageSquare, Save, Eye, EyeOff, Loader2,
  CheckCircle2, AlertCircle, RefreshCw, Link2, Lock,
} from 'lucide-react'
import { cn } from '@/lib/utils'

interface WhatsAppConfig {
  id?:             string
  provider:        string
  phoneNumberId:   string
  businessAccountId: string
  accessToken:     string
  webhookVerifyToken: string
  active:          boolean
}

const DEFAULTS: WhatsAppConfig = {
  provider: 'META',
  phoneNumberId: '',
  businessAccountId: '',
  accessToken: '',
  webhookVerifyToken: '',
  active: true,
}

export default function WhatsAppConfigPage() {
  const { data: session } = useSession()
  const isMaster = (session?.user as { role?: string })?.role === 'MASTER'

  const [config, setConfig]           = useState<WhatsAppConfig>(DEFAULTS)
  const [loading, setLoading]         = useState(true)
  const [saving, setSaving]           = useState(false)
  const [showToken, setShowToken]     = useState(false)
  const [feedback, setFeedback]       = useState<{ ok: boolean; msg: string } | null>(null)
  const [webhookUrl, setWebhookUrl]   = useState('')

  const fetchConfig = useCallback(async () => {
    setLoading(true)
    try {
      const res  = await fetch('/api/settings/whatsapp', { credentials: 'include' })
      const data = await res.json()
      if (data.success && data.data) {
        setConfig({ ...DEFAULTS, ...data.data, accessToken: '' })
      }
      // Monta URL do webhook
      if (typeof window !== 'undefined') {
        setWebhookUrl(`${window.location.origin}/api/webhook/meta`)
      }
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [])

  useEffect(() => { fetchConfig() }, [fetchConfig])

  if (session && !isMaster) {
    return (
      <div className="flex flex-col items-center justify-center gap-4 py-20 text-center">
        <div className="flex h-14 w-14 items-center justify-center rounded-full bg-green-50 text-green-600">
          <Lock size={24} />
        </div>
        <div>
          <p className="text-lg font-semibold text-gray-800">Configuração centralizada</p>
          <p className="mt-1 max-w-md text-sm text-gray-500">
            As configurações de WhatsApp são gerenciadas globalmente pelo administrador da plataforma.
            Entre em contato com o suporte para ajustes de integração.
          </p>
        </div>
      </div>
    )
  }

  const set = (key: keyof WhatsAppConfig, value: unknown) =>
    setConfig((p) => ({ ...p, [key]: value }))

  const handleSave = async () => {
    setSaving(true)
    setFeedback(null)
    try {
      const res  = await fetch('/api/settings/whatsapp', {
        method:  config.id ? 'PATCH' : 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(config),
      })
      const data = await res.json()
      setFeedback({
        ok:  data.success,
        msg: data.success
          ? 'Configuração do WhatsApp salva com sucesso.'
          : (data.error ?? 'Erro ao salvar.'),
      })
      if (data.success && data.data) {
        setConfig((p) => ({ ...p, id: data.data.id, accessToken: '' }))
      }
    } catch {
      setFeedback({ ok: false, msg: 'Erro de conexão.' })
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="max-w-2xl space-y-4">
        {Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="h-20 animate-pulse rounded-xl bg-gray-100" />
        ))}
      </div>
    )
  }

  return (
    <div className="max-w-2xl space-y-6">
      {/* ── Header ────────────────────────────────────────────────────────── */}
      <div>
        <h1 className="text-xl font-bold text-gray-900">Configuração de WhatsApp</h1>
        <p className="mt-0.5 text-sm text-gray-500">
          Integração com Meta Cloud API para envio de mensagens WhatsApp Business.
        </p>
      </div>

      {feedback && (
        <div className={cn(
          'flex items-center gap-2 rounded-xl px-4 py-3 text-sm animate-fade-in',
          feedback.ok
            ? 'bg-green-50 border border-green-200 text-green-700'
            : 'bg-red-50 border border-red-200 text-red-700',
        )}>
          {feedback.ok ? <CheckCircle2 size={15} /> : <AlertCircle size={15} />}
          {feedback.msg}
        </div>
      )}

      {/* ── Provider ──────────────────────────────────────────────────────── */}
      <div className="card">
        <div className="section-header">
          <MessageSquare size={15} className="text-brand-700" />
          <h2 className="text-sm font-semibold text-gray-800">Credenciais Meta (WhatsApp Cloud API)</h2>
        </div>
        <div className="p-4 space-y-4">
          <div className="grid gap-4 sm:grid-cols-2">
            <div>
              <label className="label">Phone Number ID *</label>
              <input
                value={config.phoneNumberId}
                onChange={(e) => set('phoneNumberId', e.target.value)}
                placeholder="123456789012345"
                className="input font-mono"
              />
              <p className="mt-1 text-xs text-gray-400">
                Encontrado em Meta for Developers → WhatsApp → Configuração.
              </p>
            </div>
            <div>
              <label className="label">Business Account ID *</label>
              <input
                value={config.businessAccountId}
                onChange={(e) => set('businessAccountId', e.target.value)}
                placeholder="987654321098765"
                className="input font-mono"
              />
            </div>
          </div>

          <div>
            <label className="label">Access Token (permanente) *</label>
            <div className="relative">
              <input
                value={config.accessToken}
                onChange={(e) => set('accessToken', e.target.value)}
                placeholder={config.id ? '(mantém o token atual)' : 'EAAxxxxxxx...'}
                type={showToken ? 'text' : 'password'}
                className="input pr-10 font-mono text-xs"
              />
              <button
                type="button"
                onClick={() => setShowToken((p) => !p)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showToken ? <EyeOff size={14} /> : <Eye size={14} />}
              </button>
            </div>
            <p className="mt-1 text-xs text-gray-400">
              Use um token permanente (System User) para não expirar.
            </p>
          </div>
        </div>
      </div>

      {/* ── Webhook ───────────────────────────────────────────────────────── */}
      <div className="card">
        <div className="section-header">
          <Link2 size={15} className="text-brand-700" />
          <h2 className="text-sm font-semibold text-gray-800">Webhook</h2>
        </div>
        <div className="p-4 space-y-4">
          <div>
            <label className="label">URL do Webhook</label>
            <div className="flex gap-2">
              <input
                value={webhookUrl}
                readOnly
                className="input flex-1 bg-gray-50 font-mono text-xs text-gray-600"
              />
              <button
                onClick={() => navigator.clipboard.writeText(webhookUrl)}
                className="btn-secondary text-xs shrink-0"
                title="Copiar URL"
              >
                Copiar
              </button>
            </div>
            <p className="mt-1 text-xs text-gray-400">
              Configure esta URL no painel do Meta for Developers → Webhooks.
            </p>
          </div>

          <div>
            <label className="label">Token de Verificação do Webhook *</label>
            <input
              value={config.webhookVerifyToken}
              onChange={(e) => set('webhookVerifyToken', e.target.value)}
              placeholder="meu_token_secreto_aqui"
              className="input font-mono"
            />
            <p className="mt-1 text-xs text-gray-400">
              Defina este token no Meta for Developers na seção Webhook → Verify Token.
            </p>
          </div>
        </div>
      </div>

      {/* ── Status ────────────────────────────────────────────────────────── */}
      <div className="card">
        <div className="p-4">
          <div className="flex items-center gap-3">
            <input
              type="checkbox"
              id="whatsapp_active"
              checked={config.active}
              onChange={(e) => set('active', e.target.checked)}
              className="h-4 w-4 rounded border-gray-300 text-brand-600 focus:ring-brand-500"
            />
            <div>
              <label htmlFor="whatsapp_active" className="text-sm font-medium text-gray-700">
                Integração WhatsApp ativa
              </label>
              <p className="text-xs text-gray-400">
                Desativando, nenhuma mensagem WhatsApp será disparada pelo sistema.
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* ── Botão salvar ──────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between">
        <button onClick={fetchConfig} disabled={loading} className="btn-secondary text-xs">
          <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
          Recarregar
        </button>
        <button onClick={handleSave} disabled={saving} className="btn-primary">
          {saving
            ? <><Loader2 size={14} className="animate-spin" />Salvando...</>
            : <><Save size={14} />Salvar configuração</>}
        </button>
      </div>

      {/* ── Nota de configuração ──────────────────────────────────────────── */}
      <div className="rounded-xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-700">
        <p className="font-semibold mb-1">Passos para configurar a integração</p>
        <ol className="space-y-1 text-xs list-decimal list-inside text-amber-600">
          <li>Acesse <span className="font-mono">developers.facebook.com</span> e crie um aplicativo tipo "Business".</li>
          <li>Adicione o produto "WhatsApp" ao aplicativo.</li>
          <li>Copie o Phone Number ID e o Business Account ID.</li>
          <li>Gere um token permanente com um System User de nível Admin.</li>
          <li>Configure o webhook com a URL acima e o token de verificação.</li>
          <li>Assine os eventos: <span className="font-mono">messages</span> e <span className="font-mono">message_status</span>.</li>
        </ol>
      </div>
    </div>
  )
}

'use client'

// =============================================================================
// Dashboard — AutoDrive
// Central administrativa com cards de KPIs e atalhos rápidos
// =============================================================================

import { useEffect, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import Link from 'next/link'
import {
  AlertCircle,
  CheckCircle2,
  Clock,
  DollarSign,
  FileText,
  RefreshCw,
  Send,
  TrendingUp,
  Upload,
  AlertTriangle,
  Activity,
  ArrowRight,
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { canAccessModule } from '@/lib/permissions'
import type { UserRole } from '@/lib/permissions'
import { GoalsPanel } from '@/components/goals/GoalsPanel'
import { RankingPositionCard } from '@/components/ranking/RankingPositionCard'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface DashboardStats {
  pendenciasAbertas:    number
  pendenciasUrgentes:   number
  pendenciasFinalizadas:number
  aguardandoResposta:   number
  comissoesPrevistos:   string
  comissoesAprovados:   string
  importacoesHoje:      number
  contratosLidosHoje:   number
  loaded: boolean
}

// ── KPI Card ──────────────────────────────────────────────────────────────────

interface KpiCardProps {
  label:       string
  value:       string | number
  description: string
  icon:        React.ElementType
  colorClass:  string
  bgClass:     string
  borderClass: string
  href?:       string
}

function KpiCard({ label, value, description, icon: Icon, colorClass, bgClass, borderClass, href }: KpiCardProps) {
  const content = (
    <div
      className={cn(
        'group relative flex items-center gap-4 rounded-xl border bg-white p-5 shadow-card',
        'transition-all duration-200',
        href ? 'cursor-pointer hover:shadow-card-hover hover:-translate-y-0.5' : '',
        borderClass,
      )}
    >
      <div className={cn('flex h-11 w-11 shrink-0 items-center justify-center rounded-xl', bgClass)}>
        <Icon size={20} className={colorClass} />
      </div>
      <div className="min-w-0 flex-1">
        <p className="text-2xl font-bold text-gray-900 tabular-nums leading-tight">
          {value}
        </p>
        <p className="text-sm font-medium text-gray-600 truncate">{label}</p>
        <p className="mt-0.5 text-xs text-gray-400 truncate">{description}</p>
      </div>
      {href && (
        <ArrowRight
          size={16}
          className="shrink-0 text-gray-300 transition-transform group-hover:translate-x-1 group-hover:text-gray-500"
        />
      )}
    </div>
  )

  if (href) return <Link href={href}>{content}</Link>
  return content
}

// ── Quick Action ─────────────────────────────────────────────────────────────

interface QuickActionProps {
  label:       string
  description: string
  icon:        React.ElementType
  href:        string
  colorClass:  string
  bgClass:     string
}

function QuickAction({ label, description, icon: Icon, href, colorClass, bgClass }: QuickActionProps) {
  return (
    <Link
      href={href}
      className={cn(
        'group flex items-center gap-3 rounded-xl p-4 transition-all duration-150',
        bgClass,
        'hover:opacity-90',
      )}
    >
      <Icon size={18} className={cn('shrink-0', colorClass)} />
      <div className="min-w-0">
        <p className={cn('text-sm font-semibold', colorClass)}>{label}</p>
        <p className="mt-0.5 text-xs text-gray-500 truncate">{description}</p>
      </div>
      <ArrowRight size={14} className={cn('ml-auto shrink-0 opacity-0 group-hover:opacity-100 transition-opacity', colorClass)} />
    </Link>
  )
}

// ── Componente principal ──────────────────────────────────────────────────────

export default function DashboardPage() {
  const { data: session } = useSession()
  const userRole = session?.user?.role as UserRole | undefined
  const firstName = session?.user?.name?.split(' ')[0] ?? 'usuário'

  const [stats, setStats] = useState<DashboardStats>({
    pendenciasAbertas:    0,
    pendenciasUrgentes:   0,
    pendenciasFinalizadas:0,
    aguardandoResposta:   0,
    comissoesPrevistos:   '—',
    comissoesAprovados:   '—',
    importacoesHoje:      0,
    contratosLidosHoje:   0,
    loaded: false,
  })
  const [isRefreshing, setIsRefreshing] = useState(false)

  const loadStats = useCallback(async () => {
    setIsRefreshing(true)
    try {
      // Busca pendências abertas
      const [abertas, urgentes, finalizadas, aguardando] = await Promise.allSettled([
        fetch('/api/pendencies?perPage=1&status=ABERTA',             { credentials: 'include' }),
        fetch('/api/pendencies?perPage=1&status=ABERTA&priority=URGENTE', { credentials: 'include' }),
        fetch('/api/pendencies?perPage=1&status=FINALIZADA',         { credentials: 'include' }),
        fetch('/api/pendencies?perPage=1&status=AGUARDANDO_RESPOSTA',{ credentials: 'include' }),
      ])

      const getTotal = async (res: PromiseSettledResult<Response>) => {
        if (res.status === 'fulfilled' && res.value.ok) {
          const j = await res.value.json()
          return j?.meta?.total ?? 0
        }
        return 0
      }

      const [a, u, f, aw] = await Promise.all([
        getTotal(abertas),
        getTotal(urgentes),
        getTotal(finalizadas),
        getTotal(aguardando),
      ])

      setStats((prev) => ({
        ...prev,
        pendenciasAbertas:    a,
        pendenciasUrgentes:   u,
        pendenciasFinalizadas:f,
        aguardandoResposta:   aw,
        loaded: true,
      }))
    } catch {
      setStats((prev) => ({ ...prev, loaded: true }))
    } finally {
      setIsRefreshing(false)
    }
  }, [])

  useEffect(() => { loadStats() }, [loadStats])

  const canSeeCommissions  = canAccessModule(userRole, 'commissions')
  const canManagePendencies = canAccessModule(userRole, 'pendencies.manage')
  const canImport          = canAccessModule(userRole, 'documents.import')
  const canReadPdf         = canAccessModule(userRole, 'documents.pdf')
  const canDispatch        = canAccessModule(userRole, 'communication.dispatch')
  const canSeeSettings     = canAccessModule(userRole, 'settings')

  // ── KPIs ────────────────────────────────────────────────────────────────────

  const kpis: KpiCardProps[] = [
    {
      label:       'Pendências Abertas',
      value:       stats.loaded ? stats.pendenciasAbertas : '—',
      description: 'Aguardando resolução',
      icon:        AlertCircle,
      colorClass:  'text-amber-600',
      bgClass:     'bg-amber-50',
      borderClass: 'border-l-4 border-l-amber-400 border-gray-100',
      href:        '/pendencias/minhas',
    },
    {
      label:       'Urgentes',
      value:       stats.loaded ? stats.pendenciasUrgentes : '—',
      description: 'Atenção imediata',
      icon:        AlertTriangle,
      colorClass:  'text-red-600',
      bgClass:     'bg-red-50',
      borderClass: 'border-l-4 border-l-red-500 border-gray-100',
      href:        '/pendencias/minhas',
    },
    {
      label:       'Finalizadas',
      value:       stats.loaded ? stats.pendenciasFinalizadas : '—',
      description: 'Concluídas no período',
      icon:        CheckCircle2,
      colorClass:  'text-brand-700',
      bgClass:     'bg-brand-50',
      borderClass: 'border-l-4 border-l-brand-600 border-gray-100',
    },
    {
      label:       'Aguardando Resposta',
      value:       stats.loaded ? stats.aguardandoResposta : '—',
      description: 'Retorno do cliente',
      icon:        Clock,
      colorClass:  'text-blue-600',
      bgClass:     'bg-blue-50',
      borderClass: 'border-l-4 border-l-blue-400 border-gray-100',
    },
  ]

  // ── Atalhos rápidos ──────────────────────────────────────────────────────────

  const quickActions: QuickActionProps[] = [
    ...(canManagePendencies ? [{
      label:       'Gerenciar Pendências',
      description: 'Acompanhe toda a equipe',
      icon:        Activity,
      href:        '/pendencias/gerencia',
      colorClass:  'text-amber-700',
      bgClass:     'bg-amber-50 hover:bg-amber-100',
    }] : []),
    ...(canDispatch ? [{
      label:       'Disparo Manual',
      description: 'Envie mensagem agora',
      icon:        Send,
      href:        '/comunicacao/disparo',
      colorClass:  'text-blue-700',
      bgClass:     'bg-blue-50 hover:bg-blue-100',
    }] : []),
    ...(canSeeCommissions ? [{
      label:       'Extrato de Comissões',
      description: 'Veja seus ganhos',
      icon:        DollarSign,
      href:        '/comissoes/extrato',
      colorClass:  'text-brand-800',
      bgClass:     'bg-brand-50 hover:bg-brand-100',
    }] : []),
    ...(canReadPdf ? [{
      label:       'Leitura de Contrato',
      description: 'Importe um PDF de contrato',
      icon:        FileText,
      href:        '/documentos/pdf',
      colorClass:  'text-purple-700',
      bgClass:     'bg-purple-50 hover:bg-purple-100',
    }] : []),
    ...(canImport ? [{
      label:       'Importar Planilha',
      description: 'Sincronizar Google Sheets',
      icon:        Upload,
      href:        '/documentos/importacao',
      colorClass:  'text-teal-700',
      bgClass:     'bg-teal-50 hover:bg-teal-100',
    }] : []),
    ...(canSeeSettings ? [{
      label:       'Configurações',
      description: 'Ajuste parâmetros do sistema',
      icon:        TrendingUp,
      href:        '/configuracoes/sistema',
      colorClass:  'text-gray-700',
      bgClass:     'bg-gray-50 hover:bg-gray-100',
    }] : []),
  ]

  return (
    <div className="max-w-screen-2xl space-y-6">
      {/* ── Cabeçalho ────────────────────────────────────────────────────── */}
      <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <h1 className="text-xl font-bold text-gray-900">
            Bom dia, {firstName}
          </h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Aqui está o resumo da sua operação.
          </p>
        </div>
        <button
          type="button"
          onClick={loadStats}
          disabled={isRefreshing}
          className="btn-secondary self-start sm:self-auto text-xs"
        >
          <RefreshCw size={13} className={cn(isRefreshing && 'animate-spin')} />
          Atualizar
        </button>
      </div>

      {/* ── Metas + posição no ranking ───────────────────────────────────── */}
      <GoalsPanel />
      <RankingPositionCard />

      {/* ── KPI Cards ────────────────────────────────────────────────────── */}
      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-4">
        {kpis.map((kpi) => (
          <KpiCard key={kpi.label} {...kpi} />
        ))}
      </div>

      {/* ── Linha principal ──────────────────────────────────────────────── */}
      <div className="grid gap-4 lg:grid-cols-3">
        {/* Central de Pendências */}
        <div className="lg:col-span-2 card">
          <div className="section-header">
            <AlertCircle size={16} className="text-amber-500" />
            <h2 className="text-sm font-semibold text-gray-800">Central de Pendências</h2>
          </div>
          <div className="p-5">
            <div className="grid gap-3 sm:grid-cols-2">
              <QuickAction
                label="Minhas Pendências"
                description="Veja suas pendências abertas"
                icon={AlertCircle}
                href="/pendencias/minhas"
                colorClass="text-amber-700"
                bgClass="bg-amber-50 hover:bg-amber-100"
              />
              {canManagePendencies && (
                <QuickAction
                  label="Gerência"
                  description="Visão da equipe"
                  icon={Activity}
                  href="/pendencias/gerencia"
                  colorClass="text-blue-700"
                  bgClass="bg-blue-50 hover:bg-blue-100"
                />
              )}
              {canAccessModule(userRole, 'pendencies.central') && (
                <QuickAction
                  label="Central Geral"
                  description="Todas as pendências"
                  icon={TrendingUp}
                  href="/pendencias/central"
                  colorClass="text-purple-700"
                  bgClass="bg-purple-50 hover:bg-purple-100"
                />
              )}
            </div>

            {/* Métricas rápidas */}
            <div className="mt-4 divide-y divide-gray-50 rounded-lg border border-gray-100">
              {[
                { label: 'Pendências abertas',          value: stats.pendenciasAbertas,     color: 'text-amber-700 bg-amber-50' },
                { label: 'Urgentes',                    value: stats.pendenciasUrgentes,     color: 'text-red-700 bg-red-50' },
                { label: 'Aguardando resposta',         value: stats.aguardandoResposta,     color: 'text-blue-700 bg-blue-50' },
                { label: 'Finalizadas no período',      value: stats.pendenciasFinalizadas,  color: 'text-brand-700 bg-brand-50' },
              ].map((row) => (
                <div key={row.label} className="flex items-center justify-between px-4 py-2.5">
                  <p className="text-sm text-gray-600">{row.label}</p>
                  <span className={cn('rounded-full px-2.5 py-0.5 text-xs font-semibold tabular-nums min-w-[2rem] text-center', row.color)}>
                    {stats.loaded ? row.value : '—'}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Atalhos rápidos */}
        <div className="card">
          <div className="section-header">
            <TrendingUp size={16} className="text-brand-700" />
            <h2 className="text-sm font-semibold text-gray-800">Atalhos Rápidos</h2>
          </div>
          <div className="p-4 space-y-2">
            {quickActions.length === 0 ? (
              <p className="py-8 text-center text-sm text-gray-400">
                Nenhum atalho disponível para seu perfil.
              </p>
            ) : (
              quickActions.map((action) => (
                <QuickAction key={action.href} {...action} />
              ))
            )}
          </div>
        </div>
      </div>

      {/* ── Alertas ──────────────────────────────────────────────────────── */}
      {stats.loaded && stats.pendenciasUrgentes > 0 && (
        <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 px-5 py-4 animate-fade-in">
          <AlertTriangle size={18} className="shrink-0 text-red-500 mt-0.5" />
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-red-800">
              {stats.pendenciasUrgentes} pendência{stats.pendenciasUrgentes > 1 ? 's' : ''} urgente{stats.pendenciasUrgentes > 1 ? 's' : ''}
            </p>
            <p className="text-xs text-red-600 mt-0.5">
              Requer atenção imediata. Clique para visualizar.
            </p>
          </div>
          <Link
            href="/pendencias/minhas"
            className="shrink-0 rounded-lg bg-red-600 px-3 py-1.5 text-xs font-semibold text-white hover:bg-red-700 transition-colors"
          >
            Ver agora
          </Link>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Desempenho — Dashboard de gestão (gerente/admin)
// Ranking por vendedor com métricas e qualidade + metas agregadas da loja/unidade.
// Consome /api/ranking e /api/goals/me. RBAC e escopo são aplicados no backend.
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { Trophy, RefreshCw, Filter } from 'lucide-react'
import { cn } from '@/lib/utils'
import { GoalCard, type GoalCardData } from '@/components/goals/GoalCard'

interface RankingMetrics {
  sales: number; purchases: number; returns: number; documentations: number
  warranties: number; services: number; overduePendencies: number
  canceledSales: number; lateDocuments: number
}
interface RankingEntry {
  userId: string; name: string; unitId: string | null; rank: number
  metrics: RankingMetrics; totalPoints: number; qualityScore: number
}
interface RankingData {
  scope: 'GENERAL' | 'UNIT'
  window: { start: string; end: string }
  entries: RankingEntry[]
  notes: string[]
}

const PERIODS = [
  { value: 'DAILY', label: 'Diário' },
  { value: 'WEEKLY', label: 'Semanal' },
  { value: 'MONTHLY', label: 'Mensal' },
  { value: 'QUARTERLY', label: 'Trimestral' },
  { value: 'YEARLY', label: 'Anual' },
]

const MANAGER_ROLES = ['MASTER', 'ADM', 'GERENTE_GERAL', 'GERENTE']

const COLS: { key: keyof RankingMetrics; label: string }[] = [
  { key: 'sales', label: 'Vendas' },
  { key: 'purchases', label: 'Compras' },
  { key: 'returns', label: 'Retornos' },
  { key: 'documentations', label: 'Doc.' },
  { key: 'warranties', label: 'Garantias' },
  { key: 'services', label: 'Serviços' },
  { key: 'overduePendencies', label: 'Venc.' },
]

export default function DesempenhoPage() {
  const { data: session } = useSession()
  const role = session?.user?.role as string | undefined
  const myId = session?.user?.id
  const isManager = role ? MANAGER_ROLES.includes(role) : false

  const [period, setPeriod] = useState('MONTHLY')
  const [unitId, setUnitId] = useState('')
  const [units, setUnits] = useState<{ value: string; label: string }[]>([])
  const [ranking, setRanking] = useState<RankingData | null>(null)
  const [goals, setGoals] = useState<GoalCardData[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!isManager) return
    fetch('/api/units', { credentials: 'include' })
      .then((r) => r.json())
      .then((j) => setUnits((j?.data ?? []).map((u: { id: string; name: string }) => ({ value: u.id, label: u.name }))))
      .catch(() => {})
  }, [isManager])

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const qs = new URLSearchParams({ period })
      if (unitId) qs.set('unitId', unitId)
      const [rkRes, glRes] = await Promise.all([
        fetch(`/api/ranking?${qs.toString()}`, { credentials: 'include' }),
        fetch('/api/goals/me', { credentials: 'include' }),
      ])
      setRanking(rkRes.ok ? (await rkRes.json())?.data ?? null : null)
      const gl = glRes.ok ? (await glRes.json())?.data ?? [] : []
      // Painel de gestão: metas agregadas (loja/unidade), não as individuais.
      setGoals(gl.filter((it: GoalCardData) => it.goal.scope === 'TENANT' || it.goal.scope === 'UNIT'))
    } catch {
      setRanking(null); setGoals([])
    } finally {
      setLoading(false)
    }
  }, [period, unitId])

  useEffect(() => { load() }, [load])

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Desempenho</h1>
          <p className="mt-1 text-sm text-gray-500">Ranking da equipe e metas agregadas por período.</p>
        </div>
        <div className="flex items-center gap-2">
          <Filter size={15} className="text-gray-400" />
          <select
            value={period}
            onChange={(e) => setPeriod(e.target.value)}
            className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
          >
            {PERIODS.map((p) => <option key={p.value} value={p.value}>{p.label}</option>)}
          </select>
          {isManager && (
            <select
              value={unitId}
              onChange={(e) => setUnitId(e.target.value)}
              className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
            >
              <option value="">Todas as unidades</option>
              {units.map((u) => <option key={u.value} value={u.value}>{u.label}</option>)}
            </select>
          )}
          <button onClick={load} disabled={loading} className="btn-secondary text-xs">
            <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
            Atualizar
          </button>
        </div>
      </div>

      {/* Metas agregadas (loja/unidade) */}
      {goals.length > 0 && (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-3">
          {goals.map((item) => <GoalCard key={item.goal.id} data={item} />)}
        </div>
      )}

      {/* Ranking */}
      <div className="card">
        <div className="section-header">
          <Trophy size={16} className="text-amber-500" />
          <h2 className="text-sm font-semibold text-gray-800">
            {ranking?.scope === 'UNIT' ? 'Ranking da Unidade' : 'Ranking Geral'}
          </h2>
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="border-b border-gray-200 bg-gray-50 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                <th className="px-4 py-3">#</th>
                <th className="px-4 py-3">Vendedor</th>
                {COLS.map((c) => <th key={c.key} className="px-3 py-3 text-right">{c.label}</th>)}
                <th className="px-3 py-3 text-right">Qualidade</th>
                <th className="px-4 py-3 text-right">Pontos</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                Array.from({ length: 5 }).map((_, i) => (
                  <tr key={i} className="border-b border-gray-100">
                    {Array.from({ length: 11 }).map((_, j) => (
                      <td key={j} className="px-4 py-3"><div className="h-4 animate-pulse rounded bg-gray-200" /></td>
                    ))}
                  </tr>
                ))
              ) : !ranking || ranking.entries.length === 0 ? (
                <tr><td colSpan={11} className="py-12 text-center text-sm text-gray-400">Sem dados de ranking no período.</td></tr>
              ) : (
                ranking.entries.map((e) => (
                  <tr key={e.userId} className={cn('border-b border-gray-100 hover:bg-gray-50', e.userId === myId && 'bg-brand-50/40')}>
                    <td className="px-4 py-3">
                      <span className={cn('inline-flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold tabular-nums',
                        e.rank <= 3 ? 'bg-amber-100 text-amber-700' : 'bg-gray-100 text-gray-500')}>
                        {e.rank}
                      </span>
                    </td>
                    <td className="px-4 py-3 font-medium text-gray-900">
                      {e.name}{e.userId === myId && <span className="ml-1 text-xs text-brand-600">(você)</span>}
                    </td>
                    {COLS.map((c) => (
                      <td key={c.key} className={cn('px-3 py-3 text-right tabular-nums',
                        c.key === 'overduePendencies' && e.metrics[c.key] > 0 ? 'text-red-600' : 'text-gray-600')}>
                        {e.metrics[c.key]}
                      </td>
                    ))}
                    <td className="px-3 py-3 text-right tabular-nums text-gray-600">{e.qualityScore}%</td>
                    <td className="px-4 py-3 text-right font-bold tabular-nums text-brand-700">{e.totalPoints}</td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {ranking?.notes && ranking.notes.length > 0 && (
        <p className="text-xs text-gray-400">
          Observações: {ranking.notes.join(' · ')}
        </p>
      )}
    </div>
  )
}

