  catalogKey: string | null
  name:       string
  status:     string
  priority:   string | null
  notes:      string | null
}

interface EvalAttachment {
  id:        string
  section:   string | null
  category:  string | null
  fileName:  string
  fileType:  string
  publicUrl: string | null
  itemId:    string | null
}

interface EvaluationSectionsProps {
  evaluationId:       string
  evaluationStatus:   string
  /** reopenCount > 0 → label do botão muda para "Reavaliar". */
  reopenCount?:       number
  readOnly?:          boolean
  /** Callback opcional ao clicar "Anterior seção" estando na 1ª aba — leva ao step anterior do wizard. */
  onBack?:            () => void
  /** Callback opcional ao clicar "Concluir avaliação" estando na última aba — avança o wizard. */
  onComplete?:        () => void
}

const TABS: SectionKey[] = ['INTERIOR', 'FRENTE', 'DIREITA', 'TRASEIRA', 'ESQUERDA', 'TEST_DRIVE']

/**
 * Remove itens duplicados da lista. Critério:
 *   - Se tem catalogKey: dedup por (section, catalogKey) — mantém o 1º
 *   - Se não tem catalogKey: dedup por (section, name normalizado)
 */
function dedupeItems(items: EvalItem[]): EvalItem[] {
  const seen = new Set<string>()
  const out: EvalItem[] = []
  for (const it of items) {
    const key = it.catalogKey
      ? `${it.section}::${it.catalogKey}`
      : `${it.section}::name::${it.name.trim().toLowerCase()}`
    if (seen.has(key)) continue
    seen.add(key)
    out.push(it)
  }
  return out
}

function statusBadge(status: string) {
  const s = ITEM_STATUS.find((x) => x.value === status)
  if (!s) return <span className="inline-block rounded-full bg-gray-100 px-2 py-0.5 text-[10px] font-medium text-gray-600">—</span>
  return <span className={`inline-block rounded-full px-2 py-0.5 text-[10px] font-medium ${s.color}`}>{s.label}</span>
}

// ── Widget de foto geral da seção (obrigatório) ──────────────────────────────

function SectionPhotoWidget({
  evaluationId, section, photos, readOnly, onChanged,
}: {
  evaluationId: string
  section:      SectionKey
  photos:       EvalAttachment[]
  readOnly?:    boolean
  onChanged:    () => void
}) {
  const fileRef   = useRef<HTMLInputElement>(null)
  const cameraRef = useRef<HTMLInputElement>(null)
  const [busy, setBusy] = useState(false)
  const [err,  setErr]  = useState('')

  async function upload(files: FileList | null) {
    if (!files || files.length === 0) return
    setBusy(true); setErr('')
    try {
      for (let i = 0; i < files.length; i++) {
        const f  = files[i]
        const fd = new FormData()
        fd.append('file', f)
        fd.append('section',  section)
        fd.append('category', 'FOTO_SECAO')
        const r = await fetch(`/api/evaluations/${evaluationId}/attachments`, { method: 'POST', body: fd })
        if (!r.ok) {
          const d = await r.json().catch(() => ({}))
          setErr(d?.error ?? 'Falha ao enviar foto.')
          break
        }
      }
      onChanged()
    } catch {
      setErr('Erro de conexão ao enviar foto.')
    } finally {
      setBusy(false)
      if (fileRef.current)   fileRef.current.value   = ''
      if (cameraRef.current) cameraRef.current.value = ''
    }
  }

  async function remove(id: string) {
    if (!confirm('Remover esta foto?')) return
    try {
      const r = await fetch(`/api/evaluations/${evaluationId}/attachments/${id}`, { method: 'DELETE' })
      if (r.ok) onChanged()
    } catch { /* silent */ }
  }

  const hasPhotos = photos.length > 0

  return (
    <div className={[
      'rounded-xl border p-3 sm:p-4',
      hasPhotos ? 'border-emerald-200 bg-emerald-50/40' : 'border-amber-300 bg-amber-50',
    ].join(' ')}>
      <div className="flex flex-wrap items-center justify-between gap-2 mb-2">
        <div>
          <p className="text-sm font-semibold text-gray-800 flex items-center gap-1.5">
            <ImageIcon className="h-4 w-4" /> Foto geral da seção
            <span className="text-red-500">*</span>
          </p>
          <p className="text-[11px] text-gray-500">
            {hasPhotos
              ? `${photos.length} foto(s) enviada(s)`
              : 'Mínimo 1 foto obrigatória antes de enviar para aprovação.'}
          </p>
        </div>
        {!readOnly && (
          <div className="flex items-center gap-1.5">
            <input
              ref={fileRef}
              type="file"
              accept="image/*"
              multiple
              className="hidden"
              onChange={(e) => upload(e.target.files)}
            />
            <input
              ref={cameraRef}
              type="file"
              accept="image/*"
              capture="environment"
              className="hidden"
              onChange={(e) => upload(e.target.files)}
            />
            <button
              type="button"
              onClick={() => cameraRef.current?.click()}
              disabled={busy}
              className="flex items-center gap-1 rounded-lg border border-brand-400 bg-white px-3 py-1.5 text-xs font-medium text-brand-700 hover:bg-brand-50 disabled:opacity-60"
            >
              {busy ? <Loader2 className="h-3 w-3 animate-spin" /> : <Camera className="h-3 w-3" />} Câmera
            </button>
            <button
              type="button"
              onClick={() => fileRef.current?.click()}
              disabled={busy}
              className="flex items-center gap-1 rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-xs font-medium text-gray-700 hover:bg-gray-50 disabled:opacity-60"
            >
              <Upload className="h-3 w-3" /> Enviar arquivo
            </button>
          </div>
        )}
      </div>

      {err && <p className="text-xs text-red-600 mb-2">{err}</p>}

      {hasPhotos && (
        <ul className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
          {photos.map((a) => (
            <li key={a.id} className="group relative aspect-square rounded-lg overflow-hidden border border-gray-200 bg-gray-100">
              {a.publicUrl ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img src={a.publicUrl} alt={a.fileName} className="h-full w-full object-cover" />
              ) : (
                <div className="h-full w-full flex items-center justify-center text-gray-400 text-[10px]">{a.fileName}</div>
              )}
              {!readOnly && (
                <button
                  type="button"
                  onClick={() => remove(a.id)}
                  className="absolute top-1 right-1 rounded-full bg-white/90 p-1 text-red-600 opacity-0 group-hover:opacity-100"
                >
                  <Trash2 className="h-3 w-3" />
                </button>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

export function EvaluationSections({
  evaluationId, evaluationStatus, reopenCount = 0, readOnly, onBack, onComplete,
}: EvaluationSectionsProps) {
  const [tab,         setTab]         = useState<SectionKey>('INTERIOR')
  const [items,       setItems]       = useState<EvalItem[]>([])
  const [attachments, setAttachments] = useState<EvalAttachment[]>([])
  const [loading,     setLoading]     = useState(true)
  const [drawer,      setDrawer]      = useState<DrawerItem | null>(null)
  const [err,         setErr]         = useState('')
  // Lock client-side: evita 2x POST /seed disparado pelo React Strict Mode
  const seedInFlight = useRef(false)
  const seedDone     = useRef<string | null>(null)

  const load = useCallback(async () => {
    setLoading(true)
    setErr('')
    try {
      const r = await fetch(`/api/evaluations/${evaluationId}`, { cache: 'no-store' })
      const d = await r.json()
      if (!r.ok) {
        setErr(d?.error ?? 'Falha ao carregar avaliação.')
        setItems([])
        return
      }
      const incoming: EvalItem[] = Array.isArray(d?.data?.items) ? d.data.items : []
      const incAttachments: EvalAttachment[] = Array.isArray(d?.data?.attachments) ? d.data.attachments : []
      setAttachments(incAttachments)

      const shouldSeed =
        incoming.length === 0 &&
        !readOnly &&
        !seedInFlight.current &&
        seedDone.current !== evaluationId

      if (shouldSeed) {
        seedInFlight.current = true
        try {
          await fetch(`/api/evaluations/${evaluationId}/items/seed`, { method: 'POST' })
          seedDone.current = evaluationId
          const r2 = await fetch(`/api/evaluations/${evaluationId}`, { cache: 'no-store' })
          const d2 = await r2.json()
          const seeded = Array.isArray(d2?.data?.items) ? d2.data.items : []
          setItems(dedupeItems(seeded))
          const seededAtts = Array.isArray(d2?.data?.attachments) ? d2.data.attachments : []
          setAttachments(seededAtts)
        } finally {
          seedInFlight.current = false
        }
      } else {
        setItems(dedupeItems(incoming))
      }
    } catch {
      setErr('Erro de conexão.')
    } finally {
      setLoading(false)
    }
  }, [evaluationId, readOnly])

  useEffect(() => { void load() }, [load])
  // evaluationStatus não usado por enquanto (mantido na assinatura para
  // compatibilidade com o InspecaoPage que passa o status). Suprime warning.
  void evaluationStatus

  const currentItems = items.filter((i) => i.section === tab)
  // Fotos da seção atual: pega tudo que é image E section=tab (qualquer category,
  // mas prioritariamente FOTO_SECAO). Fotos de item ficam dentro do item.
  const sectionPhotos = attachments.filter((a) =>
    a.section === tab &&
    a.fileType === 'image' &&
    !a.itemId,
  )
  const catalog = ITEMS[tab] ?? []

  function buttonLabel(status: string): string {
    if (reopenCount > 0) return 'Reavaliar'
    if (!status || status === 'PENDING' || status === 'NAO_AVALIADO') return 'Avaliar item'
    return 'Editar item'
  }

  return (
    <div className="flex flex-col gap-4">
      {/* Tabs */}
      <div className="flex flex-wrap gap-1 overflow-x-auto border-b border-gray-200">
        {TABS.map((t) => {
          const def = SECTIONS.find((s) => s.key === t)!
          const count = items.filter((i) => i.section === t).length
          const done  = items.filter((i) => i.section === t && i.status && i.status !== 'PENDING').length
          const photoCount = attachments.filter((a) => a.section === t && a.fileType === 'image' && !a.itemId).length
          const active = tab === t
          return (
            <button
              key={t}
              type="button"
              onClick={() => setTab(t)}
              className={[
                'whitespace-nowrap rounded-t-md px-3 py-2 text-xs font-medium border-b-2 transition-colors',
                active
                  ? 'border-brand-600 text-brand-700'
                  : 'border-transparent text-gray-500 hover:text-gray-800',
              ].join(' ')}
            >
              {def.label}
              {count > 0 && (
                <span className="ml-1.5 text-[10px] text-gray-400">({done}/{count})</span>
              )}
              <span className={[
                'ml-1.5 inline-flex items-center gap-0.5 rounded-full px-1.5 text-[9px] font-bold',
                photoCount > 0 ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700',
              ].join(' ')}>
                <Camera className="h-2.5 w-2.5" />{photoCount}
              </span>
            </button>
          )
        })}
      </div>

      {err && (
        <div className="rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">{err}</div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-10 text-gray-400">
          <Loader2 className="h-5 w-5 animate-spin" />
        </div>
      ) : (
        <>
          {/* Foto geral da seção (obrigatória) */}
          <SectionPhotoWidget
            evaluationId={evaluationId}
            section={tab}
            photos={sectionPhotos}
            readOnly={readOnly}
            onChanged={load}
          />

          <ul className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {(currentItems.length > 0 ? currentItems : catalog.map((c, i) => ({
              id: `__ph_${i}`, section: tab, catalogKey: c.key, name: c.name, status: 'PENDING', priority: null, notes: null,
            } as EvalItem))).map((it) => {
              const isPlaceholder = it.id.startsWith('__ph_')
              const itemPhotoCount = attachments.filter((a) => a.itemId === it.id && a.fileType === 'image').length
              return (
                <li key={it.id} className="flex items-center justify-between gap-3 rounded-lg border border-gray-200 bg-white px-3 py-2.5">
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 truncate">{it.name}</p>
                    <div className="mt-1 flex items-center gap-2">
                      {statusBadge(it.status || 'PENDING')}
                      {itemPhotoCount > 0 && (
                        <span className="inline-flex items-center gap-0.5 text-[10px] text-gray-500">
                          <Camera className="h-2.5 w-2.5" /> {itemPhotoCount}
                        </span>
                      )}
                    </div>
                  </div>
                  <button
                    type="button"
                    disabled={isPlaceholder || readOnly}
                    onClick={() => setDrawer({
                      id: it.id, evaluationId, name: it.name, status: it.status,
                      priority: it.priority, notes: it.notes,
                    })}
                    className="inline-flex items-center gap-1 rounded-lg border border-brand-300 bg-white px-2.5 py-1 text-xs font-medium text-brand-700 hover:bg-brand-50 disabled:opacity-50 disabled:cursor-not-allowed"
                    title={isPlaceholder ? 'Itens ainda não inicializados. Salve a avaliação antes.' : ''}
                  >
                    {buttonLabel(it.status)}
                    <ChevronRight className="h-3 w-3" />
                  </button>
                </li>
              )
            })}
          </ul>

          {/* ── Navegação entre seções ───────────────────────────────────── */}
          {(onBack || onComplete) && (
            <div className="mt-2 flex items-center justify-between border-t border-gray-100 pt-3">
              <button
                type="button"
                onClick={() => {
                  const idx = TABS.indexOf(tab)
                  if (idx > 0) setTab(TABS[idx - 1])
                  else onBack?.()
                }}
                className="flex items-center gap-1.5 rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-xs font-medium text-gray-700 hover:bg-gray-50"
              >
                <ChevronLeft className="h-3.5 w-3.5" />
                {TABS.indexOf(tab) > 0 ? `Seção anterior (${SECTIONS.find((s) => s.key === TABS[TABS.indexOf(tab) - 1])?.label})` : 'Voltar ao veículo'}
              </button>

              {TABS.indexOf(tab) < TABS.length - 1 ? (
                <button
                  type="button"
                  onClick={() => setTab(TABS[TABS.indexOf(tab) + 1])}
                  className="flex items-center gap-1.5 rounded-lg bg-brand-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-brand-700"
                >
                  Próxima seção ({SECTIONS.find((s) => s.key === TABS[TABS.indexOf(tab) + 1])?.label})
                  <ChevronRight className="h-3.5 w-3.5" />
                </button>
              ) : (
                <button
                  type="button"
                  onClick={() => onComplete?.()}
                  className="flex items-center gap-1.5 rounded-lg bg-emerald-600 px-4 py-1.5 text-xs font-semibold text-white hover:bg-emerald-700"
                >
                  <CheckCircle2 className="h-3.5 w-3.5" />
                  Concluir avaliação — ir para Cautelar
                </button>
              )}
            </div>
          )}
        </>
      )}

      {drawer && (
        <ItemDrawer
          item={drawer}
          evaluationStatus={evaluationStatus}
          isReopen={reopenCount > 0}
          readOnly={readOnly}
          existingPhotos={attachments.filter((a) => a.itemId === drawer.id && a.fileType === 'image')}
          onClose={() => setDrawer(null)}
          onSave={() => { setDrawer(null); void load() }}
        />
      )}
    </div>
  )
}

'use client'

// =============================================================================
// FipeMiniChart — gráfico SVG inline de 6 meses de histórico FIPE.
// =============================================================================

import { useEffect, useState } from 'react'
import { Loader2, TrendingUp } from 'lucide-react'
import { formatBRL } from '@/lib/masks'

interface HistoryPoint { month: string; value: number }
interface ApiResponse  { months?: HistoryPoint[]; note?: string }

interface FipeMiniChartProps {
  fipeCode:     string | null
  vehicleType:  'carros' | 'motos' | 'caminhoes'
  currentValue?: number | null
}

export function FipeMiniChart({ fipeCode, vehicleType, currentValue }: FipeMiniChartProps) {
  const [data,    setData]    = useState<HistoryPoint[]>([])
  const [note,    setNote]    = useState<string>('')
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!fipeCode) { setData([]); setNote(''); return }
    let alive = true
    setLoading(true)
    setNote('')
    fetch(`/api/evaluations/fipe/history?fipeCode=${encodeURIComponent(fipeCode)}&vehicleType=${vehicleType}`, { cache: 'no-store' })
      .then((r) => r.json() as Promise<ApiResponse>)
      .then((d) => {
        if (!alive) return
        const months = Array.isArray(d?.months) ? d.months : []
        // NaN-safe: descarta entradas inválidas. ATENÇÃO: Number(null) === 0
        // (finito), o que deixava meses sem preço entrarem como zero e
        // achatava a escala — checar null/undefined explicitamente antes.
        setData(months.filter((m) => {
          if (!m || typeof m.month !== 'string') return false
          if (m.value == null) return false
          const n = Number(m.value)
          return Number.isFinite(n) && n > 0
        }))
        if (d?.note) setNote(d.note)
      })
      .catch(() => { if (alive) { setData([]); setNote('Falha ao carregar histórico FIPE.') } })
      .finally(() => { if (alive) setLoading(false) })
    return () => { alive = false }
  }, [fipeCode, vehicleType])

  const safeCurrent = Number.isFinite(Number(currentValue)) ? Number(currentValue) : null
  const empty = !loading && data.length === 0

  return (
    <div className="rounded-xl border border-gray-200 bg-gray-50/60 p-4">
      <header className="mb-3 flex flex-wrap items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <TrendingUp className="h-4 w-4 text-brand-600" />
          <h4 className="text-sm font-semibold text-gray-800">Histórico FIPE (últimos 6 meses)</h4>
        </div>
        {safeCurrent != null && (
          <span className="text-sm font-bold text-brand-700">{formatBRL(safeCurrent)}</span>
        )}
      </header>

      {loading && (
        <div className="flex items-center justify-center py-8 text-gray-400">
          <Loader2 className="h-4 w-4 animate-spin" />
        </div>
      )}

      {!loading && empty && (
        <p className="text-xs text-gray-500 py-4 text-center">
          {note || (fipeCode ? 'Histórico FIPE indisponível para este modelo.' : 'Selecione o código FIPE para ver o histórico.')}
        </p>
      )}

      {!loading && data.length > 0 && (
        <Chart points={data} />
      )}
    </div>
  )
}

// ── SVG inline ───────────────────────────────────────────────────────────────
function Chart({ points }: { points: HistoryPoint[] }) {
  const W = 600, H = 140, P = 24
  const innerW = W - P * 2
  const innerH = H - P * 2

  const values = points.map((p) => Number(p.value)).filter(Number.isFinite)
  if (values.length === 0) {
    return <p className="text-xs text-gray-500 py-4 text-center">Histórico FIPE indisponível para este modelo.</p>
  }
  const minV = Math.min(...values)
  const maxV = Math.max(...values)
  const range = maxV - minV || 1

  const xOf = (i: number) =>
    points.length === 1 ? W / 2 : P + (i * innerW) / (points.length - 1)
  const yOf = (v: number) => P + innerH - ((v - minV) / range) * innerH

  const lineD = points
    .map((p, i) => {
      const v = Number(p.value)
      if (!Number.isFinite(v)) return null
      return `${i === 0 ? 'M' : 'L'} ${xOf(i)} ${yOf(v)}`
    })
    .filter(Boolean)
    .join(' ')

  return (
    <div className="w-full overflow-x-auto">
      <svg viewBox={`0 0 ${W} ${H}`} className="w-full max-w-full h-[140px]" preserveAspectRatio="none">
        {/* Grid */}
        {[0, 0.25, 0.5, 0.75, 1].map((t) => (
          <line
            key={t}
            x1={P} x2={W - P}
            y1={P + innerH * t} y2={P + innerH * t}
            stroke="#e5e7eb" strokeWidth={1}
          />
        ))}
        {/* Linha */}
        <path d={lineD} fill="none" stroke="#166534" strokeWidth={2} />
        {/* Dots */}
        {points.map((p, i) => {
          const v = Number(p.value)
          if (!Number.isFinite(v)) return null
          return (
            <g key={i}>
              <circle cx={xOf(i)} cy={yOf(v)} r={4} fill="#166534" />
              <title>{`${p.month}: ${formatBRL(v)}`}</title>
            </g>
          )
        })}
        {/* Eixo X */}
        {points.map((p, i) => (
          <text
            key={i}
            x={xOf(i)} y={H - 4}
            textAnchor="middle"
            fontSize={9}
            fill="#6b7280"
          >
            {p.month}
          </text>
        ))}
      </svg>
    </div>
  )
}

'use client'

// =============================================================================
// ItemDrawer — Drawer lateral para Avaliar / Editar / Reavaliar um item.
// Persiste via PATCH /api/evaluations/[id]/items/[itemId] (status, priority,
// notes) e, se houver custo/tipo de serviço, cria/atualiza um EvaluationService
// vinculado (POST /api/evaluations/[id]/services).
// Fotos do item: upload real via POST /api/evaluations/[id]/attachments com
// itemId+category=FOTO. Aceita câmera (capture=environment) ou arquivo.
// =============================================================================

import { useEffect, useRef, useState } from 'react'
import { X, Save, Loader2, Camera, Upload, Trash2 } from 'lucide-react'
import { maskBRL, parseBRL, numberToBRLMask } from '@/lib/masks'
import { ITEM_STATUS, SERVICE_TYPES, SERVICE_TYPE_LABELS, PRIORITIES } from '@/lib/evaluation/catalog'

export interface DrawerItem {
  id:           string
  evaluationId: string
  name:         string
  status:       string
  priority:     string | null
  notes:        string | null
}

export interface DrawerPhoto {
  id:        string
  fileName:  string
  publicUrl: string | null
}

interface ItemDrawerProps {
  item:             DrawerItem
  evaluationStatus: string
  isReopen:         boolean
  readOnly?:        boolean
  existingPhotos?:  DrawerPhoto[]
  onSave:           () => void
  onClose:          () => void
}

const inputCls = 'rounded-lg border border-gray-300 px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500 w-full'

export function ItemDrawer({
  item, isReopen, readOnly, existingPhotos = [], onSave, onClose,
}: ItemDrawerProps) {
  const firstTime = !item.status || item.status === 'PENDING' || item.status === 'NAO_AVALIADO'
  const headerChip = isReopen ? 'Reavaliar' : (firstTime ? 'Avaliar item' : 'Editar item')
  const buttonLabel = firstTime && !isReopen ? 'Salvar avaliação' : 'Salvar alterações'

  const [status,      setStatus]      = useState(item.status || 'PENDING')
  const [priority,    setPriority]    = useState(item.priority ?? '')
  const [notes,       setNotes]       = useState(item.notes ?? '')
  const [serviceType, setServiceType] = useState<string>('OUTRO')
  const [costMask,    setCostMask]    = useState<string>('')
  const [description, setDescription] = useState<string>('')
  const [photos,      setPhotos]      = useState<DrawerPhoto[]>(existingPhotos)
  const [photoBusy,   setPhotoBusy]   = useState(false)
  const [saving,      setSaving]      = useState(false)
  const [err,         setErr]         = useState('')

  const fileRef   = useRef<HTMLInputElement>(null)
  const cameraRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    setStatus(item.status || 'PENDING')
    setPriority(item.priority ?? '')
    setNotes(item.notes ?? '')
    setCostMask('')
    setDescription('')
    setPhotos(existingPhotos)
    setErr('')
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [item.id, item.status, item.priority, item.notes])

  async function uploadPhotos(files: FileList | null) {
    if (!files || files.length === 0 || readOnly) return
    setPhotoBusy(true); setErr('')
    try {
      const added: DrawerPhoto[] = []
      for (let i = 0; i < files.length; i++) {
        const f  = files[i]
        const fd = new FormData()
        fd.append('file', f)
        fd.append('itemId',   item.id)
        fd.append('category', 'FOTO')
        const r = await fetch(`/api/evaluations/${item.evaluationId}/attachments`, { method: 'POST', body: fd })
        const d = await r.json().catch(() => ({}))
        if (!r.ok) {
          setErr(d?.error ?? 'Falha ao enviar foto.')
          break
        }
        const att = d?.data
        if (att?.id) {
          added.push({ id: att.id, fileName: att.fileName, publicUrl: att.publicUrl })
        }
      }
      if (added.length > 0) setPhotos((p) => [...p, ...added])
    } catch {
      setErr('Erro de conexão ao enviar foto.')
    } finally {
      setPhotoBusy(false)
      if (fileRef.current)   fileRef.current.value   = ''
      if (cameraRef.current) cameraRef.current.value = ''
    }
  }

  async function removePhoto(id: string) {
    if (readOnly) return
    if (!confirm('Remover esta foto?')) return
    try {
      const r = await fetch(`/api/evaluations/${item.evaluationId}/attachments/${id}`, { method: 'DELETE' })
      if (r.ok) setPhotos((p) => p.filter((x) => x.id !== id))
    } catch { /* silent */ }
  }

  async function handleSave() {
    if (readOnly) { onClose(); return }
    setSaving(true)
    setErr('')
    try {
      const r1 = await fetch(`/api/evaluations/${item.evaluationId}/items/${item.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          status,
          priority: priority || null,
          notes:    notes    || null,
        }),
      })
      if (!r1.ok) {
        const d = await r1.json().catch(() => ({}))
        setErr(d?.error ?? 'Falha ao salvar item.')
        setSaving(false)
        return
      }

      const cost = parseBRL(costMask)
      if ((cost != null && cost > 0) || description.trim()) {
        await fetch(`/api/evaluations/${item.evaluationId}/services`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            itemId:        item.id,
            description:   description.trim() || item.name,
            serviceType,
            estimatedCost: cost ?? 0,
            priority:      priority || null,
            notes:         null,
          }),
        }).catch(() => { /* não bloqueia o save do item */ })
      }

      onSave()
    } catch {
      setErr('Erro de conexão.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <>
      <div className="fixed inset-0 z-40 bg-black/40" onClick={onClose} />
      <aside className="fixed inset-y-0 right-0 z-50 w-full max-w-[480px] bg-white shadow-2xl flex flex-col">
        <header className="flex items-start justify-between gap-3 border-b border-gray-200 px-5 py-4">
          <div className="flex-1 min-w-0">
            <span className={`inline-block rounded-full px-2 py-0.5 text-[10px] font-bold uppercase tracking-wide ${
              isReopen ? 'bg-blue-100 text-blue-800' : firstTime ? 'bg-brand-100 text-brand-800' : 'bg-amber-100 text-amber-800'
            }`}>
              {headerChip}
            </span>
            <h3 className="mt-1 text-base font-semibold text-gray-900 truncate">{item.name}</h3>
          </div>
          <button type="button" onClick={onClose} className="rounded-lg p-1.5 text-gray-400 hover:bg-gray-100">
            <X className="h-4 w-4" />
          </button>
        </header>

        <div className="flex-1 overflow-y-auto px-5 py-4 flex flex-col gap-3">
          <label className="flex flex-col gap-1">
            <span className="text-xs font-medium text-gray-600">Nome do item</span>
            <input className={inputCls + ' bg-gray-50'} value={item.name} readOnly />
          </label>

          <label className="flex flex-col gap-1">
            <span className="text-xs font-medium text-gray-600">Status</span>
            <select className={inputCls} value={status} onChange={(e) => setStatus(e.target.value)} disabled={readOnly}>
              {ITEM_STATUS.map((s) => (
                <option key={s.value} value={s.value}>{s.label}</option>
              ))}
            </select>
          </label>

          <label className="flex flex-col gap-1">
            <span className="text-xs font-medium text-gray-600">Descrição / serviço (opcional)</span>
            <textarea
              className={inputCls + ' min-h-[60px] resize-y'}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Ex: trocar capa do banco, reparar amassado"
              disabled={readOnly}
            />
          </label>

          <div className="grid grid-cols-2 gap-3">
            <label className="flex flex-col gap-1">
              <span className="text-xs font-medium text-gray-600">Tipo de serviço</span>
              <select className={inputCls} value={serviceType} onChange={(e) => setServiceType(e.target.value)} disabled={readOnly}>
                {SERVICE_TYPES.map((t) => (
                  <option key={t} value={t}>{SERVICE_TYPE_LABELS[t] ?? t}</option>
                ))}
              </select>
            </label>
            <label className="flex flex-col gap-1">
              <span className="text-xs font-medium text-gray-600">Previsão de custo (R$)</span>
              <input
                inputMode="numeric"
                className={inputCls}
                value={costMask}
                onChange={(e) => setCostMask(maskBRL(e.target.value))}
                placeholder="0,00"
                disabled={readOnly}
              />
              {costMask && (
                <span className="text-[10px] text-gray-400">
                  {numberToBRLMask(parseBRL(costMask) ?? 0)}
                </span>
              )}
            </label>
          </div>

          <label className="flex flex-col gap-1">
            <span className="text-xs font-medium text-gray-600">Prioridade</span>
            <select className={inputCls} value={priority} onChange={(e) => setPriority(e.target.value)} disabled={readOnly}>
              <option value="">Selecione</option>
              {PRIORITIES.map((p) => (
                <option key={p.value} value={p.value}>{p.label}</option>
              ))}
            </select>
          </label>

          <label className="flex flex-col gap-1">
            <span className="text-xs font-medium text-gray-600">Observações</span>
            <textarea
              className={inputCls + ' min-h-[72px] resize-y'}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Detalhes adicionais"
              disabled={readOnly}
            />
          </label>

          {/* ── Fotos do item (câmera ou arquivo) ─────────────────────────── */}
          <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs font-medium text-gray-600">Fotos do item</span>
              {!readOnly && (
                <div className="flex items-center gap-1.5">
                  <input
                    ref={fileRef}
                    type="file"
                    accept="image/*"
                    multiple
                    className="hidden"
                    onChange={(e) => uploadPhotos(e.target.files)}
                  />
                  <input
                    ref={cameraRef}
                    type="file"
                    accept="image/*"
                    capture="environment"
                    className="hidden"
                    onChange={(e) => uploadPhotos(e.target.files)}
                  />
                  <button
                    type="button"
                    onClick={() => cameraRef.current?.click()}
                    disabled={photoBusy}
                    className="flex items-center gap-1 rounded-lg border border-brand-400 bg-white px-2.5 py-1 text-xs font-medium text-brand-700 hover:bg-brand-50 disabled:opacity-60"
                  >
                    {photoBusy ? <Loader2 className="h-3 w-3 animate-spin" /> : <Camera className="h-3 w-3" />} Câmera
                  </button>
                  <button
                    type="button"
                    onClick={() => fileRef.current?.click()}
                    disabled={photoBusy}
                    className="flex items-center gap-1 rounded-lg border border-gray-300 bg-white px-2.5 py-1 text-xs font-medium text-gray-700 hover:bg-gray-50 disabled:opacity-60"
                  >
                    <Upload className="h-3 w-3" /> Arquivo
                  </button>
                </div>
              )}
            </div>
            {photos.length === 0 ? (
              <p className="text-[11px] text-gray-400 italic">Nenhuma foto. Use câmera ou arquivo.</p>
            ) : (
              <ul className="grid grid-cols-3 gap-2">
                {photos.map((p) => (
                  <li key={p.id} className="group relative aspect-square rounded-lg overflow-hidden border border-gray-200 bg-gray-50">
                    {p.publicUrl ? (
                      // eslint-disable-next-line @next/next/no-img-element
                      <img src={p.publicUrl} alt={p.fileName} className="h-full w-full object-cover" />
                    ) : (
                      <div className="h-full w-full flex items-center justify-center text-[10px] text-gray-400">{p.fileName}</div>
                    )}
                    {!readOnly && (
                      <button
                        type="button"
                        onClick={() => removePhoto(p.id)}
                        className="absolute top-1 right-1 rounded-full bg-white/90 p-1 text-red-600 opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 className="h-3 w-3" />
                      </button>
                    )}
                  </li>
                ))}
              </ul>
            )}
          </div>

          {err && <p className="text-xs text-red-600">{err}</p>}
        </div>

        <footer className="flex items-center justify-end gap-2 border-t border-gray-100 px-5 py-3">
          <button type="button" onClick={onClose} className="rounded-lg border border-gray-300 px-4 py-2 text-sm text-gray-600 hover:bg-gray-50">
            Fechar
          </button>
          {!readOnly && (
            <button
              type="button"
              onClick={handleSave}
              disabled={saving}
              className="inline-flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-medium text-white hover:bg-brand-700 disabled:opacity-60"
            >
              {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
              {buttonLabel}
            </button>
          )}
        </footer>
      </aside>
    </>
  )
}

