// ── Filtro Select ─────────────────────────────────────────────────────────────

interface FilterSelectProps {
  value: string
  onChange: (v: string) => void
  placeholder: string
  options: { value: string; label: string }[]
}

function FilterSelect({ value, onChange, placeholder, options }: FilterSelectProps) {
  return (
    <select
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-700 shadow-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
    >
      <option value="">{placeholder}</option>
      {options.map((o) => (
        <option key={o.value} value={o.value}>{o.label}</option>
      ))}
    </select>
  )
}

// ── Página principal ──────────────────────────────────────────────────────────

export default function EstoquePage() {
  const { data: session } = useSession()
  const role = (session?.user as { role?: string })?.role ?? ''

  const canManage  = canAccessModule(role, 'stock.manage')
  const canEvaluate = canAccessModule(role, 'stock.evaluate')

  // ── Estado ──────────────────────────────────────────────────────────────────
  const [vehicles, setVehicles]       = useState<Vehicle[]>([])
  const [pagination, setPagination]   = useState<Pagination | null>(null)
  const [units, setUnits]             = useState<Unit[]>([])
  const [loading, setLoading]         = useState(true)
  // viewMode persistido em localStorage — sobrevive a refresh/navegação
  const [viewMode, setViewMode] = useState<'cards' | 'list'>(() => {
    if (typeof window === 'undefined') return 'cards'
    const saved = localStorage.getItem('estoque:view')
    return saved === 'list' || saved === 'cards' ? saved : 'cards'
  })
  useEffect(() => {
    if (typeof window === 'undefined') return
    localStorage.setItem('estoque:view', viewMode)
  }, [viewMode])
  const [showFilters, setShowFilters] = useState(false)

  // Filtros
  const [search,          setSearch]          = useState('')
  const [page,            setPage]            = useState(1)
  const [unitId,          setUnitId]          = useState('')
  const [stockStatus,     setStockStatus]     = useState('')
  const [stockLocation,   setStockLocation]   = useState('')
  const [vehicleType,     setVehicleType]     = useState('')
  const [stockType,       setStockType]       = useState('')
  const [conditionType,   setConditionType]   = useState('')
  const [cautelarStatus,  setCautelarStatus]  = useState('')
  const [includeInactive, setIncludeInactive] = useState(false)

  const searchRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const [debouncedSearch, setDebouncedSearch] = useState('')

  // Debounce da busca
  useEffect(() => {
    if (searchRef.current) clearTimeout(searchRef.current)
    searchRef.current = setTimeout(() => {
      setDebouncedSearch(search)
      setPage(1)
    }, 400)
    return () => { if (searchRef.current) clearTimeout(searchRef.current) }
  }, [search])

  // Carrega unidades
  useEffect(() => {
    fetch('/api/units?limit=200', { cache: 'no-store' })
      .then((r) => r.json())
      .then((d) => { if (d.success) setUnits(d.data ?? []) })
      .catch(() => {})
  }, [])

  // Carrega veículos
  const fetchVehicles = useCallback(async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams()
      params.set('page', String(page))
      params.set('limit', '24')
      if (debouncedSearch) params.set('search', debouncedSearch)
      if (unitId)          params.set('unitId', unitId)
      if (stockStatus)     params.set('stockStatus', stockStatus)
      if (stockLocation)   params.set('stockLocation', stockLocation)
      if (vehicleType)     params.set('vehicleType', vehicleType)
      if (stockType)       params.set('stockType', stockType)
      if (conditionType)   params.set('conditionType', conditionType)
      if (cautelarStatus)  params.set('cautelarStatus', cautelarStatus)
      if (includeInactive) params.set('includeInactive', 'true')

      const res  = await fetch(`/api/vehicles?${params}`, { cache: 'no-store' })
      const data = await res.json()
      if (data.success) {
        setVehicles(data.data ?? [])
        setPagination(data.pagination ?? null)
      }
    } catch (_) {
      //
    } finally {
      setLoading(false)
    }
  }, [page, debouncedSearch, unitId, stockStatus, stockLocation, vehicleType, stockType, conditionType, cautelarStatus, includeInactive])

  useEffect(() => { fetchVehicles() }, [fetchVehicles])

  // Resetar página ao mudar filtros (exceto page)
  const resetPage = () => setPage(1)

  const hasActiveFilters = !!(unitId || stockStatus || stockLocation || vehicleType || stockType || conditionType || cautelarStatus || includeInactive || debouncedSearch)

  function clearFilters() {
    setSearch('')
    setUnitId('')
    setStockStatus('')
    setStockLocation('')
    setVehicleType('')
    setStockType('')
    setConditionType('')
    setCautelarStatus('')
    setIncludeInactive(false)
    setPage(1)
  }

  // ── Render ───────────────────────────────────────────────────────────────────

  return (
    <div className="flex flex-col gap-6">

      {/* Cabeçalho */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Estoque</h1>
          {pagination && (
            <p className="text-sm text-gray-500 mt-0.5">
              {pagination.total} {pagination.total === 1 ? 'veículo encontrado' : 'veículos encontrados'}
            </p>
          )}
        </div>
        <div className="flex items-center gap-2">
          {canEvaluate && (
            <Link
              href="/estoque/avaliacao"
              className="flex items-center gap-2 rounded-lg border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 shadow-sm hover:bg-gray-50 transition-colors"
            >
              Fazer Avaliação
            </Link>
          )}
          {canManage && (
            <Link
              href="/estoque/novo"
              className="flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-medium text-white shadow-sm hover:bg-brand-700 transition-colors"
            >
              <Plus className="h-4 w-4" />
              Adicionar Veículo
            </Link>
          )}
        </div>
      </div>

      {/* Barra de busca + controles */}
      <div className="flex flex-wrap items-center gap-3">
        {/* Busca */}
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Buscar por placa, marca, modelo, chassi..."
            className="w-full rounded-lg border border-gray-300 bg-white py-2 pl-9 pr-4 text-sm shadow-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
          />
          {search && (
            <button
              onClick={() => setSearch('')}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          )}
        </div>

        {/* Botão filtros */}
        <button
          onClick={() => setShowFilters((p) => !p)}
          className={[
            'flex items-center gap-2 rounded-lg border px-4 py-2 text-sm font-medium shadow-sm transition-colors',
            showFilters
              ? 'border-brand-500 bg-brand-50 text-brand-700'
              : 'border-gray-300 bg-white text-gray-700 hover:bg-gray-50',
          ].join(' ')}
        >
          <Filter className="h-4 w-4" />
          Filtros
          {hasActiveFilters && (
            <span className="flex h-4 w-4 items-center justify-center rounded-full bg-brand-600 text-[10px] font-bold text-white">
              •
            </span>
          )}
        </button>

        {/* Toggle visualização */}
        <div className="flex rounded-lg border border-gray-300 bg-white shadow-sm overflow-hidden">
          <button
            onClick={() => setViewMode('cards')}
            className={[
              'p-2 transition-colors',
              viewMode === 'cards' ? 'bg-brand-50 text-brand-700' : 'text-gray-500 hover:bg-gray-50',
            ].join(' ')}
            title="Visualização em cards"
          >
            <LayoutGrid className="h-4 w-4" />
          </button>
          <button
            onClick={() => setViewMode('list')}
            className={[
              'p-2 border-l border-gray-300 transition-colors',
              viewMode === 'list' ? 'bg-brand-50 text-brand-700' : 'text-gray-500 hover:bg-gray-50',
            ].join(' ')}
            title="Visualização em lista"
          >
            <List className="h-4 w-4" />
          </button>
        </div>

        {/* Quick-filter: aguardando precificação (gerente+) */}
        {canManage && (
          <button
            onClick={() => {
              const wantOn = stockStatus !== 'EM_PRECIFICACAO'
              setStockStatus(wantOn ? 'EM_PRECIFICACAO' : '')
              setIncludeInactive(wantOn)
              setPage(1)
            }}
            className={[
              'flex items-center gap-2 rounded-lg border px-3 py-2 text-sm font-medium shadow-sm transition-colors',
              stockStatus === 'EM_PRECIFICACAO'
                ? 'border-amber-400 bg-amber-100 text-amber-900'
                : 'border-amber-200 bg-amber-50 text-amber-700 hover:bg-amber-100',
            ].join(' ')}
            title="Mostrar apenas veículos liberados pelo gerente aguardando preço de venda"
          >
            <Tag className="h-4 w-4" />
            Aguardando precificação
          </button>
        )}

        {/* Atualizar */}
        <button
          onClick={fetchVehicles}
          className="rounded-lg border border-gray-300 bg-white p-2 text-gray-500 shadow-sm hover:bg-gray-50 transition-colors"
          title="Atualizar"
        >
          <RotateCcw className="h-4 w-4" />
        </button>
      </div>

      {/* Painel de filtros */}
      {showFilters && (
        <div className="rounded-xl border border-gray-200 bg-white p-4 shadow-sm">
          <div className="flex flex-wrap gap-3">
            {/* Unidade */}
            <select
              value={unitId}
              onChange={(e) => { setUnitId(e.target.value); resetPage() }}
              className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-700 shadow-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
            >
              <option value="">Todas as unidades</option>
              {units.map((u) => (
                <option key={u.id} value={u.id}>{u.name}</option>
              ))}
            </select>

            <FilterSelect
              value={stockStatus}
              onChange={(v) => { setStockStatus(v); resetPage() }}
              placeholder="Todos os status"
              options={STOCK_STATUS_OPTIONS}
            />

            <FilterSelect
              value={stockLocation}
              onChange={(v) => { setStockLocation(v); resetPage() }}
              placeholder="Localização"
              options={STOCK_LOCATION_OPTIONS}
            />

            <FilterSelect
              value={vehicleType}
              onChange={(v) => { setVehicleType(v); resetPage() }}
              placeholder="Tipo de veículo"
              options={VEHICLE_TYPE_OPTIONS}
            />

            <FilterSelect
              value={stockType}
              onChange={(v) => { setStockType(v); resetPage() }}
              placeholder="Tipo de estoque"
              options={STOCK_TYPE_OPTIONS}
            />

            <FilterSelect
              value={conditionType}
              onChange={(v) => { setConditionType(v); resetPage() }}
              placeholder="Condição"
              options={CONDITION_OPTIONS}
            />

            <FilterSelect
              value={cautelarStatus}
              onChange={(v) => { setCautelarStatus(v); resetPage() }}
              placeholder="Cautelar"
              options={CAUTELAR_OPTIONS}
            />

            {/* Incluir inativos — apenas managers */}
            {canManage && (
              <label className="flex items-center gap-2 rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-700 cursor-pointer shadow-sm">
                <input
                  type="checkbox"
                  checked={includeInactive}
                  onChange={(e) => { setIncludeInactive(e.target.checked); resetPage() }}
                  className="rounded border-gray-300 text-brand-600 focus:ring-brand-500"
                />
                Incluir inativos
              </label>
            )}

            {/* Limpar filtros */}
            {hasActiveFilters && (
              <button
                onClick={clearFilters}
                className="flex items-center gap-1.5 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm font-medium text-red-600 hover:bg-red-100 transition-colors"
              >
                <X className="h-3.5 w-3.5" />
                Limpar filtros
              </button>
            )}
          </div>
        </div>
      )}

      {/* Conteúdo */}
      {loading ? (
        viewMode === 'cards' ? (
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {Array.from({ length: 8 }).map((_, i) => <CardSkeleton key={i} />)}
          </div>
        ) : (
          <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm animate-pulse">
            <div className="h-12 bg-gray-100 border-b border-gray-200" />
            {Array.from({ length: 6 }).map((_, i) => (
              <div key={i} className="flex gap-4 px-4 py-3 border-b border-gray-100">
                <div className="h-4 w-20 rounded bg-gray-200" />
                <div className="h-4 w-40 rounded bg-gray-200" />
                <div className="h-4 w-12 rounded bg-gray-200" />
              </div>
            ))}
          </div>
        )
      ) : vehicles.length === 0 ? (
        /* Estado vazio */
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-gray-300 bg-white py-20 text-center">
          <Car className="h-14 w-14 text-gray-300 mb-4" />
          <h3 className="text-lg font-semibold text-gray-600">
            {hasActiveFilters ? 'Nenhum veículo encontrado' : 'Estoque vazio'}
          </h3>
          <p className="mt-1 text-sm text-gray-400 max-w-sm">
            {hasActiveFilters
              ? 'Tente ajustar os filtros ou limpe a busca para ver mais resultados.'
              : 'Ainda não há veículos cadastrados no estoque.'}
          </p>
          {hasActiveFilters ? (
            <button
              onClick={clearFilters}
              className="mt-4 flex items-center gap-2 rounded-lg border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
            >
              <X className="h-4 w-4" />
              Limpar filtros
            </button>
          ) : canManage ? (
            <Link
              href="/estoque/novo"
              className="mt-4 flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-medium text-white hover:bg-brand-700 transition-colors"
            >
              <Plus className="h-4 w-4" />
              Adicionar primeiro veículo
            </Link>
          ) : null}
        </div>
      ) : viewMode === 'cards' ? (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {vehicles.map((v) => <VehicleCard key={v.id} vehicle={v} />)}
        </div>
      ) : (
        <VehicleListTable vehicles={vehicles} />
      )}

      {/* Paginação */}
      {pagination && pagination.totalPages > 1 && (
        <div className="flex items-center justify-between rounded-xl border border-gray-200 bg-white px-4 py-3 shadow-sm">
          <p className="text-sm text-gray-600">
            Página {pagination.page} de {pagination.totalPages} —{' '}
            {pagination.total} veículo{pagination.total !== 1 ? 's' : ''}
          </p>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={pagination.page <= 1}
              className="flex items-center gap-1 rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              <ChevronLeft className="h-4 w-4" />
              Anterior
            </button>

            {/* Páginas numeradas */}
            <div className="flex items-center gap-1">
              {Array.from({ length: Math.min(5, pagination.totalPages) }, (_, i) => {
                const p = Math.max(1, Math.min(
                  pagination.totalPages - 4,
                  pagination.page - 2,
                )) + i
                return (
                  <button
                    key={p}
                    onClick={() => setPage(p)}
                    className={[
                      'h-8 w-8 rounded-lg text-sm font-medium transition-colors',
                      p === pagination.page
                        ? 'bg-brand-600 text-white'
                        : 'border border-gray-300 text-gray-700 hover:bg-gray-50',
                    ].join(' ')}
                  >
                    {p}
                  </button>
                )
              })}
            </div>

            <button
              onClick={() => setPage((p) => Math.min(pagination.totalPages, p + 1))}
              disabled={pagination.page >= pagination.totalPages}
              className="flex items-center gap-1 rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              Próxima
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// /master/audit — Auditoria de ações na plataforma
// =============================================================================

import { useEffect, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import {
  ShieldCheck,
  Search,
  RefreshCw,
  Download,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface AuditEntry {
  id:        string
  action:    string
  entity:    string
  entityId:  string | null
  ipAddress: string | null
  userAgent: string | null
  status:    string | null
  userName:  string | null
  userRole:  string | null
  tenantId:  string | null
  createdAt: string
}

// ── Página ────────────────────────────────────────────────────────────────────

export default function MasterAuditPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [logs, setLogs]         = useState<AuditEntry[]>([])
  const [loading, setLoading]   = useState(true)
  const [search, setSearch]     = useState('')
  const [action, setAction]     = useState('')
  const [page, setPage]         = useState(1)
  const [total, setTotal]       = useState(0)
  const PAGE_SIZE = 50

  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  const load = useCallback(() => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    const params = new URLSearchParams({
      page: String(page),
      limit: String(PAGE_SIZE),
    })
    if (search) params.set('search', search)
    if (action) params.set('action', action)
    fetch(`/api/master/audit?${params}`)
      .then((r) => r.json())
      .then((d) => {
        setLogs(d.data ?? [])
        setTotal(d.total ?? 0)
      })
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [session, page, search, action])

  useEffect(() => { load() }, [load])

  const totalPages = Math.ceil(total / PAGE_SIZE)

  const exportCSV = () => {
    const params = new URLSearchParams({ export: 'csv' })
    if (search) params.set('search', search)
    if (action) params.set('action', action)
    window.open(`/api/master/audit?${params}`, '_blank')
  }

  return (
    <div className="space-y-6 max-w-6xl">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <ShieldCheck size={22} className="text-brand-700" />
          <div>
            <h1 className="text-xl font-bold text-gray-900">Auditoria da Plataforma</h1>
            <p className="text-sm text-gray-500">{total.toLocaleString('pt-BR')} registro(s) encontrado(s)</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={exportCSV} className="btn-secondary flex items-center gap-1.5 text-sm">
            <Download size={14} />
            Exportar CSV
          </button>
          <button onClick={load} className="btn-secondary flex items-center gap-1.5 text-sm">
            <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
            Atualizar
          </button>
        </div>
      </div>

      {/* Filtros */}
      <div className="card flex flex-wrap items-center gap-3">
        <div className="relative flex-1 min-w-52">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            className="input pl-9 text-sm"
            placeholder="Buscar por usuário, entidade..."
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1) }}
          />
        </div>
        <select
          className="input text-sm w-44"
          value={action}
          onChange={(e) => { setAction(e.target.value); setPage(1) }}
        >
          <option value="">Todas as ações</option>
          {['LOGIN', 'LOGOUT', 'CREATE', 'UPDATE', 'DELETE', 'EXPORT', 'APPROVE', 'REJECT'].map((a) => (
            <option key={a} value={a}>{a}</option>
          ))}
        </select>
      </div>

      {/* Tabela */}
      <div className="card overflow-hidden p-0">
        {loading ? (
          <div className="flex h-40 items-center justify-center">
            <div className="h-7 w-7 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" />
          </div>
        ) : logs.length === 0 ? (
          <div className="flex h-40 items-center justify-center text-gray-400 text-sm">
            Nenhum log encontrado
          </div>
        ) : (
          <table className="w-full text-sm">
            <thead className="border-b border-gray-100 bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Data/Hora</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Usuário</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Ação</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Entidade</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">IP</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {logs.map((log) => (
                <tr key={log.id} className="hover:bg-gray-50">
                  <td className="px-4 py-2.5 text-xs text-gray-500 whitespace-nowrap">
                    {new Date(log.createdAt).toLocaleString('pt-BR')}
                  </td>
                  <td className="px-4 py-2.5">
                    <p className="text-xs font-medium text-gray-800">{log.userName ?? '—'}</p>
                    {log.userRole && (
                      <p className="text-[11px] text-gray-400">{log.userRole}</p>
                    )}
                  </td>
                  <td className="px-4 py-2.5">
                    <span className={`rounded-full px-2 py-0.5 text-[11px] font-bold ${
                      log.action === 'LOGIN'  ? 'bg-green-50 text-green-700'  :
                      log.action === 'DELETE' ? 'bg-red-50 text-red-700'      :
                      log.action === 'CREATE' ? 'bg-blue-50 text-blue-700'    :
                      'bg-gray-100 text-gray-600'
                    }`}>
                      {log.action}
                    </span>
                  </td>
                  <td className="px-4 py-2.5 text-xs text-gray-600">
                    {log.entity}
                    {log.entityId && (
                      <span className="ml-1 text-gray-400 font-mono">{log.entityId.slice(0, 8)}</span>
                    )}
                  </td>
                  <td className="px-4 py-2.5 text-xs font-mono text-gray-400">
                    {log.ipAddress ?? '—'}
                  </td>
                  <td className="px-4 py-2.5">
                    <span className={`text-xs font-medium ${
                      log.status === 'SUCCESS' ? 'text-green-600' :
                      log.status === 'ERROR'   ? 'text-red-600'   :
                      'text-gray-400'
                    }`}>
                      {log.status ?? '—'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* Paginação */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between border-t border-gray-100 px-4 py-3">
            <p className="text-xs text-gray-500">
              Página {page} de {totalPages} · {total.toLocaleString('pt-BR')} registros
            </p>
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                className="btn-secondary p-1.5 disabled:opacity-40"
              >
                <ChevronLeft size={14} />
              </button>
              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page >= totalPages}
                className="btn-secondary p-1.5 disabled:opacity-40"
              >
                <ChevronRight size={14} />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

// =============================================================================
