// ── Constantes de UI ──────────────────────────────────────────────────────────

const inp = 'w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'
const lbl = 'text-xs font-medium text-gray-600 block mb-1'

