  { key: '{{deal.purchaseAmount|brl}}', label: 'Valor de compra (BRL)' },
  { key: '{{deal.saleAmount|brl}}',   label: 'Valor de venda (BRL)' },
  { key: '{{quitacao.banco}}',        label: 'Banco da quitação' },
  { key: '{{quitacao.valor|brl}}',    label: 'Valor da quitação (BRL)' },
]

const EMPTY: Template = {
  id: '', tenantId: null, type: 'CONTRATO_COMPRA', name: '', description: '',
  bodyHtml: '', active: true, isDefault: false, createdAt: '', updatedAt: '',
}

export default function MasterDocumentosPage() {
  const { data: session, status } = useSession()
  const router = useRouter()
  const role = (session?.user as { role?: string })?.role

  const [list, setList]       = useState<Template[]>([])
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState<Template | null>(null)
  const [saving, setSaving]   = useState(false)
  const [toast, setToast]     = useState<{ msg: string; ok: boolean } | null>(null)

  useEffect(() => {
    if (status === 'authenticated' && role !== 'MASTER') router.replace('/inicio')
  }, [status, role, router])

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 3000)
    return () => clearTimeout(t)
  }, [toast])

  function showToast(msg: string, ok = true) { setToast({ msg, ok }) }

  async function load() {
    setLoading(true)
    try {
      const res = await fetch('/api/admin/document-templates')
      const data = await res.json()
      setList(data.data ?? [])
    } catch {
      showToast('Erro ao carregar templates', false)
    } finally {
      setLoading(false)
    }
  }
  useEffect(() => { load() }, [])

  async function save() {
    if (!editing) return
    setSaving(true)
    try {
      const isNew = !editing.id
      const url = isNew ? '/api/admin/document-templates' : `/api/admin/document-templates/${editing.id}`
      const res = await fetch(url, {
        method:  isNew ? 'POST' : 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          type:        editing.type,
          name:        editing.name,
          description: editing.description,
          bodyHtml:    editing.bodyHtml,
          active:      editing.active,
          isDefault:   editing.isDefault,
        }),
      })
      const data = await res.json().catch(() => null)
      if (!res.ok) throw new Error(data?.error ?? 'Falha ao salvar')
      showToast(isNew ? 'Template criado' : 'Template atualizado', true)
      setEditing(null)
      load()
    } catch (e) {
      showToast(e instanceof Error ? e.message : 'Erro', false)
    } finally {
      setSaving(false)
    }
  }

  async function remove(tpl: Template) {
    if (!confirm(`Remover "${tpl.name}"?`)) return
    try {
      const res = await fetch(`/api/admin/document-templates/${tpl.id}`, { method: 'DELETE' })
      if (!res.ok) {
        const d = await res.json().catch(() => null)
        throw new Error(d?.error ?? 'Falha ao remover')
      }
      showToast('Template removido', true)
      load()
    } catch (e) {
      showToast(e instanceof Error ? e.message : 'Erro', false)
    }
  }

  function insertVar(v: string) {
    if (!editing) return
    setEditing({ ...editing, bodyHtml: (editing.bodyHtml ?? '') + ' ' + v })
  }

  return (
    <div className="mx-auto max-w-6xl space-y-4">
      {toast && (
        <div className={`fixed top-4 right-4 z-50 rounded-lg border px-4 py-3 text-sm font-medium shadow-lg ${
          toast.ok ? 'border-green-200 bg-green-50 text-green-800' : 'border-red-200 bg-red-50 text-red-800'
        }`}>
          {toast.msg}
        </div>
      )}

      <div className="flex flex-wrap items-center justify-between gap-3 rounded-2xl border border-gray-200 bg-white p-4 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-brand-100">
            <FileText size={20} className="text-brand-700" />
          </div>
          <div>
            <h1 className="font-bold text-gray-900">Documentos e Templates</h1>
            <p className="text-xs text-gray-500">Modelos de contratos, procurações e termos disponíveis no sistema</p>
          </div>
        </div>
        <button
          onClick={() => setEditing({ ...EMPTY })}
          className="flex items-center gap-1.5 rounded-lg bg-brand-600 px-4 py-2 text-sm font-medium text-white hover:bg-brand-700"
        >
          <Plus size={14} /> Novo template
        </button>
      </div>

      {/* Lista */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        {loading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 size={24} className="animate-spin text-brand-600" />
          </div>
        ) : list.length === 0 ? (
          <div className="flex flex-col items-center justify-center gap-3 py-16 text-gray-400">
            <FileText size={28} />
            <p className="text-sm">Nenhum template cadastrado</p>
          </div>
        ) : (
          <table className="w-full text-sm">
            <thead className="border-b border-gray-100 bg-gray-50">
              <tr>
                {['Nome', 'Tipo', 'Escopo', 'Status', 'Atualizado em', ''].map((h) => (
                  <th key={h} className="px-4 py-3 text-left text-xs font-medium uppercase tracking-wide text-gray-500">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {list.map((t) => (
                <tr key={t.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3 font-medium text-gray-800">
                    {t.name}
                    {t.description && <p className="text-xs text-gray-400 line-clamp-1">{t.description}</p>}
                  </td>
                  <td className="px-4 py-3 text-gray-600">{TYPES.find((x) => x.value === t.type)?.label ?? t.type}</td>
                  <td className="px-4 py-3 text-xs">
                    {t.tenantId === null
                      ? <span className="rounded-full bg-indigo-100 px-2 py-0.5 text-indigo-700">Global</span>
                      : <span className="rounded-full bg-gray-100 px-2 py-0.5 text-gray-700">Tenant</span>}
                  </td>
                  <td className="px-4 py-3 text-xs">
                    {t.active
                      ? <span className="rounded-full bg-green-100 px-2 py-0.5 text-green-700">Ativo</span>
                      : <span className="rounded-full bg-gray-100 px-2 py-0.5 text-gray-500">Inativo</span>}
                  </td>
                  <td className="px-4 py-3 text-xs text-gray-500">{new Date(t.updatedAt).toLocaleString('pt-BR')}</td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1.5">
                      <button onClick={() => setEditing(t)} className="rounded-md border border-gray-300 px-2 py-1 text-xs text-gray-700 hover:bg-gray-50">
                        Editar
                      </button>
                      <button
                        onClick={() => setEditing({ ...t, id: '', name: `${t.name} (cópia)`, isDefault: false })}
                        className="rounded-md border border-gray-300 p-1 text-xs text-gray-500 hover:bg-gray-50"
                        title="Duplicar"
                      >
                        <Copy size={12} />
                      </button>
                      <button
                        onClick={() => remove(t)}
                        className="rounded-md border border-red-200 p-1 text-xs text-red-700 hover:bg-red-50"
                        title="Remover"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Editor modal */}
      {editing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="flex h-[92vh] w-full max-w-6xl flex-col rounded-2xl bg-white shadow-2xl">
            <div className="flex items-center justify-between border-b border-gray-200 px-5 py-3">
              <h3 className="font-semibold text-gray-900">
                {editing.id ? 'Editar template' : 'Novo template'}
              </h3>
              <button onClick={() => setEditing(null)} className="rounded-md p-1.5 text-gray-400 hover:bg-gray-100">
                <X size={16} />
              </button>
            </div>

            <div className="flex flex-1 overflow-hidden">
              {/* Form principal */}
              <div className="flex-1 space-y-3 overflow-auto p-5">
                <div className="grid grid-cols-2 gap-3">
                  <label className="block text-sm">
                    <span className="mb-1 block font-medium text-gray-700">Nome *</span>
                    <input
                      className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
                      value={editing.name}
                      onChange={(e) => setEditing({ ...editing, name: e.target.value })}
                    />
                  </label>
                  <label className="block text-sm">
                    <span className="mb-1 block font-medium text-gray-700">Tipo *</span>
                    <select
                      className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
                      value={editing.type}
                      onChange={(e) => setEditing({ ...editing, type: e.target.value })}
                    >
                      {TYPES.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
                    </select>
                  </label>
                </div>

                <label className="block text-sm">
                  <span className="mb-1 block font-medium text-gray-700">Descrição</span>
                  <input
                    className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
                    value={editing.description ?? ''}
                    onChange={(e) => setEditing({ ...editing, description: e.target.value })}
                  />
                </label>

                <label className="block text-sm">
                  <span className="mb-1 flex items-center justify-between font-medium text-gray-700">
                    <span>Conteúdo (HTML) *</span>
                    <span className="text-xs font-normal text-gray-400">Aceita HTML. Use variáveis ao lado.</span>
                  </span>
                  <textarea
                    className="h-[40vh] w-full rounded-lg border border-gray-300 px-3 py-2 font-mono text-xs focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
                    value={editing.bodyHtml}
                    onChange={(e) => setEditing({ ...editing, bodyHtml: e.target.value })}
                    placeholder={'<h1>Contrato de Compra e Venda</h1>\n<p>Pelo presente instrumento, {{cliente.nome}} (CPF {{cliente.cpf}})...</p>'}
                  />
                </label>

                <div className="flex items-center gap-4">
                  <label className="flex items-center gap-2 text-sm">
                    <input type="checkbox" checked={editing.active} onChange={(e) => setEditing({ ...editing, active: e.target.checked })} />
                    Ativo
                  </label>
                  <label className="flex items-center gap-2 text-sm">
                    <input type="checkbox" checked={editing.isDefault} onChange={(e) => setEditing({ ...editing, isDefault: e.target.checked })} />
                    Padrão do sistema
                  </label>
                </div>

                <div className="flex items-start gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-700">
                  <AlertCircle size={13} className="mt-0.5 shrink-0" />
                  Templates criados aqui ficam <strong>globais</strong> (disponíveis para todos os tenants).
                </div>
              </div>

              {/* Painel de variáveis */}
              <aside className="w-72 shrink-0 overflow-auto border-l border-gray-200 bg-gray-50 p-4">
                <h4 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">Variáveis disponíveis</h4>
                <p className="mb-3 text-xs text-gray-500">Clique para inserir no documento.</p>
                <ul className="space-y-1">
                  {VARIABLES.map((v) => (
                    <li key={v.key}>
                      <button
                        onClick={() => insertVar(v.key)}
                        className="w-full rounded-md border border-gray-200 bg-white px-2 py-1.5 text-left text-xs hover:border-brand-300 hover:bg-brand-50"
                      >
                        <p className="font-mono text-brand-700">{v.key}</p>
                        <p className="text-gray-500">{v.label}</p>
                      </button>
                    </li>
                  ))}
                </ul>
              </aside>
            </div>

            <div className="flex items-center justify-end gap-2 border-t border-gray-200 px-5 py-3">
              <button onClick={() => setEditing(null)} className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50">
                Cancelar
              </button>
              <button
                onClick={save}
                disabled={saving || !editing.name || !editing.bodyHtml}
                className="flex items-center gap-1.5 rounded-md bg-brand-600 px-4 py-2 text-sm font-medium text-white hover:bg-brand-700 disabled:opacity-50"
              >
                {saving ? <Loader2 size={13} className="animate-spin" /> : <Save size={13} />}
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// /master/feature-flags — Gerenciamento de Feature Flags (MASTER only)
//
// • Lista todas as flags globais
// • Toggle enable/disable inline
// • Editar rolloutPct e notas inline
// • Criar nova flag via modal
// • Excluir flag
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession }                        from 'next-auth/react'
import { useRouter }                         from 'next/navigation'
import {
  Flag, Plus, Trash2, Loader2, AlertCircle, CheckCircle2,
  ChevronDown, ChevronRight, X, Save, ToggleLeft, ToggleRight,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface TenantFlagOverride {
  tenantId: string
  enabled:  boolean
}

interface FeatureFlag {
  id:          string
  key:         string
  name:        string
  description: string | null
  enabled:     boolean
  rolloutPct:  number
  notes:       string | null
  createdAt:   string
  tenantFlags: TenantFlagOverride[]
}

// ── Helpers ───────────────────────────────────────────────────────────────────

const inputCls = 'w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'
const labelCls = 'text-xs font-medium text-gray-600 block mb-1'

// ── Modal: criar nova flag ─────────────────────────────────────────────────────

interface CreateModalProps {
  onClose:  () => void
  onSaved:  () => void
}

function CreateModal({ onClose, onSaved }: CreateModalProps) {
  const [form, setForm] = useState({
    key: '', name: '', description: '', enabled: true,
    rolloutPct: 100, notes: '',
  })
  const [saving, setSaving] = useState(false)
  const [error,  setError]  = useState('')

  function set(k: keyof typeof form) {
    return (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) =>
      setForm(p => ({ ...p, [k]: e.target.value }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    if (!form.key.trim() || !form.name.trim()) {
      setError('Chave e nome são obrigatórios.')
      return
    }
    setSaving(true)
    try {
      const res  = await fetch('/api/master/feature-flags', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          key:         form.key.trim(),
          name:        form.name.trim(),
          description: form.description.trim() || null,
          enabled:     form.enabled,
          rolloutPct:  Math.min(100, Math.max(0, Number(form.rolloutPct) || 0)),
          notes:       form.notes.trim() || null,
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao criar flag.')
      onSaved()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao criar flag.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
      <div className="w-full max-w-lg rounded-2xl bg-white shadow-2xl">
        <div className="flex items-center justify-between border-b border-gray-100 px-6 py-4">
          <h2 className="font-semibold text-gray-900">Nova feature flag</h2>
          <button onClick={onClose} className="rounded-lg p-1.5 hover:bg-gray-100">
            <X size={16} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 px-6 py-5">
          {error && (
            <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
              <AlertCircle size={13} className="shrink-0" />
              {error}
            </div>
          )}

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className={labelCls}>Chave (key) *</label>
              <input
                className={`${inputCls} font-mono`}
                placeholder="nome_da_flag"
                value={form.key}
                onChange={set('key')}
              />
              <p className="mt-1 text-xs text-gray-400">Somente letras, números e _</p>
            </div>
            <div>
              <label className={labelCls}>Nome exibição *</label>
              <input className={inputCls} placeholder="Ex: Relatório Beta" value={form.name} onChange={set('name')} />
            </div>
          </div>

          <div>
            <label className={labelCls}>Descrição</label>
            <textarea
              className={inputCls} rows={2}
              value={form.description}
              onChange={set('description')}
              placeholder="Opcional — o que essa flag controla"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className={labelCls}>Rollout (%)</label>
              <input
                type="number" min={0} max={100}
                className={inputCls}
                value={form.rolloutPct}
                onChange={set('rolloutPct')}
              />
            </div>
            <div className="flex flex-col justify-end">
              <label className="flex cursor-pointer items-center gap-2 pb-1">
                <input
                  type="checkbox"
                  className="h-4 w-4 rounded border-gray-300 text-brand-600"
                  checked={form.enabled}
                  onChange={e => setForm(p => ({ ...p, enabled: e.target.checked }))}
                />
                <span className="text-sm text-gray-700">Habilitada por padrão</span>
              </label>
            </div>
          </div>

          <div>
            <label className={labelCls}>Notas internas</label>
            <textarea
              className={inputCls} rows={2}
              value={form.notes}
              onChange={set('notes')}
              placeholder="Contexto, links de ticket, etc."
            />
          </div>

          <div className="flex items-center justify-end gap-3 pt-2">
            <button type="button" onClick={onClose} className="rounded-lg border border-gray-200 px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-50">
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 rounded-lg bg-brand-600 px-5 py-2 text-sm font-semibold text-white hover:bg-brand-700 disabled:opacity-50"
            >
              {saving ? <Loader2 size={13} className="animate-spin" /> : <Save size={13} />}
              Criar flag
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── Row: uma flag ─────────────────────────────────────────────────────────────

interface FlagRowProps {
  flag:      FeatureFlag
  onReload:  () => void
}

function FlagRow({ flag, onReload }: FlagRowProps) {
  const [toggling,  setToggling]  = useState(false)
  const [deleting,  setDeleting]  = useState(false)
  const [expanded,  setExpanded]  = useState(false)
  const [editMode,  setEditMode]  = useState(false)
  const [rollout,   setRollout]   = useState(String(flag.rolloutPct))
  const [notes,     setNotes]     = useState(flag.notes ?? '')
  const [saving,    setSaving]    = useState(false)

  async function toggle() {
    setToggling(true)
    try {
      await fetch(`/api/master/feature-flags/${flag.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ enabled: !flag.enabled }),
      })
      onReload()
    } finally {
      setToggling(false)
    }
  }

  async function handleSave() {
    setSaving(true)
    try {
      await fetch(`/api/master/feature-flags/${flag.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          rolloutPct: Math.min(100, Math.max(0, Number(rollout) || 0)),
          notes:      notes.trim() || null,
        }),
      })
      setEditMode(false)
      onReload()
    } finally {
      setSaving(false)
    }
  }

  async function handleDelete() {
    if (!confirm(`Excluir a flag "${flag.key}"? Esta ação não pode ser desfeita.`)) return
    setDeleting(true)
    try {
      await fetch(`/api/master/feature-flags/${flag.id}`, { method: 'DELETE' })
      onReload()
    } finally {
      setDeleting(false)
    }
  }

  return (
    <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
      {/* Header row */}
      <div className="flex items-center gap-3 px-4 py-3">
        {/* Expand toggle */}
        <button
          onClick={() => setExpanded(e => !e)}
          className="text-gray-400 hover:text-gray-600"
        >
          {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
        </button>

        {/* Key */}
        <code className="min-w-[180px] flex-shrink-0 rounded bg-gray-100 px-2 py-0.5 text-xs font-mono text-gray-700">
          {flag.key}
        </code>

        {/* Name + description */}
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium text-gray-900 truncate">{flag.name}</p>
          {flag.description && (
            <p className="text-xs text-gray-400 truncate">{flag.description}</p>
          )}
        </div>

        {/* Rollout */}
        <span className="hidden md:block text-xs text-gray-500 flex-shrink-0 w-16 text-center">
          {flag.rolloutPct}%
        </span>

        {/* Overrides count */}
        {flag.tenantFlags.length > 0 && (
          <span className="hidden md:block rounded-full bg-blue-50 px-2.5 py-0.5 text-xs font-medium text-blue-700 flex-shrink-0">
            {flag.tenantFlags.length} override{flag.tenantFlags.length > 1 ? 's' : ''}
          </span>
        )}

        {/* Toggle */}
        <button
          onClick={toggle}
          disabled={toggling}
          className="flex-shrink-0 disabled:opacity-50"
          title={flag.enabled ? 'Desabilitar' : 'Habilitar'}
        >
          {toggling
            ? <Loader2 size={20} className="animate-spin text-gray-400" />
            : flag.enabled
              ? <ToggleRight size={24} className="text-brand-600" />
              : <ToggleLeft  size={24} className="text-gray-300" />
          }
        </button>

        {/* Delete */}
        <button
          onClick={handleDelete}
          disabled={deleting}
          className="flex-shrink-0 rounded-lg p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600 disabled:opacity-50"
          title="Excluir flag"
        >
          {deleting ? <Loader2 size={14} className="animate-spin" /> : <Trash2 size={14} />}
        </button>
      </div>

      {/* Expanded detail */}
      {expanded && (
        <div className="border-t border-gray-100 bg-gray-50 px-4 py-4 space-y-3">
          {editMode ? (
            <div className="space-y-3">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className={labelCls}>Rollout (%)</label>
                  <input
                    type="number" min={0} max={100}
                    className={inputCls}
                    value={rollout}
                    onChange={e => setRollout(e.target.value)}
                  />
                </div>
              </div>
              <div>
                <label className={labelCls}>Notas internas</label>
                <textarea
                  rows={2}
                  className={inputCls}
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                />
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={handleSave}
                  disabled={saving}
                  className="flex items-center gap-1.5 rounded-lg bg-brand-600 px-4 py-1.5 text-xs font-semibold text-white hover:bg-brand-700 disabled:opacity-50"
                >
                  {saving ? <Loader2 size={12} className="animate-spin" /> : <Save size={12} />}
                  Salvar
                </button>
                <button
                  onClick={() => setEditMode(false)}
                  className="rounded-lg border border-gray-200 px-4 py-1.5 text-xs font-medium text-gray-600 hover:bg-white"
                >
                  Cancelar
                </button>
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center gap-4 text-xs text-gray-500">
                <span>Rollout: <strong className="text-gray-800">{flag.rolloutPct}%</strong></span>
                <span>Criado em: <strong className="text-gray-800">{new Date(flag.createdAt).toLocaleDateString('pt-BR')}</strong></span>
                <span>Status: <strong className={flag.enabled ? 'text-emerald-700' : 'text-gray-500'}>{flag.enabled ? 'Habilitada' : 'Desabilitada'}</strong></span>
              </div>
              {flag.notes && (
                <p className="text-xs text-gray-500 italic">Notas: {flag.notes}</p>
              )}
              <button
                onClick={() => setEditMode(true)}
                className="text-xs text-brand-600 hover:underline"
              >
                Editar rollout / notas
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

