export default function IntegrationsPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [creds,     setCreds]     = useState<Credential[]>([])
  const [loading,   setLoading]   = useState(true)
  const [error,     setError]     = useState('')
  const [success,   setSuccess]   = useState('')
  const [showModal, setShowModal] = useState(false)
  const [editCred,  setEditCred]  = useState<Credential | null>(null)
  const [testing,   setTesting]   = useState<string | null>(null)
  // ── Saldo (API Placas / PLATE_LOOKUP) ─────────────────────────────────────
  const [balanceLoading, setBalanceLoading] = useState(false)
  const [balanceData, setBalanceData] = useState<{
    balance: number | null
    checkedAt: string | null
    error: string | null
  }>({ balance: null, checkedAt: null, error: null })
  const [filterSvc, setFilterSvc] = useState('')

  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') router.replace('/inicio')
  }, [session, status, router])

  const load = useCallback(async () => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    setError('')
    try {
      const res  = await fetch('/api/master/integrations')
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      setCreds(data.data ?? [])
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao carregar.')
    } finally {
      setLoading(false)
    }
  }, [session])

  useEffect(() => { load() }, [load])

  async function toggleActive(cred: Credential) {
    await fetch(`/api/master/integrations/${cred.id}`, {
      method:  'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ active: !cred.active }),
    })
    load()
  }

  async function handleDelete(cred: Credential) {
    if (!confirm(`Excluir "${cred.name}"?`)) return
    await fetch(`/api/master/integrations/${cred.id}`, { method: 'DELETE' })
    load()
  }

  async function fetchBalance() {
    setBalanceLoading(true)
    setBalanceData((prev) => ({ ...prev, error: null }))
    try {
      const res  = await fetch('/api/integrations/plate/balance', { cache: 'no-store' })
      const data = await res.json()
      if (!res.ok || data?.ok === false || data?.success === false) {
        setBalanceData({
          balance:   null,
          checkedAt: new Date().toISOString(),
          error:     data?.errorMessage || data?.error || `Falha ao consultar saldo (HTTP ${res.status})`,
        })
        return
      }
      const bal = Number(data?.balance ?? data?.saldo ?? data?.data?.balance ?? 0)
      setBalanceData({
        balance:   Number.isFinite(bal) ? bal : null,
        checkedAt: new Date().toISOString(),
        error:     null,
      })
    } catch (e) {
      setBalanceData({
        balance:   null,
        checkedAt: new Date().toISOString(),
        error:     e instanceof Error ? e.message : 'Erro de rede ao consultar saldo.',
      })
    } finally {
      setBalanceLoading(false)
    }
  }

  async function handleTest(cred: Credential) {
    setTesting(cred.id)
    try {
      const res  = await fetch(`/api/master/integrations/${cred.id}`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ action: 'TEST' }),
      })
      const data = await res.json()
      setSuccess(data.message ?? 'Teste concluído.')
      setTimeout(() => setSuccess(''), 4000)
      load()
    } finally {
      setTesting(null)
    }
  }

  function handleSaved() {
    setShowModal(false)
    setEditCred(null)
    setSuccess('Credencial salva com sucesso.')
    setTimeout(() => setSuccess(''), 3000)
    load()
  }

  const filtered = filterSvc ? creds.filter(c => c.service === filterSvc) : creds

  // Agrupar por serviço
  const groups = filtered.reduce<Record<string, Credential[]>>((acc, c) => {
    if (!acc[c.service]) acc[c.service] = []
    acc[c.service].push(c)
    return acc
  }, {})

  if (status === 'loading' || loading) {
    return <div className="flex h-64 items-center justify-center"><div className="h-8 w-8 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" /></div>
  }

  return (
    <div className="max-w-4xl space-y-6">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-orange-600">
            <Plug size={18} className="text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-gray-900">Integrações Globais</h1>
            <p className="text-xs text-gray-400">{creds.length} credenciais cadastradas</p>
          </div>
        </div>
        <button onClick={() => setShowModal(true)}
          className="flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-semibold text-white hover:bg-brand-700"
        >
          <Plus size={15} />Nova credencial
        </button>
      </div>

      {error   && <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700"><AlertCircle size={15} />{error}</div>}
      {success && <div className="flex items-center gap-2 rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700"><CheckCircle2 size={15} />{success}</div>}

      {/* Filtro */}
      <div className="flex items-center gap-3">
        <select className="rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none"
          value={filterSvc}
          onChange={e => setFilterSvc(e.target.value)}
        >
          <option value="">Todos os serviços</option>
          {Object.entries(SERVICE_LABELS).map(([v, l]) => <option key={v} value={v}>{l}</option>)}
        </select>
        <button onClick={load} className="rounded-lg border border-gray-200 px-3 py-2 text-sm text-gray-600 hover:bg-gray-50">
          <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
        </button>
      </div>

      {/* Lista agrupada */}
      {Object.keys(groups).length === 0 ? (
        <div className="flex h-40 flex-col items-center justify-center gap-2 rounded-xl border-2 border-dashed border-gray-200 text-gray-400">
          <Plug size={24} />
          <p className="text-sm">Nenhuma credencial cadastrada</p>
        </div>
      ) : (
        <div className="space-y-5">
          {Object.entries(groups).map(([svc, list]) => (
            <div key={svc}>
              <div className="mb-2 flex items-center justify-between gap-2">
                <span className={`inline-flex rounded-full border px-3 py-0.5 text-xs font-semibold ${SERVICE_COLOR[svc] ?? 'bg-gray-100 text-gray-600 border-gray-200'}`}>
                  {SERVICE_LABELS[svc] ?? svc}
                </span>
                {/* Widget de saldo (apenas para PLATE_LOOKUP / API Placas) */}
                {svc === 'PLATE_LOOKUP' && list.some((c) => c.active) && (
                  <div className="flex items-center gap-2 rounded-lg border border-gray-200 bg-white px-3 py-1.5 text-xs">
                    <Wallet size={13} className="text-brand-600" />
                    {balanceLoading ? (
                      <span className="flex items-center gap-1.5 text-gray-500">
                        <Loader2 size={11} className="animate-spin" />
                        Consultando saldo…
                      </span>
                    ) : balanceData.error ? (
                      <span className="text-red-600">{balanceData.error}</span>
                    ) : balanceData.balance != null ? (
                      <>
                        <span className="text-gray-500">Saldo:</span>
                        <strong className="text-gray-900">{balanceData.balance.toLocaleString('pt-BR')}</strong>
                        <span className="text-gray-400">consultas</span>
                        {balanceData.checkedAt && (
                          <span className="text-gray-400">·</span>
                        )}
                        {balanceData.checkedAt && (
                          <span className="text-gray-400">
                            atualizado {new Date(balanceData.checkedAt).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                          </span>
                        )}
                      </>
                    ) : (
                      <span className="text-gray-500">Saldo não consultado</span>
                    )}
                    <button
                      type="button"
                      onClick={fetchBalance}
                      disabled={balanceLoading}
                      className="ml-1 rounded-md border border-gray-200 px-2 py-0.5 text-[10px] font-medium text-gray-600 hover:bg-gray-50 disabled:opacity-50"
                      title="Consultar saldo"
                    >
                      {balanceData.balance != null || balanceData.error ? 'Atualizar' : 'Consultar'}
                    </button>
                  </div>
                )}
              </div>
              <div className="space-y-2">
                {list.map(cred => (
                  <div key={cred.id} className={`rounded-xl border bg-white p-4 ${!cred.active ? 'opacity-60' : ''}`}>
                    <div className="flex items-start gap-3">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="font-medium text-gray-900 text-sm">{cred.name}</p>
                          {cred.isDefault && (
                            <span className="flex items-center gap-0.5 rounded-full bg-amber-50 border border-amber-200 px-2 py-0.5 text-[10px] font-medium text-amber-700">
                              <Star size={9} />Padrão
                            </span>
                          )}
                          {!cred.active && (
                            <span className="rounded-full bg-gray-100 px-2 py-0.5 text-[10px] text-gray-500">Inativa</span>
                          )}
                        </div>
                        {cred.description && <p className="text-xs text-gray-400 mt-0.5">{cred.description}</p>}
                        {cred.apiUrl && <p className="text-[10px] text-gray-400 font-mono mt-0.5 truncate">{cred.apiUrl}</p>}
                        <div className="mt-1.5 flex items-center gap-3 text-[10px] text-gray-400">
                          {cred.lastTestedAt && (
                            <span className={`flex items-center gap-1 ${cred.lastTestOk ? 'text-emerald-600' : 'text-red-500'}`}>
                              {cred.lastTestOk ? <CheckCircle2 size={10} /> : <AlertCircle size={10} />}
                              Testado {new Date(cred.lastTestedAt).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                            </span>
                          )}
                        </div>
                      </div>

                      {/* Ações */}
                      <div className="flex items-center gap-1 flex-shrink-0">
                        <button onClick={() => handleTest(cred)} disabled={testing === cred.id} title="Testar conexão"
                          className="rounded p-1.5 text-gray-400 hover:bg-blue-50 hover:text-blue-600 disabled:opacity-50"
                        >
                          {testing === cred.id ? <Loader2 size={13} className="animate-spin" /> : <TestTube size={13} />}
                        </button>
                        <button onClick={() => setEditCred(cred)} title="Editar"
                          className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700"
                        >
                          <Save size={13} />
                        </button>
                        <button onClick={() => toggleActive(cred)} title={cred.active ? 'Desativar' : 'Ativar'}>
                          {cred.active
                            ? <ToggleRight size={20} className="text-brand-600" />
                            : <ToggleLeft  size={20} className="text-gray-300" />
                          }
                        </button>
                        <button onClick={() => handleDelete(cred)} title="Excluir"
                          className="rounded p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600"
                        >
                          <Trash2 size={13} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {(showModal || editCred) && (
        <CredentialModal
          existing={editCred}
          onClose={() => { setShowModal(false); setEditCred(null) }}
          onSaved={handleSaved}
        />
      )}
    </div>
  )
}

'use client'

// =============================================================================
// /master/maintenance — Modo de manutenção (MASTER only)
//
// • Exibe o estado atual (global e histórico)
// • Permite ativar / desativar manutenção global com mensagem, datas e papéis permitidos
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession }                        from 'next-auth/react'
import { useRouter }                         from 'next/navigation'
import {
  Construction, AlertTriangle, CheckCircle2, Loader2,
  AlertCircle, Power, PowerOff, Clock, Info,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface MaintenanceMode {
  id:           string
  active:       boolean
  message:      string | null
  startAt:      string | null
  endAt:        string | null
  scope:        string
  scopeId:      string | null
  allowedRoles: string[]
  activatedBy:  string
  createdAt:    string
}

interface MaintenanceData {
  global:  MaintenanceMode | null
  history: MaintenanceMode[]
}

// ── Helpers ───────────────────────────────────────────────────────────────────

const inputCls = 'w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'
const labelCls = 'text-xs font-medium text-gray-600 block mb-1'

const ROLE_OPTIONS = [
  { value: 'MASTER', label: 'Master' },
  { value: 'ADMIN',  label: 'Admin' },
  { value: 'GESTOR', label: 'Gestor' },
]

function formatDate(d: string | null) {
  if (!d) return '—'
  return new Date(d).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })
}

// ── Página ────────────────────────────────────────────────────────────────────

export default function MaintenancePage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [data,    setData]    = useState<MaintenanceData | null>(null)
  const [loading, setLoading] = useState(true)
  const [saving,  setSaving]  = useState(false)
  const [error,   setError]   = useState('')
  const [success, setSuccess] = useState('')

  // Form para nova entrada
  const [form, setForm] = useState({
    active:       false,
    message:      '',
    startAt:      '',
    endAt:        '',
    allowedRoles: ['MASTER'] as string[],
  })

  // Auth guard
  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  const load = useCallback(async () => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    setError('')
    try {
      const res  = await fetch('/api/master/maintenance')
      const json = await res.json()
      if (!res.ok) throw new Error(json.error)
      setData(json.data)
      // Inicializa o form com estado atual
      const g = json.data?.global as MaintenanceMode | null
      if (g) {
        setForm({
          active:       g.active,
          message:      g.message ?? '',
          startAt:      g.startAt  ? g.startAt.slice(0, 16)  : '',
          endAt:        g.endAt    ? g.endAt.slice(0, 16)    : '',
          allowedRoles: g.allowedRoles,
        })
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao carregar dados.')
    } finally {
      setLoading(false)
    }
  }, [session])

  useEffect(() => { load() }, [load])

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSuccess('')
    setSaving(true)
    try {
      const res  = await fetch('/api/master/maintenance', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          active:       form.active,
          message:      form.message.trim()  || null,
          startAt:      form.startAt         || null,
          endAt:        form.endAt           || null,
          scope:        'GLOBAL',
          allowedRoles: form.allowedRoles,
        }),
      })
      const json = await res.json()
      if (!res.ok) throw new Error(json.error ?? 'Erro ao salvar.')
      setSuccess(json.message ?? 'Configuração salva.')
      load()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao salvar.')
    } finally {
      setSaving(false)
    }
  }

  function toggleRole(role: string) {
    setForm(p => ({
      ...p,
      allowedRoles: p.allowedRoles.includes(role)
        ? p.allowedRoles.filter(r => r !== role)
        : [...p.allowedRoles, role],
    }))
  }

  if (status === 'loading' || loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" />
      </div>
    )
  }

  const isActive = data?.global?.active === true

  return (
    <div className="max-w-2xl space-y-6">

      {/* Header */}
      <div className="flex items-center gap-3">
        <div className={`flex h-10 w-10 items-center justify-center rounded-xl ${isActive ? 'bg-amber-500' : 'bg-gray-400'}`}>
          <Construction size={18} className="text-white" />
        </div>
        <div>
          <h1 className="text-xl font-bold text-gray-900">Modo de Manutenção</h1>
          <p className="text-xs text-gray-400">Controle o acesso à plataforma durante janelas de manutenção</p>
        </div>
      </div>

      {/* Status atual */}
      <div className={`rounded-xl border px-5 py-4 ${
        isActive
          ? 'border-amber-200 bg-amber-50'
          : 'border-emerald-200 bg-emerald-50'
      }`}>
        <div className="flex items-center gap-3">
          {isActive
            ? <AlertTriangle size={20} className="text-amber-600 shrink-0" />
            : <CheckCircle2  size={20} className="text-emerald-600 shrink-0" />
          }
          <div>
            <p className={`font-semibold text-sm ${isActive ? 'text-amber-800' : 'text-emerald-800'}`}>
              {isActive ? 'Manutenção ATIVA' : 'Sistema operacional'}
            </p>
            {isActive && data?.global?.message && (
              <p className="text-xs text-amber-700 mt-0.5">{data.global.message}</p>
            )}
            {isActive && (
              <p className="text-xs text-amber-600 mt-0.5">
                Papéis com acesso: {data?.global?.allowedRoles.join(', ')}
              </p>
            )}
          </div>
          {isActive && data?.global && (
            <div className="ml-auto text-right text-xs text-amber-600 space-y-0.5">
              {data.global.startAt && <p>Início: {formatDate(data.global.startAt)}</p>}
              {data.global.endAt   && <p>Fim: {formatDate(data.global.endAt)}</p>}
            </div>
          )}
        </div>
      </div>

      {/* Mensagens de feedback */}
      {error && (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          <AlertCircle size={15} className="shrink-0" />
          {error}
        </div>
      )}
      {success && (
        <div className="flex items-center gap-2 rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700">
          <CheckCircle2 size={15} className="shrink-0" />
          {success}
        </div>
      )}

      {/* Form de configuração */}
      <form onSubmit={handleSubmit} className="rounded-xl border border-gray-200 bg-white p-5 space-y-5">
        <h2 className="font-semibold text-gray-800 text-sm">Configurar nova entrada de manutenção</h2>

        {/* Ativar / desativar */}
        <div className="flex items-center gap-4 rounded-lg border border-gray-100 bg-gray-50 p-4">
          <div className="flex-1">
            <p className="text-sm font-medium text-gray-800">Estado da manutenção</p>
            <p className="text-xs text-gray-500">Ativar bloqueará o acesso para papéis não permitidos</p>
          </div>
          <div className="flex gap-2">
            <button
              type="button"
              onClick={() => setForm(p => ({ ...p, active: false }))}
              className={`flex items-center gap-1.5 rounded-lg border px-3 py-1.5 text-xs font-medium ${
                !form.active
                  ? 'border-emerald-300 bg-emerald-50 text-emerald-700'
                  : 'border-gray-200 bg-white text-gray-500 hover:bg-gray-50'
              }`}
            >
              <Power size={12} /> Desativar
            </button>
            <button
              type="button"
              onClick={() => setForm(p => ({ ...p, active: true }))}
              className={`flex items-center gap-1.5 rounded-lg border px-3 py-1.5 text-xs font-medium ${
                form.active
                  ? 'border-amber-300 bg-amber-50 text-amber-700'
                  : 'border-gray-200 bg-white text-gray-500 hover:bg-gray-50'
              }`}
            >
              <PowerOff size={12} /> Ativar
            </button>
          </div>
        </div>

        {/* Mensagem */}
        <div>
          <label className={labelCls}>Mensagem para os usuários</label>
          <textarea
            rows={3}
            className={inputCls}
            placeholder="Ex: Sistema em manutenção para atualização. Retornaremos às 08:00."
            value={form.message}
            onChange={e => setForm(p => ({ ...p, message: e.target.value }))}
          />
        </div>

        {/* Janela de tempo */}
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className={labelCls}>
              <span className="flex items-center gap-1"><Clock size={11} /> Início</span>
            </label>
            <input
              type="datetime-local"
              className={inputCls}
              value={form.startAt}
              onChange={e => setForm(p => ({ ...p, startAt: e.target.value }))}
            />
          </div>
          <div>
            <label className={labelCls}>
              <span className="flex items-center gap-1"><Clock size={11} /> Término previsto</span>
            </label>
            <input
              type="datetime-local"
              className={inputCls}
              value={form.endAt}
              onChange={e => setForm(p => ({ ...p, endAt: e.target.value }))}
            />
          </div>
        </div>

        {/* Papéis com acesso */}
        <div>
          <label className={labelCls}>Papéis com acesso durante manutenção</label>
          <div className="flex flex-wrap gap-2 mt-1">
            {ROLE_OPTIONS.map(({ value, label }) => (
              <button
                key={value}
                type="button"
                onClick={() => toggleRole(value)}
                className={`rounded-full border px-3 py-1 text-xs font-medium ${
                  form.allowedRoles.includes(value)
                    ? 'border-brand-300 bg-brand-50 text-brand-700'
                    : 'border-gray-200 bg-white text-gray-500 hover:bg-gray-50'
                }`}
              >
                {label}
              </button>
            ))}
          </div>
          <p className="mt-1 flex items-center gap-1 text-xs text-gray-400">
            <Info size={11} />
            MASTER sempre tem acesso, independentemente da seleção.
          </p>
        </div>

        <div className="border-t border-gray-100 pt-4">
          <button
            type="submit"
            disabled={saving}
            className={`flex items-center gap-2 rounded-lg px-5 py-2.5 text-sm font-semibold text-white disabled:opacity-50 ${
              form.active
                ? 'bg-amber-600 hover:bg-amber-700'
                : 'bg-emerald-600 hover:bg-emerald-700'
            }`}
          >
            {saving
              ? <Loader2 size={14} className="animate-spin" />
              : form.active ? <PowerOff size={14} /> : <Power size={14} />
            }
            {saving ? 'Salvando...' : form.active ? 'Ativar manutenção' : 'Desativar manutenção'}
          </button>
        </div>
      </form>

      {/* Histórico */}
      {data?.history && data.history.length > 0 && (
        <div>
          <h2 className="mb-3 text-sm font-semibold uppercase tracking-wider text-gray-400">
            Histórico (últimas 10 entradas)
          </h2>
          <div className="space-y-2">
            {data.history.map(m => (
              <div
                key={m.id}
                className="flex items-center gap-3 rounded-lg border border-gray-100 bg-white px-4 py-3 text-xs"
              >
                <span className={`inline-flex items-center gap-1 rounded-full border px-2 py-0.5 font-medium ${
                  m.active
                    ? 'border-amber-200 bg-amber-50 text-amber-700'
                    : 'border-emerald-200 bg-emerald-50 text-emerald-700'
                }`}>
                  {m.active ? 'Ativada' : 'Desativada'}
                </span>
                <span className="text-gray-500">{m.scope}</span>
                {m.message && <span className="flex-1 truncate text-gray-400 italic">"{m.message}"</span>}
                <span className="ml-auto text-gray-400 flex-shrink-0">
                  {new Date(m.createdAt).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// /master/modules — Controle de módulos por tenant
// =============================================================================

import { useEffect, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import {
  Package,
  Search,
  RefreshCw,
  CheckCircle2,
  XCircle,
  ChevronDown,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface TenantModuleEntry {
  tenantId: string
  module:   string
  active:   boolean
  enabledAt: string | null
  disabledAt: string | null
}

interface TenantWithModules {
  id:       string
  publicId: string
  name:     string
  plan:     string
  status:   string
  primaryColor: string | null
  modules:  TenantModuleEntry[]
}

const ALL_MODULES = [
  { key: 'dashboard',             label: 'Dashboard' },
  { key: 'pendencies',            label: 'Pendências' },
  { key: 'negotiations',          label: 'Negociações' },
  { key: 'commissions',           label: 'Comissões' },
  { key: 'communication',         label: 'Comunicação' },
  { key: 'documents',             label: 'Documentos' },
  { key: 'registrations',         label: 'Cadastros' },
  { key: 'settings',              label: 'Configurações' },
  { key: 'logs',                  label: 'Relatórios' },
]

// ── Página ────────────────────────────────────────────────────────────────────

export default function MasterModulesPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [tenants, setTenants] = useState<TenantWithModules[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch]   = useState('')
  const [saving, setSaving]   = useState<string | null>(null)
  const [expanded, setExpanded] = useState<string | null>(null)

  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  const load = useCallback(() => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    fetch('/api/master/modules')
      .then((r) => r.json())
      .then((d) => setTenants(d.data ?? []))
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [session])

  useEffect(() => { load() }, [load])

  const toggleModule = async (tenantId: string, module: string, currentActive: boolean) => {
    const key = `${tenantId}:${module}`
    setSaving(key)
    try {
      await fetch('/api/master/modules', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tenantId, module, active: !currentActive }),
      })
      setTenants((prev) =>
        prev.map((t) =>
          t.id !== tenantId ? t : {
            ...t,
            modules: t.modules.map((m) =>
              m.module !== module ? m : { ...m, active: !currentActive },
            ),
          },
        ),
      )
    } catch (e) {
      console.error(e)
    } finally {
      setSaving(null)
    }
  }

  const filtered = tenants.filter((t) =>
    !search || t.name.toLowerCase().includes(search.toLowerCase()) || t.publicId.includes(search),
  )

  return (
    <div className="space-y-6 max-w-6xl">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Package size={22} className="text-brand-700" />
          <div>
            <h1 className="text-xl font-bold text-gray-900">Módulos por Tenant</h1>
            <p className="text-sm text-gray-500">Ative ou desative módulos por cliente</p>
          </div>
        </div>
        <button onClick={load} className="btn-secondary flex items-center gap-1.5 text-sm">
          <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
          Atualizar
        </button>
      </div>

      {/* Filtro */}
      <div className="card">
        <div className="relative max-w-sm">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            className="input pl-9 text-sm"
            placeholder="Buscar tenant..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      {/* Lista de tenants com módulos */}
      {loading ? (
        <div className="flex h-40 items-center justify-center">
          <div className="h-7 w-7 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" />
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((tenant) => {
            const isOpen = expanded === tenant.id
            const activeCount = tenant.modules.filter((m) => m.active).length

            // Map modules for quick lookup
            const moduleMap: Record<string, TenantModuleEntry> = {}
            tenant.modules.forEach((m) => { moduleMap[m.module] = m })

            return (
              <div key={tenant.id} className="card overflow-hidden p-0">
                {/* Header tenant */}
                <button
                  className="w-full flex items-center gap-3 px-4 py-3 hover:bg-gray-50 text-left"
                  onClick={() => setExpanded(isOpen ? null : tenant.id)}
                >
                  <div
                    className="flex h-8 w-8 items-center justify-center rounded-lg text-white text-xs font-bold shrink-0"
                    style={{ backgroundColor: tenant.primaryColor ?? '#166534' }}
                  >
                    {tenant.name.slice(0, 2).toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-gray-900">{tenant.name}</p>
                    <p className="text-xs text-gray-400">{tenant.publicId} · {activeCount}/{ALL_MODULES.length} módulos ativos</p>
                  </div>
                  <ChevronDown
                    size={15}
                    className={`text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`}
                  />
                </button>

                {/* Módulos grid */}
                {isOpen && (
                  <div className="border-t border-gray-100 px-4 py-4">
                    <div className="grid grid-cols-2 gap-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5">
                      {ALL_MODULES.map((mod) => {
                        const entry = moduleMap[mod.key]
                        const active = entry?.active ?? false
                        const key = `${tenant.id}:${mod.key}`
                        const isSaving = saving === key

                        return (
                          <button
                            key={mod.key}
                            onClick={() => toggleModule(tenant.id, mod.key, active)}
                            disabled={isSaving}
                            className={`
                              flex items-center gap-2 rounded-lg border px-3 py-2.5 text-left text-sm
                              transition-all duration-150
                              ${active
                                ? 'border-green-200 bg-green-50 text-green-700 hover:bg-green-100'
                                : 'border-gray-200 bg-gray-50 text-gray-500 hover:bg-gray-100'
                              }
                              ${isSaving ? 'opacity-60 cursor-not-allowed' : 'cursor-pointer'}
                            `}
                          >
                            {active
                              ? <CheckCircle2 size={13} className="shrink-0 text-green-600" />
                              : <XCircle     size={13} className="shrink-0 text-gray-400" />
                            }
                            <span className="text-xs font-medium truncate">{mod.label}</span>
                          </button>
                        )
                      })}
                    </div>
                  </div>
                )}
              </div>
            )
          })}

          {filtered.length === 0 && (
            <div className="card flex h-32 items-center justify-center text-gray-400 text-sm">
              Nenhum tenant encontrado
            </div>
          )}
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Regras de Notificação — AutoDrive (MASTER)
// Gerenciar regras globais que controlam quando e como pendências e alertas
// são gerados e distribuídos.
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import {
  Bell, Plus, Loader2, Pencil, Trash2, ToggleLeft, ToggleRight,
  CheckCircle2, AlertCircle, X, RefreshCw, ShieldAlert,
} from 'lucide-react'
import { cn } from '@/lib/utils'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface Rule {
  id:             string
  scope:          string
  name:           string
  description?:   string | null
  module:         string
  conditionType:  string
  priority:       string
  severity:       string
  slaMinutes?:    number | null
  channels:       string[]
  targetRoles:    string[]
  escalationRoles: string[]
  escalationAfterMinutes?: number | null
  maxPerDay:      number
  isActive:       boolean
  creator?:       { name: string; role: string } | null
  createdAt:      string
}

interface RuleForm {
  name:              string
  description:       string
  module:            string
  conditionType:     string
  priority:          string
  severity:          string
  slaMinutes:        string
  channels:          string[]
  targetRoles:       string[]
  escalationRoles:   string[]
  escalationAfterMinutes: string
  maxPerDay:         string
  isActive:          boolean
}

const EMPTY_FORM: RuleForm = {
  name: '', description: '', module: 'DEALS', conditionType: '',
  priority: 'MEDIA', severity: 'MEDIUM', slaMinutes: '',
  channels: ['APP_WEB'], targetRoles: ['GERENTE'], escalationRoles: [],
  escalationAfterMinutes: '', maxPerDay: '10', isActive: true,
}

const MODULE_LABELS: Record<string, string> = {
  DEALS: 'Negociações', COMMISSIONS: 'Comissões', STOCK: 'Estoque',
  CRM: 'CRM', WHATSAPP: 'WhatsApp', PENDENCIES: 'Pendências',
}

const PRIORITY_LABELS: Record<string, string> = {
  BAIXA: 'Baixa', MEDIA: 'Média', ALTA: 'Alta', URGENTE: 'Urgente',
}

const SEVERITY_LABELS: Record<string, string> = {
  LOW: 'Baixo', MEDIUM: 'Médio', HIGH: 'Alto', CRITICAL: 'Crítico',
}

const ALL_CHANNELS = ['APP_WEB', 'APP_MOBILE', 'WHATSAPP', 'EMAIL', 'PUSH']
const ALL_ROLES    = ['MASTER', 'ADM', 'GERENTE_GERAL', 'GERENTE', 'VENDEDOR_LIDER', 'VENDEDOR']

// ── Componente ────────────────────────────────────────────────────────────────

export default function NotificationRulesPage() {
  const [rules,     setRules]     = useState<Rule[]>([])
  const [loading,   setLoading]   = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editing,   setEditing]   = useState<Rule | null>(null)
  const [form,      setForm]      = useState<RuleForm>(EMPTY_FORM)
  const [saving,    setSaving]    = useState(false)
  const [feedback,  setFeedback]  = useState<{ ok: boolean; msg: string } | null>(null)
  const [deleting,  setDeleting]  = useState<string | null>(null)

  // ── Fetch ────────────────────────────────────────────────────────────────────

  const fetchRules = useCallback(async () => {
    setLoading(true)
    try {
      const res  = await fetch('/api/notification-rules', { credentials: 'include' })
      const data = await res.json()
      if (data.success) setRules(data.data ?? [])
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [])

  useEffect(() => { fetchRules() }, [fetchRules])

  // ── Modal ────────────────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditing(null)
    setForm(EMPTY_FORM)
    setFeedback(null)
    setShowModal(true)
  }

  const openEdit = (rule: Rule) => {
    setEditing(rule)
    setForm({
      name:           rule.name,
      description:    rule.description ?? '',
      module:         rule.module,
      conditionType:  rule.conditionType,
      priority:       rule.priority,
      severity:       rule.severity,
      slaMinutes:     rule.slaMinutes != null ? String(rule.slaMinutes) : '',
      channels:       rule.channels,
      targetRoles:    rule.targetRoles,
      escalationRoles: rule.escalationRoles,
      escalationAfterMinutes: rule.escalationAfterMinutes != null ? String(rule.escalationAfterMinutes) : '',
      maxPerDay:      String(rule.maxPerDay),
      isActive:       rule.isActive,
    })
    setFeedback(null)
    setShowModal(true)
  }

  const closeModal = () => { setShowModal(false); setEditing(null) }

  const toggleChannel = (ch: string) =>
    setForm((f) => ({
      ...f,
      channels: f.channels.includes(ch) ? f.channels.filter((c) => c !== ch) : [...f.channels, ch],
    }))

  const toggleRole = (role: string, field: 'targetRoles' | 'escalationRoles') =>
    setForm((f) => ({
      ...f,
      [field]: f[field].includes(role) ? f[field].filter((r) => r !== role) : [...f[field], role],
    }))

  // ── Save ──────────────────────────────────────────────────────────────────────

  const handleSave = async () => {
    if (!form.name.trim() || !form.conditionType.trim()) {
      setFeedback({ ok: false, msg: 'Nome e tipo de condição são obrigatórios.' })
      return
    }

    setSaving(true)
    setFeedback(null)

    const body = {
      name:              form.name,
      description:       form.description || undefined,
      module:            form.module,
      conditionType:     form.conditionType,
      priority:          form.priority,
      severity:          form.severity,
      slaMinutes:        form.slaMinutes ? Number(form.slaMinutes) : null,
      channels:          form.channels,
      targetRoles:       form.targetRoles,
      escalationRoles:   form.escalationRoles,
      escalationAfterMinutes: form.escalationAfterMinutes ? Number(form.escalationAfterMinutes) : null,
      maxPerDay:         Number(form.maxPerDay) || 10,
      isActive:          form.isActive,
    }

    try {
      const url    = editing ? `/api/notification-rules/${editing.id}` : '/api/notification-rules'
      const method = editing ? 'PATCH' : 'POST'
      const res    = await fetch(url, {
        method, credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
      const data = await res.json()
      if (data.success) {
        setFeedback({ ok: true, msg: editing ? 'Regra atualizada.' : 'Regra criada com sucesso.' })
        await fetchRules()
        setTimeout(closeModal, 1200)
      } else {
        setFeedback({ ok: false, msg: data.error ?? 'Erro ao salvar.' })
      }
    } catch {
      setFeedback({ ok: false, msg: 'Erro de conexão.' })
    } finally {
      setSaving(false)
    }
  }

  // ── Toggle ativo ──────────────────────────────────────────────────────────────

  const handleToggle = async (rule: Rule) => {
    try {
      await fetch(`/api/notification-rules/${rule.id}`, {
        method:  'PATCH',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ isActive: !rule.isActive }),
      })
      setRules((prev) => prev.map((r) => r.id === rule.id ? { ...r, isActive: !r.isActive } : r))
    } catch { /* silent */ }
  }

  // ── Delete ────────────────────────────────────────────────────────────────────

  const handleDelete = async (id: string) => {
    if (!confirm('Remover esta regra? Esta ação não pode ser desfeita.')) return
    setDeleting(id)
    try {
      const res = await fetch(`/api/notification-rules/${id}`, {
        method: 'DELETE', credentials: 'include',
      })
      if (res.ok) setRules((prev) => prev.filter((r) => r.id !== id))
    } catch { /* silent */ }
    finally { setDeleting(null) }
  }

  // ── Render ────────────────────────────────────────────────────────────────────

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="flex items-center gap-2 text-xl font-bold text-gray-900">
            <ShieldAlert size={20} className="text-brand-600" />
            Regras de Notificação
          </h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Regras globais que determinam quando e como pendências são criadas e alertas disparados.
          </p>
        </div>
        <div className="flex gap-2">
          <button onClick={fetchRules} disabled={loading} className="btn-secondary text-xs">
            <RefreshCw size={13} className={cn(loading && 'animate-spin')} />
          </button>
          <button onClick={openCreate} className="btn-primary text-sm">
            <Plus size={14} /> Nova regra
          </button>
        </div>
      </div>

      {/* Tabela */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-card">
        {loading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 size={20} className="animate-spin text-gray-400" />
          </div>
        ) : rules.length === 0 ? (
          <div className="py-14 text-center">
            <Bell size={32} className="mx-auto mb-2 text-gray-300" strokeWidth={1} />
            <p className="text-sm text-gray-400">Nenhuma regra configurada</p>
            <button onClick={openCreate} className="mt-3 btn-primary text-sm">
              <Plus size={14} /> Criar primeira regra
            </button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 text-sm">
              <thead className="bg-gray-50">
                <tr>
                  {['Regra', 'Módulo', 'Prioridade', 'SLA', 'Canais', 'Escopo', 'Status', 'Ações'].map((h) => (
                    <th key={h} className="whitespace-nowrap px-4 py-3 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {rules.map((rule) => (
                  <tr key={rule.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3">
                      <p className="font-medium text-gray-800">{rule.name}</p>
                      {rule.description && (
                        <p className="text-xs text-gray-400 truncate max-w-[200px]">{rule.description}</p>
                      )}
                      <p className="text-xs text-gray-400 mt-0.5">Cond.: {rule.conditionType}</p>
                    </td>
                    <td className="px-4 py-3">
                      <span className="rounded bg-purple-100 px-2 py-0.5 text-xs font-medium text-purple-700">
                        {MODULE_LABELS[rule.module] ?? rule.module}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex flex-col gap-0.5">
                        <span className="text-xs font-medium text-gray-700">{PRIORITY_LABELS[rule.priority] ?? rule.priority}</span>
                        <span className="text-xs text-gray-500">{SEVERITY_LABELS[rule.severity] ?? rule.severity}</span>
                      </div>
                    </td>
                    <td className="px-4 py-3 text-xs text-gray-600">
                      {rule.slaMinutes ? `${rule.slaMinutes}min` : '—'}
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex flex-wrap gap-1">
                        {rule.channels.map((ch) => (
                          <span key={ch} className="rounded bg-gray-100 px-1.5 py-0.5 text-xs text-gray-600">{ch}</span>
                        ))}
                      </div>
                    </td>
                    <td className="px-4 py-3">
                      <span className={cn(
                        'rounded px-2 py-0.5 text-xs font-medium',
                        rule.scope === 'GLOBAL' ? 'bg-brand-100 text-brand-700' : 'bg-gray-100 text-gray-600',
                      )}>
                        {rule.scope === 'GLOBAL' ? 'Global' : 'Tenant'}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <button onClick={() => handleToggle(rule)} className="transition">
                        {rule.isActive
                          ? <ToggleRight size={22} className="text-emerald-500" />
                          : <ToggleLeft  size={22} className="text-gray-300" />}
                      </button>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex gap-1">
                        <button onClick={() => openEdit(rule)} className="rounded p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-700 transition-colors">
                          <Pencil size={13} />
                        </button>
                        <button
                          onClick={() => handleDelete(rule.id)}
                          disabled={deleting === rule.id}
                          className="rounded p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600 transition-colors disabled:opacity-50"
                        >
                          {deleting === rule.id ? <Loader2 size={13} className="animate-spin" /> : <Trash2 size={13} />}
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Modal criar/editar */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4 backdrop-blur-sm">
          <div className="w-full max-w-2xl rounded-2xl bg-white shadow-2xl">
            {/* Modal header */}
            <div className="flex items-center justify-between border-b px-6 py-4">
              <h2 className="font-semibold text-gray-800">
                {editing ? 'Editar regra' : 'Nova regra de notificação'}
              </h2>
              <button onClick={closeModal} className="rounded p-1.5 hover:bg-gray-100 transition">
                <X size={16} />
              </button>
            </div>

            {/* Modal body */}
            <div className="max-h-[70vh] overflow-y-auto px-6 py-5 space-y-4">
              {/* Nome */}
              <div>
                <label className="label">Nome da regra *</label>
                <input
                  value={form.name}
                  onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
                  placeholder="ex: Negociação parada há +24h"
                  className="input"
                />
              </div>

              {/* Descrição */}
              <div>
                <label className="label">Descrição</label>
                <textarea
                  value={form.description}
                  onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))}
                  rows={2}
                  className="input resize-none"
                  placeholder="Explique quando esta regra dispara..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                {/* Módulo */}
                <div>
                  <label className="label">Módulo *</label>
                  <select
                    value={form.module}
                    onChange={(e) => setForm((f) => ({ ...f, module: e.target.value }))}
                    className="input"
                  >
                    {Object.entries(MODULE_LABELS).map(([k, v]) => (
                      <option key={k} value={k}>{v}</option>
                    ))}
                  </select>
                </div>

                {/* Tipo de condição */}
                <div>
                  <label className="label">Tipo de condição *</label>
                  <input
                    value={form.conditionType}
                    onChange={(e) => setForm((f) => ({ ...f, conditionType: e.target.value }))}
                    placeholder="ex: DEAL_STUCK_24H"
                    className="input"
                  />
                </div>

                {/* Prioridade */}
                <div>
                  <label className="label">Prioridade</label>
                  <select
                    value={form.priority}
                    onChange={(e) => setForm((f) => ({ ...f, priority: e.target.value }))}
                    className="input"
                  >
                    {Object.entries(PRIORITY_LABELS).map(([k, v]) => (
                      <option key={k} value={k}>{v}</option>
                    ))}
                  </select>
                </div>

                {/* Severidade */}
                <div>
                  <label className="label">Severidade</label>
                  <select
                    value={form.severity}
                    onChange={(e) => setForm((f) => ({ ...f, severity: e.target.value }))}
                    className="input"
                  >
                    {Object.entries(SEVERITY_LABELS).map(([k, v]) => (
                      <option key={k} value={k}>{v}</option>
                    ))}
                  </select>
                </div>

                {/* SLA */}
                <div>
                  <label className="label">SLA (minutos)</label>
                  <input
                    type="number" min={0}
                    value={form.slaMinutes}
                    onChange={(e) => setForm((f) => ({ ...f, slaMinutes: e.target.value }))}
                    placeholder="ex: 240 (= 4h)"
                    className="input"
                  />
                </div>

                {/* Max por dia */}
                <div>
                  <label className="label">Máx. por dia / usuário</label>
                  <input
                    type="number" min={1} max={100}
                    value={form.maxPerDay}
                    onChange={(e) => setForm((f) => ({ ...f, maxPerDay: e.target.value }))}
                    className="input"
                  />
                </div>

                {/* Escalonamento após */}
                <div>
                  <label className="label">Escalonar após (min)</label>
                  <input
                    type="number" min={0}
                    value={form.escalationAfterMinutes}
                    onChange={(e) => setForm((f) => ({ ...f, escalationAfterMinutes: e.target.value }))}
                    placeholder="ex: 60"
                    className="input"
                  />
                </div>
              </div>

              {/* Canais */}
              <div>
                <label className="label">Canais de entrega</label>
                <div className="flex flex-wrap gap-2">
                  {ALL_CHANNELS.map((ch) => (
                    <button
                      key={ch}
                      type="button"
                      onClick={() => toggleChannel(ch)}
                      className={cn(
                        'rounded-lg border px-3 py-1.5 text-xs font-medium transition',
                        form.channels.includes(ch)
                          ? 'border-brand-600 bg-brand-50 text-brand-700'
                          : 'border-gray-200 text-gray-600 hover:border-gray-300',
                      )}
                    >
                      {ch}
                    </button>
                  ))}
                </div>
              </div>

              {/* Roles alvo */}
              <div>
                <label className="label">Notificar roles</label>
                <div className="flex flex-wrap gap-2">
                  {ALL_ROLES.map((r) => (
                    <button
                      key={r}
                      type="button"
                      onClick={() => toggleRole(r, 'targetRoles')}
                      className={cn(
                        'rounded-lg border px-3 py-1.5 text-xs font-medium transition',
                        form.targetRoles.includes(r)
                          ? 'border-blue-600 bg-blue-50 text-blue-700'
                          : 'border-gray-200 text-gray-600 hover:border-gray-300',
                      )}
                    >
                      {r}
                    </button>
                  ))}
                </div>
              </div>

              {/* Roles de escalonamento */}
              <div>
                <label className="label">Roles para escalonamento</label>
                <div className="flex flex-wrap gap-2">
                  {ALL_ROLES.map((r) => (
                    <button
                      key={r}
                      type="button"
                      onClick={() => toggleRole(r, 'escalationRoles')}
                      className={cn(
                        'rounded-lg border px-3 py-1.5 text-xs font-medium transition',
                        form.escalationRoles.includes(r)
                          ? 'border-amber-600 bg-amber-50 text-amber-700'
                          : 'border-gray-200 text-gray-600 hover:border-gray-300',
                      )}
                    >
                      {r}
                    </button>
                  ))}
                </div>
              </div>

              {/* Ativo */}
              <div className="flex items-center gap-3">
                <label className="label mb-0">Regra ativa</label>
                <button
                  type="button"
                  onClick={() => setForm((f) => ({ ...f, isActive: !f.isActive }))}
                >
                  {form.isActive
                    ? <ToggleRight size={24} className="text-emerald-500" />
                    : <ToggleLeft  size={24} className="text-gray-300" />}
                </button>
              </div>

              {/* Feedback */}
              {feedback && (
                <div className={cn(
                  'flex items-center gap-2 rounded-lg border px-4 py-3 text-sm',
                  feedback.ok
                    ? 'border-emerald-200 bg-emerald-50 text-emerald-700'
                    : 'border-red-200 bg-red-50 text-red-700',
                )}>
                  {feedback.ok ? <CheckCircle2 size={15} /> : <AlertCircle size={15} />}
                  {feedback.msg}
                </div>
              )}
            </div>

            {/* Modal footer */}
            <div className="flex justify-end gap-2 border-t px-6 py-4">
              <button onClick={closeModal} className="btn-secondary">Cancelar</button>
              <button onClick={handleSave} disabled={saving} className="btn-primary">
                {saving ? <><Loader2 size={14} className="animate-spin" /> Salvando…</> : 'Salvar regra'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// /master/plans — Gestão completa de planos da plataforma (MASTER)
//
// Funcionalidades:
//   • Lista planos vindos do banco com contagem de tenants
//   • Criar / editar / excluir plano
//   • Configurar: preços, limites, recursos e módulos do menu
//   • Ativar / desativar plano sem excluir
// =============================================================================

import { useState, useEffect, useCallback, Fragment } from 'react'
import { useSession }                                  from 'next-auth/react'
import { useRouter }                                   from 'next/navigation'
import {
  Plus, Pencil, Trash2, CheckCircle2, XCircle,
  Loader2, Globe, Users, Car, Building2, HardDrive,
  MessageSquare, Mail, Clock, ChevronRight, ToggleLeft,
  ToggleRight, AlertTriangle, X, Save, DollarSign,
  LayoutGrid, ShieldCheck, Zap,
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { maskBRL, parseBRL } from '@/lib/masks'

// ── Módulos disponíveis no sistema ────────────────────────────────────────────
// Chaves mapeadas 1-para-1 com o campo `module` do Sidebar
const ALL_MODULES = [
  { key: 'dashboard',      label: 'Dashboard',      desc: 'Visão geral e KPIs',                group: 'Core'         },
  { key: 'stock',          label: 'Estoque',         desc: 'Gestão de veículos e avaliações',   group: 'Operacional'  },
  { key: 'negotiations',   label: 'Negociações',     desc: 'Pipeline de vendas e aprovações',   group: 'Operacional'  },
  { key: 'pendencies',     label: 'Pendências',      desc: 'Controle de tarefas e alertas',     group: 'Operacional'  },
  { key: 'commissions',    label: 'Comissões',       desc: 'Extrato, cálculo e regras',         group: 'Financeiro'   },
  { key: 'communication',  label: 'Comunicação',     desc: 'Disparos WhatsApp e templates',     group: 'Canais'       },
  { key: 'documents',      label: 'Documentos',      desc: 'PDF, contratos e importação',       group: 'Gestão'       },
  { key: 'registrations',  label: 'Cadastros',       desc: 'Vendedores, clientes, unidades',    group: 'Gestão'       },
  { key: 'logs',           label: 'Relatórios',      desc: 'Logs de sistema e auditoria',       group: 'Gestão'       },
  { key: 'settings',       label: 'Configurações',   desc: 'Identidade, e-mail e integrações',  group: 'Avançado'     },
  { key: 'profile',        label: 'Perfil',          desc: 'Dados e preferências do usuário',   group: 'Core'         },
]

const MODULE_GROUPS = ['Core', 'Operacional', 'Financeiro', 'Canais', 'Gestão', 'Avançado']

// ── Tipo da API ───────────────────────────────────────────────────────────────

interface Plan {
  id:                  string
  code:                string
  name:                string
  description:         string | null
  priceMonthly:        number | null
  priceYearly:         number | null
  active:              boolean
  maxUsers:            number
  maxVehicles:         number
  maxUnits:            number
  maxStorageMb:        number
  whatsappMonthly:     number
  emailMonthly:        number
  trialDays:           number
  allowWhiteLabel:     boolean
  allowCustomDomain:   boolean
  allowGoogleSheets:   boolean
  allowAdvancedReports:boolean
  allowApiAccess:      boolean
  modules:             string[]
  sortOrder:           number
  notes:               string | null
  tenantCount:         number
}

// ── Form vazio ────────────────────────────────────────────────────────────────

const EMPTY_FORM = {
  code:                '',
  name:                '',
  description:         '',
  priceMonthly:        '',
  priceYearly:         '',
  active:              true,
  maxUsers:            '10',
  maxVehicles:         '100',
  maxUnits:            '1',
  maxStorageMb:        '1024',
  whatsappMonthly:     '1000',
  emailMonthly:        '5000',
  trialDays:           '14',
  allowWhiteLabel:     false,
  allowCustomDomain:   false,
  allowGoogleSheets:   true,
  allowAdvancedReports:false,
  allowApiAccess:      false,
  modules:             ['dashboard', 'pendencies', 'registrations', 'profile'] as string[],
  sortOrder:           '0',
  notes:               '',
}

type FormState = typeof EMPTY_FORM

// ── Helpers ───────────────────────────────────────────────────────────────────

function fmtPrice(v: number | null) {
  if (v == null) return '—'
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v)
}

function planToForm(p: Plan): FormState {
  return {
    code:                p.code,
    name:                p.name,
    description:         p.description    ?? '',
    priceMonthly:        p.priceMonthly   != null ? maskBRL(String(Math.round(p.priceMonthly * 100))) : '',
    priceYearly:         p.priceYearly    != null ? maskBRL(String(Math.round(p.priceYearly  * 100))) : '',
    active:              p.active,
    maxUsers:            String(p.maxUsers),
    maxVehicles:         String(p.maxVehicles),
    maxUnits:            String(p.maxUnits),
    maxStorageMb:        String(p.maxStorageMb),
    whatsappMonthly:     String(p.whatsappMonthly),
    emailMonthly:        String(p.emailMonthly),
    trialDays:           String(p.trialDays),
    allowWhiteLabel:     p.allowWhiteLabel,
    allowCustomDomain:   p.allowCustomDomain,
    allowGoogleSheets:   p.allowGoogleSheets,
    allowAdvancedReports:p.allowAdvancedReports,
    allowApiAccess:      p.allowApiAccess,
    modules:             p.modules,
    sortOrder:           String(p.sortOrder),
    notes:               p.notes ?? '',
  }
}

function formToPayload(f: FormState) {
  return {
    code:                f.code.trim().toUpperCase(),
    name:                f.name.trim(),
    description:         f.description.trim()  || null,
    priceMonthly:        f.priceMonthly  !== '' ? parseBRL(f.priceMonthly)  : null,
    priceYearly:         f.priceYearly   !== '' ? parseBRL(f.priceYearly)   : null,
    active:              f.active,
    maxUsers:            parseInt(f.maxUsers)        || 10,
    maxVehicles:         parseInt(f.maxVehicles)     || 100,
    maxUnits:            parseInt(f.maxUnits)        || 1,
    maxStorageMb:        parseInt(f.maxStorageMb)    || 1024,
    whatsappMonthly:     parseInt(f.whatsappMonthly) || 0,
    emailMonthly:        parseInt(f.emailMonthly)    || 0,
    trialDays:           parseInt(f.trialDays)       || 0,
    allowWhiteLabel:     f.allowWhiteLabel,
    allowCustomDomain:   f.allowCustomDomain,
    allowGoogleSheets:   f.allowGoogleSheets,
    allowAdvancedReports:f.allowAdvancedReports,
    allowApiAccess:      f.allowApiAccess,
    modules:             f.modules,
    sortOrder:           parseInt(f.sortOrder) || 0,
    notes:               f.notes.trim() || null,
  }
}

// ── Subcomponentes ────────────────────────────────────────────────────────────

function Toggle({
  checked, onChange, label, desc,
}: { checked: boolean; onChange: (v: boolean) => void; label: string; desc?: string }) {
  return (
    <label className="flex items-center justify-between gap-3 cursor-pointer select-none py-1">
      <div>
        <p className="text-sm font-medium text-gray-800">{label}</p>
        {desc && <p className="text-xs text-gray-400">{desc}</p>}
      </div>
      <button
        type="button"
        onClick={() => onChange(!checked)}
        className={cn(
          'relative shrink-0 inline-flex h-5 w-9 items-center rounded-full transition-colors focus:outline-none',
          checked ? 'bg-brand-600' : 'bg-gray-300',
        )}
      >
        <span className={cn(
          'inline-block h-3.5 w-3.5 rounded-full bg-white shadow transition-transform',
          checked ? 'translate-x-4' : 'translate-x-0.5',
        )} />
      </button>
    </label>
  )
}

function InputNum({
  label, value, onChange, min = 0, suffix,
}: { label: string; value: string; onChange: (v: string) => void; min?: number; suffix?: string }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 mb-1">{label}</label>
      <div className="relative">
        <input
          type="number"
          min={min}
          value={value}
          onChange={e => onChange(e.target.value)}
          className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500 pr-12"
        />
        {suffix && (
          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-400 pointer-events-none">
            {suffix}
          </span>
        )}
      </div>
    </div>
  )
}

// ── Página principal ───────────────────────────────────────────────────────────

export default function MasterPlansPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [plans,   setPlans]   = useState<Plan[]>([])
  const [loading, setLoading] = useState(true)
  const [error,   setError]   = useState('')

  // Drawer de criação/edição
  const [drawerOpen,  setDrawerOpen]  = useState(false)
  const [editingPlan, setEditingPlan] = useState<Plan | null>(null)
  const [form,        setForm]        = useState<FormState>(EMPTY_FORM)
  const [saving,      setSaving]      = useState(false)
  const [formError,   setFormError]   = useState('')

  // Confirmação de exclusão
  const [deletingId,  setDeletingId]  = useState<string | null>(null)
  const [deleting,    setDeleting]    = useState(false)

  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  const loadPlans = useCallback(async () => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    setError('')
    try {
      const res  = await fetch('/api/master/plans')
      const data = await res.json()
      if (data.success) setPlans(data.data ?? [])
      else setError(data.error ?? 'Erro ao carregar planos.')
    } catch {
      setError('Erro de conexão.')
    } finally {
      setLoading(false)
    }
  }, [session])

  useEffect(() => { loadPlans() }, [loadPlans])

  // ── Abrir drawer ───────────────────────────────────────────────────────────

  function openNew() {
    setEditingPlan(null)
    setForm({ ...EMPTY_FORM })
    setFormError('')
    setDrawerOpen(true)
  }

  function openEdit(plan: Plan) {
    setEditingPlan(plan)
    setForm(planToForm(plan))
    setFormError('')
    setDrawerOpen(true)
  }

  function closeDrawer() {
    setDrawerOpen(false)
    setEditingPlan(null)
    setFormError('')
  }

  // ── Set form field ─────────────────────────────────────────────────────────

  function set<K extends keyof FormState>(k: K, v: FormState[K]) {
    setForm(p => ({ ...p, [k]: v }))
  }

  function toggleModule(key: string) {
    setForm(p => ({
      ...p,
      modules: p.modules.includes(key)
        ? p.modules.filter(m => m !== key)
        : [...p.modules, key],
    }))
  }

  // ── Salvar (criar ou editar) ───────────────────────────────────────────────

  async function handleSave(e: React.FormEvent) {
    e.preventDefault()
    setFormError('')

    if (!form.code.trim())  { setFormError('Código é obrigatório.'); return }
    if (!form.name.trim())  { setFormError('Nome é obrigatório.');   return }
    if (form.modules.length === 0) { setFormError('Selecione ao menos um módulo do menu.'); return }

    setSaving(true)
    try {
      const payload = formToPayload(form)
      const isEdit  = Boolean(editingPlan)

      const res = await fetch(
        isEdit ? `/api/master/plans/${editingPlan!.id}` : '/api/master/plans',
        {
          method:  isEdit ? 'PATCH' : 'POST',
          headers: { 'Content-Type': 'application/json' },
          body:    JSON.stringify(payload),
        },
      )
      const data = await res.json()
      if (!data.success) throw new Error(data.error ?? 'Erro ao salvar.')
      closeDrawer()
      loadPlans()
    } catch (err: unknown) {
      setFormError(err instanceof Error ? err.message : 'Erro ao salvar.')
    } finally {
      setSaving(false)
    }
  }

  // ── Toggle ativo ──────────────────────────────────────────────────────────

  async function toggleActive(plan: Plan) {
    try {
      const res  = await fetch(`/api/master/plans/${plan.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ active: !plan.active }),
      })
      const data = await res.json()
      if (data.success) loadPlans()
    } catch { /* silent */ }
  }

  // ── Excluir ───────────────────────────────────────────────────────────────

  async function handleDelete(id: string) {
    setDeleting(true)
    try {
      const res  = await fetch(`/api/master/plans/${id}`, { method: 'DELETE' })
      const data = await res.json()
      if (!data.success) throw new Error(data.error ?? 'Erro ao excluir.')
      setDeletingId(null)
      loadPlans()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Erro ao excluir.')
    } finally {
      setDeleting(false)
    }
  }

  // ── Cores por ordem de plano ───────────────────────────────────────────────

  const PLAN_COLORS = [
    { ring: 'ring-gray-300',   bg: 'bg-gray-50',   badge: 'bg-gray-100 text-gray-700'  },
    { ring: 'ring-blue-300',   bg: 'bg-blue-50',   badge: 'bg-blue-100 text-blue-700'  },
    { ring: 'ring-purple-300', bg: 'bg-purple-50', badge: 'bg-purple-100 text-purple-700'},
    { ring: 'ring-brand-300',  bg: 'bg-brand-50',  badge: 'bg-brand-100 text-brand-700' },
  ]

  function planColor(idx: number) {
    return PLAN_COLORS[idx % PLAN_COLORS.length]
  }

  // ── Render ─────────────────────────────────────────────────────────────────

  const inputCls = 'w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'

  return (
    <div className="space-y-6 max-w-6xl">

      {/* Header ─────────────────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <Globe size={22} className="text-brand-700" />
          <div>
            <h1 className="text-xl font-bold text-gray-900">Planos da Plataforma</h1>
            <p className="text-sm text-gray-500">
              Configure preços, limites, recursos e módulos do menu por plano
            </p>
          </div>
        </div>
        <button
          onClick={openNew}
          className="flex items-center gap-2 rounded-lg bg-brand-700 px-4 py-2.5 text-sm font-semibold text-white hover:bg-brand-600 transition-colors"
        >
          <Plus size={15} />
          Novo plano
        </button>
      </div>

      {/* Error ──────────────────────────────────────────────────────────────── */}
      {error && (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          <AlertTriangle size={15} className="shrink-0" />
          {error}
        </div>
      )}

      {/* Loading ─────────────────────────────────────────────────────────────── */}
      {loading ? (
        <div className="flex h-52 items-center justify-center">
          <Loader2 size={28} className="animate-spin text-brand-600" />
        </div>
      ) : plans.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-2xl border-2 border-dashed border-gray-200 py-20 text-center">
          <Globe size={36} className="text-gray-300 mb-3" />
          <p className="text-base font-semibold text-gray-500">Nenhum plano cadastrado</p>
          <p className="text-sm text-gray-400 mt-1">Crie o primeiro plano da plataforma</p>
          <button
            onClick={openNew}
            className="mt-4 flex items-center gap-2 rounded-lg bg-brand-700 px-4 py-2 text-sm font-semibold text-white hover:bg-brand-600"
          >
            <Plus size={14} /> Criar plano
          </button>
        </div>
      ) : (
        /* Cards de planos ───────────────────────────────────────────────────── */
        <div className="grid gap-5 lg:grid-cols-2">
          {plans.map((plan, idx) => {
            const color = planColor(idx)
            return (
              <div
                key={plan.id}
                className={cn(
                  'relative rounded-2xl border-2 bg-white shadow-sm overflow-hidden transition-all',
                  plan.active ? color.ring : 'ring-1 ring-gray-200 opacity-60',
                )}
              >
                {/* Status pill */}
                {!plan.active && (
                  <div className="absolute top-3 right-3 rounded-full bg-gray-200 px-2.5 py-0.5 text-[11px] font-semibold text-gray-600">
                    Inativo
                  </div>
                )}

                {/* Header do card */}
                <div className={cn('px-5 pt-5 pb-4', color.bg)}>
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-0.5">
                        <span className={cn('rounded-full px-2.5 py-0.5 text-[11px] font-bold tracking-wide', color.badge)}>
                          {plan.code}
                        </span>
                        <span className="text-[11px] text-gray-400 font-medium">
                          {plan.tenantCount} tenant{plan.tenantCount !== 1 ? 's' : ''}
                        </span>
                      </div>
                      <h2 className="text-lg font-bold text-gray-900 truncate">{plan.name}</h2>
                      {plan.description && (
                        <p className="text-sm text-gray-500 mt-0.5 line-clamp-1">{plan.description}</p>
                      )}
                    </div>
                    <div className="shrink-0 text-right">
                      {plan.priceMonthly != null ? (
                        <div>
                          <p className="text-xl font-bold text-gray-900">{fmtPrice(plan.priceMonthly)}</p>
                          <p className="text-xs text-gray-400">por mês</p>
                        </div>
                      ) : (
                        <p className="text-sm font-semibold text-gray-400">Sob consulta</p>
                      )}
                    </div>
                  </div>
                </div>

                {/* Corpo do card */}
                <div className="px-5 py-4 space-y-4">

                  {/* Limites */}
                  <div>
                    <p className="text-[11px] font-semibold uppercase tracking-wide text-gray-400 mb-2">Limites</p>
                    <div className="grid grid-cols-3 gap-2">
                      {[
                        { icon: Users,     label: 'Usuários',  val: plan.maxUsers    },
                        { icon: Car,       label: 'Veículos',  val: plan.maxVehicles },
                        { icon: Building2, label: 'Unidades',  val: plan.maxUnits    },
                        { icon: HardDrive, label: 'Storage',   val: `${plan.maxStorageMb >= 1024 ? `${plan.maxStorageMb / 1024}GB` : `${plan.maxStorageMb}MB`}` },
                        { icon: MessageSquare, label: 'WhatsApp/mês', val: plan.whatsappMonthly.toLocaleString('pt-BR') },
                        { icon: Mail,      label: 'E-mails/mês', val: plan.emailMonthly.toLocaleString('pt-BR') },
                      ].map(({ icon: Icon, label, val }) => (
                        <div key={label} className="rounded-lg bg-gray-50 border border-gray-100 px-2.5 py-2 text-center">
                          <Icon size={13} className="mx-auto mb-1 text-gray-400" />
                          <p className="text-[11px] text-gray-500 leading-none mb-0.5">{label}</p>
                          <p className="text-xs font-bold text-gray-800">{val}</p>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Recursos */}
                  <div>
                    <p className="text-[11px] font-semibold uppercase tracking-wide text-gray-400 mb-2">Recursos</p>
                    <div className="flex flex-wrap gap-1.5">
                      {[
                        { key: 'allowGoogleSheets',    label: 'Google Sheets',    ok: plan.allowGoogleSheets    },
                        { key: 'allowWhiteLabel',       label: 'White Label',      ok: plan.allowWhiteLabel      },
                        { key: 'allowCustomDomain',     label: 'Domínio próprio',  ok: plan.allowCustomDomain    },
                        { key: 'allowAdvancedReports',  label: 'Relatórios +',     ok: plan.allowAdvancedReports },
                        { key: 'allowApiAccess',        label: 'API Access',       ok: plan.allowApiAccess       },
                        { key: 'trial', label: `Trial ${plan.trialDays}d`, ok: plan.trialDays > 0 },
                      ].map(({ key, label, ok }) => (
                        <span
                          key={key}
                          className={cn(
                            'flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-medium',
                            ok
                              ? 'bg-emerald-50 text-emerald-700 border border-emerald-200'
                              : 'bg-gray-100 text-gray-400 border border-gray-200',
                          )}
                        >
                          {ok
                            ? <CheckCircle2 size={10} className="shrink-0" />
                            : <XCircle      size={10} className="shrink-0" />
                          }
                          {label}
                        </span>
                      ))}
                    </div>
                  </div>

                  {/* Módulos do menu */}
                  <div>
                    <p className="text-[11px] font-semibold uppercase tracking-wide text-gray-400 mb-2">Módulos no menu</p>
                    <div className="flex flex-wrap gap-1">
                      {plan.modules.length === 0 ? (
                        <span className="text-xs text-gray-400 italic">Nenhum módulo</span>
                      ) : plan.modules.map(m => {
                        const mod = ALL_MODULES.find(x => x.key === m)
                        return (
                          <span key={m} className="flex items-center gap-1 rounded-full bg-brand-50 border border-brand-200 px-2 py-0.5 text-[11px] font-medium text-brand-700">
                            <ChevronRight size={9} />
                            {mod?.label ?? m}
                          </span>
                        )
                      })}
                    </div>
                  </div>
                </div>

                {/* Footer — ações */}
                <div className="flex items-center gap-1 border-t border-gray-100 px-4 py-2.5 bg-gray-50">
                  <button
                    onClick={() => openEdit(plan)}
                    className="flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-white hover:text-brand-700 transition-colors"
                  >
                    <Pencil size={12} /> Editar
                  </button>
                  <button
                    onClick={() => toggleActive(plan)}
                    className="flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-white transition-colors"
                  >
                    {plan.active
                      ? <><ToggleRight size={13} className="text-emerald-500" /> Desativar</>
                      : <><ToggleLeft  size={13} className="text-gray-400"    /> Ativar</>
                    }
                  </button>
                  <div className="ml-auto">
                    {deletingId === plan.id ? (
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-red-600 font-medium">Confirmar exclusão?</span>
                        <button
                          onClick={() => handleDelete(plan.id)}
                          disabled={deleting}
                          className="rounded-lg bg-red-600 px-2.5 py-1 text-xs font-semibold text-white hover:bg-red-700 disabled:opacity-60"
                        >
                          {deleting ? <Loader2 size={11} className="animate-spin" /> : 'Sim'}
                        </button>
                        <button
                          onClick={() => setDeletingId(null)}
                          className="rounded-lg border border-gray-300 px-2.5 py-1 text-xs font-medium text-gray-600 hover:bg-white"
                        >
                          Não
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setDeletingId(plan.id)}
                        disabled={plan.tenantCount > 0}
                        title={plan.tenantCount > 0 ? 'Há tenants usando este plano' : 'Excluir plano'}
                        className="flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium text-red-500 hover:bg-red-50 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                      >
                        <Trash2 size={12} /> Excluir
                      </button>
                    )}
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* ── Drawer de criação/edição ────────────────────────────────────────── */}
      {drawerOpen && (
        <>
          {/* Overlay */}
          <div
            className="fixed inset-0 z-40 bg-black/30 backdrop-blur-sm"
            onClick={closeDrawer}
          />

          {/* Painel */}
          <div className="fixed inset-y-0 right-0 z-50 flex w-full max-w-2xl flex-col bg-white shadow-2xl animate-slide-in-right overflow-hidden">

            {/* Cabeçalho do drawer */}
