                  <div>
                    <label className={lbl}>Nome interno (exibição no sistema)</label>
                    <input className={inp} value={tab.internalName}
                      onChange={e => updateTab(tab._key, { internalName: e.target.value })}
                      placeholder="Vendas de Janeiro" />
