      <button
        type="button"
        onClick={addManual}
        className="flex items-center gap-2 rounded-lg border-2 border-dashed border-gray-300 px-4 py-2.5 text-sm text-gray-500 hover:border-brand-400 hover:text-brand-600 w-full justify-center"
      >
