                        }))}
                        className={cn('rounded border px-2 py-0.5 text-xs',
                          selected ? 'border-brand-400 bg-brand-50 text-brand-700' : 'border-gray-200 text-gray-500'
                        )}
                      >
                        {t.sheetName}
                      </button>
