  SUSPENSO:  { label: 'Suspenso',  cls: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  BLOQUEADO: { label: 'Bloqueado', cls: 'bg-orange-100 text-orange-700 border-orange-200' },
