  CANCELADO: { label: 'Cancelado', cls: 'bg-gray-100 text-gray-500 border-gray-200' },
  TESTE:     { label: 'Teste',     cls: 'bg-blue-100 text-blue-700 border-blue-200' },
}

const ROLE_LABELS: Record<string, string> = {
