// =============================================================================
// /master/tenants — Listagem e gestão de tenants (MASTER only)
// =============================================================================

import { useEffect, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import {
  Building2,
  Plus,
  Search,
  RefreshCw,
  ChevronRight,
  CheckCircle2,
  XCircle,
  AlertTriangle,
  Clock,
  Ban,
  AlertCircle,
  Users,
  Layers,
  ShieldBan,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface TenantCount {
  users: number
  units: number
  deals: number
}

interface Tenant {
  id:               string
  publicId:         string
  slug:             string
  name:             string
  razaoSocial:      string | null
  nomeFantasia:     string | null
  cnpj:             string | null
  plan:             string
  status:           string
  statusReason:     string | null
  primaryColor:     string | null
  responsavel:      string | null
  responsavelEmail: string | null
  trialEndsAt:      string | null
  createdAt:        string
  _count:           TenantCount
}

// ── Constantes de UI ──────────────────────────────────────────────────────────

const PLAN_LABEL: Record<string, string> = {
  BASICO: 'Básico', PRO: 'Pro', VIP: 'VIP', CUSTOM: 'Custom',
}
const PLAN_COLOR: Record<string, string> = {
  BASICO: 'bg-gray-100  text-gray-700',
  PRO:    'bg-blue-100  text-blue-700',
  VIP:    'bg-purple-100 text-purple-700',
  CUSTOM: 'bg-brand-100 text-brand-700',
}
const STATUS_ICON: Record<string, React.ElementType> = {
  ATIVO:     CheckCircle2,
  SUSPENSO:  AlertTriangle,
  BLOQUEADO: Ban,
  BANIDO:    ShieldBan,
  CANCELADO: XCircle,
  TESTE:     Clock,
}
const STATUS_COLOR: Record<string, string> = {
  ATIVO:     'text-green-600',
  SUSPENSO:  'text-amber-600',
  BLOQUEADO: 'text-orange-600',
  BANIDO:    'text-red-700',
  CANCELADO: 'text-gray-400',
  TESTE:     'text-blue-600',
}
const STATUS_LABEL: Record<string, string> = {
  ATIVO: 'Ativo', SUSPENSO: 'Suspenso', BLOQUEADO: 'Bloqueado',
  BANIDO: 'Banido', CANCELADO: 'Cancelado', TESTE: 'Teste',
}

// ── Página ────────────────────────────────────────────────────────────────────

export default function MasterTenantsPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [tenants, setTenants]         = useState<Tenant[]>([])
  const [loading, setLoading]         = useState(true)
  const [fetchError, setFetchError]   = useState<string | null>(null)
  const [search, setSearch]           = useState('')
  const [planFilter, setPlanFilter]   = useState('')
  const [statusFilter, setStatusFilter] = useState('')

  // Redireciona usuários que não são MASTER
  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  // ── Função de carregamento ─────────────────────────────────────────────────

  const load = useCallback(async () => {
    if (session?.user?.role !== 'MASTER') return

    setLoading(true)
    setFetchError(null)

    const params = new URLSearchParams()
    if (search)       params.set('search', search)
    if (planFilter)   params.set('plan',   planFilter)
    if (statusFilter) params.set('status', statusFilter)

    try {
      const res = await fetch(`/api/master/tenants?${params}`, {
        // Garante que a listagem sempre busca dados frescos — sem cache HTTP
        cache: 'no-store',
      })

      // Tenta parsear o JSON independente do status HTTP
      const json = await res.json().catch(() => null)

      if (!res.ok) {
        setFetchError(
          json?.error ?? `Erro ao carregar tenants (HTTP ${res.status}).`
        )
        setTenants([])
        return
      }

      if (!json?.success) {
        setFetchError(json?.error ?? 'Resposta inválida do servidor.')
        setTenants([])
        return
      }

      setTenants(Array.isArray(json.data) ? json.data : [])
    } catch {
      setFetchError('Falha de conexão ao carregar a lista de tenants.')
      setTenants([])
    } finally {
      setLoading(false)
    }
  }, [session, search, planFilter, statusFilter])

  useEffect(() => { load() }, [load])

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="space-y-6 max-w-6xl">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Building2 size={22} className="text-brand-700" />
          <div>
            <h1 className="text-xl font-bold text-gray-900">Tenants</h1>
            <p className="text-sm text-gray-500">
              {loading
                ? 'Carregando...'
                : fetchError
                  ? 'Erro ao carregar'
                  : `${tenants.length} empresa${tenants.length !== 1 ? 's' : ''} cadastrada${tenants.length !== 1 ? 's' : ''}`
              }
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={load}
            disabled={loading}
            className="btn-secondary flex items-center gap-1.5 text-sm"
          >
            <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
            Atualizar
          </button>
          <Link
            href="/master/tenants/novo"
            className="btn-primary flex items-center gap-1.5 text-sm"
          >
            <Plus size={14} />
            Novo Tenant
          </Link>
        </div>
      </div>

      {/* Filtros */}
      <div className="card flex flex-wrap items-center gap-3">
        <div className="relative flex-1 min-w-52">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            className="input pl-9 text-sm"
            placeholder="Buscar por nome, razão social, CNPJ, slug, ID..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <select
          className="input text-sm w-36"
          value={planFilter}
          onChange={(e) => setPlanFilter(e.target.value)}
        >
          <option value="">Todos os planos</option>
          {Object.entries(PLAN_LABEL).map(([v, l]) => (
            <option key={v} value={v}>{l}</option>
          ))}
        </select>
        <select
          className="input text-sm w-40"
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
        >
          <option value="">Todos os status</option>
          {Object.entries(STATUS_LABEL).map(([v, l]) => (
            <option key={v} value={v}>{l}</option>
          ))}
        </select>
      </div>

      {/* Erro de carregamento */}
      {fetchError && !loading && (
        <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 px-4 py-3">
          <AlertCircle size={16} className="mt-0.5 shrink-0 text-red-600" />
          <div>
            <p className="text-sm font-medium text-red-700">Falha ao carregar tenants</p>
            <p className="mt-0.5 text-sm text-red-600">{fetchError}</p>
          </div>
          <button
            onClick={load}
            className="ml-auto shrink-0 text-xs font-medium text-red-700 underline hover:no-underline"
          >
            Tentar novamente
          </button>
        </div>
      )}

      {/* Tabela */}
      <div className="card overflow-hidden p-0">
        {loading ? (
          <div className="flex h-40 items-center justify-center">
            <div className="h-7 w-7 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" />
          </div>
        ) : tenants.length === 0 && !fetchError ? (
          <div className="flex h-40 flex-col items-center justify-center gap-2 text-gray-400">
            <Building2 size={32} />
            <p className="text-sm">
              {search || planFilter || statusFilter
                ? 'Nenhuma empresa encontrada com os filtros aplicados.'
                : 'Nenhuma empresa cadastrada ainda.'}
            </p>
            {(search || planFilter || statusFilter) && (
              <button
                onClick={() => { setSearch(''); setPlanFilter(''); setStatusFilter('') }}
                className="text-xs text-brand-700 underline hover:no-underline"
              >
                Limpar filtros
              </button>
            )}
          </div>
        ) : tenants.length > 0 ? (
          <table className="w-full text-sm">
            <thead className="border-b border-gray-100 bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Empresa</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Plano</th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Status</th>
                <th className="px-4 py-3 text-center font-medium text-gray-500">
                  <span className="flex items-center justify-center gap-1">
                    <Users size={12} /> Usuários
                  </span>
                </th>
                <th className="px-4 py-3 text-center font-medium text-gray-500">
                  <span className="flex items-center justify-center gap-1">
                    <Layers size={12} /> Unidades
                  </span>
                </th>
                <th className="px-4 py-3 text-left font-medium text-gray-500">Criado em</th>
                <th className="px-4 py-3" />
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {tenants.map((t) => {
                const StatusIcon = STATUS_ICON[t.status] ?? Clock
                return (
                  <tr key={t.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2.5">
                        <div
                          className="flex h-8 w-8 items-center justify-center rounded-lg text-white text-xs font-bold shrink-0"
                          style={{ backgroundColor: t.primaryColor ?? '#166534' }}
                        >
                          {t.name.slice(0, 2).toUpperCase()}
                        </div>
                        <div>
                          <p className="font-semibold text-gray-900">{t.name}</p>
                          <p className="text-xs text-gray-400">
                            {t.nomeFantasia ?? t.razaoSocial ?? t.publicId}
                          </p>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3">
                      <span className={`rounded-full px-2.5 py-0.5 text-xs font-medium ${PLAN_COLOR[t.plan] ?? 'bg-gray-100 text-gray-700'}`}>
                        {PLAN_LABEL[t.plan] ?? t.plan}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div
                        className={`flex items-center gap-1.5 text-xs font-medium ${STATUS_COLOR[t.status] ?? 'text-gray-500'}`}
                        title={t.statusReason ?? undefined}
                      >
                        <StatusIcon size={13} />
                        {STATUS_LABEL[t.status] ?? t.status}
                      </div>
                    </td>
                    <td className="px-4 py-3 text-center text-gray-700">{t._count.users}</td>
                    <td className="px-4 py-3 text-center text-gray-700">{t._count.units}</td>
                    <td className="px-4 py-3 text-gray-500">
                      {new Date(t.createdAt).toLocaleDateString('pt-BR')}
                    </td>
                    <td className="px-4 py-3">
                      <Link
                        href={`/master/tenants/${t.id}`}
                        className="flex items-center gap-1 text-xs text-brand-700 hover:underline"
                      >
                        Detalhes <ChevronRight size={12} />
                      </Link>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        ) : null}
      </div>
    </div>
  )
}

'use client'

// =============================================================================
// /master/users/novo — Criar novo usuário em qualquer tenant (MASTER only)
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { useSession }                        from 'next-auth/react'
import { useRouter }                         from 'next/navigation'
import Link                                  from 'next/link'
import {
  UserPlus, Loader2, AlertCircle, CheckCircle2, Save,
  ChevronLeft, Eye, EyeOff, Building2, Search,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface TenantOption {
  id:       string
  publicId: string
  name:     string
  plan:     string
  status:   string
}

interface UnitOption {
  id:   string
  name: string
}

interface PositionOption {
  id:        string
  name:      string
  slug:      string
  sortOrder: number
}

// ── Constantes ────────────────────────────────────────────────────────────────

const ROLES = [
  'ADM',
  'GERENTE_GERAL',
  'GERENTE',
  'VENDEDOR_LIDER',
  'VENDEDOR',
  'USUARIO_LIDER',
  'USUARIO',
]

const ROLE_LABELS: Record<string, string> = {
  ADM:            'Administrador',
  GERENTE_GERAL:  'Gerente Geral',
  GERENTE:        'Gerente',
  VENDEDOR_LIDER: 'Vendedor Líder',
  VENDEDOR:       'Vendedor',
  USUARIO_LIDER:  'Usuário Líder',
  USUARIO:        'Usuário',
}

const inputCls = 'w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'
const labelCls = 'text-xs font-medium text-gray-600 block mb-1'

// ── Página ────────────────────────────────────────────────────────────────────

export default function NewUserPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  // Form
  const [name,               setName]               = useState('')
  const [email,              setEmail]              = useState('')
  const [password,           setPassword]           = useState('')
  const [showPwd,            setShowPwd]            = useState(false)
  const [role,               setRole]               = useState('VENDEDOR')
  const [mustChangePassword, setMustChangePassword] = useState(true)
  const [selectedTenantId,   setSelectedTenantId]   = useState('')
  const [selectedUnitId,     setSelectedUnitId]     = useState('')
  const [selectedPositionId, setSelectedPositionId] = useState('')

  // Data
  const [tenants,   setTenants]   = useState<TenantOption[]>([])
  const [units,     setUnits]     = useState<UnitOption[]>([])
  const [positions, setPositions] = useState<PositionOption[]>([])
  const [tenantSearch, setTenantSearch] = useState('')

  // UI state
  const [loadingTenants, setLoadingTenants] = useState(true)
  const [loadingUnits,   setLoadingUnits]   = useState(false)
  const [saving,         setSaving]         = useState(false)
  const [error,          setError]          = useState('')
  const [success,        setSuccess]        = useState('')

  // Guard
  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') {
      router.replace('/inicio')
    }
  }, [session, status, router])

  // Load tenants
  useEffect(() => {
    if (session?.user?.role !== 'MASTER') return
    fetch('/api/master/tenants?limit=200&page=1')
      .then(r => r.json())
      .then(d => setTenants(d.data ?? []))
      .catch(() => setError('Erro ao carregar tenants.'))
      .finally(() => setLoadingTenants(false))
  }, [session])

  // Load cargos (sistema + tenant) — não filtra por tenant aqui; usuário escolhe livre.
  useEffect(() => {
    if (session?.user?.role !== 'MASTER') return
    fetch('/api/positions?active=true')
      .then(r => r.json())
      .then(d => {
        const list: PositionOption[] = (d?.data ?? []) as PositionOption[]
        list.sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name))
        setPositions(list)
      })
      .catch(() => { /* silent */ })
  }, [session])

  // Load units when tenant changes
  const loadUnits = useCallback(async (tenantId: string) => {
    if (!tenantId) { setUnits([]); setSelectedUnitId(''); return }
    setLoadingUnits(true)
    setSelectedUnitId('')
    try {
      const res  = await fetch(`/api/master/tenants/${tenantId}`)
      const data = await res.json()
      setUnits(data.data?.units ?? [])
    } catch {
      setUnits([])
    } finally {
      setLoadingUnits(false)
    }
  }, [])

  useEffect(() => {
    loadUnits(selectedTenantId)
  }, [selectedTenantId, loadUnits])

  // Filtered tenants
  const filteredTenants = tenantSearch.trim()
    ? tenants.filter(t =>
        t.name.toLowerCase().includes(tenantSearch.toLowerCase()) ||
        t.publicId.toLowerCase().includes(tenantSearch.toLowerCase()),
      )
    : tenants

  const selectedTenant = tenants.find(t => t.id === selectedTenantId)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSuccess('')

    if (!name.trim())        { setError('Nome é obrigatório.'); return }
    if (!email.trim())       { setError('E-mail é obrigatório.'); return }
    if (password.length < 6) { setError('Senha deve ter no mínimo 6 caracteres.'); return }
    if (!selectedTenantId)   { setError('Selecione um tenant para este usuário.'); return }

    setSaving(true)
    try {
      const res = await fetch('/api/master/users', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          name:               name.trim(),
          email:              email.trim().toLowerCase(),
          password,
          role,
          tenantId:           selectedTenantId,
          unitId:             selectedUnitId   || null,
          positionId:         selectedPositionId || null,
          mustChangePassword,
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao criar usuário.')
      setSuccess(`Usuário ${data.data?.name ?? ''} criado com sucesso!`)
      setTimeout(() => router.push('/master/users'), 1500)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao criar usuário.')
    } finally {
      setSaving(false)
    }
  }

  if (status === 'loading' || loadingTenants) {
    return (
      <div className="flex h-64 items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="max-w-2xl space-y-6">

      {/* Header */}
      <div className="flex items-center gap-3">
        <Link
          href="/master/users"
          className="flex h-8 w-8 items-center justify-center rounded-lg border border-gray-200 text-gray-500 hover:bg-gray-50"
        >
          <ChevronLeft size={16} />
        </Link>
        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-600">
          <UserPlus size={18} className="text-white" />
        </div>
        <div>
          <h1 className="text-xl font-bold text-gray-900">Novo Usuário</h1>
          <p className="text-xs text-gray-400">Criar usuário em qualquer tenant da plataforma</p>
        </div>
      </div>

      {error   && (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          <AlertCircle size={15} className="shrink-0" />{error}
        </div>
      )}
      {success && (
        <div className="flex items-center gap-2 rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700">
          <CheckCircle2 size={15} className="shrink-0" />{success}
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-5">

        {/* ── Dados pessoais ── */}
        <div className="rounded-xl border border-gray-200 bg-white p-5 space-y-4">
          <h2 className="text-sm font-semibold text-gray-800">Dados do usuário</h2>

          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2 sm:col-span-1">
              <label className={labelCls}>Nome completo *</label>
              <input
                className={inputCls}
                value={name}
                onChange={e => setName(e.target.value)}
                placeholder="João da Silva"
                autoComplete="off"
              />
            </div>
            <div className="col-span-2 sm:col-span-1">
              <label className={labelCls}>E-mail *</label>
              <input
                type="email"
                className={inputCls}
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="joao@loja.com.br"
                autoComplete="off"
              />
            </div>
          </div>

          <div>
            <label className={labelCls}>Senha inicial *</label>
            <div className="relative">
              <input
                type={showPwd ? 'text' : 'password'}
                className={`${inputCls} pr-9`}
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Mínimo 6 caracteres"
                autoComplete="new-password"
              />
              <button
                type="button"
                onClick={() => setShowPwd(p => !p)}
                className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showPwd ? <EyeOff size={14} /> : <Eye size={14} />}
              </button>
            </div>
          </div>

          <div>
            <label className={labelCls}>Papel (Role) *</label>
            <select
              className={inputCls}
              value={role}
              onChange={e => setRole(e.target.value)}
            >
              {ROLES.map(r => (
                <option key={r} value={r}>{ROLE_LABELS[r] ?? r} — {r}</option>
              ))}
            </select>
            <p className="mt-1 text-xs text-gray-400">
              Define as permissões do usuário dentro do tenant.
            </p>
          </div>

          <div>
            <label className={labelCls}>Cargo</label>
            <select
              className={inputCls}
              value={selectedPositionId}
              onChange={e => setSelectedPositionId(e.target.value)}
            >
              <option value="">— sem cargo —</option>
              {positions.map(p => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
            <p className="mt-1 text-xs text-gray-400">
              Cargo organizacional (opcional). Usado para regras de comissão e relatórios.
            </p>
          </div>

          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              className="h-4 w-4 rounded border-gray-300 text-brand-600"
              checked={mustChangePassword}
              onChange={e => setMustChangePassword(e.target.checked)}
            />
            <span className="text-sm text-gray-700">
              Exigir troca de senha no primeiro acesso
            </span>
          </label>
        </div>

        {/* ── Tenant ── */}
        <div className="rounded-xl border border-gray-200 bg-white p-5 space-y-4">
          <h2 className="flex items-center gap-2 text-sm font-semibold text-gray-800">
            <Building2 size={14} className="text-brand-600" />
            Tenant *
          </h2>

          {/* Search */}
          <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input
              className="w-full rounded-lg border border-gray-300 pl-8 pr-3 py-2 text-sm focus:border-brand-500 focus:outline-none"
              placeholder="Buscar tenant por nome ou ID..."
              value={tenantSearch}
              onChange={e => setTenantSearch(e.target.value)}
            />
          </div>

          {/* List */}
          <div className="max-h-52 overflow-y-auto rounded-lg border border-gray-200 divide-y divide-gray-100">
            {filteredTenants.length === 0 ? (
              <p className="px-3 py-4 text-center text-sm text-gray-400">Nenhum tenant encontrado.</p>
            ) : filteredTenants.map(t => (
              <label
                key={t.id}
                className={`flex cursor-pointer items-center gap-3 px-3 py-2.5 hover:bg-gray-50 transition-colors ${selectedTenantId === t.id ? 'bg-brand-50' : ''}`}
              >
                <input
                  type="radio"
                  name="tenantId"
                  className="h-4 w-4 text-brand-600 border-gray-300 focus:ring-brand-500"
                  checked={selectedTenantId === t.id}
                  onChange={() => setSelectedTenantId(t.id)}
                />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 truncate">{t.name}</p>
                  <p className="text-xs text-gray-400">{t.publicId} · {t.plan} · {t.status}</p>
                </div>
              </label>
            ))}
          </div>

          {selectedTenant && (
            <div className="flex items-center gap-2 rounded-lg bg-brand-50 border border-brand-100 px-3 py-2">
              <Building2 size={13} className="text-brand-600 shrink-0" />
              <span className="text-sm text-brand-700 font-medium">{selectedTenant.name}</span>
              <span className="ml-auto text-xs text-brand-500">{selectedTenant.publicId}</span>
            </div>
          )}
        </div>

        {/* ── Unidade (opcional) ── */}
        {selectedTenantId && (
          <div className="rounded-xl border border-gray-200 bg-white p-5 space-y-3">
            <h2 className="text-sm font-semibold text-gray-800">
              Unidade
              <span className="ml-1.5 text-xs font-normal text-gray-400">(opcional)</span>
            </h2>

            {loadingUnits ? (
              <div className="flex items-center gap-2 text-sm text-gray-400">
                <Loader2 size={14} className="animate-spin" />Carregando unidades...
              </div>
            ) : units.length === 0 ? (
              <p className="text-sm text-gray-400">Este tenant não possui unidades cadastradas.</p>
            ) : (
              <select
                className={inputCls}
                value={selectedUnitId}
                onChange={e => setSelectedUnitId(e.target.value)}
              >
                <option value="">Sem unidade específica</option>
                {units.map(u => (
                  <option key={u.id} value={u.id}>{u.name}</option>
                ))}
              </select>
            )}
            <p className="text-xs text-gray-400">
              Associar a uma unidade restringe o acesso do usuário àquela unidade no tenant.
            </p>
          </div>
        )}

        {/* ── Resumo e submit ── */}
        <div className="flex items-center justify-between gap-4 rounded-xl border border-gray-200 bg-white p-4">
          <div className="text-xs text-gray-500 space-y-0.5">
            {selectedTenant && (
              <p><span className="font-medium">Tenant:</span> {selectedTenant.name}</p>
            )}
            <p><span className="font-medium">Papel:</span> {ROLE_LABELS[role] ?? role}</p>
            <p><span className="font-medium">Troca de senha:</span> {mustChangePassword ? 'Sim, no primeiro acesso' : 'Não'}</p>
          </div>
          <div className="flex gap-3">
            <Link
              href="/master/users"
              className="rounded-lg border border-gray-200 px-4 py-2 text-sm text-gray-600 hover:bg-gray-50"
            >
              Cancelar
            </Link>
            <button
              type="submit"
              disabled={saving || !selectedTenantId}
              className="flex items-center gap-2 rounded-lg bg-blue-600 px-5 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {saving
                ? <><Loader2 size={14} className="animate-spin" />Criando...</>
                : <><Save size={14} />Criar usuário</>
              }
            </button>
          </div>
        </div>

      </form>
    </div>
  )
}

'use client'

// =============================================================================
// /master/users — Gestão global de usuários (MASTER only)
//
// • Lista todos os usuários da plataforma com filtros
// • Editar role, status, tenant
// • Resetar senha
// • Ativar / inativar / bloquear
// • Criar usuário em qualquer tenant
// =============================================================================

import { useState, useEffect, useCallback, useMemo } from 'react'
import { useSession }                        from 'next-auth/react'
import { useRouter }                         from 'next/navigation'
import Link                                  from 'next/link'
import {
  Users, Search, Filter, RefreshCw, Loader2, AlertCircle,
  CheckCircle2, Shield, Edit2, Key, UserX, UserCheck,
  ChevronLeft, ChevronRight, X, Save, Plus, Eye, EyeOff,
  ExternalLink, Trash2,
} from 'lucide-react'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface UserRecord {
  id:                 string
  name:               string
  email:              string
  phone?:             string | null
  cpf?:               string | null
  role:               string
  status:             string
  tenantId:           string | null
  unitId:             string | null
  mustChangePassword: boolean
  lastLoginAt:        string | null
  createdAt:          string
  tenant:             { id: string; name: string; publicId: string; status: string } | null
  unit:               { id: string; name: string } | null
  position:           { id: string; name: string; slug: string } | null
}

interface SellerExtra {
  fullName?:       string
  shortName?:      string | null
  whatsapp?:       string | null
  cargo?:          string | null
  notes?:          string | null
  active?:         boolean
  receivesCharge?: boolean
}

interface PositionOption {
  id:        string
  name:      string
  slug:      string
  sortOrder: number
}

interface Meta { total: number; page: number; limit: number; pages: number }

// ── Helpers ───────────────────────────────────────────────────────────────────

const inputCls = 'w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'
const labelCls = 'text-xs font-medium text-gray-600 block mb-1'

const ROLE_COLOR: Record<string, string> = {
  MASTER:         'bg-purple-100 text-purple-800 border-purple-200',
  ADM:            'bg-blue-100   text-blue-800   border-blue-200',
  GERENTE_GERAL:  'bg-indigo-100 text-indigo-800 border-indigo-200',
  GERENTE:        'bg-cyan-100   text-cyan-800   border-cyan-200',
  VENDEDOR_LIDER: 'bg-teal-100   text-teal-800   border-teal-200',
  VENDEDOR:       'bg-green-100  text-green-800  border-green-200',
  USUARIO_LIDER:  'bg-orange-100 text-orange-800 border-orange-200',
  USUARIO:        'bg-gray-100   text-gray-700   border-gray-200',
}

const STATUS_COLOR: Record<string, string> = {
  ATIVO:    'bg-emerald-50 text-emerald-700 border-emerald-200',
  INATIVO:  'bg-gray-100   text-gray-600   border-gray-200',
  PENDENTE: 'bg-amber-50   text-amber-700  border-amber-200',
  BLOQUEADO:'bg-red-50     text-red-700    border-red-200',
}

const ROLES = ['MASTER','ADM','GERENTE_GERAL','GERENTE','VENDEDOR_LIDER','VENDEDOR','USUARIO_LIDER','USUARIO']
const STATUSES = ['ATIVO','INATIVO','PENDENTE','BLOQUEADO','SUSPENSO']

// Tabs visíveis (com label + cor). PENDENTE não é tab principal — fica
// junto com Ativos por padrão (usuário recém-criado pode aparecer aqui).
const STATUS_TABS: Array<{ value: string; label: string; pill: string }> = [
  { value: 'ATIVO',     label: 'Ativos',     pill: 'bg-emerald-100 text-emerald-700' },
  { value: 'SUSPENSO',  label: 'Suspensos',  pill: 'bg-amber-100 text-amber-700' },
  { value: 'BLOQUEADO', label: 'Bloqueados', pill: 'bg-red-100 text-red-700' },
  { value: 'INATIVO',   label: 'Inativos',   pill: 'bg-gray-100 text-gray-700' },
  { value: 'PENDENTE',  label: 'Pendentes',  pill: 'bg-blue-100 text-blue-700' },
]

function fmtDate(d: string | null) {
  if (!d) return '—'
  return new Date(d).toLocaleDateString('pt-BR')
}

// ── Modal: editar usuário ──────────────────────────────────────────────────────

function EditModal({ user, positions, onClose, onSaved }: { user: UserRecord; positions: PositionOption[]; onClose: () => void; onSaved: () => void }) {
  const [form, setForm] = useState({
    name:               user.name,
    email:              user.email,
    phone:              user.phone ?? '',
    cpf:                user.cpf ?? '',
    role:               user.role,
    status:             user.status,
    mustChangePassword: user.mustChangePassword,
    positionId:         user.position?.id ?? '',
  })
  const [seller, setSeller] = useState<SellerExtra & { loaded: boolean }>({
    loaded: false,
  })
  const [saving, setSaving] = useState(false)
  const [error,  setError]  = useState('')
  const [tab,    setTab]    = useState<'pessoal' | 'acesso' | 'vendedor'>('pessoal')

  const isVendedor = form.role === 'VENDEDOR'

  // Carrega sub-cadastro Seller se for vendedor (uma vez por modal)
  useEffect(() => {
    if (!isVendedor || seller.loaded) return
    ;(async () => {
      try {
        const r = await fetch(`/api/sellers?userId=${user.id}`)
        const d = await r.json().catch(() => ({}))
        const s = Array.isArray(d?.data) ? d.data.find((x: any) => x.userId === user.id) : null  // eslint-disable-line @typescript-eslint/no-explicit-any
        setSeller({
          loaded:         true,
          fullName:       s?.fullName ?? user.name,
          shortName:      s?.shortName ?? '',
          whatsapp:       s?.whatsapp ?? '',
          cargo:          s?.cargo ?? '',
          notes:          s?.notes ?? '',
          active:         s?.active ?? true,
          receivesCharge: s?.receivesCharge ?? true,
        })
      } catch {
        setSeller({ loaded: true })
      }
    })()
  }, [isVendedor, seller.loaded, user.id, user.name])

  async function handleSave(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSaving(true)
    try {
      const payload: Record<string, unknown> = {
        name:               form.name.trim(),
        email:              form.email.trim().toLowerCase(),
        phone:              form.phone || null,
        cpf:                form.cpf || null,
        role:               form.role,
        status:             form.status,
        mustChangePassword: form.mustChangePassword,
        positionId:         form.positionId || null,
      }
      if (isVendedor && seller.loaded) {
        payload.seller = {
          fullName:       seller.fullName,
          shortName:      seller.shortName,
          whatsapp:       seller.whatsapp,
          cargo:          seller.cargo,
          notes:          seller.notes,
          active:         seller.active,
          receivesCharge: seller.receivesCharge,
        }
      }
      const res  = await fetch(`/api/master/users/${user.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(payload),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro ao salvar.')
      onSaved()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
      <div className="flex max-h-[90vh] w-full max-w-2xl flex-col rounded-2xl bg-white shadow-2xl">
        <div className="flex items-center justify-between border-b border-gray-100 px-5 py-4">
          <div>
            <h2 className="font-semibold text-gray-900">Editar usuário</h2>
            <p className="text-xs text-gray-400">{user.email}</p>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 hover:bg-gray-100"><X size={15} /></button>
        </div>

        {/* Tabs internas */}
        <div className="flex gap-1 border-b border-gray-100 px-5 pt-2">
          {([
            { id: 'pessoal',  label: 'Dados pessoais' },
            { id: 'acesso',   label: 'Acesso e permissões' },
            ...(isVendedor ? [{ id: 'vendedor' as const, label: 'Vendedor' }] : []),
          ] as const).map((t) => (
            <button
              key={t.id}
              type="button"
              onClick={() => setTab(t.id)}
              className={`rounded-t-md px-3 py-2 text-xs font-medium transition-colors ${
                tab === t.id
                  ? 'border-b-2 border-brand-600 text-brand-700'
                  : 'text-gray-500 hover:text-gray-800'
              }`}
            >
              {t.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSave} className="flex flex-1 flex-col overflow-hidden">
          <div className="flex-1 space-y-4 overflow-y-auto px-5 py-4">
            {error && (
              <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
                <AlertCircle size={13} className="shrink-0" />{error}
              </div>
            )}

            {/* ── Aba: Dados pessoais ─────────────────────────────── */}
            {tab === 'pessoal' && (
              <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
                <div className="md:col-span-2">
                  <label className={labelCls}>Nome completo</label>
                  <input className={inputCls} value={form.name}
                    onChange={e => setForm(p => ({ ...p, name: e.target.value }))} />
                </div>
                <div>
                  <label className={labelCls}>E-mail</label>
                  <input type="email" className={inputCls} value={form.email}
                    onChange={e => setForm(p => ({ ...p, email: e.target.value }))} />
                </div>
                <div>
                  <label className={labelCls}>Telefone</label>
                  <input className={inputCls} placeholder="(11) 99999-9999" value={form.phone}
                    onChange={e => setForm(p => ({ ...p, phone: e.target.value }))} />
                </div>
                <div>
                  <label className={labelCls}>CPF</label>
                  <input className={inputCls} placeholder="000.000.000-00" value={form.cpf}
                    onChange={e => setForm(p => ({ ...p, cpf: e.target.value }))} />
                </div>
              </div>
            )}

            {/* ── Aba: Acesso e permissões ───────────────────────── */}
            {tab === 'acesso' && (
              <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
                <div>
                  <label className={labelCls}>Papel (Role)</label>
                  <select className={inputCls} value={form.role}
                    onChange={e => setForm(p => ({ ...p, role: e.target.value }))}>
                    {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select className={inputCls} value={form.status}
                    onChange={e => setForm(p => ({ ...p, status: e.target.value }))}>
                    {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="md:col-span-2">
                  <label className={labelCls}>Cargo (Position)</label>
                  <select className={inputCls} value={form.positionId}
                    onChange={e => setForm(p => ({ ...p, positionId: e.target.value }))}>
                    <option value="">— sem cargo —</option>
                    {positions.map(p => (
                      <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                  </select>
                </div>
                <label className="md:col-span-2 flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-brand-600"
                    checked={form.mustChangePassword}
                    onChange={e => setForm(p => ({ ...p, mustChangePassword: e.target.checked }))}
                  />
                  <span className="text-sm text-gray-700">Exigir troca de senha no próximo login</span>
                </label>
              </div>
            )}

            {/* ── Aba: Vendedor (sub-cadastro) ───────────────────── */}
            {tab === 'vendedor' && isVendedor && (
              seller.loaded ? (
                <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
                  <div>
                    <label className={labelCls}>Nome no contrato (fullName)</label>
                    <input className={inputCls} value={seller.fullName ?? ''}
                      onChange={e => setSeller(s => ({ ...s, fullName: e.target.value }))} />
                  </div>
                  <div>
                    <label className={labelCls}>Nome curto / apelido</label>
                    <input className={inputCls} value={seller.shortName ?? ''}
                      onChange={e => setSeller(s => ({ ...s, shortName: e.target.value }))} />
                  </div>
                  <div>
                    <label className={labelCls}>WhatsApp</label>
                    <input className={inputCls} placeholder="(11) 99999-9999"
                      value={seller.whatsapp ?? ''}
                      onChange={e => setSeller(s => ({ ...s, whatsapp: e.target.value }))} />
                  </div>
                  <div>
                    <label className={labelCls}>Cargo / função na loja</label>
                    <input className={inputCls} placeholder="Ex.: Vendedor Pleno"
                      value={seller.cargo ?? ''}
                      onChange={e => setSeller(s => ({ ...s, cargo: e.target.value }))} />
                  </div>
                  <div className="md:col-span-2">
                    <label className={labelCls}>Observações</label>
                    <textarea className={`${inputCls} min-h-16 resize-y`} value={seller.notes ?? ''}
                      onChange={e => setSeller(s => ({ ...s, notes: e.target.value }))} />
                  </div>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-brand-600"
                      checked={seller.active ?? true}
                      onChange={e => setSeller(s => ({ ...s, active: e.target.checked }))}
                    />
                    <span className="text-sm text-gray-700">Vendedor ativo</span>
                  </label>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-brand-600"
                      checked={seller.receivesCharge ?? true}
                      onChange={e => setSeller(s => ({ ...s, receivesCharge: e.target.checked }))}
                    />
                    <span className="text-sm text-gray-700">Recebe pendências/cobranças</span>
                  </label>
                </div>
              ) : (
                <div className="flex items-center justify-center py-10 text-gray-400">
                  <Loader2 size={20} className="animate-spin" />
                </div>
              )
            )}
          </div>

          <div className="flex gap-3 border-t border-gray-100 px-5 py-3">
            <button type="submit" disabled={saving}
              className="flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-semibold text-white hover:bg-brand-700 disabled:opacity-50"
            >
              {saving ? <Loader2 size={13} className="animate-spin" /> : <Save size={13} />}
              Salvar
            </button>
            <button type="button" onClick={onClose}
              className="rounded-lg border border-gray-200 px-4 py-2 text-sm text-gray-600 hover:bg-gray-50"
            >Cancelar</button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── Modal: resetar senha ───────────────────────────────────────────────────────

function ResetPasswordModal({ user, onClose, onSaved }: { user: UserRecord; onClose: () => void; onSaved: () => void }) {
  const [pwd,      setPwd]      = useState('')
  const [showPwd,  setShowPwd]  = useState(false)
  const [saving,   setSaving]   = useState(false)
  const [error,    setError]    = useState('')

  async function handleReset(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    if (pwd.length < 6) { setError('Mínimo 6 caracteres.'); return }
    setSaving(true)
    try {
      const res  = await fetch(`/api/master/users/${user.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ action: 'RESET_PASSWORD', newPassword: pwd, reason: 'Reset por MASTER' }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Erro.')
      onSaved()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
      <div className="w-full max-w-sm rounded-2xl bg-white shadow-2xl">
        <div className="flex items-center justify-between border-b border-gray-100 px-5 py-4">
          <div>
            <h2 className="font-semibold text-gray-900 flex items-center gap-2"><Key size={14} />Resetar senha</h2>
            <p className="text-xs text-gray-400">{user.name}</p>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 hover:bg-gray-100"><X size={15} /></button>
        </div>
        <form onSubmit={handleReset} className="space-y-4 px-5 py-4">
          {error && <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700"><AlertCircle size={13} />{error}</div>}
          <div>
            <label className={labelCls}>Nova senha</label>
            <div className="relative">
              <input
                type={showPwd ? 'text' : 'password'}
                className={`${inputCls} pr-9`}
                value={pwd}
                onChange={e => setPwd(e.target.value)}
                placeholder="Mínimo 6 caracteres"
              />
              <button type="button" onClick={() => setShowPwd(p => !p)}
                className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-400"
              >
                {showPwd ? <EyeOff size={14} /> : <Eye size={14} />}
              </button>
            </div>
            <p className="mt-1 text-xs text-amber-600">O usuário será obrigado a trocar na próxima sessão.</p>
          </div>
          <div className="flex gap-3 pt-2 border-t border-gray-100">
            <button type="submit" disabled={saving}
              className="flex items-center gap-2 rounded-lg bg-amber-600 px-4 py-2 text-sm font-semibold text-white hover:bg-amber-700 disabled:opacity-50"
            >
              {saving ? <Loader2 size={13} className="animate-spin" /> : <Key size={13} />}
              Resetar
            </button>
            <button type="button" onClick={onClose}
              className="rounded-lg border border-gray-200 px-4 py-2 text-sm text-gray-600 hover:bg-gray-50"
            >Cancelar</button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── DeleteUserModal — confirmação forte (digite EXCLUIR) ────────────────────

function DeleteUserModal({
  user, isSelf, onClose, onDeleted,
}: {
  user: UserRecord
  isSelf: boolean
  onClose: () => void
  onDeleted: (msg?: string) => void
}) {
  const [typed, setTyped] = useState('')
  const [busy,  setBusy]  = useState(false)
  const [err,   setErr]   = useState('')
  const isMaster = user.role === 'MASTER'

  async function doDelete() {
    setBusy(true); setErr('')
    try {
      const res  = await fetch(`/api/master/users/${user.id}`, { method: 'DELETE' })
      const data = await res.json().catch(() => ({}))
      if (!res.ok || !data?.success) throw new Error(data?.error ?? 'Falha ao excluir.')
      onDeleted(data?.message ?? 'Usuário inativado.')
    } catch (e) {
      setErr(e instanceof Error ? e.message : 'Erro inesperado.')
    } finally {
      setBusy(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="w-full max-w-md rounded-2xl bg-white shadow-2xl">
        <div className="flex items-center justify-between border-b border-gray-200 px-5 py-3">
          <h3 className="flex items-center gap-2 text-base font-semibold text-red-700">
            <Trash2 size={16} /> Excluir / inativar usuário
          </h3>
          <button onClick={onClose} className="rounded-md p-1.5 text-gray-400 hover:bg-gray-100">
            <X size={16} />
          </button>
        </div>

        <div className="space-y-3 p-5 text-sm">
          {isSelf && (
            <div className="rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">
              Você não pode excluir sua própria conta. Peça a outro MASTER.
            </div>
          )}

          {isMaster && !isSelf && (
            <div className="rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-800">
              Usuário <strong>MASTER</strong>. O sistema bloqueia inativar o último MASTER ativo.
            </div>
          )}

          <div className="rounded-lg border border-gray-200 bg-gray-50 p-3 text-xs text-gray-700 space-y-0.5">
            <p><strong>Nome:</strong> {user.name}</p>
            <p><strong>E-mail:</strong> {user.email}</p>
            <p><strong>Perfil:</strong> {user.role}</p>
            {user.tenant && <p><strong>Tenant:</strong> {user.tenant.name}</p>}
            {!user.tenant && <p><strong>Tenant:</strong> Plataforma (MASTER)</p>}
          </div>

          <p className="rounded-lg border border-blue-200 bg-blue-50 px-3 py-2 text-xs text-blue-800">
            O usuário será <strong>inativado</strong> (status → INATIVO). Não poderá mais logar,
            mas todos os dados históricos (logs, negociações, comissões) ficam preservados.
            Para reativar depois, basta usar o botão <em>Reativar</em> na linha.
          </p>

          <div>
            <label className="mb-1 block text-xs font-medium text-gray-700">
              Digite <span className="font-mono text-red-600">EXCLUIR</span> para confirmar:
            </label>
            <input
              type="text"
              value={typed}
              onChange={(e) => setTyped(e.target.value)}
              disabled={isSelf}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              placeholder="EXCLUIR"
            />
          </div>

          {err && (
            <div className="flex items-start gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">
              <AlertCircle size={13} className="mt-0.5 shrink-0" /> {err}
            </div>
          )}
        </div>

        <div className="flex justify-end gap-2 border-t border-gray-200 px-5 py-3">
          <button onClick={onClose} className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50">
            Cancelar
          </button>
          <button
            onClick={doDelete}
            disabled={busy || isSelf || typed.trim().toUpperCase() !== 'EXCLUIR'}
            className="flex items-center gap-1.5 rounded-md bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {busy ? <Loader2 size={13} className="animate-spin" /> : <Trash2 size={13} />}
            Confirmar
          </button>
        </div>
      </div>
    </div>
  )
}

// ── PurgeUserModal — hard delete real (force purge) ─────────────────────────

function PurgeUserModal({
  user, isSelf, onClose, onPurged,
}: {
  user: UserRecord
  isSelf: boolean
  onClose: () => void
  onPurged: (msg?: string) => void
}) {
  const [typed, setTyped] = useState('')
  const [busy,  setBusy]  = useState(false)
  const [err,   setErr]   = useState('')

  async function doPurge() {
    setBusy(true); setErr('')
    try {
      const res  = await fetch(`/api/master/users/${user.id}/purge`, { method: 'POST' })
      const data = await res.json().catch(() => ({}))
      if (!res.ok || !data?.success) throw new Error(data?.error ?? 'Falha ao purgar.')
      onPurged(data?.message ?? 'Usuário apagado permanentemente.')
    } catch (e) {
      setErr(e instanceof Error ? e.message : 'Erro inesperado.')
    } finally {
      setBusy(false)
    }
  }

  const confirmPhrase = 'EXCLUIR PERMANENTE'
  const canConfirm = !isSelf && typed.trim().toUpperCase() === confirmPhrase

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
      <div className="w-full max-w-md rounded-2xl border-2 border-red-300 bg-white shadow-2xl">
        <div className="flex items-center justify-between border-b border-red-200 bg-red-50 px-5 py-3">
          <h3 className="flex items-center gap-2 text-base font-bold text-red-800">
            <Trash2 size={16} /> EXCLUIR PERMANENTEMENTE
          </h3>
          <button onClick={onClose} className="rounded-md p-1.5 text-red-700 hover:bg-red-100">
            <X size={16} />
          </button>
        </div>

        <div className="space-y-3 p-5 text-sm">
          <div className="rounded-lg border border-red-300 bg-red-50 px-3 py-2 text-xs text-red-800">
            <strong>⚠️ Atenção:</strong> esta ação é <strong>irreversível</strong>.
            Vai apagar o usuário e <strong>todos os dados pessoais vinculados</strong> do banco
            (notificações, preferências, comentários, comissões, sellers/managers).
            Históricos auditáveis (logs, deals, pendências) terão a referência do usuário
            substituída por <em>NULL</em>.
          </div>

          {isSelf && (
            <div className="rounded-lg border border-red-300 bg-red-100 px-3 py-2 text-xs text-red-900">
              Você não pode purgar sua própria conta.
            </div>
          )}

          <div className="rounded-lg border border-gray-200 bg-gray-50 p-3 text-xs text-gray-700 space-y-0.5">
            <p><strong>Nome:</strong> {user.name}</p>
            <p><strong>E-mail:</strong> {user.email}</p>
            <p><strong>Perfil:</strong> {user.role}</p>
            <p><strong>Status atual:</strong> {user.status}</p>
            {user.tenant && <p><strong>Tenant:</strong> {user.tenant.name}</p>}
          </div>

          {user.status !== 'INATIVO' && (
            <div className="rounded-lg border border-amber-300 bg-amber-50 px-3 py-2 text-xs text-amber-800">
              Usuário precisa estar <strong>INATIVO</strong> para purgar. Inative primeiro
              pelo botão padrão (lixeira cinza).
            </div>
          )}

          <div>
            <label className="mb-1 block text-xs font-medium text-gray-700">
              Digite <span className="font-mono text-red-700">{confirmPhrase}</span> para confirmar:
            </label>
            <input
              type="text"
              value={typed}
              onChange={(e) => setTyped(e.target.value)}
              disabled={isSelf || user.status !== 'INATIVO'}
              className="w-full rounded-md border border-red-300 px-3 py-2 text-sm font-mono focus:border-red-600 focus:outline-none focus:ring-1 focus:ring-red-600 disabled:bg-gray-100 disabled:cursor-not-allowed"
              placeholder={confirmPhrase}
            />
          </div>

          {err && (
            <div className="flex items-start gap-2 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">
              <AlertCircle size={13} className="mt-0.5 shrink-0" /> {err}
            </div>
          )}
        </div>

        <div className="flex justify-end gap-2 border-t border-gray-200 px-5 py-3">
          <button onClick={onClose} className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50">
            Cancelar
          </button>
          <button
            onClick={doPurge}
            disabled={busy || !canConfirm || user.status !== 'INATIVO'}
            className="flex items-center gap-1.5 rounded-md bg-red-700 px-4 py-2 text-sm font-bold text-white hover:bg-red-800 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {busy ? <Loader2 size={13} className="animate-spin" /> : <Trash2 size={13} />}
            Excluir permanentemente
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Página principal ─────────────────────────────────────────────────────────

export default function MasterUsersPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [users,     setUsers]     = useState<UserRecord[]>([])
  const [positions, setPositions] = useState<PositionOption[]>([])
  const [meta,      setMeta]      = useState<Meta>({ total: 0, page: 1, limit: 50, pages: 1 })
  const [loading,  setLoading]  = useState(true)
  const [error,    setError]    = useState('')
  const [success,  setSuccess]  = useState('')

  // Filtros
  const [search,   setSearch]   = useState('')
  const [roleF,    setRoleF]    = useState('')
  const [statusF,  setStatusF]  = useState('')
  const [page,     setPage]     = useState(1)

  // Modals
  const [editUser,   setEditUser]   = useState<UserRecord | null>(null)
  const [resetUser,  setResetUser]  = useState<UserRecord | null>(null)
  const [deleteUser, setDeleteUser] = useState<UserRecord | null>(null)
  const [purgeUser,  setPurgeUser]  = useState<UserRecord | null>(null)

  useEffect(() => {
    if (status === 'authenticated' && session?.user?.role !== 'MASTER') router.replace('/inicio')
  }, [session, status, router])

  const load = useCallback(async () => {
    if (session?.user?.role !== 'MASTER') return
    setLoading(true)
    setError('')
    try {
      const qs = new URLSearchParams({
        page:  String(page),
        limit: '50',
        ...(search  && { search }),
        ...(roleF   && { role: roleF }),
        ...(statusF && { status: statusF }),
      })
      const res  = await fetch(`/api/master/users?${qs}`)
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      setUsers(data.data ?? [])
      setMeta(data.meta ?? { total: 0, page: 1, limit: 50, pages: 1 })
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro ao carregar usuários.')
    } finally {
      setLoading(false)
    }
  }, [session, page, search, roleF, statusF])

  useEffect(() => { load() }, [load])

  // Carrega cargos uma vez (sistema + tenant)
  useEffect(() => {
    if (session?.user?.role !== 'MASTER') return
    fetch('/api/positions?active=true')
      .then(r => r.json())
      .then(d => {
        const list: PositionOption[] = (d?.data ?? []) as PositionOption[]
        list.sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name))
        setPositions(list)
      })
      .catch(() => { /* silent */ })
  }, [session])

  function handleSaved() {
    setEditUser(null)
    setResetUser(null)
    setSuccess('Ação realizada com sucesso.')
    setTimeout(() => setSuccess(''), 3000)
    load()
  }

  async function quickStatus(user: UserRecord, newStatus: string) {
    try {
      await fetch(`/api/master/users/${user.id}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ action: 'SET_STATUS', status: newStatus }),
      })
      load()
    } catch { /* silent */ }
  }

  // Agrupa users por tenant — MASTER (tenantId=null) vira grupo especial "Plataforma".
  // Garante ordem: Plataforma primeiro, depois tenants em ordem alfabética.
  const groupedByTenant = useMemo(() => {
    const groups = new Map<string, { id: string | null; name: string; isMaster: boolean; users: UserRecord[] }>()
    for (const u of users) {
      const key = u.tenant?.id ?? '__master__'
      if (!groups.has(key)) {
        groups.set(key, {
          id:       u.tenant?.id ?? null,
          name:     u.tenant?.name ?? 'Plataforma (MASTER)',
          isMaster: !u.tenant,
          users:    [],
        })
      }
      groups.get(key)!.users.push(u)
    }
    return Array.from(groups.values()).sort((a, b) => {
      if (a.isMaster && !b.isMaster) return -1
      if (!a.isMaster && b.isMaster) return 1
      return a.name.localeCompare(b.name)
    })
  }, [users])

  if (status === 'loading' || (loading && users.length === 0)) {
    return <div className="flex h-64 items-center justify-center"><div className="h-8 w-8 animate-spin rounded-full border-4 border-brand-600 border-t-transparent" /></div>
  }

  return (
    <div className="space-y-6 max-w-7xl">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-600">
            <Users size={18} className="text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-gray-900">Usuários Globais</h1>
            <p className="text-xs text-gray-400">{meta.total} usuários na plataforma</p>
          </div>
        </div>
        <Link href="/master/users/novo" className="flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-semibold text-white hover:bg-brand-700">
          <Plus size={15} />Novo usuário
        </Link>
      </div>

      {/* Feedback */}
      {error   && <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700"><AlertCircle size={15} />{error}</div>}
      {success && <div className="flex items-center gap-2 rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700"><CheckCircle2 size={15} />{success}</div>}

      {/* Filtros */}
      <div className="flex flex-wrap gap-3 rounded-xl border border-gray-200 bg-white p-4">
        <div className="relative flex-1 min-w-[200px]">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            className="w-full rounded-lg border border-gray-300 pl-8 pr-3 py-2 text-sm focus:border-brand-500 focus:outline-none"
            placeholder="Nome ou e-mail..."
            value={search}
            onChange={e => { setSearch(e.target.value); setPage(1) }}
          />
        </div>
        <select className="rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none" value={roleF} onChange={e => { setRoleF(e.target.value); setPage(1) }}>
          <option value="">Todos os papéis</option>
          {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
        </select>
        <button onClick={load} className="rounded-lg border border-gray-200 px-3 py-2 text-sm text-gray-600 hover:bg-gray-50">
          <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
        </button>
      </div>

      {/* Tabs por status */}
      <div className="flex flex-wrap gap-1 overflow-x-auto rounded-xl border border-gray-200 bg-white p-1 shadow-sm">
        <button
          onClick={() => { setStatusF(''); setPage(1) }}
          className={`flex shrink-0 items-center gap-2 rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
            statusF === '' ? 'bg-brand-600 text-white' : 'text-gray-600 hover:bg-gray-100'
          }`}
        >
          Todos
          {meta.total > 0 && (
            <span className="rounded-full bg-white/30 px-1.5 py-0.5 text-[10px]">{meta.total}</span>
          )}
        </button>
        {STATUS_TABS.map((t) => {
          const active = statusF === t.value
          const count  = users.filter((u) => u.status === t.value).length
          return (
            <button
              key={t.value}
              onClick={() => { setStatusF(t.value); setPage(1) }}
              className={`flex shrink-0 items-center gap-2 rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
                active ? 'bg-brand-600 text-white' : `text-gray-600 hover:bg-gray-100 ${t.pill}`
              }`}
            >
              {t.label}
              {count > 0 && !active && (
                <span className="rounded-full bg-white/60 px-1.5 py-0.5 text-[10px]">{count}</span>
              )}
            </button>
          )
        })}
      </div>

      {/* Cards por tenant — cada tenant vira um card com sua própria tabela */}
      {loading ? (
        <div className="flex justify-center py-12 text-gray-400"><Loader2 size={20} className="animate-spin" /></div>
      ) : groupedByTenant.length === 0 ? (
        <div className="rounded-xl border border-gray-200 bg-white px-4 py-12 text-center text-gray-400">
          Nenhum usuário encontrado nos filtros atuais.
        </div>
      ) : (
        <div className="space-y-4">
          {groupedByTenant.map((group) => (
            <div key={group.id ?? 'master'} className={`overflow-hidden rounded-xl border bg-white shadow-sm ${
              group.isMaster ? 'border-purple-200' : 'border-gray-200'
            }`}>
              {/* Header do tenant */}
              <div className={`flex items-center justify-between border-b px-4 py-3 ${
                group.isMaster ? 'border-purple-100 bg-purple-50/50' : 'border-gray-100 bg-gray-50'
              }`}>
                <div className="flex items-center gap-2.5">
                  {group.isMaster ? (
                    <Shield size={16} className="text-purple-600" />
                  ) : (
                    <Users size={16} className="text-brand-600" />
                  )}
                  <div>
                    {group.isMaster ? (
                      <h3 className="text-sm font-semibold text-purple-900">{group.name}</h3>
                    ) : (
                      <Link href={`/master/tenants/${group.id}`} className="flex items-center gap-1 text-sm font-semibold text-gray-800 hover:text-brand-700 hover:underline">
                        {group.name}
                        <ExternalLink size={11} />
                      </Link>
                    )}
                    <p className="text-[11px] text-gray-500">
                      {group.users.length} usuário{group.users.length !== 1 ? 's' : ''}
                    </p>
                  </div>
                </div>
                <span className="rounded-full bg-gray-100 px-2.5 py-0.5 text-xs font-medium text-gray-600">
                  {group.users.length}
                </span>
              </div>

              {/* Tabela do tenant */}
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="border-b border-gray-100 bg-gray-50/50">
                    <tr>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500">Usuário</th>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500">Papel</th>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500">Cargo</th>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500">Status</th>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500">Último login</th>
                      <th className="px-4 py-2.5 text-left text-xs font-medium uppercase tracking-wide text-gray-500 w-[140px]">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {group.users.map((u) => (
                      <tr key={u.id} className="hover:bg-gray-50">
                        <td className="px-4 py-2.5">
                          <p className="font-medium text-gray-900">{u.name}</p>
                          <p className="text-xs text-gray-400">{u.email}</p>
                          {u.mustChangePassword && (
                            <span className="text-[10px] font-medium text-amber-600">⚠ Troca de senha pendente</span>
                          )}
                        </td>
                        <td className="px-4 py-2.5">
                          <span className={`inline-flex rounded-full border px-2 py-0.5 text-xs font-medium ${ROLE_COLOR[u.role] ?? 'bg-gray-100 text-gray-700'}`}>
                            {u.role}
                          </span>
                        </td>
                        <td className="px-4 py-2.5 text-xs text-gray-600">
                          {u.position ? u.position.name : <span className="text-gray-300">—</span>}
                        </td>
                        <td className="px-4 py-2.5">
                          <span className={`inline-flex rounded-full border px-2 py-0.5 text-xs font-medium ${STATUS_COLOR[u.status] ?? ''}`}>
                            {u.status}
                          </span>
                        </td>
                        <td className="px-4 py-2.5 text-xs text-gray-500">{fmtDate(u.lastLoginAt)}</td>
                        <td className="px-4 py-2.5">
                          <div className="flex items-center gap-1">
                            <button onClick={() => setEditUser(u)} title="Editar"
                              className="rounded p-1 text-gray-400 hover:bg-blue-50 hover:text-blue-600"
                            ><Edit2 size={13} /></button>
                            <button onClick={() => setResetUser(u)} title="Resetar senha"
                              className="rounded p-1 text-gray-400 hover:bg-amber-50 hover:text-amber-600"
                            ><Key size={13} /></button>
                            {u.status === 'ATIVO' ? (
                              <button onClick={() => quickStatus(u, 'BLOQUEADO')} title="Bloquear"
                                className="rounded p-1 text-gray-400 hover:bg-red-50 hover:text-red-600"
                              ><UserX size={13} /></button>
                            ) : (
                              <button onClick={() => quickStatus(u, 'ATIVO')} title="Reativar"
                                className="rounded p-1 text-gray-400 hover:bg-emerald-50 hover:text-emerald-600"
                              ><UserCheck size={13} /></button>
                            )}
                            {u.status === 'INATIVO' ? (
                              <button onClick={() => setPurgeUser(u)} title="EXCLUIR PERMANENTEMENTE (force purge)"
                                className="rounded p-1 text-red-500 hover:bg-red-100 hover:text-red-800"
                              ><Trash2 size={13} /></button>
                            ) : (
                              <button onClick={() => setDeleteUser(u)} title="Inativar (soft delete)"
                                className="rounded p-1 text-gray-400 hover:bg-red-50 hover:text-red-700"
                              ><Trash2 size={13} /></button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Paginação global */}
      {meta.pages > 1 && (
        <div className="flex items-center justify-between rounded-xl border border-gray-200 bg-white px-4 py-3 shadow-sm">
          <p className="text-xs text-gray-500">
            {((page - 1) * meta.limit) + 1}–{Math.min(page * meta.limit, meta.total)} de {meta.total} usuários
          </p>
          <div className="flex items-center gap-1">
            <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1}
              className="rounded p-1.5 text-gray-500 hover:bg-gray-100 disabled:opacity-40"
            ><ChevronLeft size={14} /></button>
            <span className="px-2 text-xs text-gray-700">{page} / {meta.pages}</span>
            <button onClick={() => setPage(p => Math.min(meta.pages, p + 1))} disabled={page === meta.pages}
              className="rounded p-1.5 text-gray-500 hover:bg-gray-100 disabled:opacity-40"
            ><ChevronRight size={14} /></button>
          </div>
        </div>
      )}

      {/* Modals */}
      {editUser  && <EditModal  user={editUser}  positions={positions} onClose={() => setEditUser(null)}  onSaved={handleSaved} />}
      {resetUser && <ResetPasswordModal user={resetUser} onClose={() => setResetUser(null)} onSaved={handleSaved} />}
      {deleteUser && (
        <DeleteUserModal
          user={deleteUser}
          isSelf={session?.user?.id === deleteUser.id}
          onClose={() => setDeleteUser(null)}
          onDeleted={(msg) => {
            setDeleteUser(null)
            load()
            if (msg) {
              setSuccess(msg)
              setTimeout(() => setSuccess(''), 4000)
            }
          }}
        />
      )}
      {purgeUser && (
        <PurgeUserModal
          user={purgeUser}
          isSelf={session?.user?.id === purgeUser.id}
          onClose={() => setPurgeUser(null)}
          onPurged={(msg) => {
            setPurgeUser(null)
            load()
            if (msg) {
              setSuccess(msg)
              setTimeout(() => setSuccess(''), 5000)
            }
          }}
        />
      )}
    </div>
  )
}

'use client'

// =============================================================================
// Gerenciar Metas — AutoDrive (tela de gestão sobre /api/goals)
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import { Plus, Pencil, Trash2, Target, X, Save, CheckCircle, AlertCircle, RefreshCw } from 'lucide-react'
import { cn } from '@/lib/utils'

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface GoalLevel { level: number; targetValue: number; label?: string | null }
interface Goal {
  id:          string
  type:        string
  scope:       string
  period:      string
  title:       string | null
  unitId:      string | null
  userId:      string | null
  startDate:   string
  endDate:     string
  targetValue: number | string
  measureUnit: string
  progressive: boolean
  status:      string
  levels:      GoalLevel[]
}

interface Option { value: string; label: string }

const TYPES: Option[] = [
  { value: 'SALES_EXCHANGE', label: 'Vendas e Trocas' },
  { value: 'PURCHASE', label: 'Compras' },
  { value: 'RETURN', label: 'Retornos' },
  { value: 'DOCUMENTATION', label: 'Documentação' },
  { value: 'EXTENDED_WARRANTY', label: 'Garantia Estendida' },
  { value: 'SERVICE', label: 'Serviços' },
]
const SCOPES: Option[] = [
  { value: 'USER', label: 'Vendedor' },
  { value: 'UNIT', label: 'Unidade' },
  { value: 'TENANT', label: 'Loja inteira' },
]
const PERIODS: Option[] = [
  { value: 'DAILY', label: 'Diário' },
  { value: 'WEEKLY', label: 'Semanal' },
  { value: 'MONTHLY', label: 'Mensal' },
  { value: 'QUARTERLY', label: 'Trimestral' },
  { value: 'YEARLY', label: 'Anual' },
  { value: 'CUSTOM', label: 'Personalizado' },
]
const UNITS_MEASURE: Option[] = [
  { value: 'QTD', label: 'Quantidade' },
  { value: 'BRL', label: 'Reais (R$)' },
  { value: 'PERCENT', label: 'Percentual (%)' },
]

const labelOf = (opts: Option[], v: string) => opts.find((o) => o.value === v)?.label ?? v

interface GoalForm {
  type: string; scope: string; period: string; title: string
  unitId: string; userId: string
  startDate: string; endDate: string
  targetValue: number; measureUnit: string
  progressive: boolean; levels: GoalLevel[]
}

const today = () => new Date().toISOString().slice(0, 10)
const emptyForm: GoalForm = {
  type: 'SALES_EXCHANGE', scope: 'USER', period: 'MONTHLY', title: '',
  unitId: '', userId: '', startDate: today(), endDate: today(),
  targetValue: 0, measureUnit: 'QTD', progressive: false, levels: [],
}

function inputClass(extra?: string) {
  return cn(
    'w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500',
    extra,
  )
}

// ── Modal ─────────────────────────────────────────────────────────────────────

function Modal({
  open, onClose, onSave, initial, saving, error, units, sellers,
}: {
  open: boolean
  onClose: () => void
  onSave: (data: GoalForm) => Promise<void>
  initial?: Goal | null
  saving: boolean
  error: string | null
  units: Option[]
  sellers: Option[]
}) {
  const [form, setForm] = useState<GoalForm>(emptyForm)

  useEffect(() => {
    if (!open) return
    if (initial) {
      setForm({
        type: initial.type, scope: initial.scope, period: initial.period,
        title: initial.title ?? '', unitId: initial.unitId ?? '', userId: initial.userId ?? '',
        startDate: initial.startDate.slice(0, 10), endDate: initial.endDate.slice(0, 10),
        targetValue: Number(initial.targetValue), measureUnit: initial.measureUnit,
        progressive: initial.progressive, levels: initial.levels ?? [],
      })
    } else {
      setForm({ ...emptyForm })
    }
  }, [open, initial])

  if (!open) return null

  const set = <K extends keyof GoalForm>(key: K, value: GoalForm[K]) =>
    setForm((prev) => ({ ...prev, [key]: value }))

  const setLevel = (i: number, patch: Partial<GoalLevel>) =>
    setForm((prev) => ({ ...prev, levels: prev.levels.map((l, idx) => (idx === i ? { ...l, ...patch } : l)) }))
  const addLevel = () =>
    setForm((prev) => ({ ...prev, levels: [...prev.levels, { level: prev.levels.length + 1, targetValue: 0, label: '' }] }))
  const removeLevel = (i: number) =>
    setForm((prev) => ({ ...prev, levels: prev.levels.filter((_, idx) => idx !== i).map((l, idx) => ({ ...l, level: idx + 1 })) }))

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative w-full max-w-2xl max-h-[90vh] overflow-y-auto rounded-2xl bg-white shadow-2xl">
        <div className="sticky top-0 z-10 flex items-center justify-between border-b border-gray-200 bg-white px-6 py-4">
          <div className="flex items-center gap-3">
            <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-brand-50">
              <Target className="h-5 w-5 text-brand-700" />
            </div>
            <h2 className="text-base font-semibold text-gray-900">{initial ? 'Editar Meta' : 'Nova Meta'}</h2>
          </div>
          <button onClick={onClose} className="rounded-lg p-1.5 text-gray-400 hover:bg-gray-100 hover:text-gray-600">
            <X className="h-5 w-5" />
          </button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSave(form) }} className="space-y-4 px-6 py-5">
          <div className="grid gap-4 sm:grid-cols-2">
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Tipo *</label>
              <select className={inputClass()} value={form.type} onChange={(e) => set('type', e.target.value)}>
                {TYPES.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Escopo *</label>
              <select className={inputClass()} value={form.scope} onChange={(e) => set('scope', e.target.value)}>
                {SCOPES.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
            </div>

            {form.scope === 'UNIT' && (
              <div className="sm:col-span-2">
                <label className="mb-1.5 block text-xs font-medium text-gray-700">Unidade *</label>
                <select className={inputClass()} value={form.unitId} onChange={(e) => set('unitId', e.target.value)}>
                  <option value="">Selecione...</option>
                  {units.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
              </div>
            )}
            {form.scope === 'USER' && (
              <div className="sm:col-span-2">
                <label className="mb-1.5 block text-xs font-medium text-gray-700">Vendedor *</label>
                <select className={inputClass()} value={form.userId} onChange={(e) => set('userId', e.target.value)}>
                  <option value="">Selecione...</option>
                  {sellers.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
              </div>
            )}

            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Título (opcional)</label>
              <input className={inputClass()} value={form.title} onChange={(e) => set('title', e.target.value)} placeholder="Ex: Meta de vendas — junho" />
            </div>

            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Período *</label>
              <select className={inputClass()} value={form.period} onChange={(e) => set('period', e.target.value)}>
                {PERIODS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Unidade de medida *</label>
              <select className={inputClass()} value={form.measureUnit} onChange={(e) => set('measureUnit', e.target.value)}>
                {UNITS_MEASURE.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
            </div>

            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Início *</label>
              <input type="date" className={inputClass()} value={form.startDate} onChange={(e) => set('startDate', e.target.value)} />
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Fim *</label>
              <input type="date" className={inputClass()} value={form.endDate} onChange={(e) => set('endDate', e.target.value)} />
            </div>

            <div className="sm:col-span-2">
              <label className="mb-1.5 block text-xs font-medium text-gray-700">Alvo base *</label>
              <input
                type="number" min={0} step="any" className={inputClass()}
                value={form.targetValue}
                onChange={(e) => set('targetValue', Number(e.target.value))}
              />
            </div>
          </div>

          {/* Progressão por níveis */}
          <div className="rounded-lg border border-gray-200 bg-gray-50 p-4">
            <div className="flex items-center justify-between">
              <span className="text-sm font-medium text-gray-700">Metas progressivas (níveis)</span>
              <button
                type="button" role="switch" aria-checked={form.progressive}
                onClick={() => set('progressive', !form.progressive)}
                className={cn('relative inline-flex h-6 w-11 items-center rounded-full transition-colors', form.progressive ? 'bg-brand-600' : 'bg-gray-300')}
              >
                <span className={cn('inline-block h-4 w-4 rounded-full bg-white shadow transition-transform', form.progressive ? 'translate-x-6' : 'translate-x-1')} />
              </button>
            </div>

            {form.progressive && (
              <div className="mt-3 space-y-2">
                {form.levels.map((lvl, i) => (
                  <div key={i} className="flex items-center gap-2">
                    <span className="w-14 shrink-0 text-xs font-semibold text-gray-500">Nível {lvl.level}</span>
                    <input
                      type="number" min={0} step="any" placeholder="Alvo"
                      className={inputClass('flex-1')}
                      value={lvl.targetValue}
                      onChange={(e) => setLevel(i, { targetValue: Number(e.target.value) })}
                    />
                    <input
                      placeholder="Rótulo (ex: Bronze)"
                      className={inputClass('flex-1')}
                      value={lvl.label ?? ''}
                      onChange={(e) => setLevel(i, { label: e.target.value })}
                    />
                    <button type="button" onClick={() => removeLevel(i)} className="rounded-lg p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600">
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                ))}
                <button type="button" onClick={addLevel} className="flex items-center gap-1.5 text-xs font-medium text-brand-700 hover:underline">
                  <Plus className="h-3.5 w-3.5" /> Adicionar nível
                </button>
              </div>
            )}
          </div>

          {error && (
            <div className="flex items-center gap-2 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-700">
              <AlertCircle className="h-4 w-4 shrink-0" />{error}
            </div>
          )}

          <div className="flex justify-end gap-3 border-t border-gray-100 pt-4">
            <button type="button" onClick={onClose} className="rounded-lg border border-gray-300 px-5 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50">Cancelar</button>
            <button type="submit" disabled={saving} className="flex items-center gap-2 rounded-lg bg-brand-700 px-5 py-2.5 text-sm font-medium text-white hover:bg-brand-800 disabled:opacity-60">
              <Save className="h-4 w-4" />{saving ? 'Salvando...' : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── Página ────────────────────────────────────────────────────────────────────

export default function MetasPage() {
  const [goals, setGoals] = useState<Goal[]>([])
  const [units, setUnits] = useState<Option[]>([])
  const [sellers, setSellers] = useState<Option[]>([])
  const [loading, setLoading] = useState(true)
  const [modalOpen, setModalOpen] = useState(false)
  const [editing, setEditing] = useState<Goal | null>(null)
  const [saving, setSaving] = useState(false)
  const [saveError, setSaveError] = useState<string | null>(null)
  const [msg, setMsg] = useState<string | null>(null)

  const flash = (m: string) => { setMsg(m); setTimeout(() => setMsg(null), 3000) }

  const fetchGoals = useCallback(async () => {
    setLoading(true)
    try {
      const res = await fetch('/api/goals', { credentials: 'include' })
      const json = await res.json()
      setGoals(json?.data ?? [])
    } catch { setGoals([]) } finally { setLoading(false) }
  }, [])

  useEffect(() => {
    fetchGoals()
    fetch('/api/units', { credentials: 'include' })
      .then((r) => r.json())
      .then((j) => setUnits((j?.data ?? []).map((u: { id: string; name: string }) => ({ value: u.id, label: u.name }))))
      .catch(() => {})
    fetch('/api/sellers', { credentials: 'include' })
      .then((r) => r.json())
      .then((j) => setSellers((j?.data ?? [])
        .filter((s: { userId?: string }) => s.userId)
        .map((s: { userId: string; fullName: string }) => ({ value: s.userId, label: s.fullName }))))
      .catch(() => {})
  }, [fetchGoals])

  const openCreate = () => { setEditing(null); setSaveError(null); setModalOpen(true) }
  const openEdit = (g: Goal) => { setEditing(g); setSaveError(null); setModalOpen(true) }

  const handleSave = async (data: GoalForm) => {
    setSaving(true); setSaveError(null)
    try {
      const body = {
        type: data.type, scope: data.scope, period: data.period,
        title: data.title || null,
        unitId: data.scope === 'UNIT' ? data.unitId : null,
        userId: data.scope === 'USER' ? data.userId : null,
        startDate: data.startDate, endDate: data.endDate,
        targetValue: data.targetValue, measureUnit: data.measureUnit,
        progressive: data.progressive,
        ...(data.progressive
          ? { levels: data.levels.map((l) => ({ level: l.level, targetValue: l.targetValue, label: l.label || null })) }
          : {}),
      }

      let goalId = editing?.id
      if (editing) {
        const res = await fetch(`/api/goals/${editing.id}`, {
          method: 'PATCH', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body),
        })
        if (!res.ok) throw new Error((await res.json())?.error ?? 'Erro ao salvar')
        // Sincroniza níveis (substituição completa) na edição.
        const lvls = data.progressive ? data.levels.map((l) => ({ level: l.level, targetValue: l.targetValue, label: l.label || null })) : []
        await fetch(`/api/goals/${editing.id}/levels`, {
          method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ levels: lvls }),
        })
      } else {
        const res = await fetch('/api/goals', {
          method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body),
        })
        if (!res.ok) throw new Error((await res.json())?.error ?? 'Erro ao criar')
        goalId = (await res.json())?.data?.id
      }

      setModalOpen(false)
      flash(editing ? 'Meta atualizada!' : 'Meta criada!')
      await fetchGoals()
      void goalId
    } catch (err) {
      setSaveError(err instanceof Error ? err.message : 'Erro ao salvar.')
    } finally { setSaving(false) }
  }

  const handleDelete = async (g: Goal) => {
    if (!confirm('Excluir esta meta? Os níveis e o progresso serão removidos.')) return
    try {
      const res = await fetch(`/api/goals/${g.id}`, { method: 'DELETE', credentials: 'include' })
      if (!res.ok) throw new Error()
      flash('Meta excluída.')
      await fetchGoals()
    } catch { flash('Erro ao excluir.') }
  }

  const recompute = async (g: Goal) => {
    try {
      const res = await fetch(`/api/goals/${g.id}/progress`, { method: 'POST', credentials: 'include' })
      if (!res.ok) throw new Error()
      flash('Progresso recalculado.')
    } catch { flash('Erro ao recalcular.') }
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Metas</h1>
          <p className="mt-1 text-sm text-gray-500">Configure metas por vendedor, unidade ou loja, com níveis progressivos.</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 rounded-lg bg-brand-700 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-800">
          <Plus className="h-4 w-4" />Nova Meta
        </button>
      </div>

      {msg && (
        <div className="flex items-center gap-2 rounded-lg bg-green-50 px-4 py-3 text-sm font-medium text-green-700">
          <CheckCircle className="h-4 w-4" />{msg}
        </div>
      )}

      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="border-b border-gray-200 bg-gray-50 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                {['Tipo', 'Escopo', 'Período', 'Alvo', 'Níveis', 'Status', 'Ações'].map((h) => (
                  <th key={h} className="whitespace-nowrap px-4 py-3">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                Array.from({ length: 4 }).map((_, i) => (
                  <tr key={i} className="border-b border-gray-100">
                    {Array.from({ length: 7 }).map((_, j) => (
                      <td key={j} className="px-4 py-3"><div className="h-4 animate-pulse rounded bg-gray-200" /></td>
                    ))}
                  </tr>
                ))
              ) : goals.length === 0 ? (
                <tr>
                  <td colSpan={7} className="py-12 text-center text-sm text-gray-400">
                    Nenhuma meta cadastrada. <button onClick={openCreate} className="text-brand-600 hover:underline">Criar agora</button>
                  </td>
                </tr>
              ) : (
                goals.map((g) => (
                  <tr key={g.id} className="border-b border-gray-100 hover:bg-gray-50">
                    <td className="px-4 py-3 font-medium text-gray-900">{g.title || labelOf(TYPES, g.type)}</td>
                    <td className="px-4 py-3 text-gray-600">{labelOf(SCOPES, g.scope)}</td>
                    <td className="px-4 py-3 text-gray-600">{labelOf(PERIODS, g.period)}</td>
                    <td className="px-4 py-3 tabular-nums text-gray-700">
                      {Number(g.targetValue).toLocaleString('pt-BR')} {g.measureUnit}
                    </td>
                    <td className="px-4 py-3 text-gray-600">{g.progressive ? `${g.levels?.length ?? 0} níveis` : '—'}</td>
                    <td className="px-4 py-3">
                      <span className={cn('rounded-full px-2 py-0.5 text-xs font-medium',
                        g.status === 'ATIVA' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500')}>
                        {g.status}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        <button onClick={() => recompute(g)} className="rounded-lg p-1.5 text-gray-400 hover:bg-blue-50 hover:text-blue-700" title="Recalcular progresso">
                          <RefreshCw className="h-4 w-4" />
                        </button>
                        <button onClick={() => openEdit(g)} className="rounded-lg p-1.5 text-gray-400 hover:bg-brand-50 hover:text-brand-700" title="Editar">
                          <Pencil className="h-4 w-4" />
                        </button>
                        <button onClick={() => handleDelete(g)} className="rounded-lg p-1.5 text-gray-400 hover:bg-red-50 hover:text-red-600" title="Excluir">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <Modal
        open={modalOpen} onClose={() => setModalOpen(false)} onSave={handleSave}
        initial={editing} saving={saving} error={saveError} units={units} sellers={sellers}
      />
    </div>
  )
}

'use client'

// =============================================================================
// AttachmentUploader — botão inline pra anexar comprovante a uma linha do
// resumo financeiro (pagamento, débito, quitação, troco) ou avulso (NFe, etc).
//
// Mostra:
//   - botão "Anexar" se nada anexado ainda
//   - chip clicável (download/preview) + botão excluir se já tem anexo
//
// Multi-anexo: o backend aceita N anexos por linha — exibimos todos.
// =============================================================================

import { useState } from 'react'
import { Paperclip, Trash2, Loader2, FileText, Image as ImageIcon, X } from 'lucide-react'

export interface Attachment {
  id:         string
  category:   string
  fileName:   string
  fileType:   string
  mimeType:   string
  publicUrl:  string | null
  notes:      string | null
  paymentId:  string | null
  debtId:     string | null
  vehicleId:  string | null
  changeId:   string | null
  uploadedByName: string | null
  uploadedAt: string
}

interface Props {
  dealId:      string
  category:    string                          // DealAttachmentCategory
  attachments: Attachment[]                    // anexos JÁ FILTRADOS dessa linha
  linkKey?:    'paymentId' | 'debtId' | 'vehicleId' | 'changeId'
  linkValue?:  string
  compact?:    boolean                          // versão menor pra linha
  canDelete?:  boolean
  onChange:    () => void                       // recarrega lista no parent
  onToast?:    (msg: string, ok?: boolean) => void
}

const ACCEPT = 'image/*,application/pdf,text/xml,application/xml'

export default function AttachmentUploader({
  dealId, category, attachments, linkKey, linkValue, compact, canDelete = true, onChange, onToast,
}: Props) {
  const [uploading, setUploading] = useState(false)
  const [deletingId, setDeletingId] = useState<string | null>(null)

  async function handleUpload(file: File) {
    if (!file) return
    setUploading(true)
    try {
      const fd = new FormData()
      fd.append('file', file)
      fd.append('category', category)
      if (linkKey && linkValue) fd.append(linkKey, linkValue)
      const res = await fetch(`/api/negotiations/${dealId}/attachments`, { method: 'POST', body: fd })
      const data = await res.json().catch(() => null)
      if (!res.ok) throw new Error(data?.error ?? 'Falha no upload')
      onToast?.('Anexo enviado', true)
      onChange()
    } catch (e) {
      onToast?.(e instanceof Error ? e.message : 'Erro no upload', false)
    } finally {
      setUploading(false)
    }
  }

  async function handleDelete(id: string) {
    if (!confirm('Remover este anexo?')) return
    setDeletingId(id)
    try {
      const res = await fetch(`/api/negotiations/${dealId}/attachments/${id}`, { method: 'DELETE' })
      if (!res.ok) {
        const data = await res.json().catch(() => null)
        throw new Error(data?.error ?? 'Falha ao remover')
      }
      onToast?.('Anexo removido', true)
      onChange()
    } catch (e) {
      onToast?.(e instanceof Error ? e.message : 'Erro ao remover', false)
    } finally {
      setDeletingId(null)
    }
  }

  const sizeBtn = compact ? 'px-2 py-1 text-[11px]' : 'px-3 py-1.5 text-xs'
  const sizeIcon = compact ? 11 : 12

  return (
    <div className="flex flex-wrap items-center gap-1.5">
      {attachments.map((a) => {
        const isImage = a.fileType === 'image'
        return (
          <span
            key={a.id}
            className="inline-flex items-center gap-1 rounded-full border border-green-200 bg-green-50 px-2 py-0.5 text-[11px] text-green-800"
            title={a.fileName}
          >
            {isImage ? <ImageIcon size={sizeIcon} /> : <FileText size={sizeIcon} />}
            {a.publicUrl ? (
              <a href={a.publicUrl} target="_blank" rel="noopener noreferrer" className="max-w-[160px] truncate hover:underline">
                {a.fileName}
              </a>
            ) : (
              <span className="max-w-[160px] truncate">{a.fileName}</span>
            )}
            {canDelete && (
              <button
                onClick={() => handleDelete(a.id)}
                disabled={deletingId === a.id}
                className="rounded-full p-0.5 hover:bg-red-100 hover:text-red-700 disabled:opacity-50"
                title="Remover"
              >
                {deletingId === a.id ? <Loader2 size={sizeIcon} className="animate-spin" /> : <X size={sizeIcon} />}
              </button>
            )}
          </span>
        )
      })}

      <label className={`inline-flex cursor-pointer items-center gap-1 rounded-md border border-gray-300 bg-white font-medium text-gray-700 hover:bg-gray-50 ${sizeBtn} ${uploading ? 'opacity-60 pointer-events-none' : ''}`}>
        {uploading ? <Loader2 size={sizeIcon} className="animate-spin" /> : <Paperclip size={sizeIcon} />}
        {attachments.length > 0 ? 'Anexar outro' : 'Anexar'}
        <input
          type="file"
          accept={ACCEPT}
          className="hidden"
          onChange={(e) => {
            const f = e.target.files?.[0]
            e.currentTarget.value = '' // permite re-anexar mesmo arquivo
            if (f) handleUpload(f)
          }}
        />
      </label>
    </div>
  )
}

'use client'

// =============================================================================
// ContractsTab — Aba "Contratos & Termos" na detalhe da negociação.
//
// O gerente/financeiro lista templates disponíveis (cadastrados pelo MASTER ou
// pelo próprio tenant), gera o documento (merge automático com dados do deal)
// e visualiza/baixa. Depois pode anexar a versão assinada como anexo da
// categoria CONTRATO_ASSINADO/PROCURACAO_ASSINADA.
// =============================================================================

import { useEffect, useState } from 'react'
import { FileText, Plus, Loader2, Eye, CheckCircle2, Trash2, Download, X, Pencil } from 'lucide-react'
import AttachmentUploader, { type Attachment } from './AttachmentUploader'

interface Template {
  id:          string
  name:        string
  type:        string
  description: string | null
  tenantId:    string | null
}

interface DealDocument {
  id:        string
  name:      string
  type:      string
  bodyHtml:  string | null
  pdfUrl:    string | null
  signedFileUrl: string | null
  signedAt:  string | null
  status:    string
  createdAt: string
}

const TYPE_LABEL: Record<string, string> = {
  CONTRATO_COMPRA:        'Contrato de Compra',
  CONTRATO_VENDA:         'Contrato de Venda',
  CONTRATO_TROCA:         'Contrato de Troca',
  CONTRATO_CONSIGNACAO:   'Contrato de Consignação',
  PROCURACAO:             'Procuração',
  RECIBO:                 'Recibo',
  TERMO_ENTREGA:          'Termo de Entrega',
  TERMO_RESPONSABILIDADE: 'Termo de Responsabilidade',
  OUTRO:                  'Outro',
}

interface Props {
  dealId:      string
  dealType:    string
  attachments: Attachment[]
  onReloadAttachments: () => void
  onToast:     (msg: string, ok?: boolean) => void
}

export default function ContractsTab({ dealId, dealType, attachments, onReloadAttachments, onToast }: Props) {
  const [templates, setTemplates] = useState<Template[]>([])
  const [docs, setDocs]           = useState<DealDocument[]>([])
  const [loading, setLoading]     = useState(true)
  const [generating, setGenerating] = useState<string | null>(null)
  const [preview, setPreview]     = useState<DealDocument | null>(null)
  const [deletingId, setDeletingId] = useState<string | null>(null)

  async function load() {
    setLoading(true)
    try {
      const [tplRes, docRes] = await Promise.all([
        fetch('/api/admin/document-templates').then((r) => r.json()),
        fetch(`/api/negotiations/${dealId}/documents`).then((r) => r.json()),
      ])
      setTemplates(tplRes.data ?? [])
      setDocs(docRes.data ?? [])
    } catch {
      onToast('Erro ao carregar templates/documentos', false)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { load() }, [dealId])  // eslint-disable-line react-hooks/exhaustive-deps

  async function generate(tpl: Template) {
    setGenerating(tpl.id)
    try {
      const res = await fetch(`/api/negotiations/${dealId}/documents`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ templateId: tpl.id }),
      })
      const data = await res.json().catch(() => null)
      if (!res.ok) throw new Error(data?.error ?? 'Falha ao gerar documento')
      onToast(`${tpl.name} gerado`, true)
      load()
    } catch (e) {
      onToast(e instanceof Error ? e.message : 'Erro', false)
    } finally {
      setGenerating(null)
    }
  }

  async function deleteDoc(doc: DealDocument) {
    if (!confirm(`Remover "${doc.name}"?`)) return
    setDeletingId(doc.id)
    try {
      const res = await fetch(`/api/negotiations/${dealId}/documents/${doc.id}`, { method: 'DELETE' })
      if (!res.ok) {
        const d = await res.json().catch(() => null)
        throw new Error(d?.error ?? 'Falha ao remover')
      }
      onToast('Documento removido', true)
      load()
    } catch (e) {
      onToast(e instanceof Error ? e.message : 'Erro', false)
    } finally {
      setDeletingId(null)
    }
  }

  // Filtra templates pertinentes ao tipo do deal (mas sempre permite genéricos)
  const relevantTemplates = templates.filter((t) => {
    if (t.type === 'OUTRO' || t.type === 'PROCURACAO' || t.type === 'TERMO_ENTREGA' || t.type === 'TERMO_RESPONSABILIDADE' || t.type === 'RECIBO') return true
    if (dealType === 'COMPRA' && t.type === 'CONTRATO_COMPRA') return true
    if (dealType === 'VENDA'  && t.type === 'CONTRATO_VENDA')  return true
    if (dealType === 'TROCA'  && (t.type === 'CONTRATO_TROCA' || t.type === 'CONTRATO_VENDA' || t.type === 'CONTRATO_COMPRA')) return true
    if (dealType === 'CONSIGNACAO' && t.type === 'CONTRATO_CONSIGNACAO') return true
    return false
  })

  // Anexos: assinados (CONTRATO_ASSINADO, PROCURACAO_ASSINADA)
  const signedContracts  = attachments.filter((a) => a.category === 'CONTRATO_ASSINADO')
  const signedProcuracao = attachments.filter((a) => a.category === 'PROCURACAO_ASSINADA')

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 size={24} className="animate-spin text-brand-600" />
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Templates disponíveis */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="flex items-center justify-between border-b border-gray-100 bg-gray-50 px-4 py-3">
          <div className="flex items-center gap-2">
            <FileText size={15} className="text-brand-600" />
            <h3 className="font-semibold text-gray-800">Modelos disponíveis</h3>
          </div>
          <span className="text-xs text-gray-500">{relevantTemplates.length} modelo(s)</span>
        </div>
        <div className="p-4">
          {relevantTemplates.length === 0 ? (
            <p className="text-sm italic text-gray-400">
              Nenhum modelo cadastrado. O administrador deve cadastrar os modelos em <span className="font-medium">Admin → Documentos</span>.
            </p>
          ) : (
            <ul className="divide-y divide-gray-50">
              {relevantTemplates.map((t) => (
                <li key={t.id} className="flex flex-wrap items-center justify-between gap-3 py-2.5">
                  <div className="min-w-0">
                    <p className="truncate font-medium text-gray-800">{t.name}</p>
                    <p className="text-xs text-gray-500">
                      {TYPE_LABEL[t.type] ?? t.type}
                      {t.tenantId === null && <span className="ml-2 rounded-full bg-indigo-100 px-2 py-0.5 text-[10px] text-indigo-700">Padrão MASTER</span>}
                    </p>
                    {t.description && <p className="mt-0.5 text-xs text-gray-400 line-clamp-1">{t.description}</p>}
                  </div>
                  <button
                    onClick={() => generate(t)}
                    disabled={generating === t.id}
                    className="flex items-center gap-1.5 rounded-md bg-brand-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-brand-700 disabled:opacity-50"
                  >
                    {generating === t.id ? <Loader2 size={12} className="animate-spin" /> : <Plus size={12} />}
                    Gerar documento
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>

      {/* Documentos gerados */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="flex items-center justify-between border-b border-gray-100 bg-gray-50 px-4 py-3">
          <div className="flex items-center gap-2">
            <Pencil size={15} className="text-brand-600" />
            <h3 className="font-semibold text-gray-800">Documentos gerados</h3>
          </div>
          <span className="text-xs text-gray-500">{docs.length}</span>
        </div>
        <div className="p-4">
          {docs.length === 0 ? (
            <p className="text-sm italic text-gray-400">Nenhum documento gerado ainda.</p>
          ) : (
            <ul className="divide-y divide-gray-50">
              {docs.map((d) => (
                <li key={d.id} className="flex flex-wrap items-center justify-between gap-3 py-2.5">
                  <div className="min-w-0">
                    <p className="truncate font-medium text-gray-800">{d.name}</p>
                    <p className="text-xs text-gray-500">
                      {TYPE_LABEL[d.type] ?? d.type} · Gerado em {new Date(d.createdAt).toLocaleString('pt-BR')}
                      {d.signedAt && <span className="ml-2 rounded-full bg-green-100 px-2 py-0.5 text-[10px] text-green-700">Assinado</span>}
                    </p>
                  </div>
                  <div className="flex items-center gap-1">
                    <button
                      onClick={() => setPreview(d)}
                      className="flex items-center gap-1 rounded-md border border-gray-300 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-700 hover:bg-gray-50"
                    >
                      <Eye size={11} /> Visualizar
                    </button>
                    <button
                      onClick={() => deleteDoc(d)}
                      disabled={deletingId === d.id}
                      className="flex items-center gap-1 rounded-md border border-red-200 bg-white px-2.5 py-1.5 text-xs font-medium text-red-700 hover:bg-red-50 disabled:opacity-50"
                    >
                      {deletingId === d.id ? <Loader2 size={11} className="animate-spin" /> : <Trash2 size={11} />}
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>

      {/* Contratos assinados (upload) */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="flex items-center gap-2 border-b border-gray-100 bg-gray-50 px-4 py-3">
          <CheckCircle2 size={15} className="text-green-600" />
          <h3 className="font-semibold text-gray-800">Contrato assinado</h3>
        </div>
        <div className="p-4">
          <AttachmentUploader
            dealId={dealId}
            category="CONTRATO_ASSINADO"
            attachments={signedContracts}
            onChange={onReloadAttachments}
            onToast={onToast}
          />
        </div>
      </div>

      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="flex items-center gap-2 border-b border-gray-100 bg-gray-50 px-4 py-3">
          <CheckCircle2 size={15} className="text-green-600" />
          <h3 className="font-semibold text-gray-800">Procuração assinada</h3>
        </div>
        <div className="p-4">
          <AttachmentUploader
            dealId={dealId}
            category="PROCURACAO_ASSINADA"
            attachments={signedProcuracao}
            onChange={onReloadAttachments}
            onToast={onToast}
          />
        </div>
      </div>

      {/* Modal de preview */}
      {preview && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="flex h-[90vh] w-full max-w-4xl flex-col rounded-2xl bg-white shadow-2xl">
            <div className="flex items-center justify-between border-b border-gray-200 px-5 py-3">
              <h3 className="font-semibold text-gray-900">{preview.name}</h3>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => window.print()}
                  className="flex items-center gap-1 rounded-md border border-gray-300 bg-white px-2.5 py-1.5 text-xs font-medium text-gray-700 hover:bg-gray-50"
                >
                  <Download size={11} /> Imprimir / PDF
                </button>
                <button onClick={() => setPreview(null)} className="rounded-md p-1.5 text-gray-400 hover:bg-gray-100">
                  <X size={16} />
                </button>
              </div>
            </div>
            <div className="flex-1 overflow-auto p-6">
              <div
                className="prose prose-sm max-w-none"
                // O conteúdo vem do nosso template HTML cadastrado pelo MASTER; é controlado.
                dangerouslySetInnerHTML={{ __html: preview.bodyHtml ?? '<p>(sem conteúdo)</p>' }}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

