          >
            <ListIcon size={13} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button
            type="button"
            onClick={() => setViewMode('cards')}
            title="Exibir em cards"
            aria-pressed={viewMode === 'cards'}
