            <div className="text-center">
              <p className="font-semibold text-gray-600">Nenhuma negociação encontrada</p>
              <p className="mt-1 text-sm text-gray-400">
                {debouncedSearch || typeFilter || statusFilter
                  ? 'Tente ajustar os filtros.'
