import { useState, useEffect, useCallback } from 'react'
import { Activity, RefreshCw, Search, Filter } from 'lucide-react'
import { cn, formatDate } from '@/lib/utils'

interface StatusHistoryEntry {
  id:              string
  pendencyId:      string
  previousStatus:  string | null
  newStatus:       string
  note:            string | null
  changedByUserId: string
  changedAt:       string
  pendency?: {
    customerName: string
    plate:        string | null
  }
  changedByUser?: {
    name: string | null
  }
}

const STATUS_COLOR: Record<string, string> = {
  ABERTA:              'bg-amber-100 text-amber-700',
  EM_ANDAMENTO:        'bg-blue-100 text-blue-700',
  AGUARDANDO_RESPOSTA: 'bg-sky-100 text-sky-700',
  PAUSADA:             'bg-gray-100 text-gray-600',
  FINALIZADA:          'bg-green-100 text-green-700',
  REATIVADA:           'bg-violet-100 text-violet-700',
  CANCELADA:           'bg-red-100 text-red-600',
  VENCIDA:             'bg-orange-100 text-orange-700',
}

export default function LogsPage() {
  const [entries, setEntries]   = useState<StatusHistoryEntry[]>([])
  const [loading, setLoading]   = useState(true)
  const [page, setPage]         = useState(1)
  const [total, setTotal]       = useState(0)
  const [search, setSearch]     = useState('')

  const PER_PAGE = 50

  const fetchLogs = useCallback(async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams({ page: String(page), perPage: String(PER_PAGE) })
      if (search) params.set('search', search)
      const res  = await fetch(`/api/logs/status?${params}`, { credentials: 'include' })
      const data = await res.json()
      if (data.success) {
        setEntries(data.data ?? [])
        setTotal(data.meta?.total ?? 0)
      }
    } catch { /* silent */ }
    finally { setLoading(false) }
  }, [page, search])

  useEffect(() => { fetchLogs() }, [fetchLogs])

  const totalPages = Math.ceil(total / PER_PAGE)

  return (
    <div className="space-y-5">
      {/* ── Header ────────────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between">
