                ))
              ) : entries.length === 0 ? (
                <tr>
                  <td colSpan={6} className="py-14 text-center">
                    <Filter size={32} className="mx-auto mb-2 text-gray-300" strokeWidth={1} />
                    <p className="text-sm text-gray-400">Nenhum log encontrado</p>
                  </td>
                </tr>
              ) : (
