// =============================================================================
// /api/admin/document-templates
//   GET  → lista templates (MASTER vê todos; lojista vê os do tenant + globais).
//   POST → cria template (MASTER cria globais; ADM/GERENTE_GERAL cria do tenant).
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'

const VALID_TYPES = new Set([
  'CONTRATO_COMPRA', 'CONTRATO_VENDA', 'CONTRATO_TROCA', 'CONTRATO_CONSIGNACAO',
  'PROCURACAO', 'RECIBO', 'TERMO_ENTREGA', 'TERMO_RESPONSABILIDADE', 'OUTRO',
])

function canManage(role?: string): boolean {
  return role === 'MASTER' || role === 'ADM' || role === 'GERENTE_GERAL'
}

export async function GET(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    const type = req.nextUrl.searchParams.get('type') ?? undefined
    const where: any = {
      active: true,
      ...(type && VALID_TYPES.has(type) ? { type: type as any } : {}),
    }
    if (session.user.role !== 'MASTER') {
      where.OR = [{ tenantId: session.user.tenantId ?? null }, { tenantId: null }]
    }

    const data = await prisma.documentTemplate.findMany({
      where,
      orderBy: [{ tenantId: 'asc' }, { type: 'asc' }, { name: 'asc' }],
    })
    return NextResponse.json({ data })
  } catch (err) {
    return handlePrismaError(err)
  }
}

export async function POST(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  if (!canManage(session.user.role)) {
    return NextResponse.json({ error: 'Sem permissão para criar templates' }, { status: 403 })
  }

  try {
    const body = await req.json()
    const type = String(body?.type ?? '').toUpperCase()
    const name = String(body?.name ?? '').trim()
    const bodyHtml = String(body?.bodyHtml ?? '')

    if (!VALID_TYPES.has(type)) return NextResponse.json({ error: 'Tipo inválido' }, { status: 400 })
    if (!name) return NextResponse.json({ error: 'Nome é obrigatório' }, { status: 400 })
    if (!bodyHtml) return NextResponse.json({ error: 'Conteúdo (bodyHtml) é obrigatório' }, { status: 400 })

    // MASTER pode criar global (tenantId=null); outros forçam tenantId do user
    const tenantId = session.user.role === 'MASTER'
      ? (body?.tenantId ?? null)
      : (session.user.tenantId ?? null)

    const data = await prisma.documentTemplate.create({
      data: {
        tenantId,
        type:        type as any,
        name,
        description: body?.description ?? null,
        bodyHtml,
        variables:   body?.variables ?? null,
        active:      body?.active ?? true,
        isDefault:   Boolean(body?.isDefault),
        createdById: session.user.id,
      },
    })
    return NextResponse.json({ data }, { status: 201 })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// API: /api/commissions/return-rules — AutoDrive
// Regras de percentual de retorno
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { canAccessModule, canPerformAction } from '@/lib/permissions'

export async function POST(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canPerformAction(session.user.role, 'commissions.rules', 'create')) {
      return NextResponse.json({ success: false, error: 'Sem permissão' }, { status: 403 })
    }

    const body = await req.json().catch(() => null) as Record<string, unknown> | null
    if (!body) return NextResponse.json({ success: false, error: 'Corpo inválido' }, { status: 400 })

    const name = String(body.name ?? '').trim()
    const percentualInformado = Number(body.percentualInformado)
    const percentualAplicado  = Number(body.percentualAplicado)
    const bank        = body.bank        ? String(body.bank).trim()        : null
    const tipoRetorno = body.tipoRetorno ? String(body.tipoRetorno).trim() : null

    if (!name) {
      return NextResponse.json({ success: false, error: 'Nome obrigatório.' }, { status: 400 })
    }
    if (!Number.isFinite(percentualInformado) || !Number.isFinite(percentualAplicado)) {
      return NextResponse.json({ success: false, error: 'Percentuais inválidos.' }, { status: 400 })
    }

    const rule = await prisma.returnPercentRule.create({
      data: {
        tenantId: session.user.tenantId ?? null,
        name,
        percentualInformado,
        percentualAplicado,
        bank,
        tipoRetorno,
        active: true,
      },
    })

    return NextResponse.json({ success: true, data: rule }, { status: 201 })
  } catch (err) {
    console.error('[POST /api/commissions/return-rules]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canAccessModule(session.user.role, 'commissions')) return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })

    const rules = await prisma.returnPercentRule.findMany({
      orderBy: { percentualInformado: 'asc' },
    })

    return NextResponse.json({ success: true, data: rules })
  } catch (err) {
    console.error('[GET /api/commissions/return-rules]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// =============================================================================
// API: /api/commissions — AutoDrive
// Listagem e gravação de extratos de comissão
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { canAccessModule } from '@/lib/permissions'

// ── GET — lista extratos ──────────────────────────────────────────────────────
export async function GET(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canAccessModule(session.user.role, 'commissions')) {
      return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })
    }

    const { searchParams } = new URL(req.url)
    const page    = Math.max(1, Number(searchParams.get('page')    ?? 1))
    const perPage = Math.min(100, Number(searchParams.get('perPage') ?? 50))
    const status  = searchParams.get('status')  || undefined
    const period  = searchParams.get('period')  || undefined
    const seller  = searchParams.get('sellerId')|| undefined

    const where: Record<string, unknown> = {}
    if (status) where.status   = status
    if (period) where.period   = period
    if (seller) where.sellerId = seller

    // VENDEDOR vê apenas as próprias comissões
    if (['VENDEDOR', 'USUARIO_LIDER', 'USUARIO'].includes(session.user.role)) {
      const s = await prisma.seller.findFirst({ where: { userId: session.user.id } })
      if (s) {
        where.sellerId = s.id
        where.userId   = session.user.id
      }
    }

    const [total, data] = await Promise.all([
      prisma.commissionExtract.count({ where: where as any }),
      prisma.commissionExtract.findMany({
        where:   where as any,
        include: { seller: { select: { fullName: true, shortName: true } } },
        orderBy: [{ period: 'desc' }, { createdAt: 'desc' }],
        skip:    (page - 1) * perPage,
        take:    perPage,
      }),
    ])

    return NextResponse.json({
      success: true,
      data,
      meta: { total, page, perPage, totalPages: Math.ceil(total / perPage) },
    })
  } catch (err) {
    console.error('[GET /api/commissions]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// ── POST — grava extratos calculados ─────────────────────────────────────────
// Recebe: { period: string, results: Array<{sellerId, sellerName, baseValue, adjustments, finalValue}> }
// Cada item gera 1-3 entradas no CommissionExtract conforme valor
export async function POST(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canAccessModule(session.user.role, 'commissions.calculate')) {
      return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })
    }

    const { period, results } = await req.json() as {
      period: string
      results: Array<{ sellerId: string; sellerName: string; baseValue: number; adjustments: number; finalValue: number }>
    }

    if (!period || !Array.isArray(results) || results.length === 0) {
      return NextResponse.json({ success: false, error: 'Dados inválidos.' }, { status: 400 })
    }

    // Buscar userId de cada vendedor para preencher campo obrigatório
    const sellerIds = [...new Set(results.map((r) => r.sellerId))]
    const sellers   = await prisma.seller.findMany({
      where: { id: { in: sellerIds } },
      select: { id: true, userId: true, fullName: true, shortName: true },
    })
    const sellerMap = Object.fromEntries(sellers.map((s) => [s.id, s]))

    const creates: ReturnType<typeof prisma.commissionExtract.create>[] = []

    for (const r of results) {
      const seller = sellerMap[r.sellerId]
      if (!seller) continue
      const userId = seller.userId

      // Valor base
      if (r.baseValue !== 0) {
        creates.push(
          prisma.commissionExtract.create({
            data: {
              userId,
              sellerId:    r.sellerId,
              period,
              type:        'BASE',
              description: `Base — ${seller.shortName ?? seller.fullName}`,
              value:       r.baseValue,
              status:      'PREVISTO',
            },
          }),
        )
      }

      // Ajustes (positivo ou negativo)
      if (r.adjustments !== 0) {
        creates.push(
          prisma.commissionExtract.create({
            data: {
              userId,
              sellerId:    r.sellerId,
              period,
              type:        'AJUSTE',
              description: `Ajuste — ${seller.shortName ?? seller.fullName}`,
              value:       r.adjustments,
              status:      'PREVISTO',
            },
          }),
        )
      }
    }

    const created = await Promise.all(creates)

    return NextResponse.json({ success: true, data: created, count: created.length }, { status: 201 })
  } catch (err) {
    console.error('[POST /api/commissions]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// =============================================================================
// API: /api/commissions/rules/[id] — Editar e excluir regra de comissão
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { canAccessModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'

// ── PUT — Editar ──────────────────────────────────────────────────────────────

export async function PUT(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canAccessModule(session.user.role, 'commissions.rules')) return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })

    const rule = await prisma.commissionRule.findUnique({ where: { id: params.id } })
    if (!rule) return NextResponse.json({ success: false, error: 'Regra não encontrada.' }, { status: 404 })

    if (session.user.tenantId && rule.tenantId !== session.user.tenantId) {
      return NextResponse.json({ success: false, error: 'Acesso negado.' }, { status: 403 })
    }

    const body = await req.json()
    const {
      name, description, ruleType, commissionType,
      role, positionId, sellerId, managerId, unitId, serviceId, warrantyId, bank,
      fromQuantity, toQuantity, fromValue, toValue,
      fixedValue, percentage, priority, active,
      validFrom, validUntil, notes,
    } = body

    if (!name?.trim())   return NextResponse.json({ success: false, error: 'Nome é obrigatório.' }, { status: 400 })
