  try {
    const session = await getServerAuthSession()
    if (!session?.user) return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    if (!canAccessModule(session.user.role, 'documents.pdf')) return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })

    const body = await req.json()

    // TODO: match customer and vehicle by name/plate if they exist
    const contract = await prisma.contract.create({
      data: {
        number:  body.contractNumber ?? null,
        type:    'VENDA',
        status:  'ATIVO',
        rawData: body,
      },
    })

    return NextResponse.json({ success: true, data: contract }, { status: 201 })
  } catch (err) {
    console.error('[POST /api/documents/contracts]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// =============================================================================
// POST /api/evaluations/[id]/items/[itemId]/revaluate
//
// Reavaliação de item: cria um EvaluationService vinculado ao item, atualiza
// status/notes do item, registra história e recalcula totais.
//
// Body:
//   {
//     status?: 'CONFORME' | 'ATENCAO' | 'REPARO' | 'OBRIGATORIO' | 'REAVALIAR' | 'NA',
//     priority?: 'BAIXA' | 'MEDIA' | 'ALTA' | 'URGENTE',
//     itemNotes?: string,
//     service: {
//       serviceType: string,
//       description: string,
//       estimatedCost: number,
//       priority?: string,
//       notes?: string,
//       responsibleId?: string,
//     } | null  // null = só atualiza item (sem adicionar serviço novo)
//   }
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { loadEvaluationContext, recalcItemTotal, recalcTotals } from '@/lib/evaluation/service'
import { canRevaluateItem }     from '@/lib/evaluation/permissions'
import { recordHistory }        from '@/lib/evaluation/history'

export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string; itemId: string } | Promise<{ id: string; itemId: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    const ctx = await loadEvaluationContext(params.id)
    if (!ctx) return NextResponse.json({ error: 'Avaliação não encontrada' }, { status: 404 })

    const user = { id: session.user.id, role: session.user.role, tenantId: session.user.tenantId }
    if (!canRevaluateItem(user, ctx))
      return NextResponse.json({ error: 'Sem permissão para reavaliar' }, { status: 403 })

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const item: any = await (prisma as any).evaluationItem.findUnique({
      where: { id: params.itemId },
    })
    if (!item || item.evaluationId !== params.id)
      return NextResponse.json({ error: 'Item não encontrado' }, { status: 404 })

    const body = await req.json()
    const { status, priority, itemNotes, service } = body

    let newService = null

    await prisma.$transaction(async (tx) => {
      // 1) Atualiza item (status/priority/notes)
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const itemUpdates: any = {}
      if (status    !== undefined) itemUpdates.status   = status
      if (priority  !== undefined) itemUpdates.priority = priority
      if (itemNotes !== undefined) itemUpdates.notes    = itemNotes

      if (Object.keys(itemUpdates).length > 0) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await (tx as any).evaluationItem.update({
          where: { id: params.itemId },
          data:  itemUpdates,
        })
      }

      // 2) Cria service (se enviado)
      if (service && service.serviceType && service.description) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        newService = await (tx as any).evaluationService.create({
          data: {
            tenantId:     ctx.tenantId ?? null,
            evaluationId: params.id,
            itemId:       params.itemId,
            section:      item.section,
            description:  String(service.description),
            serviceType:  String(service.serviceType),
            estimatedCost: service.estimatedCost != null ? Number(service.estimatedCost) : 0,
            priority:     service.priority      ?? priority ?? null,
            notes:        service.notes         ?? null,
            responsibleId: service.responsibleId ?? null,
            status:       'PREDICTED',
            createdById:  session.user.id,
          },
        })
      }
    })

    // 3) Recalcula totais (item + avaliação)
    await recalcItemTotal(params.itemId)
    await recalcTotals(params.id)

    // 4) Histórico
    await recordHistory({
      tenantId:    ctx.tenantId ?? '',
      evaluationId:params.id,
      itemId:      params.itemId,
      serviceId:   (newService as { id?: string } | null)?.id ?? null,
      userId:      session.user.id,
      userName:    session.user.name,
      userRole:    session.user.role,
      action:      newService ? 'ADD_SERVICE' : 'REVALUATE',
      oldValue:    { status: item.status, priority: item.priority, notes: item.notes },
      newValue:    { status, priority, itemNotes, service },
    })

    // 5) Retornar item atualizado + service + total da avaliação
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const fresh: any = await (prisma as any).evaluationItem.findUnique({
      where: { id: params.itemId },
    })
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const services: any[] = await (prisma as any).evaluationService.findMany({
      where: { itemId: params.itemId, status: { not: 'CANCELED' } },
      orderBy: { createdAt: 'asc' },
    })
    const ev = await prisma.vehicleEvaluation.findUnique({
      where: { id: params.id },
      select: { totalExpenses: true, status: true },
    })

    // Marca a avaliação como IN_PROGRESS se ainda estava DRAFT
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    if ((ev as any)?.status === 'DRAFT') {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await prisma.vehicleEvaluation.update({
        where: { id: params.id },
        data:  { status: 'IN_PROGRESS' as never },
      }).catch(() => {})
    }

    return NextResponse.json({
      data: {
        item:          fresh,
        services,
        service:       newService,
        totalExpenses: ev?.totalExpenses ?? 0,
      },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// POST /api/evaluations/[id]/items/seed
// Cria os itens canônicos de checklist a partir do catálogo (idempotente).
// Útil quando a avaliação foi criada antes do reformulação ou via integração.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { loadEvaluationContext } from '@/lib/evaluation/service'
import { canEditEvaluation }    from '@/lib/evaluation/permissions'
import { ITEMS, type SectionKey } from '@/lib/evaluation/catalog'

export async function POST(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    const ctx = await loadEvaluationContext(params.id)
    if (!ctx) return NextResponse.json({ error: 'Avaliação não encontrada' }, { status: 404 })
    const user = { id: session.user.id, role: session.user.role, tenantId: session.user.tenantId }
    if (!canEditEvaluation(user, ctx))
      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })

    // Tudo em uma transação serializável: evita race condition quando o
    // frontend dispara 2x simultaneamente (ex: React Strict Mode em dev).
    // A 2ª chamada vê o estado depois da 1ª e nada cria.
    const result = await prisma.$transaction(async (tx) => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const existing: Array<{ catalogKey: string | null; section: string; name: string }> =
        await (tx as any).evaluationItem.findMany({
          where:  { evaluationId: params.id },
          select: { catalogKey: true, section: true, name: true },
        })

      // Dedup das chaves já presentes: catalogKey OU section+name normalizado.
      const have = new Set<string>()
      for (const e of existing) {
        if (e.catalogKey) have.add(`k::${e.catalogKey}`)
        have.add(`n::${e.section}::${e.name.trim().toLowerCase()}`)
      }

      const sections: SectionKey[] = ['INTERIOR', 'FRENTE', 'DIREITA', 'TRASEIRA', 'ESQUERDA', 'TEST_DRIVE']
      const rows = sections.flatMap((sec) =>
        ITEMS[sec]
          .filter((it) => {
            const kKey = `k::${it.key}`
            const nKey = `n::${sec}::${it.name.trim().toLowerCase()}`
            return !have.has(kKey) && !have.has(nKey)
          })
          .map((it) => ({
            tenantId:     ctx.tenantId ?? null,
            evaluationId: params.id,
            section:      sec,
            catalogKey:   it.key,
            name:         it.name,
            status:       'PENDING' as const,
            totalExpenses: 0,
          })),
      )

      if (rows.length === 0) return { created: 0 }

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (tx as any).evaluationItem.createMany({ data: rows })
      return { created: rows.length }
    }, { isolationLevel: 'Serializable' })

    return NextResponse.json({ data: result })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// POST /api/evaluations/[id]/submit-for-approval
//
// Avaliador/vendedor envia a avaliação para o gerente precificar e liberar.
// - Valida foto obrigatória por seção (mínimo 1 FOTO_SECAO ou FOTO em cada
//   seção INTERIOR/FRENTE/DIREITA/TRASEIRA/ESQUERDA/TEST_DRIVE).
// - Marca status='AGUARDANDO_APROVACAO' + approvalRequestedAt/ById.
// - Notifica gerentes (in-app sempre; email/whatsapp best-effort).
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { loadEvaluationContext } from '@/lib/evaluation/service'
import { canSubmitForApproval }  from '@/lib/evaluation/permissions'
import { recordHistory }        from '@/lib/evaluation/history'
import { notifyByRole }         from '@/services/notification.service'

const REQUIRED_SECTIONS = ['INTERIOR', 'FRENTE', 'DIREITA', 'TRASEIRA', 'ESQUERDA', 'TEST_DRIVE'] as const

export async function POST(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try {
    const ctx = await loadEvaluationContext(params.id)
    if (!ctx) return NextResponse.json({ error: 'Avaliação não encontrada' }, { status: 404 })

    const user = { id: session.user.id, role: session.user.role, tenantId: session.user.tenantId }
    if (!canSubmitForApproval(user, ctx)) {
      return NextResponse.json({ error: 'Sem permissão para enviar para aprovação.' }, { status: 403 })
    }

    // Valida que cada seção obrigatória tenha ao menos 1 foto.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const atts: Array<{ section: string | null; category: string | null; fileType: string }> =
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (prisma as any).evaluationAttachment.findMany({
        where: { evaluationId: params.id, fileType: 'image' },
        select: { section: true, category: true, fileType: true },
      })

    const present = new Set<string>()
    for (const a of atts) if (a.section) present.add(a.section)
    const missing = REQUIRED_SECTIONS.filter((s) => !present.has(s))
    if (missing.length > 0) {
      return NextResponse.json({
        error: `Foto obrigatória ausente nas seções: ${missing.join(', ')}. Envie ao menos 1 foto em cada seção antes de enviar para aprovação.`,
        missingSections: missing,
      }, { status: 400 })
    }

    const ev = await prisma.vehicleEvaluation.findUnique({
      where: { id: params.id },
      select: { plate: true, brand: true, model: true, tenantId: true },
    })

    const updated = await prisma.vehicleEvaluation.update({
      where: { id: params.id },
      data: {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        status: 'AGUARDANDO_APROVACAO' as any,
        approvalRequestedAt:   new Date(),
        approvalRequestedById: session.user.id,
      },
    })

    await recordHistory({
      tenantId: ctx.tenantId ?? '',
      evaluationId: params.id,
      userId: session.user.id,
      userName: session.user.name,
      userRole: session.user.role,
      action: 'SUBMIT_FOR_APPROVAL',
      oldValue: { status: ctx.status },
      newValue: { status: 'AGUARDANDO_APROVACAO' },
    }).catch(() => {})

    // Notifica gerentes — in-app sempre; email/whatsapp delegados ao serviço
    // (hoje placeholders mas estrutura pronta).
    if (ctx.tenantId) {
      const title = 'Nova avaliação para aprovar'
      const desc  = [ev?.plate, ev?.brand, ev?.model].filter(Boolean).join(' • ') || 'Avaliação'
      await notifyByRole({
        tenantId: ctx.tenantId,
        roles:    ['GERENTE', 'GERENTE_GERAL', 'ADM'],
        unitId:   ctx.unitId ?? undefined,
        type:     'SISTEMA',
        title,
        message:  `${desc} aguardando precificação e liberação.`,
        actionUrl: `/estoque/avaliacao/${params.id}/inspecao`,
        metadata:  { evaluationId: params.id },
        channels:  ['APP_WEB', 'EMAIL', 'WHATSAPP'],
      }).catch((e) => { console.error('[submit-for-approval] notify failed', e) })
    }

    return NextResponse.json({ data: updated })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// GET  /api/evaluations         — Listar avaliações (filtros por tenant/unit/status)
// POST /api/evaluations         — Criar nova avaliação (DRAFT). Opcionalmente
//                                  faz seed dos itens predefinidos do catálogo.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { requireModule }        from '@/lib/permissions'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { prisma }               from '@/lib/prisma'
import { ITEMS, type SectionKey } from '@/lib/evaluation/catalog'

export async function GET(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try { requireModule(session.user.role, 'stock.evaluate') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const { searchParams } = req.nextUrl
    const status   = searchParams.get('status')   ?? ''
    const unitId   = searchParams.get('unitId')   ?? ''
    const negotId  = searchParams.get('negotiationId') ?? ''
    const search   = searchParams.get('search')   ?? ''
    const page     = Math.max(1, Number(searchParams.get('page') ?? 1))
    const take     = 50

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const where: any = {}
    if (session.user.tenantId) where.tenantId = session.user.tenantId
    if (status)  where.status = status
    if (unitId)  where.unitId = unitId
    if (negotId) where.negotiationId = negotId

    if (search) {
      where.OR = [
        { plate:     { contains: search, mode: 'insensitive' } },
        { brand:     { contains: search, mode: 'insensitive' } },
        { model:     { contains: search, mode: 'insensitive' } },
        { ownerName: { contains: search, mode: 'insensitive' } },
      ]
    }

    const [rows, total] = await Promise.all([
      prisma.vehicleEvaluation.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * take,
        take,
        select: {
          id: true, status: true, plate: true, brand: true, model: true,
          modelYear: true, km: true, fipeValue: true, evaluatedValue: true,
          suggestedSalePrice: true, totalExpenses: true,
          ownerName: true, unitId: true, evaluatedById: true,
          negotiationId: true, createdAt: true, updatedAt: true,
          result: true,
        },
      }),
      prisma.vehicleEvaluation.count({ where }),
    ])

    // Carrega fotos em paralelo (só imagens, primeira como capa + count)
    // Usa raw findMany na tabela de attachments (relação 1-N sem back-ref no
    // schema do VehicleEvaluation).
    const evalIds = rows.map((r) => r.id)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const photos: any[] = evalIds.length
      ? await (prisma as any).evaluationAttachment.findMany({
          where:   { evaluationId: { in: evalIds }, fileType: 'image' },
          orderBy: { createdAt: 'asc' },
          select:  { id: true, evaluationId: true, publicUrl: true, fileName: true, section: true, category: true },
        })
      : []

    const photosByEval = new Map<string, typeof photos>()
    for (const p of photos) {
      if (!photosByEval.has(p.evaluationId)) photosByEval.set(p.evaluationId, [])
      photosByEval.get(p.evaluationId)!.push(p)
    }

    const data = rows.map((r) => {
      const all = photosByEval.get(r.id) ?? []
      return {
        ...r,
        coverPhotoUrl: all[0]?.publicUrl ?? null,
        photoCount:    all.length,
        photos:        all.map((p) => ({
          id: p.id, url: p.publicUrl, fileName: p.fileName, section: p.section, category: p.category,
        })),
      }
    })

    return NextResponse.json({
      data,
      pagination: { page, total, totalPages: Math.ceil(total / take), limit: take },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

export async function POST(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try { requireModule(session.user.role, 'stock.evaluate') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const body = await req.json()
    const {
      plate, brand, model, version, manufactureYear, modelYear, km,
      color, fuel, transmission, chassi, renavam, vehicleType, conditionType,
      fipeCode, fipeReferenceMonth, fipeValue, evaluatedValue, desiredValue,
      minimumValue, suggestedSalePrice, evaluationNotes,
      ownerName, ownerCpf, ownerPhone, ownerEmail,
      unitId, negotiationId, vehicleId,
      seedItems,  // boolean — se true, cria os itens predefinidos do catálogo
    } = body

    // Valida unit pertence ao tenant
    let resolvedUnitId: string | null = session.user.unitId ?? null
    if (unitId && typeof unitId === 'string') {
      const u = await prisma.unit.findFirst({
        where:  { id: unitId, tenantId: session.user.tenantId ?? undefined },
        select: { id: true },
      })
      if (u) resolvedUnitId = u.id
    }

    const safeNum = (v: unknown): number | null => {
      if (v == null || v === '') return null
      const n = Number(v)
      return Number.isFinite(n) ? n : null
    }
    const ev = await prisma.vehicleEvaluation.create({
      data: {
        tenantId:        session.user.tenantId ?? null,
        unitId:          resolvedUnitId,
        vehicleId:       vehicleId ?? null,
        plate:           plate?.toUpperCase().replace(/[^A-Z0-9]/g, '') || null,
        brand:           brand ?? null,
        model:           model ?? null,
        version:         version ?? null,
        manufactureYear: safeNum(manufactureYear),
        modelYear:       safeNum(modelYear),
        km:              safeNum(km),
        color:           color ?? null,
        fuel:            fuel  ?? null,
        transmission:    transmission ?? null,
        chassi:          chassi  ?? null,
        renavam:         renavam ?? null,
        vehicleType:     vehicleType   ?? null,
        conditionType:   conditionType ?? null,
        fipeCode:           fipeCode ?? null,
        fipeReferenceMonth: fipeReferenceMonth ?? null,
        fipeValue:          safeNum(fipeValue),
        evaluatedValue:     safeNum(evaluatedValue),
        desiredValue:       safeNum(desiredValue),
        minimumValue:       safeNum(minimumValue),
        suggestedSalePrice: safeNum(suggestedSalePrice),
        evaluationNotes:    evaluationNotes    ?? null,
        ownerName:          ownerName  ?? null,
        ownerCpf:           ownerCpf   ?? null,
        ownerPhone:         ownerPhone ?? null,
        ownerEmail:         ownerEmail ?? null,
        evaluatedById:      session.user.id,
        evaluatedAt:        new Date(),
        result:             'PENDENTE',
        // Novos campos:
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        status:             'DRAFT' as any,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        totalExpenses:      0 as any,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        negotiationId:      negotiationId ?? null as any,
      },
    })

    // Seed dos itens canônicos de checklist (apenas seções de inspeção)
    if (seedItems) {
      const sections: SectionKey[] = ['INTERIOR', 'FRENTE', 'DIREITA', 'TRASEIRA', 'ESQUERDA', 'TEST_DRIVE']
      const rows = sections.flatMap((sec) =>
        ITEMS[sec].map((it) => ({
          tenantId:     session.user.tenantId ?? null,
          evaluationId: ev.id,
          section:      sec,
          catalogKey:   it.key,
          name:         it.name,
          status:       'PENDING',
          totalExpenses: 0,
        })),
      )
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (prisma as any).evaluationItem.createMany({ data: rows }).catch(() => {})
    }

    await prisma.auditLog.create({
      data: {
        userId:   session.user.id,
        tenantId: session.user.tenantId ?? null,
        action:   'CREATE',
        entity:   'VehicleEvaluation',
        entityId: ev.id,
        userName: session.user.name,
        userRole: session.user.role,
        status:   'SUCCESS',
      },
    }).catch(() => {})

    return NextResponse.json({ data: ev }, { status: 201 })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// API: /api/logs/audit — AutoDrive
// Listagem do log de auditoria com paginação e filtros
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { canAccessModule } from '@/lib/permissions'

export async function GET(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) {
      return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    }
    if (!canAccessModule(session.user.role, 'logs')) {
      return NextResponse.json({ success: false, error: 'Acesso negado' }, { status: 403 })
    }

    const { searchParams } = new URL(req.url)
    const page    = Math.max(1, Number(searchParams.get('page')    ?? 1))
    const perPage = Math.min(100, Number(searchParams.get('perPage') ?? 50))
    const action  = searchParams.get('action')  || undefined
    const entity  = searchParams.get('entity')  || undefined
    const search  = searchParams.get('search')  || undefined

    const where: Record<string, unknown> = {}
    if (action) where.action = action
    if (entity) where.entity = entity
    if (search) {
      where.OR = [
        { userName:  { contains: search, mode: 'insensitive' } },
        { entity:    { contains: search, mode: 'insensitive' } },
        { entityId:  { contains: search, mode: 'insensitive' } },
      ]
    }

    const [total, logs] = await Promise.all([
      prisma.auditLog.count({ where: where as any }),
      prisma.auditLog.findMany({
        where:   where as any,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * perPage,
        take:    perPage,
      }),
    ])

    return NextResponse.json({
      success: true,
      data:    logs,
      meta: {
        total,
        page,
        perPage,
        totalPages:  Math.ceil(total / perPage),
        hasNextPage: page * perPage < total,
        hasPrevPage: page > 1,
      },
    })
  } catch (err) {
    console.error('[GET /api/logs/audit]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// =============================================================================
// API: /api/logs/status — AutoDrive
// Histórico de mudanças de status das pendências
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'

export async function GET(req: NextRequest) {
  try {
    const session = await getServerAuthSession()
    if (!session?.user) {
      return NextResponse.json({ success: false, error: 'Não autenticado' }, { status: 401 })
    }

    const { searchParams } = new URL(req.url)
    const page    = Math.max(1, Number(searchParams.get('page')    ?? 1))
    const perPage = Math.min(100, Number(searchParams.get('perPage') ?? 50))
    const search  = searchParams.get('search') || undefined

    const where: Record<string, unknown> = {}
    if (search) {
      where.pendency = {
        OR: [
          { customerName: { contains: search, mode: 'insensitive' } },
          { plate:        { contains: search, mode: 'insensitive' } },
        ],
      }
    }

    const [total, entries] = await Promise.all([
      prisma.pendencyStatusHistory.count({ where: where as any }),
      prisma.pendencyStatusHistory.findMany({
        where:   where as any,
        include: {
          pendency:      { select: { customerName: true, plate: true } },
          changedByUser: { select: { name: true } },
        },
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * perPage,
        take:    perPage,
      }),
    ])

    return NextResponse.json({
      success: true,
      data:    entries,
      meta: {
        total,
        page,
        perPage,
        totalPages:  Math.ceil(total / perPage),
        hasNextPage: page * perPage < total,
        hasPrevPage: page > 1,
      },
    })
  } catch (err) {
    console.error('[GET /api/logs/status]', err)
    return NextResponse.json({ success: false, error: 'Erro interno' }, { status: 500 })
  }
}

// =============================================================================
// POST /api/master/communication/whatsapp/connect-test
// Testa a conexão com a Meta WhatsApp Cloud API SEM enviar mensagem.
// Faz GET no Phone Number ID para validar token + número + versão.
// Grava resultado em CommunicationTestLog e atualiza status da config.
// Apenas MASTER.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster, upsertSystemSetting } from '@/lib/master-guards'
import { prisma }  from '@/lib/prisma'
import { getWhatsAppConfig } from '../route'

interface MetaPhoneInfo {
  id:                  string
  display_phone_number: string
  verified_name:       string
  quality_rating:      string
  platform_type:       string
  throughput?:         { level: string }
  error?:              { message: string; code: number; type?: string; fbtrace_id?: string }
}

export async function POST(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  const start = Date.now()

  const cfg = await getWhatsAppConfig().catch(() => null)

  // Validações pré-requisito
  if (!cfg?.token) {
    return NextResponse.json({ success: false, error: 'Token de acesso não configurado.', errorCode: 'NO_TOKEN' }, { status: 400 })
  }
  if (!cfg?.phoneNumberId) {
    return NextResponse.json({ success: false, error: 'Phone Number ID não configurado.', errorCode: 'NO_PHONE_NUMBER_ID' }, { status: 400 })
  }

  const apiVersion = cfg.apiVersion || 'v20.0'
  const baseUrl    = (cfg.apiUrl || 'https://graph.facebook.com').replace(/\/$/, '')
  const url        = `${baseUrl}/${apiVersion}/${cfg.phoneNumberId}`

  let success = false
  let errorCode: string | undefined
  let errorMessage: string | undefined
  let errorDetails: string | undefined
  let responseData: MetaPhoneInfo | null = null
  let httpStatus = 0

  try {
    const res = await fetch(url, {
      headers: { Authorization: `Bearer ${cfg.token}` },
    })
    httpStatus = res.status

    const json = await res.json() as MetaPhoneInfo

    if (!res.ok || json.error) {
      const e = json.error
      errorCode    = e?.code ? String(e.code) : String(res.status)
      errorMessage = e?.message ?? `HTTP ${res.status}`
      errorDetails = JSON.stringify(json, null, 2)
    } else {
      success      = true
      responseData = json
    }
  } catch (err) {
    const e = err as { message?: string; code?: string }
    errorCode    = e.code ?? 'FETCH_ERROR'
    errorMessage = e.message ?? 'Erro de rede ao contactar a API Meta.'
    errorDetails = err instanceof Error ? err.stack : String(err)
  }

  const responseMs = Date.now() - start

  // Atualiza status da config
  const statusValue = success ? 'CONECTADO' : `ERRO:${errorCode}`
  await Promise.all([
    upsertSystemSetting('whatsapp.lastConnectAt',     new Date().toISOString(), 'whatsapp', session.id),
    upsertSystemSetting('whatsapp.lastConnectStatus', statusValue,              'whatsapp', session.id),
  ]).catch(() => {})

  // Grava log
  await prisma.communicationTestLog.create({
    data: {
      channel:      'WHATSAPP',
      provider:     cfg.provider ?? 'meta',
      triggeredBy:  session.id,
      target:       `PhoneNumberID:${cfg.phoneNumberId}`,
      success,
      errorCode:    errorCode    ?? null,
      errorMessage: errorMessage ?? null,
      errorDetails: errorDetails ?? null,
      responseMs,
      metadata:     responseData ? (responseData as unknown as object) : undefined,
    },
  }).catch(err => console.error('[connect-test] log failed:', err))

  if (success && responseData) {
    return NextResponse.json({
      success: true,
      message: 'Conexão com a Meta validada com sucesso.',
      phoneInfo: {
        displayNumber: responseData.display_phone_number,
        verifiedName:  responseData.verified_name,
        qualityRating: responseData.quality_rating,
        platformType:  responseData.platform_type,
        throughput:    responseData.throughput?.level,
      },
      httpStatus,
      responseMs,
    })
  }

  return NextResponse.json(
    {
      success:      false,
      error:        errorMessage ?? 'Falha na conexão com a Meta.',
      errorCode,
      errorDetails,
      httpStatus,
      responseMs,
    },
    { status: 502 },
  )
}

// =============================================================================
// /api/master/communication/whatsapp
// GET  — carrega configuração global do WhatsApp (credenciais mascaradas)
// POST — salva/atualiza configuração (segredos só sobrescritos se enviado novo valor)
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster, logMasterAction, upsertSystemSetting, getSettingGroup } from '@/lib/master-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { encrypt, decrypt, isMasked, MASKED } from '@/lib/crypto'

const GROUP = 'whatsapp'

// Chaves sensíveis — armazenadas criptografadas, retornadas mascaradas
const SECRET_KEYS = ['token', 'appSecret', 'webhookVerifyToken'] as const
type SecretKey = typeof SECRET_KEYS[number]

// Todas as chaves gerenciadas neste endpoint
const PLAIN_KEYS = [
  'whatsapp.provider',
  'whatsapp.environment',      // TEST | REAL | PRODUCTION
  'whatsapp.active',
  'whatsapp.apiUrl',
  'whatsapp.apiVersion',
  'whatsapp.phoneNumberId',
  'whatsapp.businessAccountId', // WABA ID
  'whatsapp.businessManagerId',
  'whatsapp.appId',
  'whatsapp.webhookCallbackUrl',
  'whatsapp.webhookFields',
  'whatsapp.defaultLanguage',
  'whatsapp.useOfficialTemplates',
  'whatsapp.fallbackToText',
  'whatsapp.defaultHeaderImageUrl',
  'whatsapp.defaultHeaderMediaId',
  'whatsapp.monthlyLimit',
  'whatsapp.testPhone',
  'whatsapp.lastConnectAt',
  'whatsapp.lastConnectStatus',
]

const SECRET_FULL_KEYS = SECRET_KEYS.map(k => `whatsapp.${k}`)

// ── Validação de URL base da API ──────────────────────────────────────────────

function validateApiUrl(url: string): string | null {
  if (!url) return null
  try {
    const parsed = new URL(url)
    if (parsed.protocol !== 'https:') return 'A URL base deve usar HTTPS.'
    if (parsed.hostname.includes('@'))  return 'A URL base não pode conter e-mail.'
    if (!parsed.hostname.includes('.')) return 'URL inválida.'
    return null // ok
  } catch {
    return 'URL inválida. Use o formato https://graph.facebook.com'
  }
}

// ── GET ───────────────────────────────────────────────────────────────────────

export async function GET() {
  const { error } = await requireMaster()
  if (error) return error

  try {
    const settings = await getSettingGroup(GROUP)
    const clean: Record<string, string> = {}

    for (const [k, v] of Object.entries(settings)) {
      const shortKey = k.replace(`${GROUP}.`, '')
      // Retorna máscara para segredos — nunca o valor real
      if ((SECRET_KEYS as readonly string[]).includes(shortKey)) {
        clean[shortKey] = v ? MASKED : ''
      } else {
        clean[shortKey] = v
      }
    }

    return NextResponse.json({ success: true, data: clean })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── POST ──────────────────────────────────────────────────────────────────────

export async function POST(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const body = await req.json() as Record<string, string>

    // Validação da URL base da API
    if (body.apiUrl !== undefined && body.apiUrl !== '') {
      const urlError = validateApiUrl(body.apiUrl)
      if (urlError) {
        return NextResponse.json({ success: false, error: urlError }, { status: 400 })
      }
    }

    // Validação do formato da versão da API
    if (body.apiVersion && !/^v\d+\.\d+$/.test(body.apiVersion)) {
      return NextResponse.json(
        { success: false, error: 'Versão da API inválida. Use formato v20.0, v21.0, etc.' },
        { status: 400 },
      )
    }

    // Validação: campos numéricos não podem conter @
    for (const numericField of ['phoneNumberId', 'businessAccountId', 'businessManagerId', 'appId']) {
      const val = body[numericField]
      if (val && !/^\d+$/.test(val)) {
        return NextResponse.json(
          { success: false, error: `${numericField}: aceita apenas números.` },
          { status: 400 },
        )
      }
    }

    const saves: Promise<void>[] = []

    // Chaves simples
    for (const key of PLAIN_KEYS) {
      const shortKey = key.replace(`${GROUP}.`, '')
      if (shortKey in body && body[shortKey] != null) {
        saves.push(upsertSystemSetting(key, String(body[shortKey]), GROUP, session.id, key))
      }
    }

    // Chaves sensíveis — só atualiza se vier valor novo (não mascarado)
    for (const secretShort of SECRET_KEYS) {
      const fullKey = `whatsapp.${secretShort}`
      if (secretShort in body) {
        const val = body[secretShort]
        if (!val || isMasked(val)) continue // mantém o segredo antigo
        saves.push(upsertSystemSetting(fullKey, encrypt(val), GROUP, session.id, fullKey))
      }
    }

    await Promise.all(saves)

    await logMasterAction(session, 'UPDATE_WHATSAPP_CONFIG', 'SystemSetting', null, {
      afterData: {
        provider:    body.provider,
        environment: body.environment,
        apiVersion:  body.apiVersion,
      },
      req,
    })

    return NextResponse.json({ success: true, message: 'Configurações do WhatsApp salvas com sucesso.' })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── Helpers exportados para uso interno (test routes) ─────────────────────────

export async function getWhatsAppConfig(): Promise<Record<string, string>> {
  const settings = await getSettingGroup('whatsapp')
  const config: Record<string, string> = {}

  for (const [k, v] of Object.entries(settings)) {
    const shortKey = k.replace('whatsapp.', '')
    // Descriptografar segredos para uso interno
    if ((SECRET_KEYS as readonly string[]).includes(shortKey)) {
      config[shortKey] = decrypt(v)
    } else {
      config[shortKey] = v
    }
  }

  return config
}

// =============================================================================
// POST /api/master/communication/whatsapp/webhook-validate
// Simula a validação GET do webhook Meta (hub.mode + hub.challenge + hub.verify_token).
// Faz uma chamada simulada para o próprio endpoint de webhook configurado,
// verificando se ele responde corretamente ao challenge da Meta.
// Apenas MASTER.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster } from '@/lib/master-guards'
import { prisma }        from '@/lib/prisma'
import { getWhatsAppConfig } from '../route'

export async function POST(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  const start = Date.now()
  const cfg   = await getWhatsAppConfig().catch(() => null)

  if (!cfg?.webhookCallbackUrl) {
    return NextResponse.json(
      { success: false, error: 'Webhook Callback URL não configurada.', errorCode: 'NO_WEBHOOK_URL' },
      { status: 400 },
    )
  }
  if (!cfg?.webhookVerifyToken) {
    return NextResponse.json(
      { success: false, error: 'Webhook Verify Token não configurado.', errorCode: 'NO_VERIFY_TOKEN' },
      { status: 400 },
    )
  }

  const challenge    = `challenge_${Date.now()}`
  const verifyToken  = cfg.webhookVerifyToken
  const callbackUrl  = cfg.webhookCallbackUrl

  // Monta a URL com parâmetros exatamente como a Meta faz
  const testUrl = new URL(callbackUrl)
  testUrl.searchParams.set('hub.mode',         'subscribe')
  testUrl.searchParams.set('hub.challenge',    challenge)
  testUrl.searchParams.set('hub.verify_token', verifyToken)

  let success      = false
  let errorCode:    string | undefined
  let errorMessage: string | undefined
  let errorDetails: string | undefined
  let responseBody  = ''
  let httpStatus    = 0

  try {
    const res = await fetch(testUrl.toString(), {
      method:  'GET',
      headers: { 'User-Agent': 'facebookexternalua' },
      signal:  AbortSignal.timeout(10_000),
    })

    httpStatus   = res.status
    responseBody = await res.text()

    if (res.ok && responseBody.trim() === challenge) {
      success = true
    } else if (!res.ok) {
      errorCode    = String(res.status)
      errorMessage = `Webhook retornou HTTP ${res.status}. Esperado 200.`
      errorDetails = responseBody
    } else {
      errorCode    = 'CHALLENGE_MISMATCH'
      errorMessage = `Webhook não retornou o challenge correto. Esperado: "${challenge}", Recebido: "${responseBody.trim().slice(0, 100)}"`
    }
  } catch (err) {
    const e = err as { message?: string; code?: string; name?: string }
    errorCode    = e.code ?? (e.name === 'TimeoutError' ? 'TIMEOUT' : 'FETCH_ERROR')
    errorMessage = e.name === 'TimeoutError'
      ? 'Timeout: o webhook não respondeu em 10 segundos.'
      : (e.message ?? 'Erro de rede ao chamar o webhook.')
    errorDetails = err instanceof Error ? err.stack : String(err)
  }

  const responseMs = Date.now() - start

  // Grava no webhook_logs para rastreabilidade
  await prisma.webhookLog.create({
    data: {
      provider:  'meta',
      direction: 'OUTBOUND_TEST',
      payload:   {
        url:       testUrl.toString(),
        challenge,
        success,
        response:  responseBody.slice(0, 500),
        triggeredBy: session.id,
      },
      processed: success,
      error:     errorMessage ?? null,
    },
  }).catch(() => {})

  if (success) {
    return NextResponse.json({
      success:     true,
      message:     'Webhook validado com sucesso! O endpoint respondeu corretamente ao challenge da Meta.',
      callbackUrl: cfg.webhookCallbackUrl,
      httpStatus,
      responseMs,
    })
  }

  return NextResponse.json(
    {
      success:      false,
      error:        errorMessage ?? 'Falha na validação do webhook.',
      errorCode,
      errorDetails,
      callbackUrl:  cfg.webhookCallbackUrl,
      httpStatus,
      responseMs,
    },
    { status: 502 },
  )
}

// =============================================================================
// /api/master/integrations/[id] — Gerenciar credencial de integração (MASTER only)
//
// GET    — detalhes (valores sensíveis mascarados)
// PATCH  — atualizar campos
// DELETE — excluir credencial
// POST   — ações especiais: test, rotate
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster, logMasterAction } from '@/lib/master-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { prisma } from '@/lib/prisma'
import { getBanks, getCep, getCnpj, clearBrasilApiCache } from '@/lib/brasilapi/service'
import { isAnyPlateProviderConfigured, clearPlateProviderCache } from '@/lib/plate-lookup/service'
import { clearPlacasCredentialCache, isPlacasConfigured, getBalance as getPlacasBalance } from '@/lib/integrations/placas/client'
import { getReferences as getFipeReferences, clearFipeConfigCache } from '@/lib/fipe/parallelum'
import { getServiceDef } from '@/lib/integrations/catalog'
import { clearActiveCredentialCache } from '@/lib/integrations/active'

const MASKED = '••••••••'
const SENSITIVE_KEYS = ['apiKey', 'apiSecret', 'token', 'webhookSecret']

function maskSensitive(cred: Record<string, unknown>): Record<string, unknown> {
  const masked = { ...cred }
  for (const key of SENSITIVE_KEYS) {
    if (masked[key]) masked[key] = MASKED
  }
  return masked
}

// ── GET ───────────────────────────────────────────────────────────────────────

export async function GET(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const { error } = await requireMaster()
  if (error) return error

  try {
    const cred = await prisma.integrationCredential.findUnique({ where: { id: params.id } })
    if (!cred) {
      return NextResponse.json({ success: false, error: 'Credencial não encontrada.' }, { status: 404 })
    }
    return NextResponse.json({ success: true, data: maskSensitive(cred as unknown as Record<string, unknown>) })
  } catch (err) {
    console.error('[GET /api/master/integrations/:id]', err)
    return handlePrismaError(err)
  }
}

// ── PATCH ─────────────────────────────────────────────────────────────────────

export async function PATCH(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const cred = await prisma.integrationCredential.findUnique({ where: { id: params.id } })
    if (!cred) {
      return NextResponse.json({ success: false, error: 'Credencial não encontrada.' }, { status: 404 })
    }

    const body = await req.json()
    const { name, description, apiUrl, apiKey, apiSecret, token, username, webhookSecret, isDefault, active, notes } = body

    // ── Whitelist por serviço (catálogo) ──────────────────────────────────────
    // Garante que campos indevidos enviados acidentalmente não sejam persistidos
    // (ex: PATCH com username vindo do auto-complete do browser para FIPE).
    const def = getServiceDef(cred.service)
    const allowsField = (k: string) => !def || def.fields.includes(k as never)

    // ── Validação de URL específica do serviço ────────────────────────────────
    // Bloqueia trocar para uma URL que não pertence ao provedor (ex: cadastrar
    // PlacaFipe como BrasilAPI).
    if (def?.validateUrl && apiUrl != null) {
      const urlError = def.validateUrl(String(apiUrl).trim())
      if (urlError) {
        return NextResponse.json({ success: false, error: urlError }, { status: 400 })
      }
    }

    const data: Record<string, unknown> = {}
    if (name          != null) data.name        = String(name).trim()
    if (description   != null) data.description = String(description).trim() || null
    if (active        != null) data.active      = Boolean(active)
    if (isDefault     != null) data.isDefault   = Boolean(isDefault)
    if (notes         != null) data.notes       = String(notes).trim()       || null

    if (apiUrl   != null && allowsField('apiUrl'))   data.apiUrl   = String(apiUrl).trim()   || null
    if (username != null && allowsField('username')) data.username = String(username).trim() || null

    // ── Secrets: regra rigorosa ──────────────────────────────────────────────
    // - Não veio no body → não altera (preserva valor atual)
    // - Veio === MASKED  → ignora (placeholder, preserva valor atual)
    // - Veio com string  → atualiza
    // - Veio === ''      → limpa o valor
    // Também respeita whitelist: campos indevidos para o serviço são ignorados.
    for (const key of ['apiKey', 'apiSecret', 'token', 'webhookSecret']) {
      if (!(key in body)) continue
      if (!allowsField(key)) continue
      const val = body[key]
      if (val === MASKED || val == null) continue
      const s = String(val).trim()
      data[key] = s || null
    }

    // Limpa campos que NÃO são permitidos pelo serviço atual (cleanup defensivo)
    // — só faz isso se o usuário não estiver trocando de serviço (geralmente não pode).
    for (const k of ['apiKey', 'apiSecret', 'token', 'webhookSecret', 'username', 'apiUrl']) {
      if (!allowsField(k) && cred[k as keyof typeof cred]) {
        data[k] = null
      }
    }

    // Se isDefault=true, desmarcar outros do mesmo serviço
    if (data.isDefault === true) {
      await prisma.integrationCredential.updateMany({
        where: { service: cred.service, isDefault: true, id: { not: params.id } },
        data:  { isDefault: false },
      })
    }

    const updated = await prisma.integrationCredential.update({
      where: { id: params.id },
      data,
    })
    clearActiveCredentialCache()
    // Limpa caches de service-specific (FIPE/Brasil/Plate) que possam ter
    // memorizado credencial antiga.
    if (cred.service === 'FIPE_PROVIDER' || cred.service === 'FIPE') clearFipeConfigCache()
    if (cred.service === 'PLATE_LOOKUP') { clearPlateProviderCache(); clearPlacasCredentialCache() }
    if (cred.service === 'BRASILAPI')    clearBrasilApiCache()

    await logMasterAction(session, 'UPDATE_INTEGRATION', 'IntegrationCredential', params.id, {
      beforeData: { active: cred.active, isDefault: cred.isDefault },
      afterData:  { active: updated.active, isDefault: updated.isDefault },
      req,
    })

    return NextResponse.json({
      success: true,
      data: maskSensitive(updated as unknown as Record<string, unknown>),
      message: 'Credencial atualizada com sucesso.',
    })
  } catch (err) {
    console.error('[PATCH /api/master/integrations/:id]', err)
    return handlePrismaError(err)
  }
}

// ── DELETE ─────────────────────────────────────────────────────────────────────

export async function DELETE(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const cred = await prisma.integrationCredential.findUnique({ where: { id: params.id } })
    if (!cred) {
      return NextResponse.json({ success: false, error: 'Credencial não encontrada.' }, { status: 404 })
    }

    await prisma.integrationCredential.delete({ where: { id: params.id } })
    clearActiveCredentialCache()
    if (cred.service === 'FIPE_PROVIDER' || cred.service === 'FIPE') clearFipeConfigCache()
    if (cred.service === 'PLATE_LOOKUP') { clearPlateProviderCache(); clearPlacasCredentialCache() }
    if (cred.service === 'BRASILAPI')    clearBrasilApiCache()

    await logMasterAction(session, 'DELETE_INTEGRATION', 'IntegrationCredential', params.id, {
      beforeData: { service: cred.service, name: cred.name },
      req,
    })

    return NextResponse.json({ success: true, message: 'Credencial excluída com sucesso.' })
  } catch (err) {
    console.error('[DELETE /api/master/integrations/:id]', err)
    return handlePrismaError(err)
  }
}

// ── POST — ações especiais ────────────────────────────────────────────────────
// Ações: test (testa conexão), rotate (regenera token)

export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const { action } = await req.json()

    const cred = await prisma.integrationCredential.findUnique({ where: { id: params.id } })
    if (!cred) {
      return NextResponse.json({ success: false, error: 'Credencial não encontrada.' }, { status: 404 })
    }

    if (action === 'TEST') {
      // ── Teste real por tipo de serviço ─────────────────────────────────────
      let ok      = false
      let message = ''
      const started = Date.now()

      try {
        switch (cred.service) {
          case 'BRASILAPI': {
            // Testa os 3 endpoints reais (bancos, CEP, CNPJ) para validar a
            // integração de fato. Não considera OK só porque um endpoint
            // (bancos) está cacheado.
            clearBrasilApiCache()
            const tBanks = Date.now()
            const banks  = await getBanks()
            const banksMs = Date.now() - tBanks
            const banksOk = banks.ok && Array.isArray(banks.data) && banks.data.length > 0

            const tCep = Date.now()
            const cep  = await getCep('01310100')   // Av. Paulista — sempre válido
            const cepMs = Date.now() - tCep
            const cepOk = cep.ok && !!cep.data?.cep

            const tCnpj = Date.now()
            const cnpj  = await getCnpj('00000000000191')   // Banco do Brasil — sempre válido
            const cnpjMs = Date.now() - tCnpj
            const cnpjOk = cnpj.ok && !!cnpj.data?.razao_social

            ok = banksOk && cepOk && cnpjOk
            const tag = (label: string, status: boolean, ms: number, err?: string) =>
              `${label}: ${status ? `OK (${ms}ms)` : `FALHOU${err ? ` — ${err}` : ''}`}`

            message = ok
              ? `BrasilAPI OK — Bancos: ${banks.data!.length} (${banksMs}ms) | CEP: OK (${cepMs}ms) | CNPJ: OK (${cnpjMs}ms)`
              : [
                  tag('Bancos', banksOk, banksMs, banks.error),
                  tag('CEP',    cepOk,   cepMs,   cep.error),
                  tag('CNPJ',   cnpjOk,  cnpjMs,  cnpj.error),
                ].join(' | ')
            break
          }
          case 'PLATE_LOOKUP': {
            clearPlateProviderCache()
            clearPlacasCredentialCache()
            // Prefer real check via API Placas balance se aplicável
            const apiUrl = (cred.apiUrl ?? '').toLowerCase()
            const isWdapi = apiUrl.includes('wdapi') || apiUrl.includes('apiplacas')
            if (isWdapi && (await isPlacasConfigured())) {
              const b = await getPlacasBalance()
              ok = b.success
              message = b.success
                ? `API Placas OK — saldo: ${b.balance} consultas.`
                : `API Placas falhou: ${b.errorMessage ?? 'sem retorno'}.`
            } else {
              const configured = await isAnyPlateProviderConfigured()
              ok = configured
              message = configured
                ? 'Provedor de placa configurado. Teste real requer placa válida no módulo de Avaliação.'
                : 'Nenhum provedor de placa pôde ser carregado. Verifique apiUrl/token.'
            }
            break
          }
          case 'FIPE_PROVIDER': {
            // Limpa cache da credencial para forçar re-resolução com a nova chave
            clearFipeConfigCache()
            const r  = await getFipeReferences(true)
            const ms = Date.now() - started
            ok       = r.ok && Array.isArray(r.data) && r.data.length > 0
            message  = ok
              ? `FIPE/Parallelum OK — ${r.data!.length} tabelas de referência em ${ms}ms.`
              : `FIPE/Parallelum falhou: ${r.error ?? 'sem retorno'}.`
            break
          }
          case 'CEP':
          case 'CNPJ_LOOKUP':
          case 'FIPE': {
            // Esses serviços hoje rodam via BrasilAPI internamente
            clearBrasilApiCache()
            const r = await getBanks()  // proxy de saúde: se BrasilAPI está OK, todos esses funcionam
            ok      = r.ok
            message = ok
              ? 'Provedor responde normalmente (validado via BrasilAPI).'
              : `Falha de conexão: ${r.error ?? 'desconhecido'}.`
            break
          }
          default:
            ok      = false
            message = `Teste de conexão para "${cred.service}" ainda não implementado.`
        }
      } catch (e) {
        ok      = false
        message = e instanceof Error ? e.message : 'Erro inesperado no teste.'
      }

      await prisma.integrationCredential.update({
        where: { id: params.id },
        data: {
          lastTestedAt: new Date(),
          lastTestOk:   ok,
          lastTestMsg:  message.slice(0, 500),
        },
      })

      await logMasterAction(session, 'TEST_INTEGRATION', 'IntegrationCredential', params.id, {
        afterData: { service: cred.service, testResult: ok ? 'OK' : 'FAIL', message },
        req,
      })

      return NextResponse.json({
        success: ok,
        ok,
        message,
        lastTestedAt: new Date().toISOString(),
      })
    }

    return NextResponse.json({ success: false, error: `Ação desconhecida: ${action}` }, { status: 400 })
  } catch (err) {
    console.error('[POST /api/master/integrations/:id]', err)
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/master/plans — CRUD de planos da plataforma (MASTER only)
// GET   — lista todos os planos com contagem de tenants
// POST  — cria novo plano
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster, logMasterAction } from '@/lib/master-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { prisma } from '@/lib/prisma'

export async function GET() {
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const plans = await prisma.plan.findMany({
      orderBy: [{ sortOrder: 'asc' }, { createdAt: 'asc' }],
    })

    // Contagem de tenants por code de plano
    const tenantCounts = await prisma.tenant.groupBy({
      by: ['plan'],
      _count: { _all: true },
    })
    const countMap: Record<string, number> = {}
    for (const t of tenantCounts) countMap[t.plan] = t._count._all

    const enriched = plans.map(p => ({ ...p, tenantCount: countMap[p.code] ?? 0 }))

    return NextResponse.json({ success: true, data: enriched })
  } catch (err) {
    return handlePrismaError(err)
  }
}

export async function POST(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const body = await req.json()
    const {
      code, name, description,
      priceMonthly, priceYearly,
      maxUsers, maxVehicles, maxUnits, maxStorageMb,
      whatsappMonthly, emailMonthly, trialDays,
      allowWhiteLabel, allowCustomDomain, allowGoogleSheets,
      allowAdvancedReports, allowApiAccess,
      modules, sortOrder, notes,
    } = body

    if (!code?.trim() || !name?.trim()) {
      return NextResponse.json(
        { success: false, error: 'Código e nome do plano são obrigatórios.' },
        { status: 400 },
      )
    }

    const plan = await prisma.plan.create({
      data: {
        code:               String(code).trim().toUpperCase(),
        name:               String(name).trim(),
        description:        description ? String(description).trim() : null,
        priceMonthly:       priceMonthly != null ? Number(priceMonthly) : null,
        priceYearly:        priceYearly  != null ? Number(priceYearly)  : null,
        maxUsers:           Number(maxUsers)        || 10,
        maxVehicles:        Number(maxVehicles)     || 100,
        maxUnits:           Number(maxUnits)        || 1,
        maxStorageMb:       Number(maxStorageMb)    || 1024,
        whatsappMonthly:    Number(whatsappMonthly) || 1000,
        emailMonthly:       Number(emailMonthly)    || 5000,
        trialDays:          Number(trialDays)       || 14,
        allowWhiteLabel:    Boolean(allowWhiteLabel),
        allowCustomDomain:  Boolean(allowCustomDomain),
        allowGoogleSheets:  allowGoogleSheets !== false,
        allowAdvancedReports: Boolean(allowAdvancedReports),
        allowApiAccess:     Boolean(allowApiAccess),
        modules:            Array.isArray(modules) ? modules : [],
        sortOrder:          Number(sortOrder) || 0,
        notes:              notes ? String(notes).trim() : null,
      },
    })

    await logMasterAction(session, 'CREATE_PLAN', 'Plan', plan.id, {
      afterData: { code: plan.code, name: plan.name },
      req,
    })

    return NextResponse.json({ success: true, data: plan }, { status: 201 })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// POST /api/master/sheets/[id]/configure
// Salva toda a configuração do importador de uma vez:
// planilha + abas + mapeamentos de colunas + auto-sync

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster }          from '@/lib/master-guards'
import { handlePrismaError }      from '@/lib/prisma-errors'
import { prisma }                 from '@/lib/prisma'

interface ColumnMapIn {
  columnLetter: string
  columnHeader?: string | null
  fieldName:    string
  fieldLabel?:  string | null
  required?:    boolean
  transform?:   string | null
  defaultValue?: string | null
  active?:      boolean
}

interface TabIn {
  id?:            string   // se presente → atualiza; se ausente → cria
  sheetName:      string
  internalName?:  string
  gid?:           string | null
  monthReference?: string | null
  tabType?:       string
  sortOrder?:     number
  active?:        boolean
  headerRow?:     number
  columnMaps?:    ColumnMapIn[]
}

interface AutoSyncIn {
  enabled:             boolean
  mode?:               string
  frequencyMinutes?:   number
  allowedDays?:        number[]
  startTime?:          string
  endTime?:            string
  selectedTabs?:       string[] | null
  actionAfterDownload?: string
  notifyOnNewRecords?: boolean
  notifyOnError?:      boolean
  errorNotifyTarget?:  string | null
  maxRowsPerRun?:      number
  timeoutSeconds?:     number
}

export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const body: {
      name?:         string
      spreadsheetId?: string
      description?:  string | null
      active?:       boolean
      tabs?:         TabIn[]
      tabsToDelete?: string[]    // IDs de abas removidas pelo usuário
      autoSync?:     AutoSyncIn | null
    } = await req.json()

    // ── 1. Garante que o importer existe ──────────────────────────────────────
    const existing = await prisma.googleSheetConfig.findUnique({ where: { id: params.id } })
    if (!existing) {
      return NextResponse.json({ success: false, error: 'Importador não encontrado.' }, { status: 404 })
    }

    // ── 2. Monta operações num único transaction ───────────────────────────────
    await prisma.$transaction(async (tx) => {

      // 2a. Atualiza o importer
      if (body.name !== undefined || body.spreadsheetId !== undefined || body.active !== undefined) {
        await tx.googleSheetConfig.update({
          where: { id: params.id },
          data: {
            ...(body.name          !== undefined ? { name:          body.name          } : {}),
            ...(body.spreadsheetId !== undefined ? { spreadsheetId: body.spreadsheetId } : {}),
            ...(body.description   !== undefined ? { description:   body.description   } : {}),
            ...(body.active        !== undefined ? { active:        body.active        } : {}),
          },
        })
      }

      // 2b. Remove abas deletadas pelo usuário
      if (Array.isArray(body.tabsToDelete) && body.tabsToDelete.length > 0) {
        await tx.googleSheetTab.deleteMany({
          where: { id: { in: body.tabsToDelete }, configId: params.id },
        })
      }

      // 2c. Upsert abas
      const savedTabIds: string[] = []
      for (const tab of (body.tabs ?? [])) {
        let tabId: string

        if (tab.id) {
          // Atualiza aba existente
          const updated = await tx.googleSheetTab.update({
            where: { id: tab.id, configId: params.id },
            data: {
              sheetName:      tab.sheetName,
              internalName:   tab.internalName ?? tab.sheetName,
              gid:            tab.gid            ?? null,
              monthReference: tab.monthReference ?? null,
              tabType:        (tab.tabType as any) ?? 'PERSONALIZADO',
              sortOrder:      tab.sortOrder      ?? 0,
              active:         tab.active         ?? true,
              headerRow:      tab.headerRow      ?? 1,
            },
          })
          tabId = updated.id
        } else {
          // Cria nova aba
          const created = await tx.googleSheetTab.create({
            data: {
              configId:       params.id,
              sheetName:      tab.sheetName,
              internalName:   tab.internalName ?? tab.sheetName,
              gid:            tab.gid            ?? null,
              monthReference: tab.monthReference ?? null,
              tabType:        (tab.tabType as any) ?? 'PERSONALIZADO',
              sortOrder:      tab.sortOrder      ?? 0,
              active:         tab.active         ?? true,
              headerRow:      tab.headerRow      ?? 1,
            },
          })
          tabId = created.id
        }

        savedTabIds.push(tabId)

        // 2d. Salva mapeamentos de colunas da aba
        if (Array.isArray(tab.columnMaps)) {
          await tx.googleSheetColumnMap.deleteMany({ where: { tabId } })
          const validMaps = tab.columnMaps.filter(m => m.columnLetter && m.fieldName)
          if (validMaps.length > 0) {
            await tx.googleSheetColumnMap.createMany({
              data: validMaps.map(m => ({
                tabId,
                columnLetter: m.columnLetter,
                columnHeader: m.columnHeader ?? null,
                fieldName:    m.fieldName,
                fieldLabel:   m.fieldLabel   ?? null,
                required:     m.required     ?? false,
                transform:    m.transform    ?? null,
                defaultValue: m.defaultValue ?? null,
                active:       m.active       ?? true,
              })),
            })
          }
        }
      }

      // 2e. Upsert auto-sync
      if (body.autoSync !== undefined) {
        if (body.autoSync === null) {
          // Desativa auto-sync
          await tx.googleSheetsAutoSyncConfig.updateMany({
            where: { importerId: params.id },
            data:  { enabled: false },
          })
        } else {
          const as = body.autoSync
          const existing = await tx.googleSheetsAutoSyncConfig.findUnique({
            where: { importerId: params.id },
          })

          if (existing) {
            await tx.googleSheetsAutoSyncConfig.update({
              where: { importerId: params.id },
              data: {
                enabled:             as.enabled,
                mode:                (as.mode as any)               ?? existing.mode,
                frequencyMinutes:    as.frequencyMinutes             ?? existing.frequencyMinutes,
                allowedDays:         (as.allowedDays ?? existing.allowedDays) as never,
                startTime:           as.startTime                    ?? existing.startTime,
                endTime:             as.endTime                      ?? existing.endTime,
                selectedTabs:        (as.selectedTabs ?? existing.selectedTabs ?? undefined) as never,
                actionAfterDownload: (as.actionAfterDownload as any) ?? existing.actionAfterDownload,
                notifyOnNewRecords:  as.notifyOnNewRecords           ?? existing.notifyOnNewRecords,
                notifyOnError:       as.notifyOnError                ?? existing.notifyOnError,
                errorNotifyTarget:   as.errorNotifyTarget            ?? existing.errorNotifyTarget,
                maxRowsPerRun:       as.maxRowsPerRun                ?? existing.maxRowsPerRun,
                timeoutSeconds:      as.timeoutSeconds               ?? existing.timeoutSeconds,
                status:              as.enabled ? 'AGUARDANDO' : 'PAUSADO',
              },
            })
          } else {
            await tx.googleSheetsAutoSyncConfig.create({
              data: ({
                importerId:          params.id,
                createdById:         session.id,
                enabled:             as.enabled,
                mode:                (as.mode as any)               ?? 'SIMULATION',
                frequencyMinutes:    as.frequencyMinutes             ?? 30,
                allowedDays:         as.allowedDays                  ?? [1, 2, 3, 4, 5],
                startTime:           as.startTime                    ?? '08:00',
                endTime:             as.endTime                      ?? '18:00',
                selectedTabs:        (as.selectedTabs ?? undefined) as never,
                actionAfterDownload: (as.actionAfterDownload as any) ?? 'IMPORTAR_PENDENCIAS',
                notifyOnNewRecords:  as.notifyOnNewRecords           ?? false,
                notifyOnError:       as.notifyOnError                ?? true,
                errorNotifyTarget:   as.errorNotifyTarget            ?? null,
                maxRowsPerRun:       as.maxRowsPerRun                ?? 500,
                timeoutSeconds:      as.timeoutSeconds               ?? 120,
                status:              as.enabled ? 'AGUARDANDO' : 'PAUSADO',
              }) as never,
            })
          }
        }
      }
    })

    // ── 3. Retorna o importer atualizado completo ──────────────────────────────
    const updated = await prisma.googleSheetConfig.findUnique({
      where: { id: params.id },
      include: {
        tabs: {
          include: { columnMaps: { orderBy: { columnLetter: 'asc' } } },
          orderBy: { sortOrder: 'asc' },
        },
        autoSync: true,
      },
    })

    return NextResponse.json({ success: true, data: updated })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// POST /api/master/sheets/repair-orphans
// Repara pendências órfãs (source=SHEETS, dealId=null) linkando-as às
// negociações existentes ou criando a negociação quando ainda não existe.
//
// Executar UMA VEZ após a correção do fluxo de importação.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster }     from '@/lib/master-guards'
import { prisma }            from '@/lib/prisma'
import { handlePrismaError } from '@/lib/prisma-errors'
import { runDealProcessor }  from '@/lib/sheets-deal-processor'

export async function POST(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const body    = await req.json().catch(() => ({}))
    const dryRun  = body.dryRun === true
    const limit   = typeof body.limit === 'number' ? body.limit : 500

    // ── 1. Busca pendências órfãs (source=SHEETS, dealId nulo) ───────────────
    const orphans = await (prisma.pendency as any).findMany({
      where: {
        source:  'SHEETS',
        dealId:  null,
        status:  { notIn: ['FINALIZADA', 'CANCELADA'] },
      },
      select: {
        id:           true,
        tenantId:     true,
        unitId:       true,
        negotiation:  true,
        originRecordId: true,
        customerName: true,
        plate:        true,
        responsibleId:true,
      },
      take: limit,
    })

    if (orphans.length === 0) {
      return NextResponse.json({ success: true, message: 'Nenhuma pendência órfã encontrada.', fixed: 0, stillOrphan: 0 })
    }

    let fixed       = 0
    let stillOrphan = 0
    const details: string[] = []

    for (const pendency of orphans) {
      try {
        const negotiation = pendency.negotiation as string | null

        // ── 2. Tenta localizar Deal existente pela negociação ──────────────────
        let dealId: string | null = null

        if (negotiation) {
          const deal = await (prisma.deal as any).findFirst({
            where: {
              tenantId: pendency.tenantId,
              OR: [
                { externalId: negotiation },
                { notes: { contains: `ID externo: ${negotiation}` } },
              ],
            },
            select: { id: true },
          }).catch(() => null)

          if (deal) dealId = deal.id
        }

        // ── 3. Se não achou Deal, tenta via SheetImportRow ────────────────────
        // (sheetImportRow não tem tenantId — filtra por externalId)
        if (!dealId && negotiation) {
          const stagingRow = await (prisma.sheetImportRow as any).findFirst({
            where: {
              externalId: negotiation,
              status:     { in: ['NEGOCIACAO_CRIADA', 'NEGOCIACAO_ATUALIZADA', 'PENDENTE', 'PROCESSANDO'] },
            },
            select: { dealId: true, id: true, configId: true },
          }).catch(() => null)

          if (stagingRow?.dealId) {
            dealId = stagingRow.dealId
          } else if (stagingRow?.configId && !dryRun) {
            // Staging existe mas ainda não tem deal — roda o processor para essa linha
            await runDealProcessor({
              configId:      stagingRow.configId,
              dryRun:        false,
              triggeredById: session.id,
              limitRows:     1,
            }).catch(() => {})

            // Busca dealId após processamento
            const refreshed = await (prisma.sheetImportRow as any).findUnique({
              where:  { id: stagingRow.id },
              select: { dealId: true },
            }).catch(() => null)
            if (refreshed?.dealId) dealId = refreshed.dealId
          }
        }

        // ── 4. Vincula pendência ao deal ──────────────────────────────────────
        if (dealId) {
          if (!dryRun) {
            await (prisma.pendency as any).update({
              where: { id: pendency.id },
              data:  { dealId },
            })

            await prisma.auditLog.create({
              data: {
                tenantId: pendency.tenantId,
                userId:   session.id,
                action:   'UPDATE',
                entity:   'Pendency',
                entityId: pendency.id,
                status:   'SUCCESS',
                afterData: { dealId, fix: 'orphan-repair' } as never,
              },
            }).catch(() => {})
          }
          fixed++
          details.push(`✓ Pendência ${pendency.id} (neg: ${negotiation}) → Deal ${dealId}`)
        } else {
          stillOrphan++
          details.push(`✗ Pendência ${pendency.id} (neg: ${negotiation}) — nenhuma negociação localizada`)
        }
      } catch (err) {
        stillOrphan++
        details.push(`✗ Pendência ${pendency.id}: ${err instanceof Error ? err.message : String(err)}`)
      }
    }

    return NextResponse.json({
      success: true,
      dryRun,
      totalOrphans:    orphans.length,
      fixed,
      stillOrphan,
      details:         details.slice(0, 50),
      message: dryRun
        ? `[Simulação] ${fixed} pendências poderiam ser vinculadas, ${stillOrphan} sem match.`
        : `${fixed} pendências vinculadas a negociações. ${stillOrphan} ainda sem correspondência.`,
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── GET — estatísticas de pendências órfãs ────────────────────────────────────

export async function GET(_req: NextRequest) {
  const { error } = await requireMaster()
  if (error) return error

  try {
    const total = await (prisma.pendency as any).count({
      where: { source: 'SHEETS', dealId: null, status: { notIn: ['FINALIZADA', 'CANCELADA'] } },
    })

    const byTenant = await (prisma.pendency as any).groupBy({
      by:    ['tenantId'],
      where: { source: 'SHEETS', dealId: null, status: { notIn: ['FINALIZADA', 'CANCELADA'] } },
      _count:{ _all: true },
    }).catch(() => [])

    return NextResponse.json({ success: true, totalOrphans: total, byTenant })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/master/system-identity — Identidade global da plataforma (MASTER only)
//
// GET   — retorna configuração atual (singleton)
// PATCH — atualiza campos da identidade global
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { requireMaster, logMasterAction } from '@/lib/master-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { prisma } from '@/lib/prisma'

const ALLOWED_FIELDS = [
  'systemName', 'systemSlogan',
  'logoUrl', 'faviconUrl',
  'primaryColor', 'secondaryColor', 'accentColor',
  'footerText',
  'supportEmail', 'supportPhone', 'supportUrl',
  'termsUrl', 'privacyUrl',
  'customDomain',
  'timezone', 'locale', 'currency',
] as const

type IdentityField = typeof ALLOWED_FIELDS[number]

// ── GET ───────────────────────────────────────────────────────────────────────

export async function GET() {
  const { error } = await requireMaster()
  if (error) return error

  try {
    // Singleton — pega o único registro ou cria com defaults
    let identity = await prisma.systemIdentity.findFirst()

    if (!identity) {
      identity = await prisma.systemIdentity.create({ data: {} })
    }

    return NextResponse.json({ success: true, data: identity })
  } catch (err) {
    console.error('[GET /api/master/system-identity]', err)
    return handlePrismaError(err)
  }
}

// ── PATCH ─────────────────────────────────────────────────────────────────────

export async function PATCH(req: NextRequest) {
  const { session, error } = await requireMaster()
  if (error) return error

  try {
    const body = await req.json() as Record<string, string>

    // Construir objeto de atualização apenas com campos permitidos
    const updateData: Record<string, string | null> = {
      updatedById: session.id,
    }

    for (const field of ALLOWED_FIELDS) {
      if (field in body && body[field] != null) {
        updateData[field] = String(body[field]).trim() || null as never
      }
    }

    // Garantir que systemName nunca fique vazio
    if (updateData.systemName === null) {
      updateData.systemName = 'AutoDrive'
    }

    // Upsert singleton
    let identity = await prisma.systemIdentity.findFirst()

    if (!identity) {
      identity = await prisma.systemIdentity.create({
        data: { updatedById: session.id },
      })
    }

    const updated = await prisma.systemIdentity.update({
      where: { id: identity.id },
      data:  updateData,
    })

    await logMasterAction(session, 'UPDATE_SYSTEM_IDENTITY', 'SystemIdentity', updated.id, {
      afterData: { systemName: updated.systemName, primaryColor: updated.primaryColor },
      req,
    })

    return NextResponse.json({
      success: true,
      data: updated,
      message: 'Identidade do sistema atualizada com sucesso.',
    })
  } catch (err) {
    console.error('[PATCH /api/master/system-identity]', err)
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/master/tenants — Listar e criar tenants (MASTER only)
//
// POST: cria Tenant + Unit principal + TenantPartner(s) + User ADM
//       em uma única transação Prisma. Rollback total se qualquer etapa falhar.
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { createSafeAuditLog } from '@/lib/auth-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { normalizeCNPJ, isValidCNPJ } from '@/lib/br-docs/cnpj'
import { normalizeCPF, isValidCPF } from '@/lib/br-docs/cpf'
import { normalizeCEP } from '@/lib/br-docs/cep'
import { normalizePhone } from '@/lib/br-docs/phone'
import bcrypt from 'bcryptjs'

// ── Helpers ───────────────────────────────────────────────────────────────────

function generatePublicId(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'
  let id = 'AD-'
  for (let i = 0; i < 10; i++) id += chars[Math.floor(Math.random() * chars.length)]
  return id
}

function slugify(text: string): string {
  return text
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 60)
}

// ── GET — Listar tenants ─────────────────────────────────────────────────────

export async function GET(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session || session.user.role !== 'MASTER') {
    return NextResponse.json(
      { success: false, error: 'Acesso negado. Apenas usuários MASTER podem listar tenants.' },
      { status: 403 },
    )
  }

  const { searchParams } = req.nextUrl
  const search = searchParams.get('search')?.trim() ?? ''
  const plan   = searchParams.get('plan')?.trim()   ?? ''
  const status = searchParams.get('status')?.trim() ?? ''
  const page   = Math.max(1, Number(searchParams.get('page') ?? 1))
  const limit  = Math.min(500, Math.max(1, Number(searchParams.get('limit') ?? 20)))

  const where: Record<string, unknown> = {}

  if (search) {
    where.OR = [
      { name:             { contains: search, mode: 'insensitive' } },
      { razaoSocial:      { contains: search, mode: 'insensitive' } },
      { nomeFantasia:     { contains: search, mode: 'insensitive' } },
      { publicId:         { contains: search, mode: 'insensitive' } },
      { cnpj:             { contains: search } },
      { email:            { contains: search, mode: 'insensitive' } },
    ]
  }
  if (plan)   where.plan   = plan
  if (status) where.status = status

  try {
    const [total, tenants] = await Promise.all([
      prisma.tenant.count({ where: where as never }),
      prisma.tenant.findMany({
        where:   where as never,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * limit,
        take:    limit,
        select: {
          id:               true,
          publicId:         true,
          slug:             true,
          name:             true,
          razaoSocial:      true,
          nomeFantasia:     true,
          cnpj:             true,
          plan:             true,
          status:           true,
          statusReason:     true,
          primaryColor:     true,
          phone:            true,
          email:            true,
          city:             true,
          state:            true,
          trialEndsAt:      true,
          maxUsers:         true,
          maxVehicles:      true,
          maxUnits:         true,
          createdAt:        true,
          _count: {
            select: { users: true, units: true, deals: true, partners: true },
          },
        },
      }),
    ])

    return NextResponse.json({
      success:    true,
      data:       tenants,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── POST — Criar tenant completo ──────────────────────────────────────────────

export async function POST(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session || session.user.role !== 'MASTER') {
    return NextResponse.json(
      { success: false, error: 'Acesso negado. Apenas usuários MASTER podem criar tenants.' },
      { status: 403 },
    )
  }

  try {
    const body = await req.json()

    // ── Desestrutura payload ─────────────────────────────────────────────────
    const { company, partners: rawPartners, plan: planConfig } = body as {
      company: {
        cnpj:                    string
        razaoSocial:             string
        nomeFantasia?:           string
        inscricaoEstadual?:      string
        isentoInscricaoEstadual?: boolean
        situacaoCadastral?:      string
        dataAbertura?:           string
        cnaeCode?:               string
        telefone?:               string
        email?:                  string
        address: {
          cep:          string
          logradouro:   string
          numero:       string
          complemento?: string
          bairro:       string
          cidade:       string
          estado:       string
        }
      }
      partners: Array<{
        cpf:            string
        nomeCompleto:   string
        rg?:            string
        celular?:       string
        email:          string
        dataNascimento?: string
        role?:          string
        participacao?:  number
        principal?:     boolean
        address?: {
          cep?:          string
          logradouro?:   string
          numero?:       string
          complemento?:  string
          bairro?:       string
          cidade?:       string
          estado?:       string
        }
      }>
      plan: {
        tenantPlan:    string
        tenantStatus?: string
        modules?:      string[]
        limits?: {
          maxUsers?:    number
          maxVehicles?: number
          maxUnits?:    number
        }
        trialEndsAt?: string
      }
    }

    // ── Validações básicas ───────────────────────────────────────────────────

    if (!company?.cnpj || !company?.razaoSocial?.trim()) {
      return NextResponse.json(
        { success: false, error: 'CNPJ e razão social são obrigatórios.' },
        { status: 400 },
      )
    }

    const cnpj = normalizeCNPJ(company.cnpj)
    if (!isValidCNPJ(cnpj)) {
      return NextResponse.json({ success: false, error: 'CNPJ inválido.' }, { status: 400 })
    }

    if (!rawPartners?.length) {
      return NextResponse.json(
        { success: false, error: 'Pelo menos um sócio/responsável é obrigatório.' },
        { status: 400 },
      )
    }

    // Valida sócios
    for (let i = 0; i < rawPartners.length; i++) {
      const p = rawPartners[i]
      const cpf = normalizeCPF(p.cpf)
      if (!isValidCPF(cpf)) {
        return NextResponse.json(
          { success: false, error: `CPF inválido no sócio ${i + 1}.` },
          { status: 400 },
        )
      }
      if (!p.nomeCompleto?.trim()) {
        return NextResponse.json(
          { success: false, error: `Nome completo é obrigatório no sócio ${i + 1}.` },
          { status: 400 },
        )
      }
      if (!p.email?.trim()) {
        return NextResponse.json(
          { success: false, error: `E-mail é obrigatório no sócio ${i + 1} (será usado como login do usuário ADM).` },
          { status: 400 },
        )
      }
    }

    // ── Verificações de duplicidade ──────────────────────────────────────────

    const existingCnpj = await prisma.tenant.findUnique({ where: { cnpj } })
    if (existingCnpj) {
      return NextResponse.json(
        { success: false, duplicated: true, error: 'Já existe um tenant cadastrado com este CNPJ.' },
        { status: 409 },
      )
    }

    // Verifica e-mail do sócio principal
    const principalPartner = rawPartners.find(p => p.principal) ?? rawPartners[0]
    const principalEmail   = principalPartner.email?.trim().toLowerCase()
    if (principalEmail) {
      const existingEmail = await prisma.user.findUnique({ where: { email: principalEmail } })
      if (existingEmail) {
        return NextResponse.json(
          { success: false, error: `Já existe um usuário cadastrado com o e-mail "${principalEmail}".` },
          { status: 409 },
        )
      }
    }

    // Verifica CPF do sócio principal para duplicidade de usuário
    const principalCPF = normalizeCPF(principalPartner.cpf)
    const existingCPF  = await prisma.user.findUnique({ where: { cpf: principalCPF } })
    if (existingCPF) {
      return NextResponse.json(
        { success: false, error: `Já existe um usuário cadastrado com o CPF do sócio principal.` },
        { status: 409 },
      )
    }

    // ── Gera slug único ──────────────────────────────────────────────────────

    const baseSlug  = slugify(company.nomeFantasia || company.razaoSocial)
    let   slug      = baseSlug
    let   slugSuffix = 1

    while (await prisma.tenant.findUnique({ where: { slug } })) {
      slug = `${baseSlug}-${slugSuffix++}`
    }

    // ── Gera publicId único ──────────────────────────────────────────────────

    let publicId = generatePublicId()
    while (await prisma.tenant.findUnique({ where: { publicId } })) {
      publicId = generatePublicId()
    }

    // ── Hash da senha do ADM (CPF sem pontuação) ─────────────────────────────

    const adminPassword     = principalCPF  // senha = CPF sem pontuação
    const adminPasswordHash = await bcrypt.hash(adminPassword, 12)

    // ── Garantir que o User MASTER da sessão existe no banco ────────────────
    // Causa raiz histórica do erro P2003 "Referência inválida":
    // se a sessão JWT do MASTER aponta para um User.id que foi removido (reset
    // parcial / seed apagado), o AuditLog.create dentro da transação dispara
    // P2003 → toda a criação do tenant é abortada.
    // Solução: verificar antes; se o user não existir, gravar AuditLog sem
    // userId (campo é opcional no schema) e prosseguir.
    const sessionUserExists = await prisma.user.findUnique({
      where:  { id: session.user.id },
      select: { id: true },
    }).then((u) => !!u).catch(() => false)

    if (!sessionUserExists) {
      console.warn(
        `[POST /api/master/tenants] Sessão MASTER aponta para User.id="${session.user.id}" inexistente. ` +
        'Criando tenant sem userId no AuditLog. Verifique se o banco foi resetado e refaça login.',
      )
    }

    // ── Transação atômica ────────────────────────────────────────────────────

    const result = await prisma.$transaction(async (tx) => {

      // 1. Criar Tenant
      const tenant = await tx.tenant.create({
        data: {
          publicId,
          slug,
          name:                    company.nomeFantasia?.trim()  || company.razaoSocial.trim(),
          razaoSocial:             company.razaoSocial.trim(),
          nomeFantasia:            company.nomeFantasia?.trim()  || null,
          cnpj,
          inscricaoEstadual:       company.inscricaoEstadual?.trim() || null,
          isentoInscricaoEstadual: company.isentoInscricaoEstadual ?? false,
          situacaoCadastral:       company.situacaoCadastral?.trim() || null,
          dataAbertura:            company.dataAbertura ? new Date(company.dataAbertura) : null,
          cnaeCode:                company.cnaeCode?.trim()      || null,
          phone:                   normalizePhone(company.telefone) || null,
          email:                   company.email?.trim().toLowerCase() || null,
          zipCode:                 normalizeCEP(company.address.cep),
          logradouro:              company.address.logradouro?.trim() || null,
          numero:                  company.address.numero?.trim()     || null,
          complemento:             company.address.complemento?.trim() || null,
          bairro:                  company.address.bairro?.trim()     || null,
          city:                    company.address.cidade?.trim()     || null,
          state:                   company.address.estado?.toUpperCase().trim() || null,
          plan:                    (planConfig?.tenantPlan ?? 'BASICO') as never,
          status:                  (planConfig?.tenantStatus ?? 'TESTE') as never,
          maxUsers:                planConfig?.limits?.maxUsers    ?? 10,
          maxVehicles:             planConfig?.limits?.maxVehicles ?? 100,
          maxUnits:                planConfig?.limits?.maxUnits    ?? 1,
          trialEndsAt:             planConfig?.trialEndsAt ? new Date(planConfig.trialEndsAt) : null,
          responsavel:             principalPartner.nomeCompleto?.trim() || null,
          responsavelEmail:        principalEmail                        || null,
          responsavelPhone:        normalizePhone(principalPartner.celular) || null,
        },
      })

      // 2. Criar Unit principal
      // Antes existia um hack: criava com `cnpj + '_unit'` para evitar conflito
      // com a constraint @unique de Unit.cnpj e depois atualizava. Em retentativas
      // após erros parciais, esse placeholder podia persistir e gerar P2002.
      //
      // Agora salvamos direto com o CNPJ real. A Unit Matriz tem o mesmo CNPJ
      // do Tenant (mesma pessoa jurídica). Antes da criação, removemos qualquer
      // Unit órfã com esse CNPJ (de tentativa anterior abortada).
      await tx.unit.deleteMany({ where: { cnpj, tenantId: null } }).catch(() => {})

      const mainUnit = await tx.unit.create({
        data: {
          tenantId:    tenant.id,
          name:        company.nomeFantasia?.trim() || company.razaoSocial.trim(),
          razaoSocial: company.razaoSocial.trim(),
          cnpj,
          address:     [company.address.logradouro, company.address.numero, company.address.complemento].filter(Boolean).join(', '),
          city:        company.address.cidade?.trim()  || null,
          state:       company.address.estado?.toUpperCase().trim() || null,
          zipCode:     normalizeCEP(company.address.cep),
          phone:       normalizePhone(company.telefone) || null,
          email:       company.email?.trim().toLowerCase() || null,
          responsavel: principalPartner.nomeCompleto?.trim() || null,
          active:      true,
        },
      })

      // 3. Criar User ADM (sócio principal)
      const adminUser = await tx.user.create({
        data: {
          tenantId:          tenant.id,
          unitId:            mainUnit.id,
          name:              principalPartner.nomeCompleto.trim(),
          email:             principalEmail!,
          cpf:               principalCPF,
          phone:             normalizePhone(principalPartner.celular) || null,
          passwordHash:      adminPasswordHash,
          role:              'ADM',
          status:            'ATIVO',
          mustChangePassword: true,
        },
      })

      // 4. Criar TenantPartner para cada sócio informado
      const createdPartners = []
      for (let i = 0; i < rawPartners.length; i++) {
        const p         = rawPartners[i]
        const partnerCPF = normalizeCPF(p.cpf)
        const isPrincipal = p.principal || i === 0

        const partner = await tx.tenantPartner.create({
          data: {
            tenantId:      tenant.id,
            cpf:           partnerCPF,
            nomeCompleto:  p.nomeCompleto.trim(),
            rg:            p.rg?.trim()    || null,
            celular:       normalizePhone(p.celular) || null,
            email:         p.email?.trim().toLowerCase() || null,
            dataNascimento: p.dataNascimento ? new Date(p.dataNascimento) : null,
            role:          (p.role ?? 'SOCIO') as never,
            participacao:  p.participacao ?? null,
            principal:     isPrincipal,
            cep:           normalizeCEP(p.address?.cep)        || null,
            logradouro:    p.address?.logradouro?.trim()       || null,
            numero:        p.address?.numero?.trim()           || null,
            complemento:   p.address?.complemento?.trim()      || null,
            bairro:        p.address?.bairro?.trim()           || null,
            cidade:        p.address?.cidade?.trim()           || null,
            estado:        p.address?.estado?.toUpperCase().trim() || null,
            userId:        isPrincipal ? adminUser.id : null,
            active:        true,
          },
        })
        createdPartners.push(partner)
      }

      // 5. Criar módulos ativos conforme configuração do plano
      // enabledBy é só String? sem FK declarada, mas mesmo assim só passamos
      // o userId se o user realmente existe no banco.
      const modulesToActivate = planConfig?.modules ?? [
        'dashboard', 'estoque', 'negociacoes', 'comissoes', 'clientes',
      ]
      await tx.tenantModule.createMany({
        data: modulesToActivate.map((module: string) => ({
          tenantId:  tenant.id,
          module:    module.toLowerCase(),
          active:    true,
          enabledBy: sessionUserExists ? session.user.id : null,
          enabledAt: new Date(),
        })),
        skipDuplicates: true,
      })

      // 6. AuditLog dentro da transação
      // userId é opcional (FK para User.id). Se a sessão aponta para um user
      // inexistente, gravamos sem userId — mantendo o nome/role para rastreio.
      await tx.auditLog.create({
        data: {
          userId:   sessionUserExists ? session.user.id : null,
          tenantId: tenant.id,
          action:   'CREATE',
          entity:   'Tenant',
          entityId: tenant.id,
          userName: session.user.name ?? 'MASTER',
          userRole: session.user.role ?? 'MASTER',
          status:   'SUCCESS',
        },
      })

      return { tenant, mainUnit, adminUser, partners: createdPartners }
    })

    // ── Resposta (sem senha em texto claro) ──────────────────────────────────

    return NextResponse.json(
      {
        success: true,
        message: 'Tenant cadastrado com sucesso.',
        data: {
          tenant: {
            id:       result.tenant.id,
            publicId: result.tenant.publicId,
            slug:     result.tenant.slug,
            name:     result.tenant.name,
            cnpj:     result.tenant.cnpj,
            status:   result.tenant.status,
            plan:     result.tenant.plan,
          },
          mainUnit: {
            id:   result.mainUnit.id,
            name: result.mainUnit.name,
          },
          adminUser: {
            id:    result.adminUser.id,
            name:  result.adminUser.name,
            email: result.adminUser.email,
            role:  result.adminUser.role,
          },
          partners:            result.partners.length,
          initialPasswordHint: 'CPF sem pontuação',
        },
      },
      { status: 201 },
    )

  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/negotiations/[id]/attachments
//   GET  → lista anexos do deal (com filtros opcionais).
//   POST → upload de anexo (multipart/form-data).
//
// Form fields aceitos no POST:
//   file       (File)            — obrigatório
//   category   (DealAttachmentCategory) — obrigatório
//   paymentId  (string, opcional)
//   debtId     (string, opcional)
//   vehicleId  (string, opcional)
//   changeId   (string, opcional)
//   notes      (string, opcional)
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { requireModule }        from '@/lib/permissions'
import { saveDealAttachment, validateDealUpload } from '@/lib/negotiation/storage'

export const runtime = 'nodejs'

const VALID_CATEGORIES = new Set([
  'COMPROVANTE_PAGAMENTO',
  'COMPROVANTE_QUITACAO',
  'COMPROVANTE_DEBITO',
  'COMPROVANTE_TROCO',
  'CONTRATO_ASSINADO',
  'PROCURACAO_ASSINADA',
  'NFE',
  'RECIBO',
  'OUTRO',
])

async function loadDeal(id: string) {
  return prisma.deal.findUnique({
    where:  { id },
    select: { id: true, tenantId: true, status: true },
  })
}

// Next 16: params virou Promise. Helper local.
async function resolveDealId(
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
): Promise<string | null> {
  const params = await Promise.resolve(ctxArg.params)
  return params?.id ?? null
}

// ── GET ──────────────────────────────────────────────────────────────────────
export async function GET(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const dealId = await resolveDealId(ctxArg)
  if (!dealId) return NextResponse.json({ error: 'ID ausente na URL.' }, { status: 400 })

  const deal = await loadDeal(dealId)
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  const category = req.nextUrl.searchParams.get('category') ?? undefined

  try {
    const data = await prisma.dealAttachment.findMany({
      where: {
        dealId,
        ...(category && VALID_CATEGORIES.has(category) ? { category: category as any } : {}),
      },
      orderBy: { uploadedAt: 'desc' },
    })
    return NextResponse.json({ data })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── POST ─────────────────────────────────────────────────────────────────────
export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const dealId = await resolveDealId(ctxArg)
  if (!dealId) return NextResponse.json({ error: 'ID ausente na URL.' }, { status: 400 })

  const deal = await loadDeal(dealId)
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  const formData = await req.formData().catch(() => null)
  if (!formData) return NextResponse.json({ error: 'Corpo inválido (multipart/form-data esperado).' }, { status: 400 })

  const file = formData.get('file') as File | null
  if (!file) return NextResponse.json({ error: 'Campo "file" é obrigatório.' }, { status: 400 })

  const category = String(formData.get('category') ?? '').trim().toUpperCase()
  if (!VALID_CATEGORIES.has(category)) {
    return NextResponse.json({ error: `Categoria inválida. Use uma de: ${[...VALID_CATEGORIES].join(', ')}` }, { status: 400 })
  }

  const v = validateDealUpload(file.type, file.size)
  if (!v.ok) return NextResponse.json({ error: v.error }, { status: 400 })

  try {
    const bytes = Buffer.from(await file.arrayBuffer())
    const saved = await saveDealAttachment(dealId, file.name, file.type, bytes)

    const att = await prisma.dealAttachment.create({
      data: {
        dealId,
        tenantId:       deal.tenantId,
        category:       category as any,
        fileName:       saved.fileName,
        fileType:       saved.fileType,
        mimeType:       saved.mimeType,
        fileSize:       saved.fileSize,
        storageKey:     saved.storageKey,
        publicUrl:      saved.publicUrl,
