//   GET  → lista documentos da negociação (contratos, procurações, etc).
//   POST → gera documento a partir de um templateId (merge fields aplicados).
//          Também aceita criação avulsa (sem templateId) com bodyHtml direto.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { requireModule }        from '@/lib/permissions'
import { renderTemplate, buildDealContext } from '@/lib/negotiation/document-merge'

const VALID_TYPES = new Set([
  'CONTRATO_COMPRA', 'CONTRATO_VENDA', 'CONTRATO_TROCA', 'CONTRATO_CONSIGNACAO',
  'PROCURACAO', 'RECIBO', 'TERMO_ENTREGA', 'TERMO_RESPONSABILIDADE', 'OUTRO',
])

export async function GET(_req: NextRequest, ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const deal = await prisma.deal.findUnique({
    where:  { id: params.id },
    select: { id: true, tenantId: true },
  })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  try {
    const data = await prisma.dealDocument.findMany({
      where:   { dealId: params.id },
      orderBy: { createdAt: 'desc' },
      include: { template: { select: { name: true, type: true } } },
    })
    return NextResponse.json({ data })
  } catch (err) { return handlePrismaError(err) }
}

export async function POST(req: NextRequest, ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations.manage') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const body = await req.json()
    const templateId: string | undefined = body?.templateId
    const explicitType: string | undefined = body?.type ? String(body.type).toUpperCase() : undefined
    const customName: string | undefined = body?.name
    const customHtml: string | undefined = body?.bodyHtml

    // Carrega deal com tudo necessário pro contexto de merge
    const deal = await prisma.deal.findUnique({
      where:   { id: params.id },
      include: {
        person:   true,
        customer: true,
        vehicles: true,
      },
    })
    if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })
    if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
      return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
    }

    let html  = customHtml ?? ''
    let name  = customName ?? 'Documento'
    let type  = explicitType ?? 'OUTRO'
    let templateRefId: string | null = null

    if (templateId) {
      const tpl = await prisma.documentTemplate.findUnique({ where: { id: templateId } })
      if (!tpl || !tpl.active) return NextResponse.json({ error: 'Template não disponível' }, { status: 404 })
      // visibilidade: global ou do tenant do user
      if (tpl.tenantId !== null && session.user.tenantId && tpl.tenantId !== session.user.tenantId) {
        return NextResponse.json({ error: 'Template fora do seu tenant' }, { status: 403 })
      }
      const ctx = buildDealContext(deal as any)
      html = renderTemplate(tpl.bodyHtml, ctx)
      name = customName ?? tpl.name
      type = tpl.type
      templateRefId = tpl.id
    }

    if (!VALID_TYPES.has(type)) return NextResponse.json({ error: 'Tipo inválido' }, { status: 400 })
    if (!html.trim()) return NextResponse.json({ error: 'Conteúdo vazio (informe templateId ou bodyHtml).' }, { status: 400 })

    const doc = await prisma.dealDocument.create({
      data: {
        dealId:      params.id,
        tenantId:    deal.tenantId,
        templateId:  templateRefId,
        type:        type as any,
        name,
        bodyHtml:    html,
        status:      'GERADO',
        createdById: session.user.id,
      },
    })

    return NextResponse.json({ data: doc }, { status: 201 })
  } catch (err) { return handlePrismaError(err) }
}

// =============================================================================
// POST /api/negotiations/[id]/finalize — Finalizar negociação
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'
import { canFinalizeDeal, FINALIZABLE_STATUSES } from '@/lib/negotiation-permissions'
import { createDealAudit, createStatusHistory, updateVehicleStock, computeDealBalance } from '@/lib/negotiation-service'
import { generateCommissionsForDeal } from '@/lib/commission-generator'
import { canForceFinalize } from '@/lib/negotiation-rbac'

export const dynamic = 'force-dynamic'

export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations.manage')
  } catch {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  if (!canFinalizeDeal(session.user.role)) {
    return NextResponse.json({ error: 'Sem permissão para finalizar negociações' }, { status: 403 })
  }

  let body: any = {}
  try { body = await req.json() } catch { /* sem body */ }
  const force = body?.force === true && canForceFinalize({ id: session.user.id, role: session.user.role } as any)

  const deal = await prisma.deal.findUnique({
    where: { id: params.id },
    include: {
      vehicles: { select: { id: true, vehicleId: true, role: true } },
      debts:    true,
      services: true,
      payments: true,
      discountRequests: true,
      changes:  true,
    },
  })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })

  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  if (!FINALIZABLE_STATUSES.has(deal.status)) {
    return NextResponse.json(
      { error: `Apenas negociações nos status ${Array.from(FINALIZABLE_STATUSES).join(', ')} podem ser finalizadas` },
      { status: 409 },
    )
  }

  // Bloqueio de saldo em aberto
  if (!force) {
    const balance = computeDealBalance({
      vehicleValue:     deal.vehicleValue != null ? Number(deal.vehicleValue) : Number(deal.saleAmount ?? 0),
      debts:            deal.debts,
      services:         deal.services,
      payments:         deal.payments,
      discountRequests: deal.discountRequests,
      changes:          deal.changes,
    })
    if (balance.saldo > 0.009) {
      return NextResponse.json(
        { error: 'Saldo da negociação está em aberto. Não é possível finalizar.', balance },
        { status: 422 },
      )
    }
    // saldo negativo (excedente) precisa ser coberto por troco cadastrado
    if (balance.saldo < -0.009) {
      const excedente = -balance.saldo
      if (balance.totalTroco + 0.009 < excedente) {
        return NextResponse.json(
          { error: 'Existe valor excedente sem troco cadastrado. Cadastre o troco antes de finalizar.', balance },
          { status: 422 },
        )
      }
    }
  }

  try {
    const updated = await prisma.$transaction(async (tx) => {
      const d = await tx.deal.update({
        where: { id: params.id },
        data: {
          status:      'FINALIZADA',
          finalizedAt: new Date(),
        },
      })

      // Marcar veículo vendido como VENDIDO no estoque
      for (const dv of deal.vehicles) {
        if (dv.vehicleId && dv.role === 'VENDIDO') {
          await updateVehicleStock(tx as any, dv.vehicleId, 'VENDIDO')
        }
      }

      // ── COMPRA finalizada → veículo entra no estoque em precificação ─────
      // Hoje é o momento em que a loja efetivamente "comprou" o carro do
      // cliente. Marca o Vehicle (criado pela negociação) como
      // EM_PRECIFICACAO + active=false; gerente define preço de venda em
      // /estoque/[id] aba Precificação para publicar no estoque.
      if (deal.type === 'COMPRA') {
        for (const dv of deal.vehicles) {
          if (dv.vehicleId && dv.role === 'COMPRADO') {
            await (tx as any).vehicle.update({
              where: { id: dv.vehicleId },
              data:  {
                stockStatus:        'EM_PRECIFICACAO' as any,
                active:             false,
                isAvailableForSale: false,
                entryDate:          new Date(),
              },
            }).catch((e: unknown) => {
              console.error('[finalize] failed to mark COMPRA vehicle for pricing', e)
            })
          }
        }
      }

      await createStatusHistory(tx as any, params.id, deal.status, 'FINALIZADA', session.user.id, `Finalizado por ${session.user.name}`)

      await createDealAudit(tx as any, {
        dealId:   params.id,
        tenantId: deal.tenantId,
        unitId:   deal.unitId,
        userId:   session.user.id,
        userName: session.user.name,
        userRole: session.user.role,
        action:   'FINALIZAR',
        field:    'status',
        oldValue: deal.status,
        newValue: 'FINALIZADA',
      })

      await tx.auditLog.create({
        data: {
          userId:        session.user.id,
          tenantId:      session.user.tenantId ?? null,
          action:        'FINALIZE',
          entity:        'Deal',
          entityId:      params.id,
          userName:      session.user.name,
          userRole:      session.user.role,
          status:        'SUCCESS',
          afterData:     { status: 'FINALIZADA' } as never,
          beforeData:    { status: deal.status } as never,
        },
      })

      return d
    })

    // Gera comissões automaticamente (não bloqueia o close em caso de falha)
    let commissionResult: Awaited<ReturnType<typeof generateCommissionsForDeal>> | null = null
    try {
      commissionResult = await generateCommissionsForDeal({
        dealId:      params.id,
        tenantId:    deal.tenantId ?? null,
        triggeredBy: session.user.id,
      })
    } catch (err) {
      console.error('[finalize] commission generation failed', err)
    }

    return NextResponse.json({
      data: updated,
      commissionResult: commissionResult
        ? {
            created:   commissionResult.created,
            matched:   commissionResult.matched,
            unmatched: commissionResult.unmatched,
          }
        : null,
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/negotiations/[id]/payments/[paymentId] — atualizar/remover pagamento
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'
import { isDealLocked, canAddPayment } from '@/lib/negotiation-rbac'
import { createSafeAuditLog } from '@/lib/auth-guards'

export const dynamic = 'force-dynamic'

async function loadContext(id: string, paymentId: string) {
  const deal = await prisma.deal.findUnique({
    where: { id },
    select: { id: true, tenantId: true, status: true, sellerId: true },
  })
  if (!deal) return { error: 'Negociação não encontrada', status: 404 as const }
  const payment = await prisma.dealPayment.findUnique({ where: { id: paymentId } })
  if (!payment || payment.dealId !== id) {
    return { error: 'Pagamento não encontrado', status: 404 as const }
  }
  return { deal, payment }
}

async function getActor(session: any) {
  const seller = session?.user?.id
    ? await prisma.seller.findFirst({ where: { userId: session.user.id }, select: { id: true } })
    : null
  return {
    id:       session?.user?.id,
    role:     session?.user?.role as string,
    tenantId: session?.user?.tenantId as string | null,
    sellerId: seller?.id ?? null,
  }
}

export async function PATCH(
  req: NextRequest,
  ctxArg: { params: { id: string; paymentId: string } | Promise<{ id: string; paymentId: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const ctx = await loadContext(params.id, params.paymentId)
  if ('error' in ctx) return NextResponse.json({ error: ctx.error }, { status: ctx.status })
  const { deal } = ctx
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }
  if (isDealLocked(deal.status)) {
    return NextResponse.json({ error: 'Negociação finalizada. Reabra para alterar.' }, { status: 423 })
  }
  const actor = await getActor(session)
  if (!canAddPayment(actor, deal)) {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  let body: any
  try { body = await req.json() } catch { return NextResponse.json({ error: 'Payload inválido' }, { status: 400 }) }

  const data: any = {}
  if (body?.method || body?.type) data.type = String(body.method ?? body.type).toUpperCase()
  if (body?.amount != null || body?.value != null) {
    const amt = Number(body.amount ?? body.value)
    if (!Number.isFinite(amt) || amt <= 0) return NextResponse.json({ error: 'Valor inválido' }, { status: 400 })
    data.value = amt
  }
  if (body?.bank !== undefined) data.bank = body.bank
  if (body?.cardBrand !== undefined) data.cardBrand = body.cardBrand
  if (body?.installments !== undefined) data.installments = body.installments == null ? null : Number(body.installments)
  if (body?.firstDueDate !== undefined) data.firstDueDate = body.firstDueDate ? new Date(body.firstDueDate) : null
  if (body?.dueDate !== undefined) data.dueDate = body.dueDate ? new Date(body.dueDate) : null
  if (body?.notes !== undefined) data.notes = body.notes

  try {
    const updated = await prisma.dealPayment.update({ where: { id: params.paymentId }, data })
    await createSafeAuditLog({
      userId: session.user.id, tenantId: session.user.tenantId ?? null,
      action: 'UPDATE_PAYMENT', entity: 'DealPayment', entityId: params.paymentId,
      userName: session.user.name, userRole: session.user.role,
    })
    return NextResponse.json({ data: updated })
  } catch (err) { return handlePrismaError(err) }
}

export async function DELETE(
  _req: NextRequest,
  ctxArg: { params: { id: string; paymentId: string } | Promise<{ id: string; paymentId: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const ctx = await loadContext(params.id, params.paymentId)
  if ('error' in ctx) return NextResponse.json({ error: ctx.error }, { status: ctx.status })
  const { deal } = ctx
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
