// /api/negotiations/[id] — Detalhar e editar negociação
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'
import { canEditSensitiveFields, SENSITIVE_FIELDS, EDITABLE_STATUSES } from '@/lib/negotiation-permissions'
import { computeDealTotals, createDealAudit, createStatusHistory } from '@/lib/negotiation-service'
import { canEditDeal, isDealLocked } from '@/lib/negotiation-rbac'

export const dynamic = 'force-dynamic'

const MONETARY_FIELDS = new Set([
  'saleAmount', 'purchaseAmount', 'tradeValue', 'signalAmount',
  'financedAmount', 'documentationFee', 'servicesAmount',
  'discountAmount', 'payoffAmount', 'vehicleValue', 'changeAmount',
])

export async function GET(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations')
  } catch {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  const params = await Promise.resolve(ctxArg.params)
  const dealId = params?.id
  if (!dealId) return NextResponse.json({ error: 'ID ausente na URL.' }, { status: 400 })

  const deal = await prisma.deal.findUnique({
    where:   { id: dealId },
    include: {
      person:   true,
      customer: true,
      seller:   {
        select: {
          id:       true,
          fullName: true,
          shortName: true,
          user:     { select: { id: true, name: true, email: true } },
        },
      },
      manager:  { select: { id: true, name: true, email: true } },
      vehicles: { include: { vehicle: true }, orderBy: { createdAt: 'asc' } },
      debts:    { orderBy: { createdAt: 'asc' } },
      payments: { orderBy: { createdAt: 'asc' } },
      services: { orderBy: { createdAt: 'asc' } },
      history:  { orderBy: { createdAt: 'asc' } },
      discountRequests: { orderBy: { createdAt: 'desc' } },
      changes:  { orderBy: { createdAt: 'asc' } },
      reopenLogs: { orderBy: { createdAt: 'desc' }, take: 10 },
      pendencies: {
        where:  { status: { notIn: ['FINALIZADA', 'CANCELADA'] } },
        select: { id: true, type: true, status: true, priority: true, description: true },
        take:   10,
      },
      contracts: {
        select: { id: true, type: true, createdAt: true },
        take:   5,
      },
      sheetImportRows: {
        select: {
          id:             true,
          sheetName:      true,
          externalId:     true,
          rawData:        true,
          referenceMonth: true,
          sellerName:     true,
          customerName:   true,
          plate:          true,
          vehicleModel:   true,
          status:         true,
          createdAt:      true,
        },
        take:    5,
        orderBy: { createdAt: 'desc' },
      },
    },
  })

  if (!deal) {
    return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })
  }

  // Enriquecer histórico com nome do usuário (query separada)
  const userIds = deal.history
    .map((h) => h.changedByUserId)
    .filter((id): id is string => !!id)
  const users = userIds.length
    ? await prisma.user.findMany({
        where: { id: { in: userIds } },
        select: { id: true, name: true },
      })
    : []
  const userMap = Object.fromEntries(users.map((u) => [u.id, u.name]))

  // Lookup approvedBy and cancelledBy users
  const extraUserIds = [deal.approvedById, deal.cancelledById].filter((id): id is string => !!id)
  const extraUsers = extraUserIds.length
    ? await prisma.user.findMany({
        where: { id: { in: extraUserIds } },
        select: { id: true, name: true },
      })
    : []
  const extraUserMap = Object.fromEntries(extraUsers.map((u) => [u.id, u]))

  const dealWithHistory = {
    ...deal,
    approvedBy:  deal.approvedById  ? (extraUserMap[deal.approvedById]  ?? null) : null,
    cancelledBy: deal.cancelledById ? (extraUserMap[deal.cancelledById] ?? null) : null,
    statusHistory: deal.history.map((h) => ({
      ...h,
      changedByUser: h.changedByUserId ? { name: userMap[h.changedByUserId] ?? null } : null,
    })),
  }

  // Isolamento por tenant
  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  return NextResponse.json({ data: dealWithHistory })
}

// ── PATCH — Editar negociação ─────────────────────────────────────────────────

export async function PATCH(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations')
  } catch {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  const params = await Promise.resolve(ctxArg.params)
  const dealId = params?.id
  if (!dealId) return NextResponse.json({ error: 'ID ausente na URL.' }, { status: 400 })

  const deal = await prisma.deal.findUnique({ where: { id: dealId } })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })

  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  if (isDealLocked(deal.status)) {
    return NextResponse.json(
      { error: 'Negociação finalizada. Reabra para alterar.' },
      { status: 423 },
    )
  }

  const actor = { id: session.user.id, role: session.user.role, tenantId: session.user.tenantId ?? null, sellerId: null }
  if (!canEditDeal(actor, deal)) {
    return NextResponse.json({ error: 'Sem permissão para editar esta negociação no status atual' }, { status: 403 })
  }

  let body: Record<string, unknown>
  try {
    body = await req.json()
  } catch {
    return NextResponse.json({ error: 'Payload inválido' }, { status: 400 })
  }

  const editableSensitive = canEditSensitiveFields(session.user.role)
  const sensitiveBlocked  = !editableSensitive && !EDITABLE_STATUSES.includes(deal.status)

  // Whitelist explícita de colunas escalares do Deal que aceitamos via PATCH.
  // Tudo que não estiver aqui é IGNORADO (especialmente nested objects como
  // `person`, `vehicle`, `debts`, `customer` que o wizard envia mas não são
  // colunas do Deal — Prisma os rejeitaria com PrismaClientValidationError).
  const DEAL_PATCHABLE_FIELDS = new Set<string>([
    // Identificação / relacionamentos
    'type', 'unitId', 'sellerId', 'managerId', 'personId',
    // Financeiro
    'saleAmount', 'purchaseAmount', 'financedAmount', 'documentationFee',
    'signalAmount', 'payoffAmount', 'discountAmount', 'servicesAmount',
    'vehicleValue', 'tradeValue', 'totalPayments', 'changeAmount',
    'marginAmount', 'balance',
    'paymentBank', 'paymentType',
    // Troco / dados bancários
    'changeBeneficiary', 'changeBeneficiaryCpf', 'changeBank',
    'changeAgency', 'changeAccount', 'changePix',
    // Consignação
    'consignMinValue', 'consignCommPct', 'consignDeadline',
    // Agendamento e observações
    'deliveryDate', 'notes', 'sellerNameFromSheet',
  ])

  // Campos numéricos: o wizard às vezes envia como string mascarada
  // (ex: "1.500,00"). Tratamos com parseBRL no caller, mas garantimos
  // aqui que strings vazias viram null e números/strings numéricas válidas
  // viram Number — evita "" em coluna Decimal.
  const NUMERIC_FIELDS = new Set<string>([
    'saleAmount', 'purchaseAmount', 'financedAmount', 'documentationFee',
    'signalAmount', 'payoffAmount', 'discountAmount', 'servicesAmount',
    'vehicleValue', 'tradeValue', 'totalPayments', 'changeAmount',
    'marginAmount', 'balance', 'consignMinValue', 'consignCommPct',
  ])

  function coerceValue(field: string, raw: unknown): unknown {
    if (raw === '' || raw === undefined) return null
    if (NUMERIC_FIELDS.has(field) && raw != null) {
      const n = typeof raw === 'number' ? raw : Number(raw)
      return Number.isFinite(n) ? n : null
    }
    if ((field === 'deliveryDate' || field === 'consignDeadline') && raw != null) {
      const d = raw instanceof Date ? raw : new Date(String(raw))
      return Number.isNaN(d.getTime()) ? null : d
    }
    return raw
  }

  const allowedFields: Record<string, unknown> = {}
  const auditEntries: Array<{ field: string; oldValue: unknown; newValue: unknown }> = []

  for (const [key, rawValue] of Object.entries(body)) {
    if (key === 'status') continue // status muda via endpoints específicos
    if (!DEAL_PATCHABLE_FIELDS.has(key)) continue // dropa nested objects + campos desconhecidos
    if (SENSITIVE_FIELDS.includes(key) && sensitiveBlocked) continue

    const value    = coerceValue(key, rawValue)
    const oldValue = (deal as any)[key]
    // Comparação tolerante: Decimal vira string via Prisma, então comparamos
    // sempre como string para evitar diffs falsos
    if (String(oldValue ?? '') !== String(value ?? '')) {
      allowedFields[key] = value
      auditEntries.push({ field: key, oldValue, newValue: value })
    }
  }

  // ── Person update: o wizard de edição envia `person` aninhado com todos
  // os campos do cliente (inclusive endereço). Persistimos via update do
  // Person vinculado, com merge tolerante — campos vazios NÃO sobrescrevem
  // dados existentes (evita o bug "endereço sumiu").
  const PERSON_PATCHABLE_FIELDS = [
    'type', 'cpf', 'cnpj', 'nomeCompleto', 'rg', 'dataNascimento', 'nomeMae',
    'razaoSocial', 'nomeFantasia', 'inscricaoEstadual',
    'socioAdmNome', 'socioAdmCpf', 'socioAdmPhone', 'socioAdmNomeMae',
    'socioAdmEmail', 'socioAdmWhatsapp',
    'email', 'phone', 'whatsapp',
    'cep', 'logradouro', 'numero', 'complemento', 'bairro', 'cidade', 'estado',
  ] as const

  const personBody = (body as Record<string, unknown>).person as Record<string, unknown> | undefined
  let personPatch: Record<string, unknown> | null = null
  if (personBody && typeof personBody === 'object' && deal.personId) {
    const patch: Record<string, unknown> = {}
    for (const field of PERSON_PATCHABLE_FIELDS) {
      if (!(field in personBody)) continue
      const v = personBody[field]
      // Boolean fica (true/false). String vazia, null e undefined → não toca
      // (preserva valor salvo). Datas viram Date.
      if (typeof v === 'boolean') {
        patch[field] = v
      } else if (v === '' || v == null) {
        continue
      } else if (field === 'dataNascimento') {
        const d = new Date(String(v))
        if (!Number.isNaN(d.getTime())) patch[field] = d
      } else {
        patch[field] = v
      }
    }
    if (Object.keys(patch).length > 0) personPatch = patch
  }

  // Se o usuário não enviou nenhuma mudança válida, devolvemos sucesso vazio
  // em vez de chamar update com data:{} (que Prisma também rejeita).
  if (Object.keys(allowedFields).length === 0 && !personPatch) {
    return NextResponse.json({ data: deal, message: 'Nenhuma alteração detectada.' })
  }

  // Recalcular totais se algum campo financeiro mudou
  const financialFields = ['saleAmount', 'purchaseAmount', 'tradeValue', 'signalAmount', 'financedAmount', 'documentationFee', 'servicesAmount', 'discountAmount', 'payoffAmount']
  const needsRecalc = financialFields.some((f) => f in allowedFields)

  if (needsRecalc) {
    const merged = {
      saleAmount:      allowedFields.saleAmount      ?? deal.saleAmount,
      purchaseAmount:  allowedFields.purchaseAmount  ?? deal.purchaseAmount,
      tradeValue:      allowedFields.tradeValue      ?? deal.tradeValue,
      signalAmount:    allowedFields.signalAmount    ?? deal.signalAmount,
      financedAmount:  allowedFields.financedAmount  ?? deal.financedAmount,
      documentationFee: allowedFields.documentationFee ?? deal.documentationFee,
      servicesAmount:  allowedFields.servicesAmount  ?? deal.servicesAmount,
      discountAmount:  allowedFields.discountAmount  ?? deal.discountAmount,
      payoffAmount:    allowedFields.payoffAmount    ?? deal.payoffAmount,
      changeAmount:    allowedFields.changeAmount    ?? deal.changeAmount,
    }
    const totals = computeDealTotals(merged as any)
    allowedFields.totalPayments = totals.totalPayments
    allowedFields.balance       = totals.balance
    allowedFields.marginAmount  = totals.marginAmount
  }

  try {
    const updated = await prisma.$transaction(async (tx) => {
      // Atualiza Person primeiro (se houver patch). Falha aqui aborta tudo.
      if (personPatch && deal.personId) {
        await tx.person.update({
          where: { id: deal.personId },
          data:  personPatch as never,
        })
      }

      // Só chama deal.update se houver campos do Deal a atualizar.
      // Se só o Person mudou, retornamos o deal carregado novamente.
      const d = Object.keys(allowedFields).length > 0
        ? await tx.deal.update({
            where: { id: dealId },
            data:  allowedFields as any,
          })
        : await tx.deal.findUniqueOrThrow({ where: { id: dealId } })

      // Auditoria campo a campo — paralela para não bloquear a transação
      await Promise.all(auditEntries.map(entry =>
        createDealAudit(tx as any, {
          dealId:   dealId,
          tenantId: deal.tenantId,
          unitId:   deal.unitId,
          userId:   session.user.id,
          userName: session.user.name,
          userRole: session.user.role,
          action:   'EDITAR',
          field:    entry.field,
          oldValue: entry.oldValue,
          newValue: entry.newValue,
        }),
      ))

      await tx.auditLog.create({
        data: {
          userId:   session.user.id,
          tenantId: session.user.tenantId ?? null,
          action:   'UPDATE',
          entity:   'Deal',
          entityId: dealId,
          userName: session.user.name,
          userRole: session.user.role,
          status:   'SUCCESS',
          afterData: allowedFields as never,
        },
      })

      // Auditoria específica de campos monetários (diff before/after)
      const monetaryDiff = auditEntries.filter(e => MONETARY_FIELDS.has(e.field))
      if (monetaryDiff.length > 0) {
        const before: Record<string, unknown> = {}
        const after:  Record<string, unknown> = {}
        for (const e of monetaryDiff) {
          before[e.field] = e.oldValue
          after[e.field]  = e.newValue
        }
        await tx.auditLog.create({
          data: {
            userId:     session.user.id,
            tenantId:   session.user.tenantId ?? null,
            action:     'UPDATE_MONETARY',
            entity:     'Deal',
            entityId:   dealId,
            userName:   session.user.name,
            userRole:   session.user.role,
            status:     'SUCCESS',
            beforeData: before as never,
            afterData:  after  as never,
          },
        })
      }

      return d
    })

    return NextResponse.json({ data: updated })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// DELETE /api/negotiations/[id]/services/[serviceId] — Remover serviço
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'
import { createDealAudit } from '@/lib/negotiation-service'

export async function DELETE(
  _req: NextRequest,
  ctxArg: { params: { id: string; serviceId: string } | Promise<{ id: string; serviceId: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations.manage')
  } catch {
    return NextResponse.json({ error: 'Sem permissão para remover serviços' }, { status: 403 })
  }

  const deal = await prisma.deal.findUnique({ where: { id: params.id } })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })

  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  const service = await (prisma.dealService as any).findUnique({ where: { id: params.serviceId } })
  if (!service || service.dealId !== params.id) {
    return NextResponse.json({ error: 'Serviço não encontrado' }, { status: 404 })
  }

  try {
    await prisma.$transaction(async (tx) => {
      await (tx.dealService as any).delete({ where: { id: params.serviceId } })

      const allServices: any[] = await (tx.dealService as any).findMany({
        where: { dealId: params.id },
        select: { value: true },
      })
      const servicesAmount = allServices.reduce((sum: number, s: any) => sum + Number(s.value), 0)

      await tx.deal.update({
        where: { id: params.id },
        data:  { servicesAmount },
      })

      await createDealAudit(tx as unknown as any, {
        dealId:   params.id,
        tenantId: deal.tenantId,
        unitId:   deal.unitId,
        userId:   session.user.id,
        userName: session.user.name,
        userRole: session.user.role,
        action:   'REMOVER_SERVICO',
        field:    'servicesAmount',
        oldValue: deal.servicesAmount,
        newValue: servicesAmount,
        reason:   `Serviço removido: ${service.name}`,
      })
    })

    return NextResponse.json({ success: true })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// POST /api/negotiations/[id]/services — Adicionar serviço à negociação
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'
import { createDealAudit } from '@/lib/negotiation-service'

export async function POST(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations')
  } catch {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  let body: { name?: string; value?: number; cost?: number; supplier?: string; commission?: number; notes?: string } = {}
  try {
    body = await req.json()
  } catch {
    return NextResponse.json({ error: 'Payload inválido' }, { status: 400 })
  }

  if (!body.name?.trim()) {
    return NextResponse.json({ error: 'Nome do serviço é obrigatório' }, { status: 400 })
  }
  if (!body.value || Number(body.value) <= 0) {
    return NextResponse.json({ error: 'Valor do serviço deve ser maior que zero' }, { status: 400 })
  }

  const deal = await prisma.deal.findUnique({ where: { id: params.id } })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })

  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  try {
    const result = await prisma.$transaction(async (tx) => {
      const service = await (tx.dealService as any).create({
        data: {
          dealId:     params.id,
          name:       body.name,
          value:      Number(body.value),
          cost:       body.cost       != null ? Number(body.cost)       : null,
          supplier:   body.supplier   ?? null,
          commission: body.commission != null ? Number(body.commission) : null,
          notes:      body.notes      ?? null,
        },
      })

      // Recalcular servicesAmount
      const allServices: any[] = await (tx.dealService as any).findMany({
        where: { dealId: params.id },
        select: { value: true },
      })
      const servicesAmount = allServices.reduce((sum: number, s: any) => sum + Number(s.value), 0)

      const updatedDeal = await tx.deal.update({
        where: { id: params.id },
        data:  { servicesAmount },
      })

      await createDealAudit(tx as unknown as any, {
        dealId:   params.id,
        tenantId: deal.tenantId,
        unitId:   deal.unitId,
        userId:   session.user.id,
        userName: session.user.name,
        userRole: session.user.role,
        action:   'ADICIONAR_SERVICO',
        field:    'servicesAmount',
        oldValue: deal.servicesAmount,
        newValue: servicesAmount,
        reason:   `Serviço adicionado: ${body.name}`,
      })

      return { service, deal: updatedDeal }
    })

    return NextResponse.json({ data: result }, { status: 201 })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// GET /api/negotiations/[id]/timeline — Timeline completa da negociação
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'

type TimelineEvent = {
  type: 'STATUS' | 'AUDIT' | 'SERVICE' | 'VEHICLE' | 'PENDENCY'
  icon: string
  title: string
  description?: string
  user?: string
  date: string
}

const STATUS_ICONS: Record<string, string> = {
  RASCUNHO:                  'FileText',
  EM_PREENCHIMENTO:          'Edit',
  AGUARDANDO_LIBERACAO:      'Clock',
  AGUARDANDO_APROVACAO:      'Clock',
  LIBERADA:                  'CheckCircle',
  APROVADA:                  'CheckCircle',
  RECUSADA:                  'XCircle',
  DESAPROVADA:               'XCircle',
  DEVOLVIDA_PARA_CORRECAO:   'RotateCcw',
  AGUARDANDO_SINAL:          'DollarSign',
  SINAL_RECEBIDO:            'DollarSign',
  RESERVADA:                 'Lock',
  AGUARDANDO_FINANCEIRO:     'Landmark',
  FINANCEIRO_APROVADO:       'Landmark',
  FINANCEIRO_REPROVADO:      'Landmark',
  AGUARDANDO_DOCUMENTACAO:   'FileCheck',
  DOCUMENTACAO_CONCLUIDA:    'FileCheck',
  AGUARDANDO_CONTRATO:       'FileSignature',
  CONTRATO_GERADO:           'FileSignature',
  AGUARDANDO_ASSINATURA:     'PenLine',
  ASSINADA:                  'PenLine',
  AGUARDANDO_ENTREGA:        'Truck',
  ENTREGUE:                  'Truck',
  EM_ANDAMENTO:              'Activity',
  FINALIZADA:                'Flag',
  CANCELADA:                 'Ban',
  REABERTA:                  'RefreshCw',
  BLOQUEADA:                 'Lock',
}

export async function GET(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try {
    requireModule(session.user.role, 'negotiations')
  } catch {
    return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
  }

  const deal = await prisma.deal.findUnique({
    where: { id: params.id },
    select: { id: true, tenantId: true },
  })
  if (!deal) return NextResponse.json({ error: 'Negociação não encontrada' }, { status: 404 })

  if (session.user.tenantId && deal.tenantId !== session.user.tenantId) {
    return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
  }

  const [statusHistory, auditLogs, services, vehicles, pendencies] = await Promise.all([
    prisma.dealStatusHistory.findMany({
      where: { dealId: params.id },
      orderBy: { createdAt: 'asc' },
    }),
    (prisma.dealAuditLog as any).findMany({
      where: { dealId: params.id },
      orderBy: { createdAt: 'asc' },
    }),
    (prisma.dealService as any).findMany({
      where: { dealId: params.id },
      orderBy: { createdAt: 'asc' },
    }),
    prisma.dealVehicle.findMany({
      where: { dealId: params.id },
      orderBy: { createdAt: 'asc' },
    }),
    prisma.pendency.findMany({
      where: { dealId: params.id } as any,
      orderBy: { createdAt: 'asc' },
    }),
  ])

  // Buscar nomes de usuários do histórico de status
  const userIds = statusHistory
    .map((h) => h.changedByUserId)
    .filter((id): id is string => !!id)
  const users = userIds.length
    ? await prisma.user.findMany({ where: { id: { in: userIds } }, select: { id: true, name: true } })
    : []
  const userMap = Object.fromEntries(users.map((u) => [u.id, u.name]))

  // Chaves de audit já presentes no histórico de status (evitar duplicatas)
  const statusKeys = new Set(
    statusHistory.map((h) => `${h.newStatus}:${new Date(h.createdAt).toISOString()}`)
  )

  const events: TimelineEvent[] = []

  // STATUS
  for (const h of statusHistory) {
    events.push({
      type:        'STATUS',
      icon:        STATUS_ICONS[h.newStatus] ?? 'Activity',
      title:       h.newStatus.replace(/_/g, ' '),
      description: h.reason ?? undefined,
      user:        h.changedByUserId ? (userMap[h.changedByUserId] ?? undefined) : undefined,
      date:        h.createdAt.toISOString(),
    })
  }

  // AUDIT — apenas eventos não duplicados com STATUS
  for (const a of auditLogs) {
    if (a.action === 'STATUS' || a.action === 'CRIAR') continue
    const key = `${a.newValue}:${new Date(a.createdAt).toISOString()}`
    if (statusKeys.has(key)) continue

    events.push({
      type:        'AUDIT',
      icon:        'Edit',
      title:       `${a.action}${a.field ? ` — ${a.field}` : ''}`,
      description: a.reason ?? (a.oldValue != null ? `${a.oldValue} → ${a.newValue}` : undefined),
      user:        a.userName ?? undefined,
      date:        new Date(a.createdAt).toISOString(),
    })
  }

  // SERVICE
  for (const s of services) {
    events.push({
      type:  'SERVICE',
      icon:  'Package',
      title: `Serviço adicionado: ${s.name}`,
      description: `Valor: R$ ${Number(s.value).toFixed(2)}`,
      date:  new Date(s.createdAt).toISOString(),
    })
  }

  // VEHICLE
  for (const v of vehicles) {
    const label = v.plate ?? v.model ?? 'Veículo'
    events.push({
      type:  'VEHICLE',
      icon:  'Car',
      title: `Veículo vinculado (${v.role}): ${label}`,
      date:  new Date(v.createdAt).toISOString(),
    })
  }

  // PENDENCY
  for (const p of pendencies) {
    events.push({
      type:        'PENDENCY',
      icon:        'AlertCircle',
      title:       `Pendência criada: ${p.type ?? 'NEGOCIACAO'}`,
      description: p.description ?? undefined,
      date:        new Date(p.createdAt).toISOString(),
    })
  }

  events.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())

  return NextResponse.json({ data: events })
}

// =============================================================================
// GET /api/negotiations/evaluations
// Avaliações aprovadas disponíveis para uso em negociações de TROCA.
// Requer permissão 'negotiations' (não exige 'stock.evaluate').
// Retorna apenas avaliações com result=APROVADO para seleção no wizard.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { requireModule }        from '@/lib/permissions'
import { handlePrismaError }    from '@/lib/prisma-errors'
import { canEvaluationVehicleBeUsed, type Operation } from '@/lib/evaluation/availability'

export async function GET(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const { searchParams } = req.nextUrl
    const search  = searchParams.get('search')?.trim() ?? ''
    const unitId  = searchParams.get('unitId')  ?? ''
    const page    = Math.max(1, Number(searchParams.get('page') ?? 1))
    // Limit configurável (default 20). Pra abrir modal "vazio" o cliente
    // passa ?limit=3 e mostra os 3 mais recentes.
    const take    = Math.max(1, Math.min(50, Number(searchParams.get('limit') ?? 20)))
    // Operação alvo (TROCA / COMPRA / CONSIGNACAO) — filtra availableFor
    const opRaw   = (searchParams.get('operation') ?? '').toUpperCase()
    const operation: Operation | null =
      opRaw === 'TROCA' || opRaw === 'COMPRA' || opRaw === 'CONSIGNACAO' ? opRaw : null

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const where: any = {
      // Aceita AMBOS os fluxos: legado (result=APROVADO) e novo (status=LIBERADA).
      // Avaliação só está pronta para uso em negociação quando o gerente já
      // precificou (evaluatedValue presente).
      AND: [
        {
          OR: [
            { result: 'APROVADO' },
            { status: 'LIBERADA' },
          ],
        },
        { evaluatedValue: { not: null, gt: 0 } },
      ],
    }

    // Isolamento por tenant:
    //  - MASTER (sem tenantId) vê tudo
    //  - Usuário com tenantId vê do próprio tenant E avaliações legacy com
    //    tenantId=null (criadas antes do multi-tenant ou pelo MASTER)
    if (session.user.tenantId) {
      where.AND.push({
        OR: [
          { tenantId: session.user.tenantId },
          { tenantId: null },
        ],
      })
    }

    // Filtro de unidade
    if (unitId) where.unitId = unitId
    else if (session.user.unitId && session.user.role === 'VENDEDOR') {
      where.unitId = session.user.unitId
    }

    // (Filtro de "não vinculado a deal ativo" removido — o relacionamento
    // vehicle.dealVehicles depende de o Vehicle já existir, o que NÃO
    // acontece mais antes da COMPRA ser finalizada. Avaliações LIBERADAS
    // e ainda não compradas ficam visíveis. Uma proteção adicional será
    // feita no momento de criar o DealVehicle, recusando avaliação que
    // já vire deal ativo.)

    if (search) {
      where.AND.push({
        OR: [
          { plate:      { contains: search, mode: 'insensitive' } },
          { brand:      { contains: search, mode: 'insensitive' } },
          { model:      { contains: search, mode: 'insensitive' } },
          { ownerName:  { contains: search, mode: 'insensitive' } },
          { ownerCpf:   { contains: search, mode: 'insensitive' } },
          { ownerPhone: { contains: search, mode: 'insensitive' } },
        ],
      })
    }

    const [rawData, total] = await Promise.all([
      prisma.vehicleEvaluation.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * take,
        take,
        select: {
          id:             true,
          plate:          true,
          brand:          true,
          model:          true,
          version:        true,
          manufactureYear:true,
          modelYear:      true,
          km:             true,
          color:          true,
          fuel:           true,
          evaluatedValue: true,
          fipeValue:      true,
          desiredValue:   true,
          suggestedSalePrice: true,
          minimumValue:   true,
          result:         true,
          status:         true,
          intention:      true,
          ownerName:      true,
          ownerCpf:       true,
          ownerPhone:     true,
          evaluationNotes:true,
          pendencyNotes:  true,
          cautelarStatus: true,
          createdAt:      true,
          evaluatedAt:    true,
          // Decisão do cliente + availableFor (regra centralizada)
          customerDecision:    true,
          customerDecisionAt:  true,
          customerDecisionNote:true,
          availableFor:        true,
          proposalValidUntil:  true,
          vehicleId:           true,
          cancelledAt:         true,
          evaluatedBy:    { select: { id: true, name: true } },
          unit:           { select: { id: true, name: true } },
        } as never,
      }),
      prisma.vehicleEvaluation.count({ where }),
    ])

    // Pra checagem de "vinculada a deal ativo", busca DealVehicles ligados às
    // mesmas placas/vehicleId em deals abertos (1 query batch).
    const evalIds = rawData.map((e: any) => e.id) // eslint-disable-line @typescript-eslint/no-explicit-any
    const plates  = rawData.map((e: any) => e.plate).filter(Boolean) as string[] // eslint-disable-line @typescript-eslint/no-explicit-any
    let dealVehiclesByEval: Record<string, Array<{ deal?: { status?: string | null } | null }>> = {}
    if (plates.length > 0) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const dvs: any[] = await (prisma as any).dealVehicle.findMany({
        where:  { plate: { in: plates } },
        select: { plate: true, deal: { select: { status: true } } },
      })
      // Mapeia plate → evalId (mesmas placas podem ter várias avaliações)
      const plateToEvalIds = new Map<string, string[]>()
      for (const e of rawData as any[]) { // eslint-disable-line @typescript-eslint/no-explicit-any
        if (!e.plate) continue
        const arr = plateToEvalIds.get(e.plate) ?? []
        arr.push(e.id); plateToEvalIds.set(e.plate, arr)
      }
      for (const dv of dvs) {
        const ids = plateToEvalIds.get(dv.plate) ?? []
        for (const id of ids) {
          if (!dealVehiclesByEval[id]) dealVehiclesByEval[id] = []
          dealVehiclesByEval[id].push(dv)
        }
      }
    }

    // Filtra usando a regra centralizada
    const data = (rawData as any[]).filter((e) => { // eslint-disable-line @typescript-eslint/no-explicit-any
      const check = canEvaluationVehicleBeUsed(
        { ...e, dealVehicles: dealVehiclesByEval[e.id] ?? [] },
        operation ?? 'COMPRA',
      )
      return check.canUse
    })

    void evalIds

    return NextResponse.json({
      data,
      pagination: {
        page,
        total,
        totalPages: Math.ceil(total / take),
        limit: take,
      },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/negotiations — Listar e criar negociações
// =============================================================================

import { NextResponse, type NextRequest } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma }               from '@/lib/prisma'
import { requireModule }        from '@/lib/permissions'
import { handlePrismaError }    from '@/lib/prisma-errors'

// ── GET — Listar negociações ──────────────────────────────────────────────────

export async function GET(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const { searchParams } = req.nextUrl
    const search = searchParams.get('search') ?? ''
    const type   = searchParams.get('type')   ?? ''
    const status = searchParams.get('status') ?? ''
    const unitId = searchParams.get('unitId') ?? ''
    const page   = Math.max(1, Number(searchParams.get('page') ?? 1))
    const take   = 50

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const where: any = {}

    // Isolamento por tenant
    if (session.user.tenantId) where.tenantId = session.user.tenantId

    // Filtro de unidade — opcional. VENDEDOR sempre limitado à própria unidade.
    if (session.user.role === 'VENDEDOR' && session.user.unitId) {
      where.unitId = session.user.unitId
    } else if (unitId) {
      where.unitId = unitId
    }

    // Vendedores veem apenas suas próprias negociações
    if (session.user.role === 'VENDEDOR') {
      const seller = await prisma.seller.findUnique({
        where:  { userId: session.user.id },
        select: { id: true },
      })
      // Sem cadastro de vendedor → nenhuma negociação própria
      if (!seller) return NextResponse.json({ data: [], pagination: { page, total: 0, totalPages: 0, limit: take } })
      where.sellerId = seller.id
    }

    if (type)   where.type   = type
    if (status) where.status = status

    if (search) {
      where.OR = [
        { person: { nomeCompleto: { contains: search, mode: 'insensitive' } } },
        { customer: { name: { contains: search, mode: 'insensitive' } } },
        { dealNumber: { contains: search, mode: 'insensitive' } },
        { seller: { user: { name: { contains: search, mode: 'insensitive' } } } },
      ]
    }

    const [deals, total, typeCounts, statusCounts] = await Promise.all([
      prisma.deal.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * take,
        take,
        select: {
          id:                  true,
          dealNumber:          true,
          type:                true,
          status:              true,
          source:              true,
          isSellerProvisional: true,
          saleAmount:          true,
          totalPayments:       true,
          vehicleValue:        true,
          createdAt:           true,
          person:   { select: { nomeCompleto: true } },
          customer: { select: { name: true } },
          seller:   { select: { fullName: true, user: { select: { name: true } } } },
          sellerNameFromSheet: true,
          vehicles: {
            take:    1,
            orderBy: { createdAt: 'asc' },
            select:  { plate: true, brand: true, model: true, year: true, role: true },
          },
        },
      }),
      prisma.deal.count({ where }),
      prisma.deal.groupBy({
        by:    ['type'],
        where,
        _count: { _all: true },
      }),
      prisma.deal.groupBy({
        by:    ['status'],
        where,
        _count: { _all: true },
      }),
    ])

    // Converte groupBy em mapa { VENDA: N, COMPRA: N, ... }
    const byType = typeCounts.reduce<Record<string, number>>((acc, row) => {
      acc[row.type] = row._count._all
      return acc
    }, {})

    const byStatus = statusCounts.reduce<Record<string, number>>((acc, row) => {
      acc[row.status] = row._count._all
      return acc
    }, {})

    return NextResponse.json({
      data:       deals,
      pagination: { page, total, totalPages: Math.ceil(total / take), limit: take },
      byType,
      byStatus,
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── POST — Criar negociação ───────────────────────────────────────────────────

export async function POST(req: NextRequest) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })

  try { requireModule(session.user.role, 'negotiations') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  try {
    const body = await req.json()
    const {
      type, person, customer, personId: bodyPersonId,
      // Localização
      unitId: bodyUnitId, sellerId: bodySellerId,
      vehicle, tradeInVehicle,
      // Valores
      saleAmount, purchaseAmount, financedAmount, documentationFee,
      signalAmount, payoffAmount, discountAmount, paymentBank, paymentType,
      consignMinValue, consignCommPct, consignDeadline,
      vehicleValue, tradeValue, totalPayments, changeAmount,
      // Dados bancários do cliente (compra)
      changeBeneficiary, changeBeneficiaryCpf, changeBank, changeAgency, changeAccount, changePix,
      // Agendamento
      deliveryDate,
      // Débitos do wizard (array criado de uma vez com a negociação)
      debts,
      // Pagamentos cadastrados no wizard
      payments,
      // Geral
      notes, submit,
    } = body

    if (!type) {
      return NextResponse.json({ error: 'Tipo da negociação é obrigatório.' }, { status: 400 })
    }
    if (!bodyPersonId && !person?.nomeCompleto && !customer?.name) {
      return NextResponse.json({ error: 'Cliente é obrigatório.' }, { status: 400 })
    }

    // ── Validação de campos obrigatórios PF/PJ (apenas quando cadastro novo) ──
    // bodyPersonId pula validação (cadastro já existente).
    if (!bodyPersonId && person && submit) {
      const errors: string[] = []
      const isPJ = person.type === 'JURIDICA'

      // Comum: contato e endereço
      if (!person.phone || person.phone.replace(/\D/g, '').length < 10)
        errors.push('Celular é obrigatório.')
      if (!person.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(person.email))
        errors.push('E-mail é obrigatório e deve ser válido.')
      if (!person.cep || person.cep.replace(/\D/g, '').length !== 8)
        errors.push('CEP é obrigatório.')
      if (!person.logradouro) errors.push('Logradouro é obrigatório.')
      if (!person.numero)     errors.push('Número é obrigatório.')
      if (!person.bairro)     errors.push('Bairro é obrigatório.')
      if (!person.cidade)     errors.push('Cidade é obrigatória.')
      if (!person.estado)     errors.push('Estado é obrigatório.')

      if (isPJ) {
        if (!person.cnpj || person.cnpj.replace(/\D/g, '').length !== 14)
          errors.push('CNPJ é obrigatório.')
        if (!person.razaoSocial) errors.push('Razão social é obrigatória.')
        // Responsável Legal completo (PF)
        if (!person.socioAdmCpf || person.socioAdmCpf.replace(/\D/g, '').length !== 11)
          errors.push('CPF do responsável legal é obrigatório.')
        if (!person.socioAdmNome)
          errors.push('Nome completo do responsável legal é obrigatório.')
        if (!person.socioAdmRg)
          errors.push('RG do responsável legal é obrigatório.')
        if (!person.socioAdmDataNascimento)
          errors.push('Data de nascimento do responsável legal é obrigatória.')
        if (!person.socioAdmEmail || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(person.socioAdmEmail))
          errors.push('E-mail do responsável legal é obrigatório e deve ser válido.')
        if (!person.socioAdmPhone || person.socioAdmPhone.replace(/\D/g, '').length < 10)
          errors.push('Celular do responsável legal é obrigatório.')
        if (!person.socioAdmCep || person.socioAdmCep.replace(/\D/g, '').length !== 8)
          errors.push('CEP do responsável legal é obrigatório.')
        if (!person.socioAdmLogradouro) errors.push('Logradouro do responsável legal é obrigatório.')
        if (!person.socioAdmNumero)     errors.push('Número do responsável legal é obrigatório.')
        if (!person.socioAdmBairro)     errors.push('Bairro do responsável legal é obrigatório.')
        if (!person.socioAdmCidade)     errors.push('Cidade do responsável legal é obrigatória.')
        if (!person.socioAdmEstado)     errors.push('Estado do responsável legal é obrigatório.')
      } else {
        if (!person.cpf || person.cpf.replace(/\D/g, '').length !== 11)
          errors.push('CPF é obrigatório.')
        if (!person.nomeCompleto) errors.push('Nome completo é obrigatório.')
        if (!person.rg) errors.push('RG é obrigatório.')
        if (!person.dataNascimento) errors.push('Data de nascimento é obrigatória.')
      }

      if (errors.length > 0) {
        return NextResponse.json(
          { error: errors[0], errors },
          { status: 400 },
        )
      }
    }

    // ── Resolução segura de unitId ──────────────────────────────────────────────
    // Aceita do body apenas se a unidade pertencer ao tenant da sessão.
    // Cai de volta para session.user.unitId quando não fornecido/inválido.
    let resolvedUnitId: string | null = session.user.unitId ?? null
    if (bodyUnitId && typeof bodyUnitId === 'string') {
      const unit = await prisma.unit.findFirst({
        where:  { id: bodyUnitId, tenantId: session.user.tenantId ?? undefined },
        select: { id: true },
      })
      if (unit) resolvedUnitId = unit.id
    }

    // ── Resolução segura de sellerId ────────────────────────────────────────────
    // VENDEDOR só pode usar o próprio cadastro (ignora body.sellerId).
    // GERENTE+/ADM pode escolher qualquer vendedor da unidade.
    const ownSeller = await prisma.seller.findUnique({
      where:  { userId: session.user.id },
      select: { id: true },
    })

    let resolvedSellerId: string | null = ownSeller?.id ?? null
    if (bodySellerId && typeof bodySellerId === 'string' && session.user.role !== 'VENDEDOR') {
      const sel = await prisma.seller.findFirst({
        where: {
          id: bodySellerId,
          ...(resolvedUnitId      ? { unitId:   resolvedUnitId } : {}),
          ...(session.user.tenantId ? { tenantId: session.user.tenantId } : {}),
        },
        select: { id: true },
      })
      if (sel) resolvedSellerId = sel.id
    }

    const result = await prisma.$transaction(async (tx) => {
      let personId: string | null = null

      // 1) Reuso: se o wizard já vinculou um Person existente, valida tenant e usa.
      if (bodyPersonId) {
        const existing = await tx.person.findFirst({
          where:  { id: bodyPersonId, tenantId: session.user.tenantId ?? undefined },
          select: { id: true },
        })
        if (existing) personId = existing.id
      }

      // 2) Caso contrário, cria/atualiza por documento.
      if (!personId && person?.nomeCompleto) {
        let personRecord = null
        if (person.cpf || person.cnpj) {
          personRecord = await tx.person.findFirst({
            where: {
              tenantId: session.user.tenantId ?? undefined,
              OR: [
                person.cpf  ? { cpf:  person.cpf  } : undefined,
                person.cnpj ? { cnpj: person.cnpj } : undefined,
              ].filter(Boolean) as object[],
            },
          })
        }

        // Campos extras do sócio adm (RG/data nasc/endereço) ainda não têm coluna
        // dedicada — guardamos como JSON no notes para preservar sem perder a UI.
        const socioAdmExtras = person.type === 'JURIDICA' ? {
          socioAdmRg:             person.socioAdmRg             ?? null,
          socioAdmDataNascimento: person.socioAdmDataNascimento ?? null,
          socioAdmCep:            person.socioAdmCep            ?? null,
          socioAdmLogradouro:     person.socioAdmLogradouro     ?? null,
          socioAdmNumero:         person.socioAdmNumero         ?? null,
          socioAdmComplemento:    person.socioAdmComplemento    ?? null,
          socioAdmBairro:         person.socioAdmBairro         ?? null,
          socioAdmCidade:         person.socioAdmCidade         ?? null,
          socioAdmEstado:         person.socioAdmEstado         ?? null,
        } : null
        const hasSocioExtras = socioAdmExtras &&
          Object.values(socioAdmExtras).some((v) => v != null && v !== '')
        const notesJson = hasSocioExtras
          ? `__socioAdmExtras__=${JSON.stringify(socioAdmExtras)}`
          : null

        if (!personRecord) {
          personRecord = await tx.person.create({
            data: {
              tenantId:          session.user.tenantId ?? null,
              type:              person.type   ?? 'FISICA',
              cpf:               person.cpf    ?? null,
              cnpj:              person.cnpj   ?? null,
              nomeCompleto:      person.nomeCompleto,
              rg:                person.rg              ?? null,
              dataNascimento:    person.dataNascimento
                                   ? new Date(person.dataNascimento) : null,
              nomeMae:           person.nomeMae           ?? null,
              razaoSocial:       person.razaoSocial       ?? null,
              nomeFantasia:      person.nomeFantasia      ?? null,
              inscricaoEstadual: person.inscricaoEstadual ?? null,
              socioAdmNome:      person.socioAdmNome      ?? null,
              socioAdmCpf:       person.socioAdmCpf       ?? null,
              socioAdmPhone:     person.socioAdmPhone     ?? null,
              socioAdmNomeMae:   person.socioAdmNomeMae   ?? null,
              socioAdmEmail:     person.socioAdmEmail     ?? null,
              socioAdmWhatsapp:  person.socioAdmWhatsapp  ?? false,
              email:             person.email   ?? null,
              phone:             person.phone   ?? null,
              whatsapp:          person.whatsapp ?? false,
              cep:               person.cep        ?? null,
              logradouro:        person.logradouro ?? null,
              numero:            person.numero     ?? null,
              complemento:       person.complemento ?? null,
              bairro:            person.bairro     ?? null,
              cidade:            person.cidade     ?? null,
              estado:            person.estado     ?? null,
              notes:             notesJson,
            },
          })
        }
        personId = personRecord.id
      }

      const count = await tx.deal.count({ where: { tenantId: session.user.tenantId ?? undefined } })
      const dealNumber    = `NEG-${new Date().getFullYear()}-${String(count + 1).padStart(4, '0')}`
      const initialStatus = submit ? 'AGUARDANDO_APROVACAO' : 'RASCUNHO'

      const deal = await tx.deal.create({
        data: {
          dealNumber,
          tenantId: session.user.tenantId ?? null,
          unitId:   resolvedUnitId,
          sellerId: resolvedSellerId,
          personId,
          type,
          status:     initialStatus,
          source:     'MANUAL',
          // Financeiro
          saleAmount:       saleAmount        ? Number(saleAmount)       : null,
          purchaseAmount:   purchaseAmount    ? Number(purchaseAmount)   : null,
          financedAmount:   financedAmount    ? Number(financedAmount)   : null,
          documentationFee: documentationFee  ? Number(documentationFee) : null,
          signalAmount:     signalAmount      ? Number(signalAmount)     : null,
          payoffAmount:     payoffAmount      ? Number(payoffAmount)     : null,
          discountAmount:   discountAmount    ? Number(discountAmount)   : null,
          paymentBank:      paymentBank       ?? null,
          paymentType:      paymentType       ?? null,
          // Legado / calculados
          vehicleValue:  vehicleValue  ? Number(vehicleValue)  : saleAmount  ? Number(saleAmount)  : null,
          tradeValue:    tradeValue    ? Number(tradeValue)    : null,
          totalPayments: totalPayments ? Number(totalPayments) : null,
          changeAmount:  changeAmount  ? Number(changeAmount)  : null,
          // Agendamento
          deliveryDate: deliveryDate   ? new Date(deliveryDate) : null,
          // Troco/Dados bancários
          changeBeneficiary:    changeBeneficiary    ?? null,
          changeBeneficiaryCpf: changeBeneficiaryCpf ?? null,
          changeBank:           changeBank           ?? null,
          changeAgency:         changeAgency         ?? null,
          changeAccount:        changeAccount        ?? null,
          changePix:            changePix            ?? null,
          // Consignação
          consignMinValue:  consignMinValue  ? Number(consignMinValue)  : null,
          consignCommPct:   consignCommPct   ? Number(consignCommPct)   : null,
          consignDeadline:  consignDeadline  ? new Date(consignDeadline): null,
          notes: notes ?? null,
        } as never,
      })

      const vehicleRoleMap: Record<string, string> = {
        VENDA: 'VENDIDO', COMPRA: 'COMPRADO', TROCA: 'VENDIDO', CONSIGNACAO: 'CONSIGNADO',
      }

      if (vehicle?.plate || vehicle?.brand || vehicle?.vehicleId) {
        // Se o usuário selecionou veículo do estoque, usa o ID diretamente
        let vehicleId: string | null = vehicle?.vehicleId ?? null

        if (!vehicleId) {
          // Tenta localizar por placa existente
          let vehicleRecord = vehicle.plate
            ? await tx.vehicle.findFirst({
                where: { tenantId: session.user.tenantId ?? undefined, plate: vehicle.plate.toUpperCase() },
              })
            : null

          if (!vehicleRecord) {
            vehicleRecord = await tx.vehicle.create({
              data: {
                tenantId: session.user.tenantId ?? null,
                unitId:   resolvedUnitId,
                plate:    vehicle.plate?.toUpperCase() ?? null,
                brand:    vehicle.brand  ?? null,
                model:    vehicle.model  ?? null,
                year:     vehicle.year   ? Number(vehicle.year) : null,
                color:    vehicle.color  ?? null,
                km:       vehicle.km     ? Number(vehicle.km)   : null,
              },
            })
          }
          vehicleId = vehicleRecord.id
        }

        // ── Guard: impede duplicidade de venda do mesmo veículo ───────────
        // Pra VENDA/TROCA, recusa se o veículo já está em outra negociação
        // ativa (qualquer status que não seja terminal). Mensagem clara
        // pro vendedor saber quem está com o carro.
        if (vehicleId && (type === 'VENDA' || type === 'TROCA')) {
          const OPEN = ['AGUARDANDO_APROVACAO', 'AGUARDANDO_LIBERACAO',
            'APROVADA', 'LIBERADA', 'SINAL_RECEBIDO', 'RESERVADA',
            'AGUARDANDO_FINANCEIRO', 'FINANCEIRO_APROVADO',
            'AGUARDANDO_DOCUMENTACAO', 'DOCUMENTACAO_CONCLUIDA',
            'AGUARDANDO_CONTRATO', 'CONTRATO_GERADO',
            'AGUARDANDO_ASSINATURA', 'ASSINADA',
            'AGUARDANDO_ENTREGA', 'ENTREGUE', 'EM_ANDAMENTO', 'FINALIZADA']
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const conflict: any = await tx.dealVehicle.findFirst({
            where: {
              vehicleId,
              role:  { in: ['VENDIDO', 'CONSIGNADO'] },
              deal:  { status: { in: OPEN as never[] } },
            },
            select: {
              deal: {
                select: {
                  id: true, dealNumber: true, status: true,
                  seller: { select: { fullName: true, shortName: true } },
                },
              },
            },
          })
          if (conflict?.deal) {
            const APPROVED = new Set(OPEN.filter((s) => s !== 'AGUARDANDO_APROVACAO' && s !== 'AGUARDANDO_LIBERACAO'))
            const sellerLbl = conflict.deal.seller?.shortName ?? conflict.deal.seller?.fullName ?? 'outro vendedor'
            const negLbl    = conflict.deal.dealNumber ?? conflict.deal.id.slice(0, 8)
            const msg = APPROVED.has(conflict.deal.status)
              ? `Este veículo não está mais disponível. Venda já liberada pelo gerente na negociação ${negLbl}.`
              : `Este veículo já está em negociação pelo vendedor ${sellerLbl} (negociação ${negLbl}).`
            throw new Error(msg)
          }
        }

        await tx.dealVehicle.create({
          data: {
            dealId:    deal.id,
            vehicleId,
            role:      vehicleRoleMap[type] ?? 'VENDIDO',
            plate:     vehicle.plate?.toUpperCase() ?? null,
            brand:     vehicle.brand  ?? null,
            model:     vehicle.model  ?? null,
            year:      vehicle.year   ? Number(vehicle.year) : null,
            color:     vehicle.color  ?? null,
            km:        vehicle.km     ? Number(vehicle.km)   : null,
            agreedValue: saleAmount || purchaseAmount
              ? Number(saleAmount ?? purchaseAmount ?? 0) : null,
          } as never,
        })

        // Marca veículo do estoque como EM_NEGOCIACAO
        if (vehicle?.vehicleId && (type === 'VENDA' || type === 'TROCA')) {
          await tx.vehicle.update({
            where: { id: vehicle.vehicleId },
            data:  { stockStatus: 'EM_NEGOCIACAO' as never },
          }).catch(() => {})
        }
      }

      // 5. Veículo de troca (TROCA)
      if (type === 'TROCA' && tradeInVehicle?.plate) {
        // ── Guard duplicidade: avaliação não pode entrar em 2 trocas ativas
        if (tradeInVehicle.evaluationId) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const ev: any = await (tx as any).vehicleEvaluation.findUnique({
            where:  { id: tradeInVehicle.evaluationId },
            select: {
              id: true, status: true, result: true,
              customerDecision: true, availableFor: true,
              cancelledAt: true, proposalValidUntil: true,
            },
          })
          if (!ev) {
            throw new Error('Avaliação informada não foi encontrada.')
          }
          // Reusa o helper canEvaluationVehicleBeUsed pra mensagem consistente
          // (não importa aqui pra evitar ciclo — duplica a checagem mínima).
          if (ev.cancelledAt)
            throw new Error('Este veículo avaliado não está disponível para troca. Avaliação cancelada.')
          const releasedOk = ['LIBERADA', 'APROVADO', 'APPROVED', 'FINALIZED'].includes(
            (ev.status ?? ev.result ?? '').toUpperCase(),
          ) || (ev.result ?? '').toUpperCase() === 'APROVADO'
          if (!releasedOk)
            throw new Error('Este veículo avaliado não está disponível para troca. Proposta ainda não liberada pelo gerente.')
          const decision = (ev.customerDecision ?? 'PENDENTE').toUpperCase()
          if (decision !== 'ACEITA')
            throw new Error('Este veículo avaliado não está disponível para troca. Cliente ainda não aceitou a proposta.')
          const af = (ev.availableFor ?? '').toUpperCase()
          if (af && !af.split(',').map((s: string) => s.trim()).includes('TROCA'))
            throw new Error('Este veículo avaliado não está disponível para troca. Liberação do gerente é para outra operação.')
          // Já vinculada a deal ativo?
          const OPEN = ['AGUARDANDO_APROVACAO', 'AGUARDANDO_LIBERACAO',
            'APROVADA', 'LIBERADA', 'SINAL_RECEBIDO', 'RESERVADA',
            'AGUARDANDO_FINANCEIRO', 'FINANCEIRO_APROVADO',
            'AGUARDANDO_DOCUMENTACAO', 'DOCUMENTACAO_CONCLUIDA',
            'AGUARDANDO_CONTRATO', 'CONTRATO_GERADO',
            'AGUARDANDO_ASSINATURA', 'ASSINADA',
            'AGUARDANDO_ENTREGA', 'ENTREGUE', 'EM_ANDAMENTO', 'FINALIZADA']
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const conflict: any = await tx.dealVehicle.findFirst({
            where: {
              role:  'TROCA',
              plate: tradeInVehicle.plate.toUpperCase(),
              deal:  { status: { in: OPEN as never[] } },
            },
            select: { deal: { select: { id: true, dealNumber: true } } },
          })
          if (conflict?.deal) {
            const neg = conflict.deal.dealNumber ?? conflict.deal.id.slice(0, 8)
            throw new Error(`Este veículo avaliado já está vinculado à negociação ${neg}.`)
          }
        }

        await tx.dealVehicle.create({
          data: {
            dealId:        deal.id,
            role:          'TROCA',
            plate:         tradeInVehicle.plate?.toUpperCase()  ?? null,
            brand:         tradeInVehicle.brand  ?? null,
            model:         tradeInVehicle.model  ?? null,
            year:          tradeInVehicle.year   ? Number(tradeInVehicle.year)  : null,
            color:         tradeInVehicle.color  ?? null,
            km:            tradeInVehicle.km     ? Number(tradeInVehicle.km)    : null,
            condition:     tradeInVehicle.condition ?? null,
            agreedValue:   tradeInVehicle.agreedValue   ? Number(tradeInVehicle.agreedValue)   : null,
            evaluatedValue:tradeInVehicle.evaluatedValue ? Number(tradeInVehicle.evaluatedValue): null,
            fipeValue:     tradeInVehicle.fipeValue      ? Number(tradeInVehicle.fipeValue)     : null,
            hasFinancing:  tradeInVehicle.hasFinancing   ?? false,
            payoffValue:   tradeInVehicle.payoffValue    ? Number(tradeInVehicle.payoffValue)   : null,
            payoffBank:    tradeInVehicle.payoffBank     ?? null,
            notes:         tradeInVehicle.notes          ?? null,
          } as never,
        })
      }

      // 6. Débitos do wizard (array opcional)
      if (Array.isArray(debts) && debts.length > 0) {
        await (tx.dealDebt as any).createMany({
          data: debts.map((d: {
            vehicleRole?: string
            type: string
            description?: string
            value: number
            responsavel?: string
            notes?: string
          }) => ({
            dealId:      deal.id,
            vehicleRole: d.vehicleRole ?? null,
            type:        d.type,
            description: d.description ?? null,
            value:       Number(d.value),
            responsavel: d.responsavel ?? 'LOJA',
            notes:       d.notes       ?? null,
          })),
        })
      }

      // 6.5. Pagamentos do wizard (array opcional)
      if (Array.isArray(payments) && payments.length > 0) {
        const isVendedor = ['VENDEDOR', 'VENDEDOR_LIDER'].includes(session.user.role)
        await (tx.dealPayment as any).createMany({
          data: payments.map((p: any) => {
            // Sanitiza retorno % pra 0..6 com 2 casas
            let returnPct: number | null = null
            if (p.returnPct != null && p.returnPct !== '') {
              const n = Number(p.returnPct)
              if (Number.isFinite(n)) returnPct = Math.min(6, Math.max(0, Math.round(n * 100) / 100))
            }
            // Vendedor só pode mandar PENDENTE
            const rawStatus = typeof p.status === 'string' ? p.status.toUpperCase() : null
            const status    = isVendedor
              ? 'PENDENTE'
              : (['PENDENTE', 'CONFIRMADO', 'CANCELADO'].includes(rawStatus ?? '') ? rawStatus : 'PENDENTE')

            return {
              dealId:                  deal.id,
              tenantId:                session.user.tenantId ?? null,
              type:                    String(p.type ?? 'OUTROS').toUpperCase(),
              status,
              value:                   Number(p.amount ?? p.value ?? 0),
              bank:                    p.bank      || null,
              cardBrand:               p.cardBrand || null,
              pixKey:                  p.pixKey    || null,
              agency:                  p.agency    || null,
              account:                 p.account   || null,
              installments:            p.installments ? Number(p.installments) : null,
              installmentValue:        p.installmentValue != null && p.installmentValue !== '' ? Number(p.installmentValue) : null,
              installmentIntervalDays: p.installmentIntervalDays ? Number(p.installmentIntervalDays) : null,
              returnPct,
              vehiclePlate:            p.vehiclePlate || null,
              firstDueDate:            p.firstDueDate ? new Date(p.firstDueDate) : null,
              dueDate:                 p.dueDate      ? new Date(p.dueDate)      : null,
              paidAt:                  p.paidAt       ? new Date(p.paidAt)       : null,
              notes:                   p.notes || null,
              createdById:             session.user.id,
            }
          }),
        })
      }

      // 6.6. Troco (se cadastrado no wizard com beneficiário)
      if (changeAmount && Number(changeAmount) > 0 && (changeBeneficiary || changePix || changeBank)) {
        await (tx.dealChange as any).create({
          data: {
            dealId:      deal.id,
            tenantId:    session.user.tenantId ?? null,
            value:       Number(changeAmount),
            beneficiary: changeBeneficiary || 'Cliente',
            document:    changeBeneficiaryCpf || null,
            bank:        changeBank    || null,
            agency:      changeAgency  || null,
            account:     changeAccount || null,
            pixKey:      changePix     || null,
            createdById: session.user.id,
          },
        })
      }

      // 7. Histórico inicial
      await tx.dealStatusHistory.create({
        data: {
          dealId:          deal.id,
          previousStatus:  null,
          newStatus:       initialStatus,
          changedByUserId: session.user.id,
          reason:          submit ? 'Criada e enviada para aprovação' : 'Negociação criada',
        },
      })

      // 8. Auditoria
      await tx.auditLog.create({
        data: {
          userId:   session.user.id,
          tenantId: session.user.tenantId ?? null,
          action:   'CREATE',
          entity:   'Deal',
          entityId: deal.id,
          userName: session.user.name,
          userRole: session.user.role,
          status:   'SUCCESS',
          afterData: { type, status: initialStatus, dealNumber } as never,
        },
      })

      return deal
    })

    return NextResponse.json({ data: result }, { status: 201 })
  } catch (err) {
    return handlePrismaError(err)
  }
}

