// =============================================================================
// GET /api/vehicles/[id]/documents
//
// Agrega TODOS os documentos do veículo, vindos de fontes diferentes:
//   • EvaluationAttachment — CRLV, ATPV-e, laudos, fotos das avaliações
//   • DealAttachment       — contratos, NFe, comprovantes, RENAVE de deals
//
// Categoriza em 3 grupos:
//   1) "DOCUMENTOS DO VEÍCULO"  (CRLV, ATPV_E, DUT_CRV, NFE)
//   2) "LAUDOS"                  (LAUDO_CAUTELAR, vistoria, técnico)
//   3) "NEGOCIAÇÃO"              (CONTRATO_*, PROCURACAO_*, RECIBO, COMPROVANTE_*)
//
// Reaproveita o mesmo storage do cautelar (publicUrl) — não duplica nada.
// Aceita ?type=CRLV pra filtrar por categoria específica.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { getServerAuthSession } from '@/lib/auth'
import { prisma } from '@/lib/prisma'
import { requireModule } from '@/lib/permissions'
import { handlePrismaError } from '@/lib/prisma-errors'

export const dynamic = 'force-dynamic'

type DocGroup = 'VEHICLE' | 'LAUDO' | 'NEGOTIATION' | 'OUTRO'

const GROUP_BY_CATEGORY: Record<string, DocGroup> = {
  CRLV: 'VEHICLE', ATPV_E: 'VEHICLE', DUT_CRV: 'VEHICLE', NFE: 'VEHICLE',
  LAUDO_CAUTELAR: 'LAUDO', VISTORIA: 'LAUDO', LAUDO_TECNICO: 'LAUDO',
  CONTRATO_ASSINADO: 'NEGOTIATION', PROCURACAO_ASSINADA: 'NEGOTIATION',
  RECIBO: 'NEGOTIATION',
  COMPROVANTE_PAGAMENTO: 'NEGOTIATION', COMPROVANTE_QUITACAO: 'NEGOTIATION',
  COMPROVANTE_DEBITO: 'NEGOTIATION', COMPROVANTE_TROCO: 'NEGOTIATION',
}

const GROUP_LABEL: Record<DocGroup, string> = {
  VEHICLE:     'Documentos do veículo',
  LAUDO:       'Laudos',
  NEGOTIATION: 'Negociação',
  OUTRO:       'Outros',
}

export async function GET(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> },
) {
  const session = await getServerAuthSession()
  if (!session) return NextResponse.json({ error: 'Não autenticado' }, { status: 401 })
  try { requireModule(session.user.role, 'stock') }
  catch { return NextResponse.json({ error: 'Sem permissão' }, { status: 403 }) }

  const params = await Promise.resolve(ctxArg.params)
  const vehicleId = params?.id
  if (!vehicleId) return NextResponse.json({ error: 'ID ausente' }, { status: 400 })

  const typeFilter = (req.nextUrl.searchParams.get('type') ?? '').toUpperCase()

  try {
    // 1) Confirma vehicle existe e isola por tenant
    const vehicle = await prisma.vehicle.findUnique({
      where:  { id: vehicleId },
      select: { id: true, tenantId: true, plate: true },
    })
    if (!vehicle) return NextResponse.json({ error: 'Veículo não encontrado' }, { status: 404 })
    if (session.user.tenantId && vehicle.tenantId && vehicle.tenantId !== session.user.tenantId) {
      return NextResponse.json({ error: 'Acesso negado' }, { status: 403 })
    }

    // 2) IDs de avaliações que pertencem a esse veículo (vehicleId direto OU
    //    placa+tenant para histórico legado anterior à existência do vehicleId)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const evals: any[] = await prisma.vehicleEvaluation.findMany({
      where: {
        OR: [
          { vehicleId },
          ...(vehicle.plate
            ? [{ plate: vehicle.plate, tenantId: vehicle.tenantId ?? undefined }]
            : []),
        ],
      },
      select: { id: true, createdAt: true },
    })
    const evalIds = evals.map((e) => e.id)

    // 3) IDs de DealVehicles ligados (pra puxar attachments dos deals)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const dealVehicles: any[] = await prisma.dealVehicle.findMany({
      where:  { vehicleId },
      select: { dealId: true },
    })
    const dealIds = Array.from(new Set(dealVehicles.map((dv) => dv.dealId)))

    // 4) Carrega anexos em paralelo das 2 fontes
    const [evalAttachments, dealAttachments] = await Promise.all([
      evalIds.length
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ? (prisma as any).evaluationAttachment.findMany({
            where: {
              evaluationId: { in: evalIds },
              ...(typeFilter ? { category: typeFilter } : {}),
            },
            orderBy: { createdAt: 'desc' },
            select: {
              id: true, fileName: true, fileType: true, mimeType: true, fileSize: true,
              publicUrl: true, storageKey: true, category: true, section: true,
              uploadedByName: true, createdAt: true, evaluationId: true,
            },
          })
        : [],
      dealIds.length
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ? (prisma as any).dealAttachment.findMany({
            where: {
              dealId: { in: dealIds },
              ...(typeFilter ? { category: typeFilter } : {}),
            },
            orderBy: { uploadedAt: 'desc' },
            select: {
              id: true, fileName: true, fileType: true, mimeType: true, fileSize: true,
              publicUrl: true, storageKey: true, category: true, notes: true,
              uploadedByName: true, uploadedAt: true, dealId: true,
            },
          })
        : [],
    ])

    // 5) Unifica em shape único
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    type UnifiedDoc = {
      id: string; source: 'EVALUATION' | 'DEAL';
      sourceId: string; sourceLabel: string;
      category: string; categoryLabel: string;
      group: DocGroup; groupLabel: string;
      title: string;
      fileName: string; fileType: string; mimeType: string; fileSize: number | null;
      publicUrl: string | null; uploadedByName: string | null; createdAt: Date;
    }

    const docs: UnifiedDoc[] = []

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    for (const a of (evalAttachments as any[])) {
      const cat = (a.category ?? '').toUpperCase()
      const group = GROUP_BY_CATEGORY[cat] ?? 'OUTRO'
      docs.push({
        id:            a.id,
        source:        'EVALUATION',
        sourceId:      a.evaluationId,
        sourceLabel:   'Avaliação',
        category:      cat,
        categoryLabel: cat.replace(/_/g, ' '),
        group,
        groupLabel:    GROUP_LABEL[group],
        title:         cat === 'CRLV' ? `CRLV - ${vehicle.plate ?? ''}`.trim() : (a.fileName ?? cat),
        fileName:      a.fileName,
        fileType:      a.fileType,
        mimeType:      a.mimeType,
        fileSize:      a.fileSize,
        publicUrl:     a.publicUrl,
        uploadedByName: a.uploadedByName,
        createdAt:     a.createdAt,
      })
    }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    for (const a of (dealAttachments as any[])) {
      const cat = (a.category ?? '').toUpperCase()
      const group = GROUP_BY_CATEGORY[cat] ?? 'NEGOTIATION'
      docs.push({
        id:            a.id,
        source:        'DEAL',
        sourceId:      a.dealId,
        sourceLabel:   'Negociação',
        category:      cat,
        categoryLabel: cat.replace(/_/g, ' '),
        group,
        groupLabel:    GROUP_LABEL[group],
        title:         a.fileName ?? cat,
        fileName:      a.fileName,
        fileType:      a.fileType,
        mimeType:      a.mimeType,
        fileSize:      a.fileSize,
        publicUrl:     a.publicUrl,
        uploadedByName: a.uploadedByName,
        createdAt:     a.uploadedAt,
      })
    }

    // 6) Ordena por data desc + agrupa
    docs.sort((a, b) => +new Date(b.createdAt) - +new Date(a.createdAt))

    const grouped: Record<DocGroup, UnifiedDoc[]> = {
      VEHICLE: [], LAUDO: [], NEGOTIATION: [], OUTRO: [],
    }
    for (const d of docs) grouped[d.group].push(d)

    return NextResponse.json({
      data:      docs,
      groups:    grouped,
      summary:   {
        total: docs.length,
        byGroup: Object.fromEntries(Object.entries(grouped).map(([g, arr]) => [g, arr.length])),
      },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/vehicles/[id]/pricing
//
// GET   — retorna precificação atual + últimos 20 eventos de histórico.
//         Permissão: stock.view (todos com acesso ao estoque).
// PATCH — atualiza precificação. Permissão: gerente+ (stock.manage).
//         Para cada campo alterado grava VehiclePricingHistory + AuditLog.
//         Se isAvailableForSale=true, ativa o veículo e marca stockStatus=
//         DISPONIVEL automaticamente.
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import {
  getSessionUser,
  assertTenantId,
  tenantWhere,
  unauthorizedResponse,
  forbiddenResponse,
  createSafeAuditLog,
} from '@/lib/auth-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { canAccessModule } from '@/lib/permissions'

// ── helpers ───────────────────────────────────────────────────────────────────

function toNum(v: unknown): number | null {
  if (v == null || v === '') return null
  const n = typeof v === 'number'
    ? v
    : Number(String(v).replace(/[^\d.,-]/g, '').replace(/\./g, '').replace(',', '.'))
  return Number.isFinite(n) ? n : null
}

function toDate(v: unknown): Date | null {
  if (!v) return null
  const d = new Date(String(v))
  return Number.isNaN(d.getTime()) ? null : d
}

function decToNum(v: unknown): number | null {
  if (v == null) return null
  // Prisma Decimal has toString
  const n = Number(String(v))
  return Number.isFinite(n) ? n : null
}

// ── GET ───────────────────────────────────────────────────────────────────────

export async function GET(
  _req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const user = await getSessionUser()
  if (!user) return unauthorizedResponse()
  if (!canAccessModule(user.role, 'stock.view')) return forbiddenResponse()

  try {
    const tenantId = assertTenantId(user.tenantId, user.role)

    const vehicle = await prisma.vehicle.findFirst({
      where: { id: params.id, ...tenantWhere(user.role, tenantId) },
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      select: {
        id:                 true,
        salePrice:          true,
        purchasePrice:      true,
        fipeValue:          true,
        promoPrice:         true,
        isPromo:            true,
        promoStartsAt:      true,
        promoEndsAt:        true,
        isAvailableForSale: true,
        pricingNotes:       true,
        pricedById:         true,
        pricedAt:           true,
        stockStatus:        true,
        active:             true,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
    })

    if (!vehicle) {
      return NextResponse.json({ success: false, error: 'Veículo não encontrado.' }, { status: 404 })
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const history = await (prisma as any).vehiclePricingHistory.findMany({
      where:   { vehicleId: params.id },
      orderBy: { createdAt: 'desc' },
      take:    20,
    })

    // Resolve nomes dos usuários que alteraram
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const userIds = Array.from(new Set(history.map((h: any) => h.changedById).filter(Boolean)))
    const users = userIds.length > 0
      ? await prisma.user.findMany({
          where:  { id: { in: userIds as string[] } },
          select: { id: true, name: true },
        })
      : []
    const userMap = Object.fromEntries(users.map((u) => [u.id, u.name]))

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const historyOut = history.map((h: any) => ({
      ...h,
      changedByName: userMap[h.changedById] ?? null,
    }))

    return NextResponse.json({ success: true, data: { vehicle, history: historyOut } })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── PATCH ─────────────────────────────────────────────────────────────────────

export async function PATCH(
  req: NextRequest,
  ctxArg: { params: { id: string } | Promise<{ id: string }> }) {
  /* ASYNC_PARAMS_FIXED */ const params = await Promise.resolve(ctxArg.params)
  const user = await getSessionUser()
  if (!user) return unauthorizedResponse()
  if (!canAccessModule(user.role, 'stock.manage')) {
    return forbiddenResponse('Apenas gerência pode alterar a precificação de venda.')
  }

  try {
    const tenantId = assertTenantId(user.tenantId, user.role)

    const existing = await prisma.vehicle.findFirst({
      where: { id: params.id, ...tenantWhere(user.role, tenantId) },
    })
    if (!existing) {
      return NextResponse.json({ success: false, error: 'Veículo não encontrado.' }, { status: 404 })
    }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const ex = existing as any

    const body = await req.json().catch(() => ({}))

    const salePrice          = body.salePrice          !== undefined ? toNum(body.salePrice)          : undefined
    const promoPrice         = body.promoPrice         !== undefined ? toNum(body.promoPrice)         : undefined
    const isPromo            = body.isPromo            !== undefined ? Boolean(body.isPromo)          : undefined
    const promoStartsAt      = body.promoStartsAt      !== undefined ? toDate(body.promoStartsAt)     : undefined
    const promoEndsAt        = body.promoEndsAt        !== undefined ? toDate(body.promoEndsAt)       : undefined
    const isAvailableForSale = body.isAvailableForSale !== undefined ? Boolean(body.isAvailableForSale) : undefined
    const pricingNotes       = body.pricingNotes       !== undefined ? (String(body.pricingNotes).trim() || null) : undefined
    const reason             = typeof body.reason === 'string' ? body.reason.trim() : null

    // Validações monetárias
    if (salePrice  !== undefined && salePrice  !== null && salePrice  <= 0) {
      return NextResponse.json({ success: false, error: 'Preço de venda deve ser maior que zero.' }, { status: 400 })
    }
    if (promoPrice !== undefined && promoPrice !== null && promoPrice <= 0) {
      return NextResponse.json({ success: false, error: 'Preço promocional deve ser maior que zero.' }, { status: 400 })
    }
    if (isPromo === true && (promoPrice == null && ex.promoPrice == null)) {
      return NextResponse.json({ success: false, error: 'Para ativar promoção, informe um preço promocional.' }, { status: 400 })
    }

    // ── Monta diff de campos alterados ──────────────────────────────────────
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const updates: any = {
      pricedById: user.id,
      pricedAt:   new Date(),
    }
    if (salePrice          !== undefined) updates.salePrice          = salePrice
    if (promoPrice         !== undefined) updates.promoPrice         = promoPrice
    if (isPromo            !== undefined) updates.isPromo            = isPromo
    if (promoStartsAt      !== undefined) updates.promoStartsAt      = promoStartsAt
    if (promoEndsAt        !== undefined) updates.promoEndsAt        = promoEndsAt
    if (isAvailableForSale !== undefined) updates.isAvailableForSale = isAvailableForSale
    if (pricingNotes       !== undefined) updates.pricingNotes       = pricingNotes

    // Side-effect: ao publicar, ativa o veículo e marca como DISPONIVEL
    let activatedNow = false
    if (isAvailableForSale === true && !ex.active) {
      updates.active = true
      activatedNow = true
    }
    if (isAvailableForSale === true && (ex.stockStatus === 'EM_PRECIFICACAO' || ex.stockStatus == null)) {
      updates.stockStatus = isPromo === true ? 'EM_PROMOCAO' : 'DISPONIVEL'
    }
    if (isAvailableForSale === false && ex.stockStatus === 'DISPONIVEL') {
      // volta para pré-publicação se for despublicado
      updates.stockStatus = 'EM_PRECIFICACAO'
    }

    const updated = await prisma.vehicle.update({
      where: { id: params.id },
      data:  updates,
    })

    // ── Grava VehiclePricingHistory para cada campo alterado ───────────────
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const histRecords: any[] = []

    const oldSale  = decToNum(ex.salePrice)
    const newSale  = salePrice  !== undefined ? salePrice  : oldSale
    const oldPromo = decToNum(ex.promoPrice)
    const newPromo = promoPrice !== undefined ? promoPrice : oldPromo
    const oldAvail = !!ex.isAvailableForSale
    const newAvail = isAvailableForSale !== undefined ? isAvailableForSale : oldAvail
    const oldIsPromo = !!ex.isPromo
    const newIsPromo = isPromo !== undefined ? isPromo : oldIsPromo

    if (salePrice !== undefined && oldSale !== newSale) {
      histRecords.push({
        vehicleId:    params.id,
        tenantId,
        changedById:  user.id,
        action:       oldSale == null ? 'SET_PRICE' : 'UPDATE_PRICE',
        oldSalePrice: oldSale,
        newSalePrice: newSale,
        reason,
      })
    }
    if (promoPrice !== undefined && oldPromo !== newPromo) {
      histRecords.push({
        vehicleId:     params.id,
        tenantId,
        changedById:   user.id,
        action:        'UPDATE_PRICE',
        oldPromoPrice: oldPromo,
        newPromoPrice: newPromo,
        reason,
      })
    }
    if (isPromo !== undefined && oldIsPromo !== newIsPromo) {
      histRecords.push({
        vehicleId:   params.id,
        tenantId,
        changedById: user.id,
        action:      newIsPromo ? 'PROMO_START' : 'PROMO_END',
        oldIsPromo,
        newIsPromo,
        reason,
      })
    }
    if (isAvailableForSale !== undefined && oldAvail !== newAvail) {
      histRecords.push({
        vehicleId:      params.id,
        tenantId,
        changedById:    user.id,
        action:         newAvail ? 'AVAILABILITY_ON' : 'AVAILABILITY_OFF',
        oldIsAvailable: oldAvail,
        newIsAvailable: newAvail,
        reason,
      })
    }
    if (pricingNotes !== undefined && (ex.pricingNotes ?? null) !== (pricingNotes ?? null)) {
      histRecords.push({
        vehicleId:   params.id,
        tenantId,
        changedById: user.id,
        action:      'NOTES_UPDATE',
        reason,
      })
    }

    if (histRecords.length > 0) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (prisma as any).vehiclePricingHistory.createMany({ data: histRecords })
    }

    await createSafeAuditLog({
      userId:   user.id,
      tenantId,
      action:   'VEHICLE_PRICING_UPDATE',
      entity:   'Vehicle',
      entityId: params.id,
      userName: user.name,
      userRole: user.role,
    })

    return NextResponse.json({ success: true, data: updated, activated: activatedNow })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// =============================================================================
// /api/vehicles — Listagem e criação de veículos em estoque (multi-tenant)
// =============================================================================

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import {
  getSessionUser,
  assertTenantId,
  tenantWhere,
  unauthorizedResponse,
  forbiddenResponse,
  assertUnitBelongsToTenant,
  createSafeAuditLog,
} from '@/lib/auth-guards'
import { handlePrismaError } from '@/lib/prisma-errors'
import { canAccessModule } from '@/lib/permissions'

// Status que NÃO finalizaram a negociação — veículo está em negociação ativa
const OPEN_DEAL_STATUSES = ['RASCUNHO', 'AGUARDANDO_LIBERACAO', 'LIBERADA', 'EM_ANDAMENTO', 'REABERTA']

// ── GET — Listar estoque com filtros e paginação ──────────────────────────────

export async function GET(req: NextRequest) {
  const user = await getSessionUser()
  if (!user) return unauthorizedResponse()
  if (!canAccessModule(user.role, 'stock.view')) return forbiddenResponse('Sem acesso ao módulo de estoque.')

  try {
    const tenantId = assertTenantId(user.tenantId, user.role)

    const { searchParams } = new URL(req.url)

    // Paginação
    const page  = Math.max(1, Number(searchParams.get('page')  ?? 1))
    const limit = Math.min(100, Math.max(1, Number(searchParams.get('limit') ?? 24)))

    // Filtros
    const search        = searchParams.get('search')?.trim()        ?? ''
    const unitId        = searchParams.get('unitId')                ?? ''
    const stockStatus   = searchParams.get('stockStatus')           ?? ''
    const stockLocation = searchParams.get('stockLocation')         ?? ''
    const vehicleType   = searchParams.get('vehicleType')           ?? ''
    const stockType     = searchParams.get('stockType')             ?? ''
    const conditionType = searchParams.get('conditionType')         ?? ''
    const pendencyIds   = searchParams.get('pendencyIds')           ?? ''
    const cautelarStatus = searchParams.get('cautelarStatus')       ?? ''
    const includeInactive = searchParams.get('includeInactive') === 'true'

    // Base where com isolamento de tenant
    const baseWhere = tenantWhere(user.role, tenantId)
    const where: Record<string, unknown> = {
      ...baseWhere,
      ...(includeInactive ? {} : { active: true }),
    }

    // Filtro de unidade — valida que pertence ao tenant se não for MASTER
    if (unitId) {
      if (user.role !== 'MASTER') {
        await assertUnitBelongsToTenant(unitId, tenantId, user.role)
      }
      where.unitId = unitId
    }

    if (stockStatus)   where.stockStatus   = stockStatus
    if (stockLocation) where.stockLocation = stockLocation
    if (vehicleType)   where.vehicleType   = vehicleType
    if (stockType)     where.stockType     = stockType
    if (conditionType) where.conditionType = conditionType
    if (cautelarStatus) where.cautelarStatus = cautelarStatus

    // Filtro por pendências ativas
    if (pendencyIds) {
      const ids = pendencyIds.split(',').filter(Boolean)
      if (ids.length > 0) {
        where.stockPendencies = {
          some: { optionId: { in: ids }, resolved: false },
        }
      }
    }

    // Busca textual
    if (search) {
      where.OR = [
        { plate:   { contains: search, mode: 'insensitive' } },
        { brand:   { contains: search, mode: 'insensitive' } },
        { model:   { contains: search, mode: 'insensitive' } },
        { version: { contains: search, mode: 'insensitive' } },
        { chassi:  { contains: search, mode: 'insensitive' } },
        { renavam: { contains: search, mode: 'insensitive' } },
        { color:   { contains: search, mode: 'insensitive' } },
        { fuel:    { contains: search, mode: 'insensitive' } },
        { customer: { name: { contains: search, mode: 'insensitive' } } },
        { unit:     { name: { contains: search, mode: 'insensitive' } } },
      ]
    }

    const [total, vehicles] = await Promise.all([
      prisma.vehicle.count({ where: where as never }),
      prisma.vehicle.findMany({
        where:   where as never,
        orderBy: { createdAt: 'desc' },
        skip:    (page - 1) * limit,
        take:    limit,
        select: {
          id:           true,
          tenantId:     true,
          unitId:       true,
          plate:        true,
          brand:        true,
          model:        true,
          version:      true,
          year:         true,
          modelYear:    true,
          km:           true,
          color:        true,
          fuel:         true,
          transmission: true,
          doors:        true,
          vehicleType:  true,
          conditionType: true,
          stockType:    true,
          stockLocation: true,
          stockStatus:  true,
          salePrice:    true,
          purchasePrice: true,
          fipeValue:    true,
          cautelarStatus: true,
          mainPhotoUrl: true,
          active:       true,
          entryDate:    true,
          exitDate:     true,
          notes:        true,
          createdAt:    true,
          updatedAt:    true,
          unit: {
            select: { id: true, name: true },
          },
          customer: {
            select: { id: true, name: true },
          },
          photos: {
            orderBy: { order: 'asc' },
            select: { id: true, url: true, isMain: true, caption: true },
          },
          stockPendencies: {
            where: { resolved: false },
            select: {
              id: true,
              notes: true,
              option: { select: { id: true, label: true, category: true } },
            },
          },
          // Verificar negociações abertas via DealVehicle → Deal
          // Inclui vendedor e unidade para exibir tag "Em negociação por X da unidade Y"
          dealVehicles: {
            where: {
              deal: { status: { in: OPEN_DEAL_STATUSES as never } },
            },
            select: {
              dealId: true,
              deal: {
                select: {
                  id:         true,
                  dealNumber: true,
                  status:     true,
                  unitId:     true,
                  seller: {
                    select: {
                      id:       true,
                      fullName: true,
                      user:     { select: { id: true, name: true } },
                    },
                  },
                },
              },
            },
            take: 1,
          },
          _count: { select: { photos: true, stockPendencies: true } },
        },
      }),
    ])

    // ── A relação dealVehicles vem do select via Prisma mas o TS pode perder
    // o tipo após `as never` no `status: { in: ... }`. Tratamos como `any[]`
    // só nessa transformação para evitar TS2339 spurious.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const vehiclesAny = vehicles as any[]

    // Buscar nomes de unidades referenciadas pelas negociações abertas (em batch)
    const dealUnitIds = Array.from(new Set(
      vehiclesAny
        .map((v) => v.dealVehicles?.[0]?.deal?.unitId as string | undefined)
        .filter((id): id is string => !!id),
    ))
    const dealUnits = dealUnitIds.length > 0
      ? await prisma.unit.findMany({
          where:  { id: { in: dealUnitIds } },
          select: { id: true, name: true },
        })
      : []
    const unitNameMap = Object.fromEntries(dealUnits.map((u) => [u.id, u.name]))

    // ── displayPhotos: fotos do marketing PRIMEIRO; fallback fotos das
    //    avaliações vinculadas (FOTO_SECAO) pra cobrir veículos recém-liberados
    //    que ainda não passaram pelo marketing. Top 6 imagens.
    const vehicleIds = vehiclesAny.map((v) => v.id)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let evalPhotosByVehicle: Record<string, string[]> = {}
    if (vehicleIds.length > 0) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const evals: any[] = await prisma.vehicleEvaluation.findMany({
        where:  { vehicleId: { in: vehicleIds } },
        select: { id: true, vehicleId: true },
      })
      const evalIdToVeh = new Map<string, string>(
        evals.filter((e) => e.vehicleId).map((e) => [e.id, e.vehicleId as string]),
      )
      const evalIds = Array.from(evalIdToVeh.keys())
      if (evalIds.length > 0) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const atts: any[] = await (prisma as any).evaluationAttachment.findMany({
          where:   { evaluationId: { in: evalIds }, fileType: 'image' },
          orderBy: { createdAt: 'asc' },
          select:  { evaluationId: true, publicUrl: true, itemId: true, category: true },
        })
        for (const a of atts) {
          if (!a.publicUrl) continue
          // Prefere fotos sem itemId (foto geral da seção) sobre fotos de itens
          const vehId = evalIdToVeh.get(a.evaluationId)
          if (!vehId) continue
          if (!evalPhotosByVehicle[vehId]) evalPhotosByVehicle[vehId] = []
          // Ordena: FOTO_SECAO sem itemId primeiro
          const isSection = !a.itemId
          if (isSection) evalPhotosByVehicle[vehId].unshift(a.publicUrl)
          else evalPhotosByVehicle[vehId].push(a.publicUrl)
        }
      }
    }

    // Computa hasOpenNegotiation com info de vendedor e unidade da negociação
    const data = vehiclesAny.map((v) => {
      const openDealRow = v.dealVehicles?.[0]
      const openDeal    = openDealRow?.deal
      const sellerName  = openDeal?.seller?.fullName
                        ?? openDeal?.seller?.user?.name
                        ?? null
      const unitName    = openDeal?.unitId ? (unitNameMap[openDeal.unitId] ?? null) : null

      // displayPhotos: prioriza VehiclePhoto (marketing) → fallback fotos da avaliação
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const marketingPhotos: string[] = (v.photos ?? [])
        .sort((a: any, b: any) => (b.isMain ? 1 : 0) - (a.isMain ? 1 : 0)) // main primeiro
        .map((p: any) => p.url)
        .filter((u: string | null): u is string => !!u)
      const fallbackPhotos = marketingPhotos.length === 0
        ? (evalPhotosByVehicle[v.id] ?? [])
        : []
      const displayPhotos = [...marketingPhotos, ...fallbackPhotos].slice(0, 6)

      return {
        ...v,
        displayPhotos,
        hasOpenNegotiation:    !!openDeal,
        openNegotiationId:     openDeal?.id          ?? null,
        openNegotiationNumber: openDeal?.dealNumber ?? null,
        openNegotiationStatus: openDeal?.status      ?? null,
        openNegotiationSeller: sellerName,
        openNegotiationUnit:   unitName,
      }
    })

    return NextResponse.json({
      success: true,
      data,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    })
  } catch (err) {
    return handlePrismaError(err)
  }
}

// ── POST — Criar veículo no estoque ──────────────────────────────────────────

export async function POST(req: NextRequest) {
  const user = await getSessionUser()
  if (!user) return unauthorizedResponse()
  if (!canAccessModule(user.role, 'stock.manage')) {
    return forbiddenResponse('Apenas gerentes e administradores podem cadastrar veículos.')
  }

  try {
    const tenantId = assertTenantId(user.tenantId, user.role)
    const body = await req.json()

    const {
      plate, chassi, renavam,
      brand, model, version, year, modelYear, km, color, fuel, transmission, doors,
      vehicleType, conditionType, stockType, stockLocation, stockStatus,
      salePrice, purchasePrice, fipeValue,
      cautelarStatus, cautelarNumber, cautelarNotes,
      mainPhotoUrl, notes, unitId, customerId, entryDate,
    } = body

    if (!brand?.trim() || !model?.trim()) {
      return NextResponse.json(
        { success: false, error: 'Marca e modelo são obrigatórios.' },
        { status: 400 },
      )
    }

    // Valida unitId
    const resolvedUnitId = unitId?.trim() || null
    if (resolvedUnitId) {
      await assertUnitBelongsToTenant(resolvedUnitId, tenantId, user.role)
    }

    const vehicle = await prisma.vehicle.create({
      data: {
        tenantId,
        unitId:       resolvedUnitId,
        customerId:   customerId    ? String(customerId)   : null,
        plate:        plate?.trim() ? String(plate).trim().toUpperCase() : null,
        chassi:       chassi?.trim()  ? String(chassi).trim().toUpperCase()  : null,
        renavam:      renavam?.trim() ? String(renavam).trim()               : null,
        brand:        String(brand).trim(),
        model:        String(model).trim(),
        version:      version?.trim() ? String(version).trim() : null,
        year:         year        ? Number(year)        : null,
        modelYear:    modelYear   ? Number(modelYear)   : null,
        km:           km          ? Number(km)          : null,
        color:        color?.trim()  ? String(color).trim()   : null,
        fuel:         fuel?.trim()   ? String(fuel).trim()    : null,
        transmission: transmission?.trim() ? String(transmission).trim() : null,
        doors:        doors       ? Number(doors)       : null,
        vehicleType:  vehicleType   ?? null,
        conditionType: conditionType ?? null,
        stockType:    stockType     ?? null,
        stockLocation: stockLocation ?? null,
        stockStatus:  stockStatus    ?? 'DISPONIVEL',
        salePrice:    salePrice    != null ? salePrice    : null,
        purchasePrice: purchasePrice != null ? purchasePrice : null,
        fipeValue:    fipeValue    != null ? fipeValue    : null,
        cautelarStatus:  cautelarStatus  ?? 'SEM_CAUTELAR',
        cautelarNumber:  cautelarNumber?.trim()  || null,
        cautelarNotes:   cautelarNotes?.trim()   || null,
        mainPhotoUrl:    mainPhotoUrl?.trim()    || null,
        notes:           notes?.trim()           || null,
        entryDate:    entryDate ? new Date(entryDate) : new Date(),
        active:       true,
      },
    })

    await createSafeAuditLog({
      userId:   user.id,
      tenantId,
      action:   'CREATE',
      entity:   'Vehicle',
      entityId: vehicle.id,
      userName: user.name,
      userRole: user.role,
    })

    return NextResponse.json(
      { success: true, data: vehicle, message: 'Veículo cadastrado com sucesso.' },
      { status: 201 },
    )
  } catch (err) {
    return handlePrismaError(err)
  }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

const VERIFY_TOKEN = process.env.META_WEBHOOK_VERIFY_TOKEN ?? 'autodrive_verify_token'

// =============================================================================
// GET — Verificação do webhook pela Meta
// =============================================================================
export async function GET(req: Request) {
  const { searchParams } = new URL(req.url)
  const mode = searchParams.get('hub.mode')
  const token = searchParams.get('hub.verify_token')
  const challenge = searchParams.get('hub.challenge')

  if (mode === 'subscribe' && token === VERIFY_TOKEN) {
    console.info('[webhook/meta] Verificação bem-sucedida')
    return new Response(challenge ?? '', { status: 200 })
  }

  return new Response('Forbidden', { status: 403 })
}

// =============================================================================
// POST — Recebimento de eventos da Meta
// =============================================================================
export async function POST(req: Request) {
  let rawPayload: unknown

  try {
    rawPayload = await req.json()
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 })
  }

  // Registrar o payload bruto
  await prisma.webhookLog.create({
    data: {
      provider: 'META',
      direction: 'INBOUND',
      payload: rawPayload as any,
      processed: false,
    },
  }).catch(err => console.error('[webhook] Failed to save log:', err))

  try {
    const body = rawPayload as any
    const entry = body?.entry?.[0]
    const changes = entry?.changes?.[0]
    const value = changes?.value

    if (!value) {
      return NextResponse.json({ status: 'ok' })
    }

    // Processar mensagens recebidas
    if (value.messages?.length > 0) {
      for (const msg of value.messages) {
        await processInboundMessage(msg, value.contacts?.[0])
      }
    }

    // Processar status de entrega/leitura
    if (value.statuses?.length > 0) {
      for (const status of value.statuses) {
        await processMessageStatus(status)
      }
    }

    // Marcar log como processado
    await prisma.webhookLog.updateMany({
      where: { processed: false, provider: 'META' },
      data: { processed: true },
    }).catch(() => { /* silent */ })

  } catch (err) {
    console.error('[webhook/meta] Processing error:', err)
    await prisma.webhookLog.updateMany({
      where: { processed: false, provider: 'META' },
      data: { error: String(err) },
    }).catch(() => { /* silent */ })
  }

  return NextResponse.json({ status: 'ok' })
}

// =============================================================================
// Processamento de mensagem recebida
// =============================================================================
async function processInboundMessage(msg: any, contact: any) {
  const from = msg.from // número WhatsApp do remetente
  const messageType = msg.type
  const messageBody = msg.text?.body ?? msg.caption ?? ''
  const profileName = contact?.profile?.name ?? null
  const whatsappMessageId = msg.id

  // Buscar vendedor pelo WhatsApp
  const seller = await prisma.seller.findFirst({
    where: { whatsapp: { contains: from.replace(/\D/g, '').slice(-11) } },
  })

  // Buscar pendência mais recente deste vendedor
  let pendencyId: string | null = null
  if (seller) {
    const recentPendency = await prisma.pendency.findFirst({
      where: { responsibleId: seller.id, status: { in: ['ABERTA', 'EM_ANDAMENTO'] } },
      orderBy: { lastSentAt: 'desc' },
    })
    pendencyId = recentPendency?.id ?? null
  }

  // Salvar retorno
  const messageReturn = await prisma.messageReturn.create({
    data: {
      whatsappFrom: from,
      profileName,
      messageType,
      messageBody,
      whatsappMessageId,
      pendencyId,
      sellerId: seller?.id ?? null,
      managerId: pendencyId
        ? (await prisma.pendency.findUnique({ where: { id: pendencyId }, select: { managerId: true } }))?.managerId ?? null
        : null,
      customerName: pendencyId
        ? (await prisma.pendency.findUnique({ where: { id: pendencyId }, select: { customerName: true } }))?.customerName ?? null
        : null,
      plate: pendencyId
        ? (await prisma.pendency.findUnique({ where: { id: pendencyId }, select: { plate: true } }))?.plate ?? null
        : null,
      rawPayload: msg,
    },
  })

  // Detectar resposta positiva (inteligência básica)
  const positiveKeywords = ['resolvido', 'já entreguei', 'processo entregue', 'feito', 'já mandei', 'finalizado', 'ok', 'entregue', 'concluído']
  const isPositive = positiveKeywords.some(kw => messageBody.toLowerCase().includes(kw))

  // Notificar gerente responsável
  if (pendencyId) {
    const pendency = await prisma.pendency.findUnique({
      where: { id: pendencyId },
      include: { manager: { select: { userId: true } } },
    })

    if (pendency?.manager?.userId) {
      await prisma.notification.create({
        data: {
          userId: pendency.manager.userId,
          type: 'RESPOSTA',
          title: `${profileName ?? 'Vendedor'} respondeu uma pendência`,
          message: `Cliente: ${pendency.customerName} | Placa: ${pendency.plate ?? '—'} | Resposta: ${messageBody.slice(0, 100)}${isPositive ? ' ✓' : ''}`,
          actionUrl: `/pendencias/gerencia`,
        },
      })
    }
  }
}

// =============================================================================
// Processamento de status de mensagem
// =============================================================================
async function processMessageStatus(status: any) {
  const { id: whatsappMessageId, status: msgStatus, recipient_id } = status

  await prisma.pendencyMessage.updateMany({
    where: { whatsappMessageId },
    data: { status: msgStatus },
  })
}

'use client'

// =============================================================================
// FipeWizard — Stepper Tipo → Marca → Modelo → Ano/Variante → Preço
//
// Consome as rotas internas que proxiam o provider FIPE (Parallelum):
//   GET /api/integrations/fipe/brands  ?tipoVeiculo=
//   GET /api/integrations/fipe/models  ?tipoVeiculo=&brandId=
//   GET /api/integrations/fipe/years   ?tipoVeiculo=&brandId=&modelId=
//   GET /api/integrations/fipe/price   ?tipoVeiculo=&brandId=&modelId=&yearId=
//
// Ao concluir, dispara onComplete com os campos prontos para salvar em
// VehicleEvaluation/Deal:
//   { codigoFipe, valor, valorNumber, mesReferencia, marca, modelo,
//     anoModelo, combustivel, tipoVeiculo, dataConsulta }
// =============================================================================

import { useCallback, useEffect, useMemo, useState } from 'react'
import {
  Car, Bike, Truck, ChevronRight, Loader2, Search, AlertTriangle,
  CheckCircle2, RefreshCcw, X,
} from 'lucide-react'

export interface FipeResult {
  codigoFipe:    string
  valor:         string        // "R$ 95.000,00"
  valorNumber:   number        // 95000
  mesReferencia: string        // "maio/2026 "
  marca:         string
  modelo:        string
  anoModelo:     number | null
  combustivel:   string
  tipoVeiculo:   'carros' | 'motos' | 'caminhoes'
  dataConsulta:  string        // ISO
}

// Provider Parallelum: { code, name }
interface Brand   { code: string; name: string }
interface Model   { code: string; name: string }
interface Year    { code: string; name: string }
interface PriceData {
  brand:           string
  codeFipe:        string
  fuel:            string
  fuelAcronym:     string
  model:           string
  modelYear:       number
  price:           string         // "R$ 95.000,00"
  referenceMonth:  string         // "abril de 2024"
  vehicleType:     number
}

type Tipo = 'carros' | 'motos' | 'caminhoes'

const TIPOS: Array<{ value: Tipo; label: string; Icon: typeof Car }> = [
  { value: 'carros',     label: 'Carro',    Icon: Car },
  { value: 'motos',      label: 'Moto',     Icon: Bike },
  { value: 'caminhoes',  label: 'Caminhão', Icon: Truck },
]

function parseValor(v: string): number {
  const n = parseFloat(v.replace(/[R$\s.]/g, '').replace(',', '.'))
  return isNaN(n) ? 0 : n
}

const baseInput =
  'w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500'

// ── Componente ────────────────────────────────────────────────────────────────

export function FipeWizard({
  initialTipo = 'carros',
  onComplete,
  onCancel,
}: {
  initialTipo?: Tipo
  onComplete: (r: FipeResult) => void
  onCancel?:  () => void
}) {
  const [tipo,       setTipo]       = useState<Tipo>(initialTipo)
  const [brands,     setBrands]     = useState<Brand[]>([])
  const [brandQuery, setBrandQuery] = useState('')
  const [brandSel,   setBrandSel]   = useState<Brand | null>(null)
  const [models,     setModels]     = useState<Model[]>([])
  const [modelQuery, setModelQuery] = useState('')
  const [modelSel,   setModelSel]   = useState<Model | null>(null)
  const [years,      setYears]      = useState<Year[]>([])
  const [yearSel,    setYearSel]    = useState<Year | null>(null)
  const [price,      setPrice]      = useState<PriceData | null>(null)

  const [loading, setLoading] = useState<null | 'brands' | 'models' | 'years' | 'price'>(null)
  const [error,   setError]   = useState<string>('')

  // ── Carrega marcas quando muda o tipo ──────────────────────────────────────
  const loadBrands = useCallback(async (t: Tipo) => {
    setLoading('brands')
    setError('')
    setBrands([])
    setBrandSel(null)
    setModels([]); setModelSel(null)
    setYears([]);  setYearSel(null)
    setPrice(null)
    try {
      const res  = await fetch(`/api/integrations/fipe/brands?tipoVeiculo=${t}`)
      const json = await res.json()
      if (!json.ok) throw new Error(json.error ?? 'Falha ao carregar marcas FIPE.')
      setBrands(Array.isArray(json.data) ? json.data : [])
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Falha ao carregar marcas FIPE.')
    } finally {
      setLoading(null)
    }
  }, [])

  useEffect(() => { loadBrands(tipo) }, [tipo, loadBrands])

  // ── Carrega modelos ao selecionar marca ────────────────────────────────────
  const loadModels = useCallback(async (b: Brand) => {
    setLoading('models')
    setError('')
    setModels([]); setModelSel(null)
    setYears([]);  setYearSel(null)
    setPrice(null)
    try {
      const res  = await fetch(`/api/integrations/fipe/models?tipoVeiculo=${tipo}&brandId=${encodeURIComponent(b.code)}`)
      const json = await res.json()
      if (!json.ok) throw new Error(json.error ?? 'Falha ao carregar modelos FIPE.')
      setModels(Array.isArray(json.data) ? json.data : [])
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Falha ao carregar modelos FIPE.')
    } finally {
      setLoading(null)
    }
  }, [tipo])

  // ── Carrega anos/combustível ao selecionar modelo ──────────────────────────
  const loadYears = useCallback(async (m: Model) => {
    if (!brandSel) return
    setLoading('years')
    setError('')
    setYears([]); setYearSel(null); setPrice(null)
    try {
      const res  = await fetch(
        `/api/integrations/fipe/years?tipoVeiculo=${tipo}&brandId=${encodeURIComponent(brandSel.code)}&modelId=${encodeURIComponent(m.code)}`,
      )
      const json = await res.json()
      if (!json.ok) throw new Error(json.error ?? 'Falha ao carregar anos FIPE.')
      setYears(Array.isArray(json.data) ? json.data : [])
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Falha ao carregar anos FIPE.')
    } finally {
      setLoading(null)
    }
  }, [tipo, brandSel])

  // ── Consulta preço ao selecionar ano ───────────────────────────────────────
  const loadPrice = useCallback(async (y: Year) => {
    if (!brandSel || !modelSel) return
    setLoading('price')
    setError('')
    setPrice(null)
    try {
      const res  = await fetch(
        `/api/integrations/fipe/price?tipoVeiculo=${tipo}&brandId=${encodeURIComponent(brandSel.code)}&modelId=${encodeURIComponent(modelSel.code)}&yearId=${encodeURIComponent(y.code)}`,
      )
      const json = await res.json()
      if (!json.ok) throw new Error(json.error ?? 'Falha ao consultar preço FIPE.')
      setPrice(json.data as PriceData)
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Falha ao consultar preço FIPE.')
    } finally {
      setLoading(null)
    }
  }, [tipo, brandSel, modelSel])

  const filteredBrands = useMemo(() => {
    const q = brandQuery.trim().toLowerCase()
    if (!q) return brands.slice(0, 60)
    return brands.filter((b) => b.name.toLowerCase().includes(q)).slice(0, 60)
  }, [brands, brandQuery])

  const filteredModels = useMemo(() => {
    const q = modelQuery.trim().toLowerCase()
    if (!q) return models.slice(0, 60)
    return models.filter((m) => m.name.toLowerCase().includes(q)).slice(0, 60)
  }, [models, modelQuery])

  // ── Confirmar (chamado pelo botão depois do preço carregado) ───────────────
  const handleConfirm = () => {
    if (!price || !yearSel) return
    onComplete({
      codigoFipe:    price.codeFipe,
      valor:         price.price,
      valorNumber:   parseValor(price.price),
      mesReferencia: price.referenceMonth,
      marca:         price.brand,
      modelo:        price.model,
      anoModelo:     typeof price.modelYear === 'number' ? price.modelYear : null,
      combustivel:   price.fuel,
      tipoVeiculo:   tipo,
      dataConsulta:  new Date().toISOString(),
    })
  }

  // ── UI ──────────────────────────────────────────────────────────────────────

  return (
    <div className="space-y-4">
      {/* Crumbs */}
      <div className="flex flex-wrap items-center gap-2 text-xs text-gray-600">
        <span className="font-semibold">FIPE:</span>
        <Crumb active={!brandSel} done={!!brandSel}>{TIPOS.find((t) => t.value === tipo)?.label}</Crumb>
        <ChevronRight size={12} className="text-gray-300" />
        <Crumb active={!!brandSel && !modelSel} done={!!modelSel}>{brandSel?.name ?? 'Marca'}</Crumb>
        <ChevronRight size={12} className="text-gray-300" />
        <Crumb active={!!modelSel && !yearSel} done={!!yearSel}>{modelSel?.name ?? 'Modelo'}</Crumb>
        <ChevronRight size={12} className="text-gray-300" />
        <Crumb active={!!yearSel && !price} done={!!price}>{yearSel?.name ?? 'Ano'}</Crumb>
        <ChevronRight size={12} className="text-gray-300" />
        <Crumb active={!!price}>Preço</Crumb>
        {onCancel && (
          <button
            type="button"
            onClick={onCancel}
            className="ml-auto flex items-center gap-1 text-xs text-gray-500 hover:text-gray-800"
          >
            <X size={11} /> Cancelar
          </button>
        )}
      </div>

      {error && (
        <div className="flex items-start gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-800">
          <AlertTriangle size={12} className="mt-0.5 shrink-0" />
          <span className="flex-1">{error}</span>
          <button
            type="button"
            onClick={() => loadBrands(tipo)}
            className="ml-auto flex items-center gap-1 text-amber-900 hover:underline"
          >
            <RefreshCcw size={11} /> Recarregar
          </button>
        </div>
      )}

      {/* Tipo */}
      <div>
        <p className="mb-2 text-[11px] font-semibold uppercase tracking-wide text-gray-500">Tipo de veículo</p>
        <div className="grid grid-cols-3 gap-2">
          {TIPOS.map(({ value, label, Icon }) => (
            <button
              key={value}
              type="button"
              onClick={() => setTipo(value)}
              className={`flex items-center justify-center gap-2 rounded-lg border-2 px-3 py-2 text-sm font-medium transition-all ${
                tipo === value
                  ? 'border-brand-500 bg-brand-50 text-brand-700'
                  : 'border-gray-200 bg-white text-gray-700 hover:border-brand-300'
              }`}
            >
              <Icon size={14} />
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Marca */}
      <Panel title="Marca" loading={loading === 'brands'}>
        <SearchInput value={brandQuery} onChange={setBrandQuery} placeholder="Buscar marca..." />
        <div className="mt-2 max-h-44 overflow-y-auto rounded-lg border border-gray-100">
          {filteredBrands.length === 0 && loading !== 'brands' && (
            <p className="px-3 py-3 text-xs text-gray-400">Nenhuma marca encontrada.</p>
          )}
          <ul className="divide-y divide-gray-50">
            {filteredBrands.map((b) => (
              <li key={b.code}>
                <button
                  type="button"
                  onClick={() => { setBrandSel(b); loadModels(b) }}
                  className={`flex w-full items-center justify-between gap-2 px-3 py-2 text-left text-sm hover:bg-brand-50 ${
                    brandSel?.code === b.code ? 'bg-brand-50/70 font-semibold text-brand-800' : 'text-gray-700'
                  }`}
                >
                  <span>{b.name}</span>
                  {brandSel?.code === b.code && <CheckCircle2 size={13} className="text-brand-600" />}
                </button>
              </li>
            ))}
          </ul>
        </div>
      </Panel>

      {/* Modelo */}
      {brandSel && (
        <Panel title="Modelo" loading={loading === 'models'}>
          <SearchInput value={modelQuery} onChange={setModelQuery} placeholder="Buscar modelo..." />
          <div className="mt-2 max-h-44 overflow-y-auto rounded-lg border border-gray-100">
            {filteredModels.length === 0 && loading !== 'models' && (
              <p className="px-3 py-3 text-xs text-gray-400">Nenhum modelo disponível.</p>
            )}
            <ul className="divide-y divide-gray-50">
              {filteredModels.map((m) => (
                <li key={m.code}>
                  <button
                    type="button"
                    onClick={() => { setModelSel(m); loadYears(m) }}
                    className={`flex w-full items-center justify-between gap-2 px-3 py-2 text-left text-sm hover:bg-brand-50 ${
                      modelSel?.code === m.code ? 'bg-brand-50/70 font-semibold text-brand-800' : 'text-gray-700'
                    }`}
                  >
                    <span className="truncate pr-2">{m.name}</span>
                    <span className="font-mono text-[10px] text-gray-400">{m.code}</span>
                  </button>
                </li>
              ))}
            </ul>
          </div>
        </Panel>
      )}

      {/* Ano / combustível */}
      {modelSel && (
        <Panel title="Ano / Combustível" loading={loading === 'years'}>
          {years.length === 0 && loading !== 'years' && !error && (
            <p className="px-3 py-3 text-xs text-gray-400">Aguardando anos…</p>
          )}
          <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
            {years.map((y) => (
              <button
                key={y.code}
                type="button"
                onClick={() => { setYearSel(y); loadPrice(y) }}
                className={`rounded-lg border-2 px-3 py-2 text-left text-sm transition-all ${
                  yearSel?.code === y.code
                    ? 'border-brand-500 bg-brand-50 text-brand-800'
                    : 'border-gray-200 bg-white hover:border-brand-300'
                }`}
              >
                <span className="block font-semibold">{y.name}</span>
                <span className="block font-mono text-[10px] text-gray-400">{y.code}</span>
              </button>
            ))}
          </div>
        </Panel>
      )}

      {/* Preço final */}
      {yearSel && (
        <Panel title="Preço FIPE" loading={loading === 'price'}>
          {!price && loading !== 'price' && !error && (
            <p className="px-3 py-3 text-xs text-gray-400">Aguardando preço…</p>
          )}
          {price && (
            <div className="flex flex-col gap-3 rounded-xl border-2 border-emerald-200 bg-emerald-50/40 p-4">
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-gray-900">{price.model}</p>
                  <p className="text-[11px] text-gray-500">
                    {price.brand} · {price.modelYear} · {price.fuel}
                    <span className="ml-2 font-mono text-gray-400">FIPE {price.codeFipe}</span>
                  </p>
                </div>
                <div className="text-right shrink-0">
                  <p className="text-xl font-bold text-emerald-700">{price.price}</p>
                  <p className="text-[10px] text-gray-400">{price.referenceMonth}</p>
                </div>
              </div>
              <button
                type="button"
                onClick={handleConfirm}
                className="flex items-center justify-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-semibold text-white shadow-sm hover:bg-brand-700"
              >
                <CheckCircle2 size={14} />
                Usar esta consulta FIPE
              </button>
            </div>
          )}
        </Panel>
      )}
    </div>
  )
}

// ── Subcomponentes ────────────────────────────────────────────────────────────

function Crumb({ children, active, done }: { children: React.ReactNode; active?: boolean; done?: boolean }) {
  return (
    <span className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-medium ${
      done   ? 'bg-emerald-50 text-emerald-700'
      : active ? 'bg-brand-100 text-brand-800'
      : 'bg-gray-100 text-gray-500'
    }`}>
      {children}
    </span>
  )
}

function Panel({ title, loading, children }: { title: string; loading?: boolean; children: React.ReactNode }) {
  return (
    <div className="rounded-xl border border-gray-200 bg-white p-3">
      <div className="mb-2 flex items-center justify-between">
        <p className="text-[11px] font-semibold uppercase tracking-wide text-gray-500">{title}</p>
        {loading && <Loader2 size={12} className="animate-spin text-gray-400" />}
      </div>
      {children}
    </div>
  )
}

function SearchInput({ value, onChange, placeholder }: { value: string; onChange: (v: string) => void; placeholder?: string }) {
  return (
    <div className="relative">
      <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-gray-400" />
      <input
        className={`${baseInput} pl-7`}
        value={value}
        placeholder={placeholder}
        onChange={(e) => onChange(e.target.value)}
      />
    </div>
  )
}

'use client'

// =============================================================================
// PlateInput — Campo de placa com máscara dinâmica e busca automática
// =============================================================================

import { useState, useEffect, useRef, useCallback } from 'react'
import { Search, Loader2, CheckCircle2, XCircle, AlertCircle, RefreshCw } from 'lucide-react'
import { maskPlateInput, isValidPlate, normalizePlate } from '@/lib/vehicles/plate'
import type { VehicleLookupData } from '@/lib/vehicle-lookup/types'

type LookupStatus = 'idle' | 'loading' | 'found' | 'not_found' | 'error'

interface PlateInputProps {
  value:    string
  onChange: (normalized: string, display: string) => void
  onLookupResult?: (data: VehicleLookupData | null, status: LookupStatus) => void
  disabled?: boolean
}

const STATUS_CONFIG: Record<LookupStatus, { icon: React.ReactNode; text: string; className: string } | null> = {
  idle:      null,
  loading: {
    icon:      <Loader2 className="h-4 w-4 animate-spin" />,
    text:      'Consultando dados do veículo...',
    className: 'text-brand-600',
  },
  found: {
    icon:      <CheckCircle2 className="h-4 w-4" />,
    text:      'Dados carregados automaticamente.',
    className: 'text-emerald-600',
  },
  not_found: {
    icon:      <AlertCircle className="h-4 w-4" />,
    text:      'Não encontramos os dados automaticamente. Preencha manualmente.',
    className: 'text-amber-600',
  },
  error: {
    icon:      <XCircle className="h-4 w-4" />,
    text:      'Não foi possível consultar a placa agora. Preencha manualmente ou tente novamente.',
    className: 'text-red-600',
  },
}

/** Delay em ms antes de disparar a consulta após a última tecla */
const DEBOUNCE_MS = 600

export function PlateInput({ value, onChange, onLookupResult, disabled }: PlateInputProps) {
  const [display,    setDisplay]    = useState('')
  const [status,     setStatus]     = useState<LookupStatus>('idle')
  const [lastLooked, setLastLooked] = useState('')
  const [overrideMsg, setOverrideMsg] = useState<string | null>(null)
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // Sincroniza display quando value chega como prop normalizado
  useEffect(() => {
    if (!display && value) setDisplay(value)
  }, [value]) // eslint-disable-line react-hooks/exhaustive-deps

  const doLookup = useCallback(async (plate: string, force = false) => {
    if (!force && plate === lastLooked) return
    setStatus('loading')
    setOverrideMsg(null)
    setLastLooked(plate)

    try {
      const url = `/api/vehicles/lookup-by-plate?plate=${encodeURIComponent(plate)}${force ? '&refresh=true' : ''}`
      const res  = await fetch(url)
      const data = await res.json()

      if (!res.ok || !data.success) {
        setStatus('error')
        if (data?.error) setOverrideMsg(String(data.error))
        onLookupResult?.(null, 'error')
        return
      }

      if (data.found && data.data) {
        setStatus('found')
        onLookupResult?.(data.data, 'found')
      } else {
        setStatus('not_found')
        // O backend agora envia mensagem específica quando API de placa
        // não está configurada (PLATE_LOOKUP). Usamos ela quando vier.
        if (data?.message) setOverrideMsg(String(data.message))
        onLookupResult?.(null, 'not_found')
      }
    } catch (_) {
      setStatus('error')
      onLookupResult?.(null, 'error')
    }
  }, [lastLooked, onLookupResult])

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const raw     = e.target.value
    const masked  = maskPlateInput(raw)
    const normal  = normalizePlate(masked)
    setDisplay(masked)
    onChange(normal, masked)

    // Reset status ao digitar
    if (status !== 'idle') setStatus('idle')
    onLookupResult?.(null, 'idle')

    // Cancela debounce anterior
    if (debounceRef.current) clearTimeout(debounceRef.current)

    // Dispara consulta quando placa ficar válida
    if (isValidPlate(normal)) {
      debounceRef.current = setTimeout(() => doLookup(normal), DEBOUNCE_MS)
    }
  }

  const statusConfig = STATUS_CONFIG[status]
  const isPlateValid = isValidPlate(normalizePlate(display))

  return (
    <div className="flex flex-col gap-2">
      <div className="relative">
        <Search className="absolute left-3 top-1/2 h-5 w-5 -translate-y-1/2 text-gray-400" />
        <input
          type="text"
          value={display}
          onChange={handleChange}
          disabled={disabled}
          placeholder="ABC-1234 ou ABC1D23"
          maxLength={8}
          className={[
            'w-full rounded-xl border py-3 pl-10 pr-12 font-mono text-lg font-bold uppercase tracking-widest shadow-sm',
            'focus:outline-none focus:ring-2 focus:ring-brand-500',
            status === 'found'
              ? 'border-emerald-400 bg-emerald-50 text-emerald-900'
              : status === 'error'
                ? 'border-red-300 bg-red-50'
                : 'border-gray-300 bg-white text-gray-900',
            disabled ? 'opacity-50 cursor-not-allowed' : '',
          ].join(' ')}
          autoComplete="off"
          spellCheck={false}
        />
        {/* Status indicator inline */}
        <div className="absolute right-3 top-1/2 -translate-y-1/2">
          {status === 'loading' && <Loader2 className="h-5 w-5 animate-spin text-brand-500" />}
          {status === 'found'   && <CheckCircle2 className="h-5 w-5 text-emerald-500" />}
          {status === 'error'   && <XCircle className="h-5 w-5 text-red-500" />}
          {status === 'not_found' && <AlertCircle className="h-5 w-5 text-amber-500" />}
        </div>
      </div>

      {/* Mensagem de status — usa override do servidor quando disponível */}
      {statusConfig && (
        <div className={`flex items-center gap-2 text-sm font-medium ${statusConfig.className}`}>
          {statusConfig.icon}
          <span>{overrideMsg ?? statusConfig.text}</span>
        </div>
      )}

      {/* Botão consultar novamente */}
      {(status === 'found' || status === 'not_found' || status === 'error') && isPlateValid && (
        <button
          type="button"
          onClick={() => doLookup(normalizePlate(display), true)}
          className="flex w-fit items-center gap-1.5 rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-gray-50 transition-colors"
        >
          <RefreshCw className="h-3.5 w-3.5" />
          Consultar novamente
        </button>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// VehicleCard — Card de veículo para a listagem do estoque
// =============================================================================

import { useEffect, useRef, useState } from 'react'
import Image from 'next/image'
import Link from 'next/link'
import { MapPin, Gauge, Calendar, AlertTriangle, Tag, Car, ChevronLeft, ChevronRight } from 'lucide-react'
import { VehicleStatusBadge, CautelarBadge, StockTypeBadge, ConditionBadge } from './VehicleStatusBadge'
import { cn } from '@/lib/utils'

interface VehiclePendency {
  id: string
  option: { label: string; category: string | null }
}

interface VehicleCardProps {
  vehicle: {
    id: string
    plate:        string | null
    brand:        string
    model:        string
    version:      string | null
    year:         number | null
    modelYear:    number | null
    km:           number | null
    color:        string | null
    fuel:         string | null
    salePrice:    number | null
    mainPhotoUrl: string | null
    stockStatus:  string
    stockType:    string | null
    stockLocation: string | null
    conditionType: string | null
    cautelarStatus: string
    unit:          { id: string; name: string } | null
    stockPendencies: VehiclePendency[]
    hasOpenNegotiation:    boolean
    openNegotiationId:     string | null
    openNegotiationNumber?: string | null
    openNegotiationStatus?: string | null
    openNegotiationSeller?: string | null
    openNegotiationUnit?:   string | null
    /** URLs ordenadas: marketing primeiro, fallback fotos da avaliação. */
    displayPhotos?:        string[]
    _count: { photos: number; stockPendencies: number }
  }
  className?: string
}

function formatCurrency(value: number | null): string {
  if (value == null) return '—'
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value)
}

function formatKm(km: number | null): string {
  if (km == null) return '—'
  return new Intl.NumberFormat('pt-BR').format(km) + ' km'
}

