// ── Carrossel das fotos do card (auto-rotate + setas no hover) ──────────────
function VehicleCardCarousel({ photos, alt }: { photos: string[]; alt: string }) {
  const [idx, setIdx] = useState(0)
  const [hovering, setHovering] = useState(false)
  const total = photos.length
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null)

  // Auto-rotate quando não está hover (4s)
  useEffect(() => {
    if (total <= 1) return
    if (hovering) {
      if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null }
      return
    }
    intervalRef.current = setInterval(() => setIdx((i) => (i + 1) % total), 4000)
    return () => { if (intervalRef.current) clearInterval(intervalRef.current) }
  }, [total, hovering])

  // Reset índice se a lista muda
  useEffect(() => { setIdx((i) => (i >= total ? 0 : i)) }, [total])

  if (total === 0) {
    return (
      <div className="flex h-full items-center justify-center">
        <Car className="h-16 w-16 text-gray-300" />
      </div>
    )
  }

  return (
    <div
      className="relative h-full w-full"
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
    >
      <Image
        key={photos[idx]}
        src={photos[idx]}
        alt={alt}
        fill
        className="object-cover transition-opacity duration-300"
        sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
        unoptimized
      />

      {total > 1 && (
        <>
          {/* Setas (visíveis no hover) */}
          <button
            type="button"
            onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIdx((i) => (i - 1 + total) % total) }}
            className="absolute left-1 top-1/2 z-10 -translate-y-1/2 rounded-full bg-black/40 p-1 text-white opacity-0 transition-opacity hover:bg-black/60 group-hover:opacity-100"
            aria-label="Foto anterior"
          >
            <ChevronLeft size={14} />
          </button>
          <button
            type="button"
            onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIdx((i) => (i + 1) % total) }}
            className="absolute right-1 top-1/2 z-10 -translate-y-1/2 rounded-full bg-black/40 p-1 text-white opacity-0 transition-opacity hover:bg-black/60 group-hover:opacity-100"
            aria-label="Próxima foto"
          >
            <ChevronRight size={14} />
          </button>

          {/* Dots indicators */}
          <div className="absolute bottom-1.5 left-1/2 z-10 flex -translate-x-1/2 gap-1">
            {photos.map((_, i) => (
              <button
                key={i}
                type="button"
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIdx(i) }}
                className={cn(
                  'h-1.5 rounded-full transition-all',
                  i === idx ? 'w-4 bg-white' : 'w-1.5 bg-white/50',
                )}
                aria-label={`Foto ${i + 1}`}
              />
            ))}
          </div>
        </>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// VehicleComboBox — Seleção hierárquica Marca → Modelo → Versão com FIPE
//
// Defensivo por design:
//   • Nunca chama .toLowerCase() em valor undefined/null
//   • Aceita options em qualquer formato de API (code/codigo/id, name/nome/label)
//   • Filtra itens inválidos sem quebrar
//   • Toda chamada async tem try/catch/finally
//   • Loading nunca fica infinito
// =============================================================================

import { useState, useEffect, useRef } from 'react'
import { ChevronDown, Loader2, Search, AlertCircle } from 'lucide-react'
import type { FipePrice, VehicleCategory } from '@/lib/vehicle-lookup/types'

// ── Tipo flexível que aceita o que vier da API ────────────────────────────────

export type AnyOption = {
  id?:          string | number | null
  code?:        string | number | null
  codigo?:      string | number | null
  value?:       string | number | null
  name?:        string | null
  nome?:        string | null
  label?:       string | null
  text?:        string | null
  description?: string | null
  descricao?:   string | null
  [key: string]: unknown
}

// ── Helpers defensivos ────────────────────────────────────────────────────────

/** Extrai o label de um item de opção em qualquer formato */
function getOptionLabel(option: unknown): string {
  if (option == null || typeof option !== 'object') return ''
  const o = option as AnyOption
  const raw =
    o.name        ??
    o.nome        ??
    o.label       ??
    o.text        ??
    o.description ??
    o.descricao   ??
    o.code        ??
    o.codigo      ??
    o.value       ??
    o.id
  return String(raw ?? '').trim()
}

/** Extrai o value/code de um item de opção em qualquer formato */
function getOptionValue(option: unknown): string {
  if (option == null || typeof option !== 'object') return ''
  const o = option as AnyOption
  const raw =
    o.code   ??
    o.codigo ??
    o.id     ??
    o.value  ??
    o.name   ??
    o.nome   ??
    o.label
  return String(raw ?? '').trim()
}

/** Normaliza qualquer array de opções para { code, name } seguro */
function normalizeOptions(raw: unknown): { code: string; name: string }[] {
  if (!Array.isArray(raw)) return []
  return raw
    .filter(Boolean)                           // remove null/undefined
    .map((item) => ({
      code: getOptionValue(item),
      name: getOptionLabel(item),
    }))
    .filter((o) => o.code !== '' || o.name !== '') // remove itens completamente vazios
}

// ── ComboBox interno genérico e defensivo ─────────────────────────────────────

interface ComboBoxProps {
  label:         string
  value:         string
  onChange:      (code: string, name: string) => void
  options:       { code: string; name: string }[]
  loading?:      boolean
  error?:        string
  disabled?:     boolean
  placeholder?:  string
  emptyMessage?: string
  required?:     boolean
}

function ComboBox({
  label, value, onChange, options, loading, error,
  disabled, placeholder, emptyMessage, required,
}: ComboBoxProps) {
  const [open,  setOpen]  = useState(false)
  const [query, setQuery] = useState('')
  const ref = useRef<HTMLDivElement>(null)

  // Garantia: options sempre é array de objetos com code/name string
  const safeOptions = Array.isArray(options)
    ? options.filter((o) => o != null && typeof o === 'object')
    : []

  // Filtragem 100% segura — sem risco de TypeError
  const safeQuery  = String(query ?? '').trim().toLowerCase()
  const filtered   = safeQuery
    ? safeOptions.filter((o) => String(o.name ?? '').toLowerCase().includes(safeQuery))
    : safeOptions

  const selected   = safeOptions.find((o) => String(o.code ?? '') === String(value ?? ''))
  const displayLabel = selected ? String(selected.name ?? '') : ''

  // Fechar ao clicar fora
  useEffect(() => {
    function handleOutside(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false)
        setQuery('')
      }
    }
    document.addEventListener('mousedown', handleOutside)
    return () => document.removeEventListener('mousedown', handleOutside)
  }, [])

  // Fechar com Escape
  useEffect(() => {
    function handleKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { setOpen(false); setQuery('') }
    }
    if (open) document.addEventListener('keydown', handleKey)
    return () => document.removeEventListener('keydown', handleKey)
  }, [open])

  return (
    <div className="flex flex-col gap-1">
      <label className="text-xs font-medium text-gray-600">
        {label}
        {required && <span className="ml-0.5 text-red-500">*</span>}
      </label>

      <div ref={ref} className="relative">
        <button
          type="button"
          disabled={disabled || loading}
          onClick={() => !disabled && !loading && setOpen((p) => !p)}
          className={[
            'flex w-full items-center justify-between gap-2 rounded-lg border px-3 py-2 text-sm text-left transition-colors',
            'focus:outline-none focus:ring-1 focus:ring-brand-500',
            disabled || loading
              ? 'cursor-not-allowed opacity-50 bg-gray-50 border-gray-200'
              : 'bg-white hover:border-brand-400 cursor-pointer',
            error
              ? 'border-red-300'
              : displayLabel
                ? 'border-gray-300 text-gray-900'
                : 'border-gray-300 text-gray-400',
          ].join(' ')}
        >
          <span className="truncate min-w-0">
            {displayLabel || placeholder || 'Selecione...'}
          </span>
          {loading
            ? <Loader2 className="h-4 w-4 shrink-0 animate-spin text-gray-400" />
            : <ChevronDown className={`h-4 w-4 shrink-0 text-gray-400 transition-transform ${open ? 'rotate-180' : ''}`} />
          }
        </button>

        {open && !loading && (
          <div className="absolute left-0 top-full z-[60] mt-1 w-full min-w-[200px] rounded-xl border border-gray-200 bg-white shadow-xl">
            {/* Campo de busca */}
            <div className="border-b border-gray-100 p-2">
              <div className="relative">
                <Search className="absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-gray-400" />
                <input
                  autoFocus
                  value={query}
                  onChange={(e) => setQuery(e.target.value ?? '')}
                  onKeyDown={(e) => e.stopPropagation()}
                  className="w-full rounded-md border border-gray-200 py-1.5 pl-7 pr-2 text-sm focus:border-brand-400 focus:outline-none"
                  placeholder="Pesquisar..."
                />
              </div>
            </div>

            {/* Lista */}
            <ul
              className="max-h-60 overflow-y-auto py-1"
              role="listbox"
            >
              {filtered.length === 0 ? (
                <li className="px-3 py-3 text-sm text-gray-400 text-center">
                  {emptyMessage || 'Nenhum resultado'}
                </li>
              ) : (
                filtered.map((o, i) => {
                  const code  = String(o.code ?? i)
                  const name  = String(o.name ?? '')
                  const isSelected = code === String(value ?? '')
                  return (
                    <li key={`${code}-${i}`} role="option" aria-selected={isSelected}>
                      <button
                        type="button"
                        onClick={() => { onChange(code, name); setOpen(false); setQuery('') }}
                        className={[
                          'w-full px-3 py-2 text-left text-sm transition-colors',
                          isSelected
                            ? 'bg-brand-50 font-medium text-brand-700'
                            : 'text-gray-700 hover:bg-gray-50',
                        ].join(' ')}
                      >
                        {name || code || '—'}
                      </button>
                    </li>
                  )
                })
              )}
            </ul>
          </div>
        )}
      </div>

      {error && (
        <p className="flex items-center gap-1 text-xs text-red-500">
          <AlertCircle className="h-3 w-3 shrink-0" />
          {error}
        </p>
      )}
    </div>
  )
}

// ── VehicleComboBox (cascata Marca → Modelo → Versão) ─────────────────────────

export interface VehicleComboSelection {
  vehicleType:  VehicleCategory | ''
  brandCode:    string
  brandName:    string
  modelCode:    string
  modelName:    string
  versionCode:  string
  versionLabel: string
  modelYear:    number | null
  fipeCode:     string
  fipeValue:    number | null
  fipeMonth:    string
  fuel:         string
}

export const EMPTY_COMBO_SELECTION: VehicleComboSelection = {
  vehicleType: '', brandCode: '', brandName: '', modelCode: '', modelName: '',
  versionCode: '', versionLabel: '', modelYear: null,
  fipeCode: '', fipeValue: null, fipeMonth: '', fuel: '',
}

interface VehicleComboBoxProps {
  value:        VehicleComboSelection
  onChange:     (sel: VehicleComboSelection) => void
  initialType?: VehicleCategory
  disabled?:    boolean
}

const VEHICLE_TYPES = [
  { code: 'CAR',        label: 'Carro' },
  { code: 'MOTORCYCLE', label: 'Moto' },
  { code: 'TRUCK',      label: 'Caminhão' },
]

function safeFmt(value: number): string {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value)
}

export function VehicleComboBox({ value, onChange, initialType, disabled }: VehicleComboBoxProps) {
  const [brands,   setBrands]   = useState<{ code: string; name: string }[]>([])
  const [models,   setModels]   = useState<{ code: string; name: string }[]>([])
  const [versions, setVersions] = useState<{ code: string; name: string }[]>([])

  const [loadingBrands,   setLoadingBrands]   = useState(false)
  const [loadingModels,   setLoadingModels]   = useState(false)
  const [loadingVersions, setLoadingVersions] = useState(false)
  const [loadingFipe,     setLoadingFipe]     = useState(false)

  const [brandError,   setBrandError]   = useState('')
  const [modelError,   setModelError]   = useState('')
  const [versionError, setVersionError] = useState('')
  const [fipeError,    setFipeError]    = useState('')

  // Determina o tipo efetivo (prop ou initialType)
  const effectiveType = value.vehicleType || initialType || ''

  // ── Carrega marcas quando tipo muda ─────────────────────────────────────────
  useEffect(() => {
    if (!effectiveType) return

    setLoadingBrands(true)
    setBrandError('')
    setBrands([])
    setModels([])
    setVersions([])

    const controller = new AbortController()
    fetch(`/api/vehicles/brands?type=${effectiveType}`, { signal: controller.signal })
      .then((r) => r.json())
      .then((d) => {
        if (d?.success && Array.isArray(d.data)) {
          setBrands(normalizeOptions(d.data))
        } else {
          setBrandError('Não foi possível carregar as marcas.')
        }
      })
      .catch((err) => {
        if (err?.name !== 'AbortError') {
          setBrandError('Erro ao carregar marcas. Tente novamente.')
        }
      })
      .finally(() => setLoadingBrands(false))

    return () => controller.abort()
  }, [effectiveType])

  // ── Carrega modelos quando marca muda ────────────────────────────────────────
  useEffect(() => {
    if (!value.brandCode || !effectiveType) return

    setLoadingModels(true)
    setModelError('')
    setModels([])
    setVersions([])

    const controller = new AbortController()
    fetch(`/api/vehicles/models?brandCode=${value.brandCode}&type=${effectiveType}`, { signal: controller.signal })
      .then((r) => r.json())
      .then((d) => {
        if (d?.success && Array.isArray(d.data)) {
          setModels(normalizeOptions(d.data))
        } else {
          setModelError('Não foi possível carregar os modelos.')
        }
      })
      .catch((err) => {
        if (err?.name !== 'AbortError') {
          setModelError('Erro ao carregar modelos. Tente novamente.')
        }
      })
      .finally(() => setLoadingModels(false))

    return () => controller.abort()
  }, [value.brandCode, effectiveType])

  // ── Carrega versões quando modelo muda ───────────────────────────────────────
  useEffect(() => {
    if (!value.modelCode || !value.brandCode || !effectiveType) return

    setLoadingVersions(true)
    setVersionError('')
    setVersions([])

    const controller = new AbortController()
    fetch(
      `/api/vehicles/versions?brandCode=${value.brandCode}&modelCode=${value.modelCode}&type=${effectiveType}`,
      { signal: controller.signal },
    )
      .then((r) => r.json())
      .then((d) => {
        if (d?.success && Array.isArray(d.data)) {
          // Versões vêm como FipeVersion — normalizar para { code, name }
          const normalized = (d.data as unknown[])
            .filter(Boolean)
            .map((item) => {
              const i = item as { code?: string; yearLabel?: string; modelYear?: number; fuelLabel?: string; name?: string; nome?: string }
              const code = String(i?.code ?? '')
              const name = i?.yearLabel
                ?? (i?.modelYear ? `${i.modelYear} — ${i.fuelLabel ?? ''}` : null)
                ?? String(i?.name ?? i?.nome ?? code)
              return { code, name: name.trim() }
            })
            .filter((o) => o.code)
          setVersions(normalized)
        } else {
          setVersionError('Não foi possível carregar as versões.')
        }
      })
      .catch((err) => {
        if (err?.name !== 'AbortError') {
          setVersionError('Erro ao carregar versões. Tente novamente.')
        }
      })
      .finally(() => setLoadingVersions(false))

    return () => controller.abort()
  }, [value.modelCode, value.brandCode, effectiveType])

  // ── Busca FIPE quando versão é selecionada ───────────────────────────────────
  async function fetchFipe(versionCode: string, versionLabel: string) {
    if (!value.brandCode || !value.modelCode || !effectiveType) return

    // Extrai modelYear do código "2022-1" → 2022, ou do label
    const yearMatch = versionCode.match(/^(\d{4})/)
    const modelYear = yearMatch ? Number(yearMatch[1]) : null

    setLoadingFipe(true)
    setFipeError('')

    try {
      const url = `/api/vehicles/fipe?brandCode=${value.brandCode}&modelCode=${value.modelCode}&yearCode=${encodeURIComponent(versionCode)}&type=${effectiveType}`
      const res  = await fetch(url)
      const data: { success?: boolean; data?: FipePrice; error?: string } = await res.json().catch(() => ({}))

      if (data?.success && data.data) {
        onChange({
          ...value,
          versionCode,
          versionLabel,
          modelYear,
          fipeCode:  data.data.fipeCode  ?? '',
          fipeValue: data.data.value     ?? null,
          fipeMonth: data.data.referenceMonth ?? '',
          fuel:      data.data.fuel      ?? '',
        })
      } else {
        setFipeError(data?.error ?? 'Não foi possível consultar a Tabela FIPE. Preencha manualmente.')
        onChange({ ...value, versionCode, versionLabel, modelYear })
      }
    } catch (_) {
      setFipeError('Erro ao consultar a Tabela FIPE. Preencha manualmente.')
      onChange({ ...value, versionCode, versionLabel, modelYear })
    } finally {
      setLoadingFipe(false)
    }
  }

  // ── Handlers ──────────────────────────────────────────────────────────────────

  function handleType(code: string) {
    onChange({
      ...EMPTY_COMBO_SELECTION,
      vehicleType: code as VehicleCategory,
    })
  }

  function handleBrand(code: string, name: string) {
    onChange({
      ...value,
      brandCode: code, brandName: name,
      modelCode: '', modelName: '',
      versionCode: '', versionLabel: '', modelYear: null,
      fipeCode: '', fipeValue: null, fipeMonth: '', fuel: '',
    })
  }

  function handleModel(code: string, name: string) {
    onChange({
      ...value,
      modelCode: code, modelName: name,
      versionCode: '', versionLabel: '', modelYear: null,
      fipeCode: '', fipeValue: null, fipeMonth: '', fuel: '',
    })
  }

  function handleVersion(code: string) {
    const ver = versions.find((v) => v.code === code)
    const label = ver?.name ?? code
    fetchFipe(code, label)
  }

  // ── Render ────────────────────────────────────────────────────────────────────

  return (
    <div className="flex flex-col gap-4">

      {/* Tipo de Veículo */}
      <div className="flex flex-col gap-1">
        <label className="text-xs font-medium text-gray-600">Tipo de Veículo</label>
        <div className="flex gap-2">
          {VEHICLE_TYPES.map((t) => (
            <button
              key={t.code}
              type="button"
              disabled={disabled}
              onClick={() => handleType(t.code)}
              className={[
                'flex-1 rounded-lg border px-3 py-2 text-sm font-medium transition-colors',
                value.vehicleType === t.code
                  ? 'border-brand-500 bg-brand-50 text-brand-700 shadow-sm'
                  : 'border-gray-300 text-gray-600 hover:border-brand-300 hover:bg-gray-50',
                disabled ? 'cursor-not-allowed opacity-50' : 'cursor-pointer',
              ].join(' ')}
            >
              {t.label}
            </button>
          ))}
        </div>
      </div>

      {/* Cascata Marca → Modelo → Versão */}
      <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
        <ComboBox
          label="Marca"
          required
          value={value.brandCode}
          onChange={handleBrand}
          options={brands}
          loading={loadingBrands}
          error={brandError}
          disabled={disabled || !effectiveType}
          placeholder={effectiveType ? 'Selecione a marca' : 'Selecione o tipo primeiro'}
          emptyMessage="Nenhuma marca encontrada"
        />

        <ComboBox
          label="Modelo"
          required
          value={value.modelCode}
          onChange={handleModel}
          options={models}
          loading={loadingModels}
          error={modelError}
          disabled={disabled || !value.brandCode}
          placeholder={value.brandCode ? 'Selecione o modelo' : 'Selecione a marca primeiro'}
          emptyMessage="Nenhum modelo encontrado"
        />

        <ComboBox
          label="Versão / Ano"
          value={value.versionCode}
          onChange={handleVersion}
          options={versions}
          loading={loadingVersions || loadingFipe}
          error={versionError || fipeError}
          disabled={disabled || !value.modelCode}
          placeholder={value.modelCode ? 'Selecione a versão' : 'Selecione o modelo primeiro'}
          emptyMessage="Nenhuma versão encontrada"
        />
      </div>

      {/* Resultado FIPE */}
      {loadingFipe && (
        <div className="flex items-center gap-2 text-sm text-brand-600">
          <Loader2 className="h-4 w-4 animate-spin" />
          Consultando Tabela FIPE...
        </div>
      )}

      {value.fipeValue != null && !loadingFipe && (
        <div className="flex flex-wrap items-stretch gap-3 rounded-xl border border-brand-200 bg-brand-50 px-4 py-3">
          <div className="flex flex-col">
            <span className="text-xs text-brand-500">Tabela FIPE</span>
            <p className="text-lg font-bold text-brand-800">{safeFmt(value.fipeValue)}</p>
          </div>
          {value.fipeCode && (
            <div className="flex flex-col border-l border-brand-200 pl-3">
              <span className="text-xs text-brand-500">Código</span>
              <p className="font-mono font-medium text-brand-700">{value.fipeCode}</p>
            </div>
          )}
          {value.fipeMonth && (
            <div className="flex flex-col border-l border-brand-200 pl-3">
              <span className="text-xs text-brand-500">Referência</span>
              <p className="font-medium text-brand-700">{value.fipeMonth}</p>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// VehicleSalePricingPanel — Painel "Precificação de Venda"
//
// Gerente+: formulário para editar salePrice/promo/availability/notes
// Vendedor: resumo read-only (sem campos sensíveis editáveis)
// Mostra também timeline com as últimas alterações registradas.
// =============================================================================

import { useState, useEffect, useCallback } from 'react'
import {
  DollarSign, Tag, History, Save, Loader2, ToggleLeft, ToggleRight,
  CheckCircle2, XCircle, AlertCircle,
} from 'lucide-react'
import { maskBRL, parseBRL, numberToBRLMask, formatBRL } from '@/lib/masks'

interface PricingState {
  salePrice:          number | null
  purchasePrice:      number | null
  fipeValue:          number | null
  promoPrice:         number | null
  isPromo:            boolean
  promoStartsAt:      string | null
  promoEndsAt:        string | null
  isAvailableForSale: boolean
  pricingNotes:       string | null
  pricedById:         string | null
  pricedAt:           string | null
  stockStatus:        string | null
  active:             boolean
}

interface PricingHistoryRow {
  id:              string
  changedById:     string
  changedByName:   string | null
  action:          string
  oldSalePrice:    number | null
  newSalePrice:    number | null
  oldPromoPrice:   number | null
  newPromoPrice:   number | null
  oldIsAvailable:  boolean | null
  newIsAvailable:  boolean | null
  oldIsPromo:      boolean | null
  newIsPromo:      boolean | null
  reason:          string | null
  createdAt:       string
}

interface Props {
  vehicleId: string
  canManage: boolean
}

const ACTION_LABEL: Record<string, string> = {
  SET_PRICE:        'Definiu preço de venda',
  UPDATE_PRICE:     'Atualizou preço',
  PROMO_START:      'Iniciou promoção',
  PROMO_END:        'Encerrou promoção',
  AVAILABILITY_ON:  'Publicou no estoque',
  AVAILABILITY_OFF: 'Despublicou do estoque',
  NOTES_UPDATE:     'Atualizou observações',
}

function fmtDate(iso: string | null): string {
  if (!iso) return '—'
  const d = new Date(iso)
  return d.toLocaleString('pt-BR', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit',
  })
}

function fmtDateInput(iso: string | null): string {
  if (!iso) return ''
  const d = new Date(iso)
  if (Number.isNaN(d.getTime())) return ''
  // yyyy-MM-ddTHH:mm para <input type="datetime-local">
  const pad = (n: number) => String(n).padStart(2, '0')
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`
}

export function VehicleSalePricingPanel({ vehicleId, canManage }: Props) {
  const [loading, setLoading] = useState(true)
  const [saving,  setSaving]  = useState(false)
  const [error,   setError]   = useState<string | null>(null)
  const [success, setSuccess] = useState<string | null>(null)
  const [data,    setData]    = useState<PricingState | null>(null)
  const [history, setHistory] = useState<PricingHistoryRow[]>([])

  // Form state (controlled)
  const [salePriceMask,  setSalePriceMask]  = useState('')
  const [promoPriceMask, setPromoPriceMask] = useState('')
  const [isPromo,            setIsPromo]            = useState(false)
  const [promoStartsAt,      setPromoStartsAt]      = useState('')
  const [promoEndsAt,        setPromoEndsAt]        = useState('')
  const [isAvailableForSale, setIsAvailableForSale] = useState(false)
  const [pricingNotes,       setPricingNotes]       = useState('')
  const [reason,             setReason]             = useState('')

  const load = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const res  = await fetch(`/api/vehicles/${vehicleId}/pricing`, { cache: 'no-store' })
      const json = await res.json()
      if (!res.ok || !json.success) {
        setError(json?.error ?? 'Falha ao carregar precificação.')
        return
      }
      const v = json.data.vehicle as PricingState
      setData(v)
      setHistory(json.data.history ?? [])
      setSalePriceMask(numberToBRLMask(v.salePrice))
      setPromoPriceMask(numberToBRLMask(v.promoPrice))
      setIsPromo(!!v.isPromo)
      setPromoStartsAt(fmtDateInput(v.promoStartsAt))
      setPromoEndsAt(fmtDateInput(v.promoEndsAt))
      setIsAvailableForSale(!!v.isAvailableForSale)
      setPricingNotes(v.pricingNotes ?? '')
    } catch {
      setError('Erro de conexão.')
    } finally {
      setLoading(false)
    }
  }, [vehicleId])

  useEffect(() => { load() }, [load])

  async function handleSave() {
    setSaving(true)
    setError(null)
    setSuccess(null)
    try {
      const body = {
        salePrice:          parseBRL(salePriceMask),
        promoPrice:         isPromo ? parseBRL(promoPriceMask) : null,
        isPromo,
        promoStartsAt:      promoStartsAt || null,
        promoEndsAt:        promoEndsAt   || null,
        isAvailableForSale,
        pricingNotes:       pricingNotes.trim() || null,
        reason:             reason.trim() || null,
      }
      const res  = await fetch(`/api/vehicles/${vehicleId}/pricing`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(body),
      })
      const json = await res.json()
      if (!res.ok || !json.success) {
        setError(json?.error ?? 'Falha ao salvar precificação.')
        return
      }
      setSuccess('Precificação salva com sucesso.')
      setReason('')
      await load()
    } catch {
      setError('Erro de conexão.')
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-10 text-gray-400">
        <Loader2 className="h-5 w-5 animate-spin" />
      </div>
    )
  }

  if (!data) {
    return (
      <div className="rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
        {error ?? 'Sem dados de precificação.'}
      </div>
    )
  }

  // ── Read-only para vendedor ────────────────────────────────────────────────
  if (!canManage) {
    return (
      <div className="flex flex-col gap-4">
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
          <SummaryCard label="Preço de Venda"      value={formatBRL(data.salePrice)} accent />
          <SummaryCard label="Preço Promocional"   value={data.isPromo ? formatBRL(data.promoPrice) : '—'} />
          <SummaryCard label="Disponível para Venda" value={data.isAvailableForSale ? 'Sim' : 'Não'} />
        </div>
        {data.pricingNotes && (
          <div className="rounded-lg bg-gray-50 p-3">
            <p className="text-xs font-medium text-gray-500 mb-1">Observações</p>
            <p className="text-sm text-gray-700 whitespace-pre-wrap">{data.pricingNotes}</p>
          </div>
        )}
        <HistoryTimeline history={history} />
      </div>
    )
  }

  // ── Editor gerente+ ────────────────────────────────────────────────────────
  return (
    <div className="flex flex-col gap-5">

      {/* Status atual */}
      <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
        <SummaryCard label="Compra (avaliado)" value={formatBRL(data.purchasePrice)} />
        <SummaryCard label="FIPE atual"        value={formatBRL(data.fipeValue)} />
        <SummaryCard
          label="Última atualização"
          value={data.pricedAt ? fmtDate(data.pricedAt) : '—'}
        />
      </div>

      {/* Feedback */}
      {error && (
        <div className="flex items-start gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
          <span>{error}</span>
        </div>
      )}
      {success && (
        <div className="flex items-start gap-2 rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700">
          <CheckCircle2 className="h-4 w-4 mt-0.5 shrink-0" />
          <span>{success}</span>
        </div>
      )}

      {/* Formulário */}
      <div className="rounded-xl border border-gray-200 bg-white p-4">
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          <FieldMoney
            label="Preço de Venda"
            value={salePriceMask}
            onChange={(v) => setSalePriceMask(maskBRL(v))}
            icon={<DollarSign className="h-4 w-4 text-brand-500" />}
            required
          />

          <div className="flex flex-col gap-2">
            <ToggleField
              label="Em promoção"
              icon={<Tag className="h-4 w-4 text-amber-500" />}
              checked={isPromo}
              onChange={setIsPromo}
            />
            {isPromo && (
              <FieldMoney
                label="Preço promocional"
                value={promoPriceMask}
                onChange={(v) => setPromoPriceMask(maskBRL(v))}
              />
            )}
          </div>

          {isPromo && (
            <>
              <DateTimeField
                label="Início da promoção"
                value={promoStartsAt}
                onChange={setPromoStartsAt}
              />
              <DateTimeField
                label="Fim da promoção"
                value={promoEndsAt}
                onChange={setPromoEndsAt}
              />
            </>
          )}

          <ToggleField
            label="Disponível para venda (publicar no estoque)"
            icon={<CheckCircle2 className="h-4 w-4 text-emerald-500" />}
            checked={isAvailableForSale}
            onChange={setIsAvailableForSale}
          />

          <div className="sm:col-span-2">
            <label className="mb-1 block text-xs font-medium text-gray-600">Observações internas</label>
            <textarea
              value={pricingNotes}
              onChange={(e) => setPricingNotes(e.target.value)}
              rows={3}
              className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
              placeholder="Notas visíveis apenas para a equipe..."
            />
          </div>

          <div className="sm:col-span-2">
            <label className="mb-1 block text-xs font-medium text-gray-600">Motivo da alteração (opcional)</label>
            <input
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
              placeholder="Ex.: ajuste de margem, alinhamento com FIPE..."
            />
          </div>
        </div>

        <div className="mt-4 flex items-center justify-end gap-2">
          <button
            onClick={handleSave}
            disabled={saving}
            className="flex items-center gap-2 rounded-lg bg-brand-600 px-4 py-2 text-sm font-medium text-white shadow-sm hover:bg-brand-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
            {saving ? 'Salvando...' : 'Salvar precificação'}
          </button>
        </div>
      </div>

      <HistoryTimeline history={history} />
    </div>
  )
}

// ── Subcomponentes ───────────────────────────────────────────────────────────

function SummaryCard({ label, value, accent }: { label: string; value: string; accent?: boolean }) {
  return (
    <div className={[
      'rounded-xl p-4 text-center',
      accent ? 'bg-brand-50 border border-brand-200' : 'bg-gray-50',
    ].join(' ')}>
      <p className={['text-xs', accent ? 'text-brand-600' : 'text-gray-500'].join(' ')}>{label}</p>
      <p className={['mt-1 text-lg font-bold', accent ? 'text-brand-700' : 'text-gray-900'].join(' ')}>{value}</p>
    </div>
  )
}

function FieldMoney({
  label, value, onChange, icon, required,
}: {
  label: string
  value: string
  onChange: (v: string) => void
  icon?: React.ReactNode
  required?: boolean
}) {
  return (
    <div>
      <label className="mb-1 block text-xs font-medium text-gray-600">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <div className="relative">
        {icon && <div className="absolute left-3 top-1/2 -translate-y-1/2">{icon}</div>}
        <span className="absolute left-9 top-1/2 -translate-y-1/2 text-sm text-gray-400">R$</span>
        <input
          inputMode="numeric"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className={[
            'w-full rounded-lg border border-gray-300 py-2 pr-3 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500',
            icon ? 'pl-16' : 'pl-10',
          ].join(' ')}
          placeholder="0,00"
        />
      </div>
    </div>
  )
}

function ToggleField({
  label, checked, onChange, icon,
}: {
  label: string
  checked: boolean
  onChange: (v: boolean) => void
  icon?: React.ReactNode
}) {
  return (
    <button
      type="button"
      onClick={() => onChange(!checked)}
      className={[
        'flex items-center justify-between gap-3 rounded-lg border px-3 py-2 text-left text-sm transition-colors',
        checked
          ? 'border-brand-300 bg-brand-50 text-brand-800'
          : 'border-gray-300 bg-white text-gray-700 hover:bg-gray-50',
      ].join(' ')}
    >
      <span className="flex items-center gap-2 font-medium">
        {icon}
        {label}
      </span>
      {checked
        ? <ToggleRight className="h-5 w-5 text-brand-600" />
        : <ToggleLeft  className="h-5 w-5 text-gray-400" />}
    </button>
  )
}

function DateTimeField({ label, value, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
  return (
    <div>
      <label className="mb-1 block text-xs font-medium text-gray-600">{label}</label>
      <input
        type="datetime-local"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-brand-500 focus:outline-none focus:ring-1 focus:ring-brand-500"
      />
    </div>
  )
}

function HistoryTimeline({ history }: { history: PricingHistoryRow[] }) {
  return (
    <div>
      <h4 className="mb-3 flex items-center gap-2 text-sm font-semibold text-gray-700">
        <History className="h-4 w-4 text-gray-500" />
        Histórico de Precificação
        <span className="text-xs font-normal text-gray-400">({history.length})</span>
      </h4>
      {history.length === 0 ? (
        <p className="rounded-lg bg-gray-50 px-4 py-6 text-center text-sm text-gray-400">
          Nenhuma alteração registrada ainda.
        </p>
      ) : (
        <ol className="flex flex-col gap-2">
          {history.map((h) => {
            const label = ACTION_LABEL[h.action] ?? h.action
            const isPositive = ['AVAILABILITY_ON', 'PROMO_START', 'SET_PRICE'].includes(h.action)
            const isNegative = ['AVAILABILITY_OFF', 'PROMO_END'].includes(h.action)
            return (
              <li
                key={h.id}
                className={[
                  'rounded-lg border px-3 py-2',
                  isPositive ? 'border-emerald-200 bg-emerald-50'
                  : isNegative ? 'border-amber-200 bg-amber-50'
                  : 'border-gray-200 bg-white',
                ].join(' ')}
              >
                <div className="flex items-center justify-between gap-2">
                  <p className="text-sm font-medium text-gray-900 flex items-center gap-2">
                    {isPositive ? <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600" />
                    : isNegative ? <XCircle className="h-3.5 w-3.5 text-amber-600" />
                    : <Tag className="h-3.5 w-3.5 text-gray-500" />}
                    {label}
                  </p>
                  <span className="text-xs text-gray-500">{fmtDate(h.createdAt)}</span>
                </div>
                <p className="mt-0.5 text-xs text-gray-600">
                  Por <span className="font-medium">{h.changedByName ?? '—'}</span>
                </p>
                {h.oldSalePrice != null || h.newSalePrice != null ? (
                  <p className="mt-1 text-xs text-gray-700">
                    Venda: <span className="line-through opacity-60">{formatBRL(h.oldSalePrice)}</span>
                    {' → '}<span className="font-semibold">{formatBRL(h.newSalePrice)}</span>
                  </p>
                ) : null}
                {h.oldPromoPrice != null || h.newPromoPrice != null ? (
                  <p className="mt-1 text-xs text-gray-700">
                    Promo: <span className="line-through opacity-60">{formatBRL(h.oldPromoPrice)}</span>
                    {' → '}<span className="font-semibold">{formatBRL(h.newPromoPrice)}</span>
                  </p>
                ) : null}
                {h.reason && (
                  <p className="mt-1 text-xs italic text-gray-600">"{h.reason}"</p>
                )}
              </li>
            )
          })}
        </ol>
      )}
    </div>
  )
}

'use client'

// =============================================================================
// GoalsPanel — Busca as metas ativas do usuário (/api/goals/me) e renderiza os
// cards com progresso. Trata loading, vazio e erro.
// =============================================================================

import { useEffect, useState, useCallback } from 'react'
import { Target, RefreshCw } from 'lucide-react'
import { cn } from '@/lib/utils'
import { GoalCard, type GoalCardData } from '@/components/goals/GoalCard'

export function GoalsPanel() {
  const [items, setItems] = useState<GoalCardData[]>([])
  const [state, setState] = useState<'loading' | 'ready' | 'error'>('loading')
  const [refreshing, setRefreshing] = useState(false)

  const load = useCallback(async () => {
    setRefreshing(true)
    try {
      const res = await fetch('/api/goals/me', { credentials: 'include' })
      if (!res.ok) throw new Error('fetch failed')
      const json = await res.json()
      setItems(Array.isArray(json?.data) ? json.data : [])
      setState('ready')
    } catch {
      setState('error')
    } finally {
      setRefreshing(false)
    }
  }, [])

  useEffect(() => { load() }, [load])

  return (
    <div className="card">
      <div className="section-header justify-between">
        <div className="flex items-center gap-2">
          <Target size={16} className="text-brand-700" />
          <h2 className="text-sm font-semibold text-gray-800">Minhas Metas</h2>
        </div>
        <button
          type="button"
          onClick={load}
          disabled={refreshing}
          className="text-gray-400 transition-colors hover:text-gray-600"
          aria-label="Atualizar metas"
        >
          <RefreshCw size={14} className={cn(refreshing && 'animate-spin')} />
        </button>
      </div>

      <div className="p-5">
        {state === 'loading' && (
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-3">
            {[0, 1, 2].map((i) => (
              <div key={i} className="h-32 animate-pulse rounded-xl bg-gray-50" />
            ))}
          </div>
        )}

        {state === 'error' && (
          <p className="py-8 text-center text-sm text-gray-400">
            Não foi possível carregar suas metas.
          </p>
        )}

        {state === 'ready' && items.length === 0 && (
          <p className="py-8 text-center text-sm text-gray-400">
            Nenhuma meta ativa no momento.
          </p>
        )}

        {state === 'ready' && items.length > 0 && (
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-3">
            {items.map((item) => (
              <GoalCard key={item.goal.id} data={item} />
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

// =============================================================================
// ImpersonationBanner — Barra de alerta quando MASTER está em sessão de impersonation
//
// Mostra: quem está sendo impersonado, em qual tenant, e botões para:
//   • Ir ao Painel Master (sem encerrar a sessão)
//   • Encerrar impersonation (encerra no servidor e redireciona ao painel master)
// Persiste via sessionStorage (limpa ao fechar o browser/tab).
// =============================================================================

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { ShieldAlert, Loader2, LogOut, Crown } from 'lucide-react'
import { useImpersonationStore } from '@/store/impersonationStore'

export function ImpersonationBanner() {
  const { active, endImpersonation } = useImpersonationStore()
  const router  = useRouter()
  const [ending, setEnding] = useState(false)

  if (!active) return null

  async function handleEnd() {
    if (!active) return
    setEnding(true)
    try {
      await fetch(`/api/master/tenants/${active.tenant.id}/impersonate`, {
        method:  'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ impersonationSessionId: active.impersonationSessionId }),
      })
    } catch {
      // mesmo com erro de rede, limpamos o estado local
    } finally {
      endImpersonation()
      setEnding(false)
      router.push('/master/tenants/' + active.tenant.id)
    }
  }

  function handleGoToMaster() {
    // Navega ao painel master sem encerrar a sessão de impersonation
    router.push('/master/tenants/' + active!.tenant.id)
  }

  const elapsed = Math.floor((Date.now() - new Date(active.startedAt).getTime()) / 60000)

  return (
    <div className="z-[100] flex items-center gap-3 bg-amber-500 px-4 py-2 text-sm text-white shadow-md">
      <ShieldAlert size={16} className="shrink-0 animate-pulse" />

      <div className="flex flex-1 items-center gap-2 flex-wrap min-w-0">
        <span className="font-semibold">MODO IMPERSONATION</span>
        <span className="opacity-80">·</span>
        <span>
          Visualizando como{' '}
          <strong>{active.targetUser.name}</strong>
          {' '}
          <span className="opacity-75 text-xs">({active.targetUser.role})</span>
        </span>
        <span className="opacity-80">·</span>
        <span>
          Tenant: <strong>{active.tenant.name}</strong>
        </span>
        {elapsed > 0 && (
          <>
            <span className="opacity-80">·</span>
            <span className="text-xs opacity-75">{elapsed}min</span>
          </>
        )}
      </div>

      {/* Botão: voltar ao painel master sem encerrar */}
      <button
        onClick={handleGoToMaster}
        disabled={ending}
        className="flex shrink-0 items-center gap-1.5 rounded-md bg-white/20 px-3 py-1 text-xs font-semibold hover:bg-white/30 disabled:opacity-60 transition-colors"
        title="Ir ao painel Master deste tenant sem encerrar a impersonation"
      >
        <Crown size={12} />
        Painel Master
      </button>

      {/* Separador */}
      <span className="opacity-40 select-none">|</span>

      {/* Botão: encerrar impersonation completamente */}
      <button
        onClick={handleEnd}
        disabled={ending}
        className="flex shrink-0 items-center gap-1.5 rounded-md bg-white/10 border border-white/30 px-3 py-1 text-xs font-semibold hover:bg-red-600/60 disabled:opacity-60 transition-colors"
        title="Encerrar sessão de impersonation e voltar ao painel Master"
      >
        {ending
          ? <Loader2 size={12} className="animate-spin" />
          : <LogOut size={12} />
        }
        {ending ? 'Encerrando...' : 'Sair do modo impersonation'}
      </button>
    </div>
  )
}

