// ── Função principal ──────────────────────────────────────────────────────────

export async function runDealProcessor(opts: DealProcessorOptions): Promise<DealProcessorSummary> {
  const startedAt = Date.now()
  const summary: DealProcessorSummary = {
    totalRows:          0,
    skipped:            0,
    dealsCreated:       0,
    dealsUpdated:       0,
    provisionalSellers: 0,
    pendenciesCreated:  0,
    errors:             0,
    errorDetails:       [],
    durationMs:         0,
    dryRun:             opts.dryRun ?? false,
  }

  // Carrega configuração
  const config = await prisma.googleSheetConfig.findUnique({
    where: { id: opts.configId },
  })
  if (!config)          throw new Error('Importador não encontrado.')
  if (!config.tenantId) throw new Error('Tenant não configurado no importador.')
  if (!config.unitId)   throw new Error('Unidade não configurada no importador.')

  const resolvedIds = await resolveConfigIds(config.tenantId!, config.unitId!)
  const tenantId    = resolvedIds.tenantId
  const unitId      = resolvedIds.unitId

  // Opcional: resetar linhas com ERRO/AGUARDANDO_CONFERENCIA/PROCESSANDO para PENDENTE
  if (opts.resetPending) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    await (prisma.sheetImportRow as any).updateMany({
      where: { configId: opts.configId, status: { in: ['ERRO', 'AGUARDANDO_CONFERENCIA', 'PROCESSANDO'] } },
      data:  { status: 'PENDENTE', errorMessage: null, processedAt: null },
    })
  }

  // Carrega linhas PENDENTES
  const limit = opts.limitRows && opts.limitRows > 0 ? opts.limitRows : undefined
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const rows: any[] = await (prisma.sheetImportRow as any).findMany({
    where:   { configId: opts.configId, status: 'PENDENTE' },
    orderBy: { createdAt: 'asc' },
    take:    limit,
  })

  summary.totalRows = rows.length

  for (const row of rows) {
    const raw: Record<string, string> = (row.rawData as Record<string, string>) ?? {}

    // Campos da linha (denormalizados primeiro, rawData como fallback)
    const externalId   = row.externalId    ?? raw.negotiation ?? raw.externalId ?? ''
    const customerName = (row.customerName ?? raw.customerName ?? raw.unit ?? '').trim() || '(não informado)'
    const sellerName   = (row.sellerName   ?? raw.sellerName   ?? '').trim() || undefined
    const plate        = normalizePlate(row.plate ?? raw.plate)
    const vehicleModel = (row.vehicleModel ?? raw.vehicle ?? '').trim() || undefined
    const statusMain   = (row.statusMain   ?? raw.statusMain   ?? '').trim()
    const statusDetail = (row.statusDetail ?? raw.statusDetail ?? '').trim() || undefined
    const saleDateRaw  = row.saleDate      ?? raw.saleDate
    const saleValue    = parseDecimalValue(row.saleValue    ?? raw.saleValue)
    const docValue     = parseDecimalValue(row.docValue     ?? raw.docValue)
    const financedValue= parseDecimalValue(row.financedValue?? raw.financedValue)
    const bank         = (row.bank         ?? raw.bank ?? '').trim() || undefined
    const returnType   = (row.returnType   ?? raw.returnType  ?? '').trim() || undefined
    const dealTypeRaw  = (row.dealType     ?? raw.dealType    ?? '').trim()
    const saleDate     = parseDateValue(saleDateRaw)
    const dealType     = mapDealType(dealTypeRaw || statusMain)
    const dealStatus   = mapDealStatus(statusMain)
    const sheetName    = row.sheetName ?? ''
    const negotiation  = externalId || undefined

    // Marca como PROCESSANDO
    if (!opts.dryRun) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (prisma.sheetImportRow as any).update({
        where: { id: row.id },
        data:  { status: 'PROCESSANDO' },
      })
    }

    try {
      // ── 1. Resolve vendedor ─────────────────────────────────────────────────
      const sellerRes = await resolveSellerWithFallback(sellerName, unitId)

      if (opts.dryRun) {
        summary.skipped++
        if (sellerRes.isProvisional) summary.provisionalSellers++
        continue
      }

      // ── 2. Upsert Customer ──────────────────────────────────────────────────
      const customerId = await upsertCustomer(tenantId, customerName)

      // ── 3. Upsert Vehicle ───────────────────────────────────────────────────
      const vehicleId = await upsertVehicle(tenantId, unitId, plate, vehicleModel, customerId)

      // ── 4. Upsert Deal ──────────────────────────────────────────────────────
      const dedupeWhere = externalId
        ? { tenantId, externalId }
        : null

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const existingDeal = dedupeWhere
        ? await (prisma.deal as any).findFirst({ where: dedupeWhere })
        : null

      const dealNotes = [
        `Negociação importada da planilha. Origem: ${row.referenceMonth ?? sheetName}.`,
        externalId              ? `ID externo: ${externalId}.`                         : null,
        sellerRes.isProvisional ? sellerRes.warning ?? 'Vendedor vinculado provisoriamente.' : null,
        returnType              ? `Tipo de retorno: ${returnType}.`                    : null,
      ].filter(Boolean).join('\n')

      // Gera dealNumber único para novas negociações
      const dealYear  = new Date().getFullYear()
      const dealCount = await prisma.deal.count({ where: { tenantId } }).catch(() => 0)
      const dealNumber = `NEG-${dealYear}-${String(dealCount + 1).padStart(4, '0')}`

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const dealData: any = {
        tenantId,
        unitId,
        sellerId:           sellerRes.sellerId ?? undefined,
        customerId:         customerId         ?? undefined,
        type:               dealType,
        status:             dealStatus,
        source:             'PLANILHA',
        saleDate:           saleDate           ?? undefined,
        vehicleValue:       saleValue          !== null ? saleValue : undefined,
        externalId:         externalId         || undefined,
        sellerNameFromSheet:sellerName         ?? undefined,
        isSellerProvisional:sellerRes.isProvisional,
        notes:              dealNotes,
      }

      let dealId: string
      let isUpdate = false

      if (existingDeal) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await (prisma.deal as any).update({ where: { id: existingDeal.id }, data: dealData })
        dealId   = existingDeal.id
        isUpdate = true

        await prisma.dealStatusHistory.create({
          data: {
            dealId,
            previousStatus: existingDeal.status,
            newStatus:      dealStatus,
            reason:         `Atualizado por reprocessamento de planilha. Aba: ${sheetName}. ID externo: ${externalId || '—'}.`,
          },
        }).catch(() => {})
      } else {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const created = await (prisma.deal as any).create({ data: { ...dealData, dealNumber } })
        dealId = created.id

        await prisma.dealStatusHistory.create({
          data: {
            dealId,
            newStatus: dealStatus,
            reason: `Negociação criada automaticamente a partir de dados importados da planilha. Origem: ${row.referenceMonth ?? sheetName}. ID externo: ${externalId || '—'}.`,
          },
        }).catch(() => {})
      }

      // ── 5. DealVehicle ──────────────────────────────────────────────────────
      if (vehicleId) {
        await ensureDealVehicle(dealId, vehicleId).catch(() => {})
      }

      // ── 6. Contract (financeiro) ────────────────────────────────────────────
      await upsertContract({
        tenantId,
        unitId,
        dealId,
        customerId,
        vehicleId,
        sellerId:      sellerRes.sellerId,
        saleValue,
        docValue,
        financedValue,
        bank,
        saleDate,
        dealType,
      }).catch(() => {})

      // ── 7. Pendências ───────────────────────────────────────────────────────
      let pendencyCount = 0

      // Pendência de status (veículo não entregue, aguardando doc, etc.)
      if (sellerRes.sellerId && hasPendencyKeyword(statusMain)) {
        const created = await createStatusPendency({
          tenantId,
          unitId,
          dealId,
          sellerId:     sellerRes.sellerId,
          customerId,
          vehicleId,
          customerName,
          plate,
          negotiation,
          statusMain,
          statusDetail,
          sheetName,
        }).catch(() => false)
        if (created) pendencyCount++
      }

      // Pendência administrativa de vendedor provisório
      if (sellerRes.isProvisional && sellerRes.sellerId) {
        await createProvisionalSellerPendency({
          tenantId,
          unitId,
          dealId,
          sellerId:     sellerRes.sellerId,
          customerName,
          plate,
          negotiation,
          warning:      sellerRes.warning ?? 'Vendedor vinculado provisoriamente.',
        }).catch(() => {})
        pendencyCount++
      }

      summary.pendenciesCreated += pendencyCount

      // ── 8. AuditLog ─────────────────────────────────────────────────────────
      await prisma.auditLog.create({
        data: {
          tenantId,
          userId:   opts.triggeredById ?? undefined,
          action:   isUpdate ? 'UPDATE' : 'CREATE',
          entity:   'Deal',
          entityId: dealId,
          afterData: {
            externalId,
            customerName,
            sellerName:       sellerName ?? null,
            isSellerProvisional: sellerRes.isProvisional,
            source: 'SHEETS',
            sheetName,
          },
          status: 'SUCCESS',
        },
      }).catch(() => {})

      // ── Atualiza SheetImportRow ─────────────────────────────────────────────
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await (prisma.sheetImportRow as any).update({
        where: { id: row.id },
        data:  {
          status:         isUpdate ? 'NEGOCIACAO_ATUALIZADA' : 'NEGOCIACAO_CRIADA',
          dealId,
          warningMessage: sellerRes.warning ?? undefined,
          processedAt:    new Date(),
        },
      })

      if (isUpdate) summary.dealsUpdated++
      else          summary.dealsCreated++
      if (sellerRes.isProvisional) summary.provisionalSellers++

    } catch (err) {
      summary.errors++
      const msg = err instanceof Error ? err.message : String(err)
      summary.errorDetails.push(`[${externalId || row.id}] ${msg}`)

      if (!opts.dryRun) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await (prisma.sheetImportRow as any).update({
          where: { id: row.id },
          data:  {
            status:       'ERRO',
            errorMessage: msg.slice(0, 500),
            processedAt:  new Date(),
          },
        }).catch(() => {})
      }
    }
  }

  summary.durationMs = Date.now() - startedAt
  return summary
}

// ── Processa uma linha de dados mapeados diretamente em Deal ─────────────────
// Reutilizado tanto por runDealProcessor (staging) quanto por
// runDealProcessorFromSheet (leitura direta da planilha).

interface RowData {
  externalId:    string
  customerName:  string
  sellerName:    string | undefined
  plate:         string | null
  vehicleModel:  string | undefined
  statusMain:    string
  statusDetail:  string | undefined
  saleDate:      Date | null
  saleValue:     number | null
  docValue:      number | null
  financedValue: number | null
  bank:          string | undefined
  returnType:    string | undefined
  dealType:      string
  sheetName:     string
  referenceMonth:string | undefined
  negotiation:   string | undefined
}

async function processRowIntoDeals(
  row:         RowData,
  tenantId:    string,
  unitId:      string,
  opts:        { dryRun?: boolean; triggeredById?: string },
  summary:     DealProcessorSummary,
  stagingId?:  string,   // SheetImportRow.id se existir
): Promise<void> {
  const dealType   = mapDealType(row.dealType || row.statusMain)
  const dealStatus = mapDealStatus(row.statusMain)

  // 1. Resolve vendedor
  const sellerRes = await resolveSellerWithFallback(row.sellerName, unitId)

  if (opts.dryRun) {
    summary.skipped++
    if (sellerRes.isProvisional) summary.provisionalSellers++
    return
  }

  // 2. Upsert Customer
  const customerId = await upsertCustomer(tenantId, row.customerName)

  // 3. Upsert Vehicle
  const vehicleId = await upsertVehicle(tenantId, unitId, row.plate, row.vehicleModel, customerId)

  // 4. Upsert Deal
  // Dedup primário: por externalId (funciona após migração).
  // Dedup secundário: por nota "ID externo: X" nas notas (funciona antes da migração).
  let existingDeal: { id: string; status: string } | null = null

  if (row.externalId) {
    // Tenta dedup via coluna externalId (pós-migração)
    existingDeal = await (prisma.deal as any)
      .findFirst({ where: { tenantId, externalId: row.externalId } })
      .catch(() => null)

    // Fallback: dedup via campo notes (pré-migração — evita duplicação ao reprocessar)
    if (!existingDeal) {
      existingDeal = await prisma.deal.findFirst({
        where: { tenantId, notes: { contains: `ID externo: ${row.externalId}` } },
      }).catch(() => null)
    }
  }

  const dealNotes = [
    `Negociação importada da planilha. Origem: ${row.referenceMonth ?? row.sheetName}.`,
    row.externalId          ? `ID externo: ${row.externalId}.`                          : null,
    sellerRes.isProvisional ? sellerRes.warning ?? 'Vendedor vinculado provisoriamente.' : null,
    row.returnType          ? `Tipo de retorno: ${row.returnType}.`                      : null,
  ].filter(Boolean).join('\n')

  // Campos base — sempre existem no schema original
  const baseDealData = {
    tenantId,
    unitId,
    sellerId:     sellerRes.sellerId ?? undefined,
    customerId:   customerId         ?? undefined,
    type:         dealType           as 'VENDA' | 'TROCA' | 'COMPRA' | 'CONSIGNACAO',
    status:       dealStatus         as 'EM_ANDAMENTO' | 'FINALIZADA' | 'CANCELADA',
    vehicleValue: row.saleValue !== null ? row.saleValue : undefined,
    notes:        dealNotes,
  }

  // Gera dealNumber único (campo adicionado pela migração)
  const dealYear  = new Date().getFullYear()
  const dealCount = await prisma.deal.count({ where: { tenantId } }).catch(() => 0)
  const dealNumber = `NEG-${dealYear}-${String(dealCount + 1).padStart(4, '0')}`

  // Campos extras (adicionados pela migração) — tentados mas não obrigatórios
  const extraDealFields = {
    saleDate:           row.saleDate      ?? undefined,
    externalId:         row.externalId    || undefined,
    sellerNameFromSheet:row.sellerName    ?? undefined,
    isSellerProvisional:sellerRes.isProvisional,
    source:             'PLANILHA',
    dealNumber:         existingDeal ? undefined : dealNumber,
  }

  let dealId: string
  let isUpdate = false

  if (existingDeal) {
    // Tenta atualizar com todos os campos; se falhar (pré-migração), usa só os base
    await (prisma.deal as any).update({
      where: { id: existingDeal.id },
      data:  { ...baseDealData, ...extraDealFields },
    }).catch(async () => {
      await prisma.deal.update({ where: { id: existingDeal!.id }, data: baseDealData })
    })

    dealId   = existingDeal.id
    isUpdate = true
    await prisma.dealStatusHistory.create({
      data: {
        dealId,
        previousStatus: existingDeal.status,
        newStatus:      dealStatus,
        reason: `Atualizado por reprocessamento de planilha. Aba: ${row.sheetName}. ID: ${row.externalId || '—'}.`,
      },
    }).catch(() => {})
  } else {
    // Tenta criar com todos os campos; se falhar (pré-migração), usa só os base
    const created: { id: string } = await (prisma.deal as any)
      .create({ data: { ...baseDealData, ...extraDealFields } })
      .catch(async () => prisma.deal.create({ data: baseDealData }))

    dealId = created.id
    await prisma.dealStatusHistory.create({
      data: {
        dealId,
        newStatus: dealStatus,
        reason: `Negociação criada automaticamente a partir de dados importados da planilha. Origem: ${row.referenceMonth ?? row.sheetName}. ID externo: ${row.externalId || '—'}.`,
      },
    }).catch(() => {})
  }

  // 5. DealVehicle
  if (vehicleId) await ensureDealVehicle(dealId, vehicleId).catch(() => {})

  // 6. Contract
  await upsertContract({
    tenantId, unitId, dealId, customerId, vehicleId,
    sellerId:      sellerRes.sellerId,
    saleValue:     row.saleValue,
    docValue:      row.docValue,
    financedValue: row.financedValue,
    bank:          row.bank,
    saleDate:      row.saleDate,
    dealType,
  }).catch(() => {})

  // 7. Pendências
  let pendencyCount = 0
  if (sellerRes.sellerId && hasPendencyKeyword(row.statusMain)) {
    const ok = await createStatusPendency({
      tenantId, unitId, dealId,
      sellerId:     sellerRes.sellerId,
      customerId, vehicleId,
      customerName: row.customerName,
      plate:        row.plate,
      negotiation:  row.negotiation,
      statusMain:   row.statusMain,
      statusDetail: row.statusDetail,
      sheetName:    row.sheetName,
    }).catch(() => false)
    if (ok) pendencyCount++
  }
  if (sellerRes.isProvisional && sellerRes.sellerId) {
    await createProvisionalSellerPendency({
      tenantId, unitId, dealId,
      sellerId:     sellerRes.sellerId,
      customerName: row.customerName,
      plate:        row.plate,
      negotiation:  row.negotiation,
      warning:      sellerRes.warning ?? 'Vendedor vinculado provisoriamente.',
    }).catch(() => {})
    pendencyCount++
  }
  summary.pendenciesCreated += pendencyCount

  // 8. AuditLog
  await prisma.auditLog.create({
    data: {
      tenantId,
      userId:    opts.triggeredById ?? undefined,
      action:    isUpdate ? 'UPDATE' : 'CREATE',
      entity:    'Deal',
      entityId:  dealId,
      afterData: { externalId: row.externalId, customerName: row.customerName, source: 'SHEETS' },
      status:    'SUCCESS',
    },
  }).catch(() => {})

  // 9. Atualiza staging se existir
  if (stagingId) {
    await (prisma.sheetImportRow as any).update({
      where: { id: stagingId },
      data:  {
        status:         isUpdate ? 'NEGOCIACAO_ATUALIZADA' : 'NEGOCIACAO_CRIADA',
        dealId,
        warningMessage: sellerRes.warning ?? undefined,
        processedAt:    new Date(),
      },
    }).catch(() => {})
  }

  if (isUpdate) summary.dealsUpdated++
  else          summary.dealsCreated++
  if (sellerRes.isProvisional) summary.provisionalSellers++
}

// ── Resolve IDs reais de Tenant e Unit ───────────────────────────────────────
// O GoogleSheetConfig pode armazenar publicId ("AD-XXXX") ou name ("Loja X")
// em vez do CUID real. Esta função garante que usamos o id correto para FKs.

async function resolveConfigIds(
  rawTenantId: string,
  rawUnitId:   string,
): Promise<{ tenantId: string; unitId: string }> {
  // Detecta se parece um CUID (começa com 'c' e tem 25+ chars) ou não
  const isCuid = (s: string) => /^c[a-z0-9]{20,}$/.test(s)

  // Resolve tenant
  let tenantId = rawTenantId
  if (!isCuid(rawTenantId)) {
    const t = await prisma.tenant.findFirst({
      where: { OR: [{ publicId: rawTenantId }, { slug: rawTenantId }, { name: rawTenantId }] },
      select: { id: true },
    })
    if (t) tenantId = t.id
  }

  // Resolve unit
  let unitId = rawUnitId
  if (!isCuid(rawUnitId)) {
    const u = await prisma.unit.findFirst({
      where: { OR: [{ name: { equals: rawUnitId, mode: 'insensitive' } }, { id: rawUnitId }] },
      select: { id: true },
    })
    if (u) unitId = u.id
  }

  return { tenantId, unitId }
}

// ── Opções para leitura direta da planilha ────────────────────────────────────

export interface DealProcessorFromSheetOptions {
  configId:       string
  tabId?:         string   // undefined = todas as abas ativas
  dryRun?:        boolean
  triggeredById?: string
  maxRows?:       number
}

// ── Lê a planilha e processa cada linha como Deal (sem staging pré-existente) ─

export async function runDealProcessorFromSheet(
  opts: DealProcessorFromSheetOptions,
): Promise<DealProcessorSummary> {
  const startedAt = Date.now()
  const summary: DealProcessorSummary = {
    totalRows: 0, skipped: 0, dealsCreated: 0, dealsUpdated: 0,
    provisionalSellers: 0, pendenciesCreated: 0, errors: 0,
    errorDetails: [], durationMs: 0, dryRun: opts.dryRun ?? false,
  }

  // Carrega configuração
  const config = await prisma.googleSheetConfig.findUnique({
    where:   { id: opts.configId },
    include: {
      tabs: {
        where:   { active: true },
        orderBy: [{ sortOrder: 'asc' }, { createdAt: 'asc' }],
      },
    },
  })
  if (!config)          throw new Error('Importador não encontrado.')
  if (!config.tenantId) throw new Error('Tenant não configurado no importador.')
  if (!config.unitId)   throw new Error('Unidade não configurada no importador.')
  if (!config.tabs || config.tabs.length === 0) throw new Error('Nenhuma aba ativa cadastrada.')

  // Resolve IDs reais de tenant e unit (o config pode guardar publicId ou name em vez do CUID)
  const resolvedIds = await resolveConfigIds(config.tenantId!, config.unitId!)
  const tenantId = resolvedIds.tenantId
  const unitId   = resolvedIds.unitId

  const mapping = (config.columnMapping ?? {}) as Record<string, string>
  const maxRows = opts.maxRows && opts.maxRows > 0 ? opts.maxRows : Infinity

  const activeTabs = opts.tabId
    ? config.tabs.filter(t => t.id === opts.tabId)
    : config.tabs

  const auth   = await buildGoogleAuth()
  const sheets = google.sheets({ version: 'v4', auth })

  for (const tab of activeTabs) {
    try {
      const response = await sheets.spreadsheets.values.get({
        spreadsheetId: config.spreadsheetId,
        range:         `${tab.sheetName}!A1:ZZ`,
      })

      const allRows  = response.data.values ?? []
      if (allRows.length < 2) continue

      const dataRows = allRows.slice(tab.headerRow ?? 1)
      let rowIndex   = tab.headerRow ?? 1

      for (const rawRow of dataRows) {
        if (summary.totalRows >= maxRows) break
        rowIndex++

        // Aplica mapeamento
        const mapped: Record<string, string> = {}
        Object.entries(mapping).forEach(([idx, field]) => {
          mapped[field] = String(rawRow[Number(idx)] ?? '').trim()
        })

        // Validações mínimas
        const negotiationId = mapped.negotiation || mapped.externalId || ''
        if (!negotiationId) continue
        if (!mapped.customerName && !mapped.unit) continue

        summary.totalRows++

        // Tenta salvar no staging (não bloqueante)
        let stagingId: string | undefined
        try {
          const dedupeKey = `${config.id}:${tab.sheetName}:${negotiationId}`
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const existingStaging: any = await (prisma.sheetImportRow as any).findFirst({ where: { dedupeKey } }).catch(() => null)

          const stagingData = {
            configId:      config.id,
            tabId:         tab.id,
            sheetName:     tab.sheetName,
            rowIndex,
            referenceMonth:tab.monthReference ?? undefined,
            rawData:       mapped,
            externalId:    negotiationId || undefined,
            dedupeKey,
            customerName:  mapped.customerName || mapped.unit || undefined,
            sellerName:    mapped.sellerName   || undefined,
            plate:         mapped.plate        || undefined,
            vehicleModel:  mapped.vehicle      || undefined,
            saleDate:      mapped.saleDate     || undefined,
            statusMain:    mapped.statusMain   || undefined,
            statusDetail:  mapped.statusDetail || undefined,
            saleValue:     mapped.saleValue    || undefined,
            docValue:      mapped.docValue     || undefined,
            financedValue: mapped.financedValue|| undefined,
            bank:          mapped.bank         || undefined,
            returnType:    mapped.returnType   || undefined,
            dealType:      mapped.dealType     || undefined,
            timeInStock:   mapped.timeInStock  || undefined,
            status:        'PROCESSANDO' as const,
            updatedAt:     new Date(),
          }

          if (existingStaging) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const updated: any = await (prisma.sheetImportRow as any).update({
              where: { id: existingStaging.id },
              data:  { ...stagingData, errorMessage: null },
            }).catch(() => null)
            stagingId = updated?.id
          } else {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const created: any = await (prisma.sheetImportRow as any).create({ data: stagingData }).catch(() => null)
            stagingId = created?.id
          }
        } catch {
          // Staging opcional — não bloqueia o processamento
        }

        // Processa a linha
        try {
          const rowData: RowData = {
            externalId:    negotiationId,
            customerName:  mapped.customerName || mapped.unit || '(não informado)',
            sellerName:    mapped.sellerName   || undefined,
            plate:         normalizePlate(mapped.plate),
            vehicleModel:  mapped.vehicle      || undefined,
            statusMain:    mapped.statusMain   || '',
            statusDetail:  mapped.statusDetail || undefined,
            saleDate:      parseDateValue(mapped.saleDate),
            saleValue:     parseDecimalValue(mapped.saleValue),
            docValue:      parseDecimalValue(mapped.docValue),
            financedValue: parseDecimalValue(mapped.financedValue),
            bank:          mapped.bank         || undefined,
            returnType:    mapped.returnType   || undefined,
            dealType:      mapped.dealType     || '',
            sheetName:     tab.sheetName,
            referenceMonth:tab.monthReference  ?? undefined,
            negotiation:   negotiationId       || undefined,
          }

          await processRowIntoDeals(rowData, tenantId, unitId, opts, summary, stagingId)
        } catch (err) {
          summary.errors++
          const msg = err instanceof Error ? err.message : String(err)
          summary.errorDetails.push(`[${negotiationId}] ${msg}`)

          if (stagingId) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await (prisma.sheetImportRow as any).update({
              where: { id: stagingId },
              data:  { status: 'ERRO', errorMessage: msg.slice(0, 500), processedAt: new Date() },
            }).catch(() => {})
          }
        }
      }

      // Atualiza lastSync da aba
      if (!opts.dryRun) {
        await prisma.googleSheetTab.update({
          where: { id: tab.id },
          data:  { lastSyncAt: new Date(), lastSyncStatus: 'SUCCESS', totalRowsLast: dataRows.length },
        }).catch(() => {})
      }
    } catch (tabErr) {
      const msg = tabErr instanceof Error ? tabErr.message : String(tabErr)
      summary.errors++
      summary.errorDetails.push(`Aba ${tab.sheetName}: ${msg}`)
    }
  }

  summary.durationMs = Date.now() - startedAt
  return summary
}

// ── Estatísticas de linhas importadas ─────────────────────────────────────────

export async function getSheetRowStats(configId: string): Promise<SheetRowStats> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const groups: any[] = await (prisma.sheetImportRow as any).groupBy({
    by:    ['status'],
    where: { configId },
    _count:{ _all: true },
  })

  const countByStatus: Record<string, number> = {}
  for (const g of groups) countByStatus[g.status] = g._count._all

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const lastRow: any = await (prisma.sheetImportRow as any).findFirst({
    where:   { configId, processedAt: { not: null } },
    orderBy: { processedAt: 'desc' },
    select:  { processedAt: true },
  })

  return {
    total:           Object.values(countByStatus).reduce((a, b) => a + b, 0),
    pending:         countByStatus['PENDENTE']              ?? 0,
    dealCreated:     countByStatus['NEGOCIACAO_CRIADA']     ?? 0,
    dealUpdated:     countByStatus['NEGOCIACAO_ATUALIZADA'] ?? 0,
    waitingReview:   countByStatus['AGUARDANDO_CONFERENCIA']?? 0,
    error:           countByStatus['ERRO']                  ?? 0,
    ignored:         countByStatus['IGNORADA']              ?? 0,
    lastProcessedAt: lastRow?.processedAt?.toISOString()    ?? null,
  }
}

// =============================================================================
// Provedor de consulta veicular autorizado/contratado
// =============================================================================
//
// Este adapter é o ponto de integração com provedores externos AUTORIZADOS,
// como SERPRO, APIs estaduais conveniadas, ou provedores privados contratados.
//
// IMPORTANTE — Requisitos legais e de segurança:
//   • Use SOMENTE bases, APIs e provedores com autorização expressa.
//   • Não utilize scraping, CAPTCHA bypass ou acesso não autorizado.
//   • Dados como chassi completo, RENAVAM e restrições só estarão disponíveis
//     se o provedor contratado e a legislação vigente permitirem.
//   • Dados pessoais do proprietário (nome, CPF) não devem ser retornados sem
//     base legal adequada e finalidade justificada (LGPD, art. 7°).
//   • API keys e tokens NUNCA devem chegar ao frontend.
//   • Configure via variáveis de ambiente no servidor.
//
// Variáveis de ambiente necessárias:
//   VEHICLE_LOOKUP_API_URL    — URL base da API contratada
//   VEHICLE_LOOKUP_API_KEY    — Chave/token de autenticação
//   VEHICLE_LOOKUP_TIMEOUT_MS — Timeout em ms (padrão: 8000)
//
// Para habilitar, configure as variáveis acima. Se não configuradas,
// este provedor retorna found: false graciosamente e o sistema continua
// com fallback manual.
// =============================================================================

import type { VehicleLookupProvider, VehicleLookupResult, VehicleLookupData } from '../types'
import { getActiveIntegrationCredential } from '@/lib/integrations/active'

const ENV_API_URL = process.env.VEHICLE_LOOKUP_API_URL
const ENV_API_KEY = process.env.VEHICLE_LOOKUP_API_KEY
const TIMEOUT_MS  = Number(process.env.VEHICLE_LOOKUP_TIMEOUT_MS ?? 8_000)

interface ResolvedPlateConfig {
  url:   string
  key:   string
  source: 'integration' | 'env'
}

/**
 * Resolve a configuração ativa: primeiro tenta IntegrationCredential
 * (service=PLATE_LOOKUP, configurada via /master/integrations), depois
 * cai no fallback de variáveis de ambiente (dev local).
 */
async function resolvePlateConfig(): Promise<ResolvedPlateConfig | null> {
  try {
    const cred = await getActiveIntegrationCredential('PLATE_LOOKUP')
    if (cred?.apiUrl && cred?.apiKey) {
      return { url: cred.apiUrl.replace(/\/+$/, ''), key: cred.apiKey, source: 'integration' }
    }
  } catch { /* DB indisponível — segue para env */ }

  if (ENV_API_URL && ENV_API_KEY) {
    return { url: ENV_API_URL.replace(/\/+$/, ''), key: ENV_API_KEY, source: 'env' }
  }
  return null
}

/** Verifica se o provedor está configurado (DB ou env). */
export async function isAuthorizedProviderConfigured(): Promise<boolean> {
  const cfg = await resolvePlateConfig()
  return !!cfg
}

export class AuthorizedProvider implements VehicleLookupProvider {
  readonly name = 'authorized_provider'

  async lookupByPlate(plate: string): Promise<VehicleLookupResult> {
    const cfg = await resolvePlateConfig()
    if (!cfg) {
      return {
        success: true,
        found:   false,
        message: 'API de placa não configurada. Configure uma credencial PLATE_LOOKUP em /master/integrations ou preencha os dados manualmente.',
      }
    }
    const API_URL = cfg.url
    const API_KEY = cfg.key

    const controller = new AbortController()
    const timer = setTimeout(() => controller.abort(), TIMEOUT_MS)

    try {
      const response = await fetch(`${API_URL}/consulta/placa/${plate}`, {
        method:  'GET',
        headers: {
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type':  'application/json',
          'Accept':        'application/json',
        },
        signal: controller.signal,
      })

      clearTimeout(timer)

      if (!response.ok) {
        if (response.status === 404) {
          return { success: true, found: false, source: this.name }
        }
        console.warn(`[AuthorizedProvider] HTTP ${response.status} para placa ${plate}`)
        return {
          success: false,
          found:   false,
          error:   'Provedor retornou erro. Tente novamente ou preencha manualmente.',
        }
      }

      const raw = await response.json()
      const data = normalizePlacaResponse(plate, raw)
      return { success: true, found: true, source: this.name, data }
    } catch (err: unknown) {
      clearTimeout(timer)
      const isAbort = err instanceof Error && err.name === 'AbortError'
      console.warn(`[AuthorizedProvider] ${isAbort ? 'Timeout' : 'Erro'} ao consultar placa ${plate}:`, err)
      return {
        success: false,
        found:   false,
        error:   isAbort
          ? 'Tempo limite da consulta excedido. Tente novamente ou preencha manualmente.'
          : 'Falha ao conectar com o provedor. Preencha manualmente.',
      }
    }
  }

}

// =============================================================================
// Normalizador da resposta da API Placas
// =============================================================================
//
// A API Placas retorna campos em formatos diferentes em níveis distintos:
//   - root:  MARCA, MODELO, SUBMODELO, VERSAO, marca, modelo, marcaModelo,
//            ano, anoModelo, chassi, cor, municipio, origem, placa, uf,
//            placa_alternativa, situacao, logo, extra, fipe.dados
//   - extra: ano_fabricacao, ano_modelo, caixa_cambio, cilindradas,
//            combustivel, especie, modelo, municipio, nacionalidade,
//            quantidade_passageiro, segmento, sub_segmento, tipo_veiculo,
//            uf_placa, placa_modelo_novo, placa_modelo_antigo
//   - fipe.dados[]: { codigo_fipe, texto_marca, texto_modelo, texto_valor,
//                     mes_referencia, ano_modelo, combustivel, score,
//                     tipo_modelo }
//
// As regras de fallback e seleção do "melhor FIPE" estão documentadas no
// requisito de produto e seguem a ordem: maior score → mesmo ano_modelo →
// combustível compatível → similaridade textual. Quando o provedor não traz
// um campo, deixamos vazio para preenchimento manual.

const TIPO_MODELO_TO_CATEGORY: Record<string, 'CAR' | 'MOTORCYCLE' | 'TRUCK'> = {
  '1': 'CAR', '2': 'MOTORCYCLE', '3': 'TRUCK',
}

function inferVehicleType(rawTipo: unknown, extraTipo: unknown, fipeTipo: unknown): 'CAR' | 'MOTORCYCLE' | 'TRUCK' | undefined {
  const candidates = [rawTipo, extraTipo, fipeTipo]
    .filter((v) => v != null)
    .map((v) => String(v).toUpperCase().trim())
  for (const v of candidates) {
    if (v === '1' || v === '2' || v === '3') return TIPO_MODELO_TO_CATEGORY[v]
    if (v.includes('MOTO'))     return 'MOTORCYCLE'
    if (v.includes('CAMINHAO') || v.includes('CAMINHÃO') || v.includes('CAMINHONETE TRUCK')) return 'TRUCK'
    if (v.includes('CARRO') || v.includes('AUTOMOVEL') || v.includes('AUTOMÓVEL') ||
        v.includes('CAMIONETA') || v.includes('CAMINHONETE') || v.includes('UTILITARIO') ||
        v.includes('UTILITÁRIO') || v.includes('SUV') || v.includes('PICAPE')) return 'CAR'
  }
  return undefined
}

/** Remove a marca do início do nome do modelo, ex: "VOLKSWAGEN GOL 1.0" → "GOL 1.0" */
function stripBrandFromModel(model: string, brand: string): string {
  if (!model || !brand) return model
  const b = brand.toUpperCase().trim()
  const m = model.toUpperCase().trim()
  if (m.startsWith(b + ' ')) return model.slice(brand.length).trim()
  return model
}

interface FipeDado {
  codigo_fipe?:    string
  texto_marca?:    string
  texto_modelo?:   string
  texto_valor?:    string
  mes_referencia?: string
  ano_modelo?:     string | number
  combustivel?:    string
  score?:          number
  tipo_modelo?:    string | number
}

/** Parser tolerante de "R$ 91.320,00" / "91.320,00" / "91320" / number → number em reais */
function parseFipeValue(s: unknown): number | null {
  if (s == null || s === '') return null
  if (typeof s === 'number') return Number.isFinite(s) ? s : null
  const str = String(s).trim().replace(/^R\$\s*/i, '').replace(/\s/g, '')
  if (!str) return null
  // Se tem vírgula, ela é decimal e pontos são milhar. Senão, pontos são milhar.
  const normalized = str.includes(',')
    ? str.replace(/\./g, '').replace(',', '.')
    : str.replace(/\./g, '')
  const n = Number(normalized)
  return Number.isFinite(n) && n > 0 ? n : null
}

/** Seleciona o melhor item FIPE entre as opções disponíveis. */
export function pickBestFipe(
  dados: FipeDado[] | undefined,
  ctx: { brand?: string; model?: string; version?: string; anoModelo?: number | null; combustivel?: string | null },
): FipeDado | null {
  if (!Array.isArray(dados) || dados.length === 0) return null
  const norm = (s: string) => s.toUpperCase().normalize('NFD').replace(/[̀-ͯ]/g, '')
  const targetTxt = norm([ctx.brand, ctx.model, ctx.version].filter(Boolean).join(' '))

  const scored = dados.map((d) => {
    const baseScore = Number(d.score ?? 0)
    let bonus = 0
    if (ctx.anoModelo && d.ano_modelo && Number(d.ano_modelo) === ctx.anoModelo) bonus += 100
    if (ctx.combustivel && d.combustivel && norm(d.combustivel).startsWith(norm(ctx.combustivel)[0] ?? '')) bonus += 25
    if (targetTxt && d.texto_modelo) {
      const dm = norm(d.texto_modelo)
      // similaridade simples: palavras em comum
      const targetWords = new Set(targetTxt.split(/\s+/).filter(Boolean))
      const overlap = dm.split(/\s+/).filter((w) => targetWords.has(w)).length
      bonus += overlap * 10
    }
    return { d, total: baseScore + bonus }
  })
  scored.sort((a, b) => b.total - a.total)
  return scored[0]?.d ?? null
}

export function normalizePlacaResponse(plate: string, raw: Record<string, unknown>): VehicleLookupData {
  const r = raw as {
    MARCA?: string; MODELO?: string; SUBMODELO?: string; VERSAO?: string
    marca?: string; modelo?: string; marcaModelo?: string
    ano?: string | number; anoModelo?: string | number
    chassi?: string; cor?: string; municipio?: string; origem?: string
    placa?: string; uf?: string; tipo_veiculo?: string; vehicleType?: string
    extra?: Record<string, unknown>
    fipe?: { dados?: FipeDado[] }
  }
  const extra = (r.extra ?? {}) as Record<string, unknown>

  // ── Marca ─────────────────────────────────────────────────────────────────
  const brand = (
    (typeof r.marca === 'string' && r.marca) ||
    (typeof r.MARCA === 'string' && r.MARCA) ||
    (typeof r.marcaModelo === 'string' && r.marcaModelo.split('/')[0]) ||
    ''
  ).trim() || undefined

  // ── Modelo ───────────────────────────────────────────────────────────────
  const modelFromMarcaModelo = typeof r.marcaModelo === 'string' && r.marcaModelo.includes('/')
    ? r.marcaModelo.split('/').slice(1).join('/').trim()
    : ''
  const extraModelRaw = typeof extra.modelo === 'string' ? extra.modelo : ''
  const extraModelClean = brand && extraModelRaw ? stripBrandFromModel(extraModelRaw, brand) : extraModelRaw
  let model = (
    (typeof r.modelo === 'string' && r.modelo) ||
    (typeof r.MODELO === 'string' && r.MODELO) ||
    (typeof r.SUBMODELO === 'string' && r.SUBMODELO) ||
    extraModelClean ||
    modelFromMarcaModelo ||
    ''
  ).trim() || undefined

  // ── Versão ───────────────────────────────────────────────────────────────
  // Não preencher "T" sozinho se a API trouxe texto completo via FIPE/SUBMODELO.
  let version = (
    (typeof r.VERSAO === 'string' && r.VERSAO.trim().length > 1 && r.VERSAO) ||
    (typeof r.SUBMODELO === 'string' && r.SUBMODELO) ||
    ''
  ).trim() || undefined

  // ── Anos ─────────────────────────────────────────────────────────────────
  const anoFabricacao = toIntOrUndefined(extra.ano_fabricacao) ?? toIntOrUndefined(r.ano)
  const anoModelo     = toIntOrUndefined(extra.ano_modelo)     ?? toIntOrUndefined(r.anoModelo)

  // ── Combustível ──────────────────────────────────────────────────────────
  const combustivel = (typeof extra.combustivel === 'string' && extra.combustivel.trim()) || undefined

  // ── Tipo de veículo ──────────────────────────────────────────────────────
  const fipeDados = r.fipe?.dados
  const fipeTipoModelo = fipeDados?.[0]?.tipo_modelo
  const vehicleType = inferVehicleType(r.tipo_veiculo ?? r.vehicleType, extra.tipo_veiculo ?? extra.segmento, fipeTipoModelo)

  // ── FIPE: escolhe a melhor entrada do array ─────────────────────────────
  const best = pickBestFipe(fipeDados, { brand, model, version, anoModelo: anoModelo ?? null, combustivel: combustivel ?? null })
  const fipeValue = best ? (parseFipeValue(best.texto_valor) ?? undefined) : undefined
  const fipeCode = best?.codigo_fipe || undefined
  const fipeReferenceMonth = best?.mes_referencia?.trim() || undefined

  // Fallback de versão a partir do FIPE quando ainda não temos texto significativo
  if ((!version || version.length <= 1) && best?.texto_modelo) {
    const txt = best.texto_modelo.trim()
    // Remove prefixo de modelo ("GOL 1.0 FLEX" → "1.0 FLEX") se possível
    if (model) {
      const m = txt.toUpperCase().indexOf(model.toUpperCase())
      version = (m >= 0 ? txt.slice(m + model.length).trim() : txt) || version
    } else {
      version = txt
    }
  }

  // Fallback de combustível a partir do FIPE
  const fuelFinal = combustivel ?? (best?.combustivel ? best.combustivel : undefined)

  const data: VehicleLookupData = {
    plate: (typeof r.placa === 'string' && r.placa) ||
           (typeof extra.placa_modelo_novo === 'string' ? extra.placa_modelo_novo : plate),
    vehicleType,
    brand,
    model,
    version,
    fullModel: [brand, model, version].filter(Boolean).join(' ') || undefined,
    manufactureYear: anoFabricacao,
    modelYear: anoModelo,
    fuel: fuelFinal,
    color: typeof r.cor === 'string' ? r.cor : undefined,
    chassi: typeof r.chassi === 'string' ? r.chassi : undefined,
    renavam: undefined, // API Placas não retorna renavam — preenchimento manual
    engine: undefined,  // motor textual não retornado — preenchimento manual
    displacement: typeof extra.cilindradas === 'string' ? extra.cilindradas : undefined,
    power: undefined,
    transmission: typeof extra.caixa_cambio === 'string' && (extra.caixa_cambio as string).trim()
      ? (extra.caixa_cambio as string)
      : undefined,
    doors: undefined, // não vem na API Placas — preenchimento manual
    bodyType: undefined,
    fipeCode,
    fipeValue,
    fipeReferenceMonth,
    restrictions: [],
    raw,
  }
  return data
}

function toIntOrUndefined(v: unknown): number | undefined {
  if (v == null || v === '') return undefined
  const n = typeof v === 'number' ? v : Number(String(v).replace(/\D/g, ''))
  return Number.isFinite(n) && n > 0 ? Math.floor(n) : undefined
}

// =============================================================================
// Meta WhatsApp Cloud API Service
// =============================================================================

interface SendTemplateParams {
  to: string
  templateName: string
  languageCode?: string
  bodyParams?: string[]
  headerImageUrl?: string
}

interface SendTextParams {
  to: string
  text: string
}

interface MetaApiResponse {
  messages?: Array<{ id: string }>
  error?: { message: string; code: number }
}

class MetaWhatsAppService {
  private get apiVersion() {
    return process.env.META_API_VERSION ?? 'v19.0'
  }
  private get phoneNumberId() {
    return process.env.META_PHONE_NUMBER_ID ?? ''
  }
  private get accessToken() {
    return process.env.META_WHATSAPP_TOKEN ?? ''
  }
  private get baseUrl() {
    return `https://graph.facebook.com/${this.apiVersion}/${this.phoneNumberId}/messages`
  }

  private async request(body: unknown): Promise<MetaApiResponse> {
    const res = await fetch(this.baseUrl, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.accessToken}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(body),
    })

    const data = await res.json() as MetaApiResponse

    if (!res.ok) {
      throw new Error(`Meta API error: ${data.error?.message ?? 'Unknown error'} (code: ${data.error?.code})`)
    }

    return data
  }

  async sendTemplate({ to, templateName, languageCode = 'pt_BR', bodyParams = [], headerImageUrl }: SendTemplateParams) {
    const components: any[] = []

    if (headerImageUrl) {
      components.push({
        type: 'header',
        parameters: [{ type: 'image', image: { link: headerImageUrl } }],
      })
    }

    if (bodyParams.length > 0) {
      components.push({
        type: 'body',
        parameters: bodyParams.map(p => ({ type: 'text', text: p })),
      })
    }

    const body = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: to.replace(/\D/g, ''),
      type: 'template',
      template: {
        name: templateName,
        language: { code: languageCode },
        components: components.length > 0 ? components : undefined,
      },
    }

    return this.request(body)
  }

  async sendText({ to, text }: SendTextParams) {
    const body = {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: to.replace(/\D/g, ''),
      type: 'text',
      text: { body: text, preview_url: false },
    }

    return this.request(body)
  }

  async getMessageStatus(messageId: string) {
    const url = `https://graph.facebook.com/${this.apiVersion}/${messageId}`
    const res = await fetch(url, {
      headers: { 'Authorization': `Bearer ${this.accessToken}` },
    })
    return res.json()
  }
}

// Exportar instância singleton e também uma factory para provedores futuros
export const metaWhatsApp = new MetaWhatsAppService()

// =============================================================================
// Interface de provedor genérico (preparado para Zenvia, Twilio, etc.)
// =============================================================================
export interface WhatsAppProvider {
  sendTemplate(params: SendTemplateParams): Promise<MetaApiResponse>
  sendText(params: SendTextParams): Promise<MetaApiResponse>
  getMessageStatus(messageId: string): Promise<unknown>
}

export function getWhatsAppProvider(): WhatsAppProvider {
  // Futuramente: ler o provedor ativo das configurações e retornar a instância correta
  return metaWhatsApp
}
